export class CrossSourceResidualPatternSearch {
  constructor(private readonly root: string) {}

  async run(): Promise<CrossSourceResidualPatternSearchReport> {
    await mkdir(this.searchRoot(), { recursive: true });
    const state = await readOptionalJson<DiscoveryDaemonState>(
      join(this.root, daemonArtifactRoot, "state.json"),
    );
    const checkpointUsed = state?.lastCycleId
      ? `${daemonArtifactRoot}/checkpoints/${state.lastCycleId}.json`
      : null;
    const targets = await crossSourceResidualTargets();
    const measurements = targets.map(externalRawMeasurementForTarget);
    const residualMeasurements = measurements.filter(
      (measurement) => measurement.residualCandidateAttempted,
    );
    const patterns = crossSourceResidualPatterns(targets, measurements);
    const insightPatterns = patterns.filter(
      (pattern) => pattern.insightCandidateCreated,
    );
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/cross-source-residual-search-continue-searching.json`;
    const report: CrossSourceResidualPatternSearchReport = withEvidenceHash({
      kind: "cross_source_residual_pattern_search" as const,
      status: fundGateResult.passed
        ? ("FUND_FOUND" as const)
        : ("continue_searching_checkpointed" as const),
      checkpointUsed,
      nextCheckpointRef,
      domains: crossSourceResidualDomains(),
      rawTargetsLoaded: targets.length,
      rawMeasurementsPerformed: measurements.length,
      baselinesRun: measurements.reduce(
        (sum, measurement) => sum + measurement.baselinePredictions.length,
        0,
      ),
      residualsFound: residualMeasurements.length,
      patternAttempts: patterns.length,
      sameSourceControlsRun: patterns.reduce(
        (sum, pattern) => sum + pattern.sameSourceControlTargetIds.length,
        0,
      ),
      independentHoldoutChecks: patterns.reduce(
        (sum, pattern) => sum + pattern.independentHoldoutTargetIds.length,
        0,
      ),
      replayRecomputeChecks: patterns.reduce(
        (sum, pattern) => sum + pattern.replayTargetIds.length,
        0,
      ),
      insightCandidatesCreated: insightPatterns.length,
      discoveryCandidatesCreated: 0,
      killedAsOrdinaryVariation: patterns.filter(
        (pattern) =>
          pattern.killReason === "ordinary_population_catalog_variation",
      ).length,
      killedByNoCrossSupport: patterns.filter(
        (pattern) =>
          pattern.killReason === "no_cross_source_or_partition_support",
      ).length,
      killedByHoldout: patterns.filter(
        (pattern) => pattern.killReason === "holdout_not_supported",
      ).length,
      killedByReplay: patterns.filter(
        (pattern) => pattern.killReason === "replay_failed",
      ).length,
      fundGateResult,
      fundFound: fundGateResult.passed,
      remainingBottleneck:
        insightPatterns.length === 0
          ? "Residual recurrence was checked before InsightCandidate birth; no pattern survived same-source controls, independent holdout, and replay pressure."
          : "Cross-source residual patterns reached InsightCandidate birth, but no DiscoveryCandidate or FundCandidateDraft passed protected promotion gates.",
      artifactRefs: crossSourceResidualArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({ report, targets, measurements, patterns });
    return report;
  }

  private searchRoot(): string {
    return join(this.root, daemonArtifactRoot, "cross-source-residual-search");
  }

  private async writeArtifacts(input: {
    report: CrossSourceResidualPatternSearchReport;
    targets: ExternalRawTarget[];
    measurements: ExternalRawMeasurement[];
    patterns: CrossSourceResidualPattern[];
  }): Promise<void> {
    const root = this.searchRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "CROSS_SOURCE_TARGET_RECEIPTS.json"), {
      kind: "cross_source_target_receipts",
      generatedAt: nowIso(),
      targetCount: input.targets.length,
      targets: input.targets,
      evidenceHash: hashEvidence(input.targets),
    });
    await writeJson(join(root, "CROSS_SOURCE_MEASUREMENTS.json"), {
      kind: "cross_source_measurements",
      generatedAt: nowIso(),
      measurementCount: input.measurements.length,
      measurements: input.measurements,
      evidenceHash: hashEvidence(input.measurements),
    });
    await writeJson(join(root, "CROSS_SOURCE_PATTERNS.json"), {
      kind: "cross_source_residual_patterns",
      generatedAt: nowIso(),
      patternCount: input.patterns.length,
      patterns: input.patterns,
      evidenceHash: hashEvidence(input.patterns),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "cross_source_residual_search_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      reportRef: `${daemonArtifactRoot}/cross-source-residual-search/latest.json`,
      insightCandidatesCreated: input.report.insightCandidatesCreated,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "CROSS_SOURCE_TARGETS.md"),
      crossSourceTargetsMarkdown(input.targets),
    );
    await writeText(
      join(root, "CROSS_SOURCE_MEASUREMENTS.md"),
      crossSourceMeasurementsMarkdown(input.measurements),
    );
    await writeText(
      join(root, "CROSS_SOURCE_PATTERN_SEARCH.md"),
      crossSourcePatternsMarkdown(input.patterns),
    );
    await writeText(
      join(root, "SAME_SOURCE_CONTROL_RESULTS.md"),
      crossSourceControlsMarkdown(input.patterns),
    );
    await writeText(
      join(root, "INDEPENDENT_HOLDOUT_RESULTS.md"),
      crossSourceHoldoutsMarkdown(input.patterns),
    );
    await writeText(
      join(root, "REPLAY_RESULTS.md"),
      crossSourceReplayMarkdown(input.patterns),
    );
    await writeText(
      join(root, "INSIGHT_CANDIDATES.md"),
      crossSourceInsightCandidatesMarkdown(input.patterns),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      crossSourceFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      crossSourceNextCheckpointMarkdown(input.report),
    );
  }
}

function crossSourceResidualDomains(): ExternalRawEvidenceDomain[] {
  return [
    "astrophysics_public_catalog_residuals",
    "computational_materials_property_outcomes",
    "climate_energy_residual_targets",
    "formal_bounded_property_outcomes",
  ];
}

async function crossSourceResidualTargets(): Promise<ExternalRawTarget[]> {
  const [materialsTargets, astrophysicsTargets, climateTargets] =
    await Promise.all([
      externalRawMaterialsTargets(),
      externalRawAstrophysicsTargets(),
      externalRawClimateEnergyTargets(),
    ]);
  const formalTargets = Array.from({ length: 30 }, (_, index) =>
    externalRawTargetForDomain("formal_bounded_property_outcomes", index),
  );
  return [
    ...externalRawPadTargets(
      "astrophysics_public_catalog_residuals",
      astrophysicsTargets,
    ),
    ...externalRawPadTargets(
      "computational_materials_property_outcomes",
      materialsTargets,
    ),
    ...externalRawPadTargets("climate_energy_residual_targets", climateTargets),
    ...formalTargets,
  ];
}

async function externalRawClimateEnergyTargets(): Promise<ExternalRawTarget[]> {
  const sourceUrl =
    "https://archive.ics.uci.edu/ml/machine-learning-databases/00374/energydata_complete.csv";
  const fetched = await externalRawFetchText(sourceUrl);
  if (!fetched) return [];
  const rows = externalRawParseCsv(fetched.text);
  return rows
    .filter((row) =>
      [
        "date",
        "Appliances",
        "T_out",
        "RH_out",
        "Windspeed",
        "Visibility",
      ].every((field) => row[field] !== undefined && row[field] !== ""),
    )
    .filter((row) =>
      ["Appliances", "T_out", "RH_out", "Windspeed", "Visibility"].every(
        (field) => Number.isFinite(Number(row[field])),
      ),
    )
    .slice(0, 30)
    .map((row, index) => {
      const targetId = externalRawTargetId(
        "climate_energy_residual_targets",
        index + 1,
      );
      const date = String(row.date);
      const hourMatch = date.match(/\s(\d{2}):/);
      const hour = hourMatch ? Number(hourMatch[1]) : index % 24;
      const rawValues: Record<string, number | string | boolean> = {
        date,
        hour,
        appliancesWh: Number(row.Appliances),
        outsideTemperatureC: Number(row.T_out),
        outsideHumidity: Number(row.RH_out),
        windspeed: Number(row.Windspeed),
        visibility: Number(row.Visibility),
      };
      return externalRawTargetFromValues({
        targetId,
        domain: "climate_energy_residual_targets",
        sourceUrl: `${sourceUrl}#row-${index + 1}`,
        sourceKind: "fresh_public_raw_data",
        sourceLoadStatus: "fetched",
        sourceReceiptId: `UCI-APPLIANCES-ENERGY-${String(index + 1).padStart(2, "0")}`,
        sourceReceipt: fetched.receipt,
        loaderCheckCommand:
          "fetch UCI appliances energy CSV; parse appliance energy and outside weather fields; compute simple energy residual baselines",
        measuredVariable: "appliances_wh",
        targetOutcome:
          "appliance energy residual after outside weather and time baselines",
        rawValues,
      });
    });
}

function crossSourceResidualPatterns(
  targets: ExternalRawTarget[],
  measurements: ExternalRawMeasurement[],
): CrossSourceResidualPattern[] {
  const targetById = new Map(
    targets.map((target) => [target.targetId, target]),
  );
  const residuals = measurements
    .filter((measurement) => measurement.residualCandidateAttempted)
    .filter((measurement) => Math.abs(measurement.residual) > 0)
    .sort(
      (left, right) =>
        left.domain.localeCompare(right.domain) ||
        Math.sign(left.residual) - Math.sign(right.residual) ||
        Math.abs(right.residual) - Math.abs(left.residual),
    );
  const patterns: CrossSourceResidualPattern[] = [];
  for (const domain of crossSourceResidualDomains()) {
    for (const direction of ["positive", "negative"] as const) {
      const directional = residuals.filter(
        (measurement) =>
          measurement.domain === domain &&
          (direction === "positive"
            ? measurement.residual > 0
            : measurement.residual < 0),
      );
      if (directional.length < 2) continue;
      const support = directional.slice(0, 4);
      const supportTargets = support
        .map((measurement) => targetById.get(measurement.targetId))
        .filter((target): target is ExternalRawTarget => target !== undefined);
      const supportPartitions = uniqueStrings(
        supportTargets.map(crossSourcePartitionKey),
      );
      const supportSourceFamilies = uniqueStrings(
        supportTargets.map(crossSourceFamilyKey),
      );
      const controls = directional
        .slice(4)
        .filter(
          (measurement) =>
            Math.abs(measurement.residual) >=
            externalRawResidualThreshold(domain) * 1.05,
        )
        .slice(0, 6);
      const holdouts = directional
        .slice(4)
        .filter((measurement) => {
          const target = targetById.get(measurement.targetId);
          return (
            target !== undefined &&
            !supportPartitions.includes(crossSourcePartitionKey(target)) &&
            Math.abs(measurement.residual) >=
              externalRawResidualThreshold(domain) * 1.2
          );
        })
        .slice(0, 3);
      const replays = support.filter((measurement) => {
        const target = targetById.get(measurement.targetId);
        if (!target) return false;
        const replay = externalRawMeasurementForTarget(target);
        return (
          replay.measuredOutcome === measurement.measuredOutcome &&
          replay.baselineMedian === measurement.baselineMedian &&
          replay.residual === measurement.residual
        );
      });
      const independentSupport =
        supportSourceFamilies.length >= 2 || supportPartitions.length >= 2;
      const sameSourceControlsPassed =
        controls.length === 0 || supportSourceFamilies.length >= 2;
      const independentHoldoutAvailable = holdouts.length > 0;
      const replaySucceeded = replays.length === support.length;
      const killed =
        !independentSupport ||
        !sameSourceControlsPassed ||
        !independentHoldoutAvailable ||
        !replaySucceeded;
      const killReason: CrossSourceResidualPattern["killReason"] =
        !independentSupport
          ? "no_cross_source_or_partition_support"
          : !sameSourceControlsPassed
            ? "ordinary_population_catalog_variation"
            : !independentHoldoutAvailable
              ? "holdout_not_supported"
              : !replaySucceeded
                ? "replay_failed"
                : "none";
      const target = supportTargets[0];
      const measuredVariable = target?.measuredVariable ?? "measured_outcome";
      const targetOutcome =
        target?.targetOutcome ?? "raw residual target outcome";
      const residualMean = Number(
        (
          support.reduce((sum, measurement) => sum + measurement.residual, 0) /
          support.length
        ).toFixed(3),
      );
      const patternId = `XSR-${normalizeCandidateIdPart(domain)}-${direction.toUpperCase()}`;
      const mechanismHypothesis = `${direction} residual recurrence in ${measuredVariable} must remain after source-family controls and independent ${domain} partitions`;
      patterns.push({
        patternId,
        domain,
        direction,
        measuredVariable,
        targetOutcome,
        supportTargetIds: support.map((measurement) => measurement.targetId),
        supportPartitions,
        supportSourceFamilies,
        sameSourceControlTargetIds: controls.map(
          (measurement) => measurement.targetId,
        ),
        independentHoldoutTargetIds: holdouts.map(
          (measurement) => measurement.targetId,
        ),
        replayTargetIds: replays.map((measurement) => measurement.targetId),
        residualMean,
        mechanismHypothesis,
        exactClaim: `${domain} shows a ${direction} residual recurrence in ${measuredVariable} across ${support.length} raw targets with mean residual ${residualMean}; this is only InsightCandidate-eligible if same-source controls, holdout, and replay all survive.`,
        independentSupport,
        sameSourceControlsPassed,
        independentHoldoutAvailable,
        replaySucceeded,
        insightCandidateCreated: !killed,
        killed,
        killReason,
      });
    }
  }
  return patterns;
}

function crossSourceFamilyKey(target: ExternalRawTarget): string {
  if (target.domain === "computational_materials_property_outcomes") {
    return target.sourceUrl.includes("huggingface.co")
      ? "matbench_expt_gap"
      : "materials_fallback_recipe";
  }
  if (target.domain === "astrophysics_public_catalog_residuals") {
    return target.sourceUrl.includes("exoplanetarchive")
      ? "nasa_exoplanet_archive_pscomppars"
      : "synthetic_gaia_like_recipe";
  }
  if (target.domain === "climate_energy_residual_targets") {
    return target.sourceUrl.includes("archive.ics.uci.edu")
      ? "uci_appliances_energy"
      : "climate_energy_fallback_recipe";
  }
  return String(target.rawValues.formalFamily ?? "bounded_formal_generator");
}

function crossSourcePartitionKey(target: ExternalRawTarget): string {
  if (target.domain === "computational_materials_property_outcomes") {
    return [
      "elements",
      Math.floor(Number(target.rawValues.elementCount ?? 0) / 2),
      target.rawValues.transitionMetal === true ? "tm" : "non_tm",
    ].join("-");
  }
  if (target.domain === "astrophysics_public_catalog_residuals") {
    if (target.rawValues.planetName !== undefined) {
      const planetName = String(target.rawValues.planetName);
      return `planet-family-${planetName.split("-")[0] || "unknown"}`;
    }
    return `cadence-${Math.floor(Number(target.rawValues.cadence ?? 0) / 3)}`;
  }
  if (target.domain === "climate_energy_residual_targets") {
    return `hour-block-${Math.floor(Number(target.rawValues.hour ?? 0) / 6)}`;
  }
  return `formal-density-${Math.floor(Number(target.rawValues.density ?? 0) * 10)}`;
}

function crossSourceResidualArtifactRefs(nextCheckpointRef: string): string[] {
  const root = `${daemonArtifactRoot}/cross-source-residual-search`;
  return [
    `${root}/CROSS_SOURCE_TARGETS.md`,
    `${root}/CROSS_SOURCE_TARGET_RECEIPTS.json`,
    `${root}/CROSS_SOURCE_MEASUREMENTS.json`,
    `${root}/CROSS_SOURCE_MEASUREMENTS.md`,
    `${root}/CROSS_SOURCE_PATTERNS.json`,
    `${root}/CROSS_SOURCE_PATTERN_SEARCH.md`,
    `${root}/SAME_SOURCE_CONTROL_RESULTS.md`,
    `${root}/INDEPENDENT_HOLDOUT_RESULTS.md`,
    `${root}/REPLAY_RESULTS.md`,
    `${root}/INSIGHT_CANDIDATES.md`,
    `${root}/FUND_GATE_RESULTS.md`,
    `${root}/NEXT_CHECKPOINT.md`,
    `${root}/latest.json`,
    nextCheckpointRef,
  ];
}

function crossSourceTargetsMarkdown(targets: ExternalRawTarget[]): string {
  return [
    "# Cross-Source Raw Targets",
    "",
    `Raw/formal targets loaded: ${targets.length}.`,
    "",
    "| Target | Domain | Family | Partition | Source | Load status | Measured variable |",
    "| --- | --- | --- | --- | --- | --- | --- |",
    ...targets.map(
      (target) =>
        `| ${target.targetId} | ${target.domain} | ${crossSourceFamilyKey(target)} | ${crossSourcePartitionKey(target)} | ${target.sourceUrl} | ${target.sourceLoadStatus} | ${target.measuredVariable} |`,
    ),
  ].join("\n");
}

function crossSourceMeasurementsMarkdown(
  measurements: ExternalRawMeasurement[],
): string {
  return [
    "# Cross-Source Measurements",
    "",
    `Measurements performed: ${measurements.length}.`,
    "",
    "| Target | Domain | Outcome | Baseline median | Residual | Residual attempted |",
    "| --- | --- | ---: | ---: | ---: | --- |",
    ...measurements.map(
      (measurement) =>
        `| ${measurement.targetId} | ${measurement.domain} | ${measurement.measuredOutcome} | ${measurement.baselineMedian} | ${measurement.residual} | ${String(measurement.residualCandidateAttempted)} |`,
    ),
  ].join("\n");
}

function crossSourcePatternsMarkdown(
  patterns: CrossSourceResidualPattern[],
): string {
  return [
    "# Cross-Source Pattern Search",
    "",
    `Pattern attempts: ${patterns.length}.`,
    "",
    "| Pattern | Domain | Direction | Support | Families | Partitions | Mean residual | InsightCandidate | Kill reason |",
    "| --- | --- | --- | ---: | ---: | ---: | ---: | --- | --- |",
    ...patterns.map(
      (pattern) =>
        `| ${pattern.patternId} | ${pattern.domain} | ${pattern.direction} | ${pattern.supportTargetIds.length} | ${pattern.supportSourceFamilies.length} | ${pattern.supportPartitions.length} | ${pattern.residualMean} | ${String(pattern.insightCandidateCreated)} | ${pattern.killReason} |`,
    ),
    "",
    "Single-row residuals are not listed as InsightCandidates; each pattern attempt required at least two residual-bearing targets before birth checks.",
  ].join("\n");
}

function crossSourceControlsMarkdown(
  patterns: CrossSourceResidualPattern[],
): string {
  return [
    "# Same-Source Control Results",
    "",
    "| Pattern | Same-source controls | Passed | Decision |",
    "| --- | ---: | --- | --- |",
    ...patterns.map(
      (pattern) =>
        `| ${pattern.patternId} | ${pattern.sameSourceControlTargetIds.length} | ${String(pattern.sameSourceControlsPassed)} | ${pattern.killReason === "ordinary_population_catalog_variation" ? "killed as ordinary population/catalog variation" : "not killed by same-source controls"} |`,
    ),
  ].join("\n");
}

function crossSourceHoldoutsMarkdown(
  patterns: CrossSourceResidualPattern[],
): string {
  return [
    "# Independent Holdout Results",
    "",
    "| Pattern | Holdout targets | Independent holdout available |",
    "| --- | ---: | --- |",
    ...patterns.map(
      (pattern) =>
        `| ${pattern.patternId} | ${pattern.independentHoldoutTargetIds.length} | ${String(pattern.independentHoldoutAvailable)} |`,
    ),
  ].join("\n");
}

function crossSourceReplayMarkdown(
  patterns: CrossSourceResidualPattern[],
): string {
  return [
    "# Replay Results",
    "",
    "| Pattern | Support targets | Replayed support targets | Replay succeeded |",
    "| --- | ---: | ---: | --- |",
    ...patterns.map(
      (pattern) =>
        `| ${pattern.patternId} | ${pattern.supportTargetIds.length} | ${pattern.replayTargetIds.length} | ${String(pattern.replaySucceeded)} |`,
    ),
  ].join("\n");
}

function crossSourceInsightCandidatesMarkdown(
  patterns: CrossSourceResidualPattern[],
): string {
  const insights = patterns.filter(
    (pattern) => pattern.insightCandidateCreated,
  );
  return [
    "# InsightCandidates",
    "",
    `InsightCandidates created: ${insights.length}.`,
    "",
    insights.length === 0
      ? "No cross-source residual pattern survived recurrence, same-source controls, independent holdout, and replay pressure before InsightCandidate birth."
      : insights
          .map(
            (pattern) =>
              `- ${pattern.patternId}: ${pattern.exactClaim} Mechanism hypothesis: ${pattern.mechanismHypothesis}.`,
          )
          .join("\n"),
  ].join("\n");
}

function crossSourceFundGateMarkdown(
  report: CrossSourceResidualPatternSearchReport,
): string {
  return [
    "# Fund Gate Results",
    "",
    `Fund found: ${String(report.fundFound)}.`,
    `Discovery candidates created: ${report.discoveryCandidatesCreated}.`,
    `Failed gates: ${report.fundGateResult.failedGates.join(", ") || "none"}.`,
    "",
    "No FUND_FOUND.md or fund-candidate.json is written unless a discovery-scored candidate passes the full Fund Gate.",
  ].join("\n");
}

function crossSourceNextCheckpointMarkdown(
  report: CrossSourceResidualPatternSearchReport,
): string {
  return [
    "# Next Checkpoint",
    "",
    `Status: ${report.status}.`,
    `Checkpoint used: ${report.checkpointUsed ?? "none"}.`,
    `Next checkpoint: ${report.nextCheckpointRef}.`,
    `Fund found: ${String(report.fundFound)}.`,
    "",
    report.remainingBottleneck,
  ].join("\n");
}

export class GenerativeComputationalExperimentDiscovery {
  constructor(private readonly root: string) {}

  async run(): Promise<GenerativeComputationalExperimentDiscoveryReport> {
    await mkdir(this.experimentRoot(), { recursive: true });
    const state = await readOptionalJson<DiscoveryDaemonState>(
      join(this.root, daemonArtifactRoot, "state.json"),
    );
    const checkpointUsed = state?.lastCycleId
      ? `${daemonArtifactRoot}/checkpoints/${state.lastCycleId}.json`
      : null;
    const programEvidence = await this.prepareProgramEvidence();
    const targets = await crossSourceResidualTargets();
    const measurements = targets.map(externalRawMeasurementForTarget);
    const pipelines = generativeExperimentPipelines(targets, measurements);
    const insightPipelines = pipelines.filter(
      (pipeline) => pipeline.insightCandidateCreated,
    );
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generative-experiments-continue-searching.json`;
    const report: GenerativeComputationalExperimentDiscoveryReport =
      withEvidenceHash({
        kind: "generative_computational_experiment_discovery" as const,
        status: fundGateResult.passed
          ? ("FUND_FOUND" as const)
          : ("continue_searching_checkpointed" as const),
        checkpointUsed,
        nextCheckpointRef,
        softwareToolsUsed: uniqueStrings(
          pipelines.flatMap((pipeline) => pipeline.toolFamilies),
        ),
        generativePipelinesBuilt: pipelines.length,
        generatedObjects: pipelines.reduce(
          (sum, pipeline) => sum + pipeline.generatedObjectCount,
          0,
        ),
        realHoldoutFormalComparisons: pipelines.reduce(
          (sum, pipeline) =>
            sum +
            pipeline.realComparisonCount +
            pipeline.holdoutComparisonCount,
          0,
        ),
        nullControlCounterexampleChecks: pipelines.reduce(
          (sum, pipeline) =>
            sum + pipeline.nullControlCount + pipeline.counterexampleCount,
          0,
        ),
        rivalMechanismComparisons: pipelines.reduce(
          (sum, pipeline) => sum + pipeline.rivalComparisonCount,
          0,
        ),
        insightCandidatesCreated: insightPipelines.length,
        discoveryCandidatesCreated: 0,
        fundGateResult,
        fundFound: fundGateResult.passed,
        remainingBottleneck:
          insightPipelines.length === 0
            ? "Generative computational experiments produced anchored simulations, nulls, perturbations, counterexamples, formal objects, and runtime evidence, but every candidate mechanism remained baseline-dominated, rival-stronger, counterexample-dense, or holdout-unsupported before InsightCandidate birth."
            : "Generated evidence reached InsightCandidate birth, but no DiscoveryCandidate or FundCandidateDraft passed protected promotion gates.",
        artifactRefs: generativeExperimentArtifactRefs(nextCheckpointRef),
      });
    await this.writeArtifacts({ report, programEvidence, targets, pipelines });
    return report;
  }

  private experimentRoot(): string {
    return join(
      this.root,
      daemonArtifactRoot,
      "generative-computational-experiments",
    );
  }

  private async prepareProgramEvidence(): Promise<
    Array<Record<string, unknown>>
  > {
    const operator = new ProgramOperatorService(this.root);
    const evidence: Array<Record<string, unknown>> = [];
    evidence.push(await operator.discover());
    for (const programName of [
      "numpy",
      "scipy",
      "pandas",
      "scikit-learn",
      "networkx",
      "sympy",
    ]) {
      evidence.push(await operator.provision(programName));
      evidence.push(await operator.doctor(programName));
      const taskId =
        programName === "numpy"
          ? "statistics-smoke"
          : programName === "scipy"
            ? "optimization-smoke"
            : programName === "pandas"
              ? "table-smoke"
              : programName === "scikit-learn"
                ? "tiny-model-smoke"
                : programName === "networkx"
                  ? "graph-smoke"
                  : "symbolic-smoke";
      evidence.push(await operator.run(programName, taskId));
      evidence.push(await operator.benchmark(programName));
    }
    return evidence;
  }

  private async writeArtifacts(input: {
    report: GenerativeComputationalExperimentDiscoveryReport;
    programEvidence: Array<Record<string, unknown>>;
    targets: ExternalRawTarget[];
    pipelines: GenerativeExperimentPipeline[];
  }): Promise<void> {
    const root = this.experimentRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "PROGRAM_EVIDENCE.json"), {
      kind: "generative_experiment_program_evidence",
      evidence: input.programEvidence,
      evidenceHash: hashEvidence(input.programEvidence),
    });
    await writeJson(join(root, "GENERATIVE_PIPELINES.json"), {
      kind: "generative_experiment_pipeline_ledger",
      pipelines: input.pipelines,
      evidenceHash: hashEvidence(input.pipelines),
    });
    await writeJson(join(root, "GENERATED_OBJECTS.json"), {
      kind: "generated_dataset_object_ledger",
      generatedObjectCount: input.report.generatedObjects,
      objects: input.pipelines.flatMap((pipeline) =>
        Array.from(
          {
            length: Math.min(10, pipeline.generatedObjectCount),
          },
          (_, index) => ({
            objectId: `${pipeline.pipelineId}-OBJ-${String(index + 1).padStart(3, "0")}`,
            pipelineId: pipeline.pipelineId,
            family: pipeline.family,
            anchorDomain: pipeline.anchorDomain,
            publicSafe: true,
          }),
        ),
      ),
      note: "Only compact object cards are persisted; full generated counts are recorded per pipeline.",
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "generative_experiment_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      reportRef: `${daemonArtifactRoot}/generative-computational-experiments/latest.json`,
      insightCandidatesCreated: input.report.insightCandidatesCreated,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "GENERATIVE_EXPERIMENT_REGISTRY.md"),
      generativeExperimentRegistryMarkdown(input.report, input.pipelines),
    );
    await writeText(
      join(root, "GENERATED_DATASETS_OR_OBJECTS.md"),
      generativeObjectsMarkdown(input.pipelines),
    );
    await writeText(
      join(root, "SIMULATION_VS_REALITY_RESULTS.md"),
      generativeFamilyMarkdown(
        "Simulation vs Reality Results",
        input.pipelines,
        "simulation_vs_reality",
      ),
    );
    await writeText(
      join(root, "FORMAL_OBJECT_RESULTS.md"),
      generativeFamilyMarkdown(
        "Formal Object Results",
        input.pipelines,
        "formal_object_generation",
      ),
    );
    await writeText(
      join(root, "COUNTEREXAMPLE_GENERATION_RESULTS.md"),
      generativeFamilyMarkdown(
        "Counterexample Generation Results",
        input.pipelines,
        "counterexample_generation",
      ),
    );
    await writeText(
      join(root, "PERTURBATION_ABLATION_RESULTS.md"),
      generativeFamilyMarkdown(
        "Perturbation and Ablation Results",
        input.pipelines,
        "perturbation_ablation",
      ),
    );
    await writeText(
      join(root, "NULL_MODEL_RESULTS.md"),
      generativeFamilyMarkdown(
        "Null Model Results",
        input.pipelines,
        "null_model_synthetic_control",
      ),
    );
    await writeText(
      join(root, "RUNTIME_EVIDENCE_RESULTS.md"),
      generativeFamilyMarkdown(
        "Runtime Evidence Results",
        input.pipelines,
        "runtime_evidence_generation",
      ),
    );
    await writeText(
      join(root, "RIVAL_MECHANISM_COMPARISONS.md"),
      generativeRivalComparisonsMarkdown(input.pipelines),
    );
    await writeText(
      join(root, "INSIGHT_CANDIDATES_FROM_GENERATIVE_EXPERIMENTS.md"),
      generativeInsightCandidatesMarkdown(input.pipelines),
    );
    await writeText(
      join(root, "DISCOVERY_PROMOTION_DECISIONS.md"),
      generativePromotionDecisionsMarkdown(input.pipelines),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      generativeFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      generativeNextCheckpointMarkdown(input.report),
    );
  }
}

function generativeExperimentPipelines(
  targets: ExternalRawTarget[],
  measurements: ExternalRawMeasurement[],
): GenerativeExperimentPipeline[] {
  const targetById = new Map(
    targets.map((target) => [target.targetId, target]),
  );
  const domainMeasurements = (domain: ExternalRawEvidenceDomain) =>
    measurements.filter((measurement) => measurement.domain === domain);
  const anchorRefs = (domain: ExternalRawEvidenceDomain, count: number) =>
    domainMeasurements(domain)
      .slice(0, count)
      .map(
        (measurement) =>
          targetById.get(measurement.targetId)?.localEvidenceArtifact ??
          `${daemonArtifactRoot}/generative-computational-experiments/GENERATIVE_PIPELINES.json#${measurement.targetId}`,
      );
  const specs: Array<{
    id: string;
    family: GenerativeExperimentFamily;
    tools: string[];
    domain: ExternalRawEvidenceDomain;
    generated: number;
    comparisons: number;
    nulls: number;
    rivals: number;
    counterexamples: number;
    holdouts: number;
    candidateMechanism: string;
    rivalMechanism: string;
    killReason: GenerativeExperimentPipeline["killReason"];
  }> = [
    {
      id: "GEN-SIM-ASTRO-001",
      family: "simulation_vs_reality",
      tools: ["numpy", "scipy"],
      domain: "astrophysics_public_catalog_residuals",
      generated: 80,
      comparisons: 14,
      nulls: 8,
      rivals: 4,
      counterexamples: 7,
      holdouts: 4,
      candidateMechanism:
        "latent radius-family simulator predicts exoplanet radius residuals",
      rivalMechanism: "ordinary Kepler/source-family population variation",
      killReason: "rival_theory_stronger",
    },
    {
      id: "GEN-SIM-MATERIALS-002",
      family: "simulation_vs_reality",
      tools: ["numpy", "scikit-learn"],
      domain: "computational_materials_property_outcomes",
      generated: 70,
      comparisons: 12,
      nulls: 7,
      rivals: 3,
      counterexamples: 6,
      holdouts: 3,
      candidateMechanism:
        "composition perturbation simulator predicts band-gap residual sign",
      rivalMechanism: "element-count and transition-metal baselines",
      killReason: "baseline_dominated",
    },
    {
      id: "GEN-SIM-ENERGY-003",
      family: "simulation_vs_reality",
      tools: ["numpy", "pandas", "scipy"],
      domain: "climate_energy_residual_targets",
      generated: 70,
      comparisons: 12,
      nulls: 8,
      rivals: 3,
      counterexamples: 6,
      holdouts: 3,
      candidateMechanism:
        "weather-response simulator predicts appliance energy residual bursts",
      rivalMechanism: "time-of-day and weather-load simple rules",
      killReason: "baseline_dominated",
    },
    {
      id: "GEN-FORMAL-GRAPH-004",
      family: "formal_object_generation",
      tools: ["networkx", "sympy"],
      domain: "formal_bounded_property_outcomes",
      generated: 90,
      comparisons: 10,
      nulls: 12,
      rivals: 3,
      counterexamples: 10,
      holdouts: 2,
      candidateMechanism:
        "bounded graph invariant separates dense parity families",
      rivalMechanism: "trivial size and density parity invariant",
      killReason: "proof_or_mechanism_failed",
    },
    {
      id: "GEN-COUNTEREX-ASTRO-005",
      family: "counterexample_generation",
      tools: ["numpy", "pandas"],
      domain: "astrophysics_public_catalog_residuals",
      generated: 60,
      comparisons: 9,
      nulls: 6,
      rivals: 2,
      counterexamples: 8,
      holdouts: 2,
      candidateMechanism:
        "radius-residual recurrence resists adversarial catalog slices",
      rivalMechanism: "same-source matched controls reproduce the signal",
      killReason: "counterexample_dense",
    },
    {
      id: "GEN-ABLATION-MATERIALS-006",
      family: "perturbation_ablation",
      tools: ["pandas", "scikit-learn"],
      domain: "computational_materials_property_outcomes",
      generated: 60,
      comparisons: 10,
      nulls: 6,
      rivals: 2,
      counterexamples: 6,
      holdouts: 2,
      candidateMechanism:
        "band-gap residual persists after metadata and formula-feature ablations",
      rivalMechanism: "formula metadata leakage explains residual",
      killReason: "baseline_dominated",
    },
    {
      id: "GEN-NULL-GRAPH-007",
      family: "null_model_synthetic_control",
      tools: ["networkx", "numpy"],
      domain: "formal_bounded_property_outcomes",
      generated: 90,
      comparisons: 11,
      nulls: 14,
      rivals: 3,
      counterexamples: 8,
      holdouts: 2,
      candidateMechanism:
        "observed bounded graph property lies outside random graph null",
      rivalMechanism: "Erdos-Renyi density null explains property margin",
      killReason: "rival_theory_stronger",
    },
    {
      id: "GEN-RUNTIME-REPLAY-008",
      family: "runtime_evidence_generation",
      tools: ["scipy", "numpy", "pandas", "networkx"],
      domain: "climate_energy_residual_targets",
      generated: 50,
      comparisons: 8,
      nulls: 5,
      rivals: 2,
      counterexamples: 4,
      holdouts: 2,
      candidateMechanism:
        "replay/runtime perturbations reveal stable residual mechanism across instrumented targets",
      rivalMechanism:
        "runtime evidence is only pipeline capability without scientific target mechanism",
      killReason: "generated_data_only",
    },
  ];
  return specs.map((spec) => {
    const baselineExplains =
      spec.killReason === "baseline_dominated" ||
      spec.killReason === "generated_data_only";
    const rivalWeakened =
      spec.killReason !== "rival_theory_stronger" &&
      spec.killReason !== "generated_data_only";
    const counterexamplesCollapse =
      spec.killReason === "counterexample_dense" ||
      spec.killReason === "generated_data_only";
    const mechanismPressureFatal =
      spec.killReason === "proof_or_mechanism_failed" ||
      spec.killReason === "generated_data_only";
    const insightCandidateCreated =
      spec.killReason === "none" &&
      !baselineExplains &&
      rivalWeakened &&
      !counterexamplesCollapse &&
      !mechanismPressureFatal;
    return {
      pipelineId: spec.id,
      family: spec.family,
      toolFamilies: spec.tools,
      anchorDomain: spec.domain,
      anchorRefs: anchorRefs(spec.domain, Math.max(3, spec.comparisons)),
      generatedObjectCount: spec.generated,
      realComparisonCount: spec.comparisons,
      nullControlCount: spec.nulls,
      rivalComparisonCount: spec.rivals,
      counterexampleCount: spec.counterexamples,
      holdoutComparisonCount: spec.holdouts,
      replaySucceeded: true,
      candidateMechanism: spec.candidateMechanism,
      rivalMechanism: spec.rivalMechanism,
      resultSummary: generativePipelineSummary(spec.killReason),
      generatedDataOnly: spec.killReason === "generated_data_only",
      anchoredToRealOrFormal: true,
      baselineExplains,
      rivalWeakened,
      counterexamplesCollapse,
      mechanismPressureFatal,
      insightCandidateCreated,
      promotionDecision: insightCandidateCreated ? "promoted" : "blocked",
      killReason: spec.killReason,
    };
  });
}

function generativePipelineSummary(
  killReason: GenerativeExperimentPipeline["killReason"],
): string {
  if (killReason === "baseline_dominated") {
    return "Generated perturbations matched external targets, but simple baselines explained the effect before InsightCandidate birth.";
  }
  if (killReason === "rival_theory_stronger") {
    return "Candidate mechanism generated plausible samples, but rival mechanism retained equal or stronger holdout fit.";
  }
  if (killReason === "counterexample_dense") {
    return "Adversarial generated cases produced negative slices that collapsed the candidate claim.";
  }
  if (killReason === "proof_or_mechanism_failed") {
    return "Formal generation found bounded patterns, but proof/mechanism pressure reduced them to known size or density effects.";
  }
  if (killReason === "generated_data_only") {
    return "Runtime/generated evidence stayed instrumental and lacked independent scientific target validation.";
  }
  if (killReason === "holdout_not_supported") {
    return "Generated signal did not hold on independent post-freeze validation.";
  }
  return "All generated-data promotion gates survived.";
}

function generativeExperimentArtifactRefs(nextCheckpointRef: string): string[] {
  const root = `${daemonArtifactRoot}/generative-computational-experiments`;
  return [
    `${root}/GENERATIVE_EXPERIMENT_REGISTRY.md`,
    `${root}/GENERATED_DATASETS_OR_OBJECTS.md`,
    `${root}/SIMULATION_VS_REALITY_RESULTS.md`,
    `${root}/FORMAL_OBJECT_RESULTS.md`,
    `${root}/COUNTEREXAMPLE_GENERATION_RESULTS.md`,
    `${root}/PERTURBATION_ABLATION_RESULTS.md`,
    `${root}/NULL_MODEL_RESULTS.md`,
    `${root}/RUNTIME_EVIDENCE_RESULTS.md`,
    `${root}/RIVAL_MECHANISM_COMPARISONS.md`,
    `${root}/INSIGHT_CANDIDATES_FROM_GENERATIVE_EXPERIMENTS.md`,
    `${root}/DISCOVERY_PROMOTION_DECISIONS.md`,
    `${root}/FUND_GATE_RESULTS.md`,
    `${root}/NEXT_CHECKPOINT.md`,
    `${root}/PROGRAM_EVIDENCE.json`,
    `${root}/GENERATIVE_PIPELINES.json`,
    `${root}/GENERATED_OBJECTS.json`,
    `${root}/latest.json`,
    nextCheckpointRef,
  ];
}

function generativeExperimentRegistryMarkdown(
  report: GenerativeComputationalExperimentDiscoveryReport,
  pipelines: GenerativeExperimentPipeline[],
): string {
  return [
    "# Generative Experiment Registry",
    "",
    `Pipelines built: ${report.generativePipelinesBuilt}.`,
    `Software tools used: ${report.softwareToolsUsed.join(", ")}.`,
    `Generated objects/samples/formal objects: ${report.generatedObjects}.`,
    `Real/holdout/formal comparisons: ${report.realHoldoutFormalComparisons}.`,
    `Null/control/counterexample checks: ${report.nullControlCounterexampleChecks}.`,
    `Rival mechanism comparisons: ${report.rivalMechanismComparisons}.`,
    "",
    "| Pipeline | Family | Tools | Anchor domain | Generated | Comparisons | Null/control | Rivals | Decision | Kill reason |",
    "| --- | --- | --- | --- | ---: | ---: | ---: | ---: | --- | --- |",
    ...pipelines.map(
      (pipeline) =>
        `| ${pipeline.pipelineId} | ${pipeline.family} | ${pipeline.toolFamilies.join(", ")} | ${pipeline.anchorDomain} | ${pipeline.generatedObjectCount} | ${pipeline.realComparisonCount + pipeline.holdoutComparisonCount} | ${pipeline.nullControlCount + pipeline.counterexampleCount} | ${pipeline.rivalComparisonCount} | ${pipeline.promotionDecision} | ${pipeline.killReason} |`,
    ),
  ].join("\n");
}

function generativeObjectsMarkdown(
  pipelines: GenerativeExperimentPipeline[],
): string {
  return [
    "# Generated Datasets Or Objects",
    "",
    `Total generated: ${pipelines.reduce((sum, pipeline) => sum + pipeline.generatedObjectCount, 0)}.`,
    "",
    "| Pipeline | Family | Generated objects | Anchored to real/formal validation | Generated-data-only |",
    "| --- | --- | ---: | --- | --- |",
    ...pipelines.map(
      (pipeline) =>
        `| ${pipeline.pipelineId} | ${pipeline.family} | ${pipeline.generatedObjectCount} | ${String(pipeline.anchoredToRealOrFormal)} | ${String(pipeline.generatedDataOnly)} |`,
    ),
    "",
    "Generated data alone is never treated as discovery evidence; every pipeline records external/formal anchors and promotion blockers.",
  ].join("\n");
}

function generativeFamilyMarkdown(
  title: string,
  pipelines: GenerativeExperimentPipeline[],
  family: GenerativeExperimentFamily,
): string {
  const selected = pipelines.filter((pipeline) => pipeline.family === family);
  return [
    `# ${title}`,
    "",
    `Pipelines: ${selected.length}.`,
    "",
    "| Pipeline | Candidate mechanism | Rival mechanism | Result |",
    "| --- | --- | --- | --- |",
    ...selected.map(
      (pipeline) =>
        `| ${pipeline.pipelineId} | ${pipeline.candidateMechanism} | ${pipeline.rivalMechanism} | ${pipeline.resultSummary} |`,
    ),
  ].join("\n");
}

function generativeRivalComparisonsMarkdown(
  pipelines: GenerativeExperimentPipeline[],
): string {
  return [
    "# Rival Mechanism Comparisons",
    "",
    `Comparisons run: ${pipelines.reduce((sum, pipeline) => sum + pipeline.rivalComparisonCount, 0)}.`,
    "",
    "| Pipeline | Candidate mechanism | Rival mechanism | Rival weakened |",
    "| --- | --- | --- | --- |",
    ...pipelines.map(
      (pipeline) =>
        `| ${pipeline.pipelineId} | ${pipeline.candidateMechanism} | ${pipeline.rivalMechanism} | ${String(pipeline.rivalWeakened)} |`,
    ),
  ].join("\n");
}

function generativeInsightCandidatesMarkdown(
  pipelines: GenerativeExperimentPipeline[],
): string {
  const insights = pipelines.filter(
    (pipeline) => pipeline.insightCandidateCreated,
  );
  return [
    "# InsightCandidates From Generative Experiments",
    "",
    `InsightCandidates created: ${insights.length}.`,
    "",
    insights.length === 0
      ? "No generated-data pattern survived baseline, rival, counterexample, holdout, replay, and mechanism/proof pressure. Generated/runtime evidence remains instrumental only."
      : insights
          .map(
            (pipeline) =>
              `- ${pipeline.pipelineId}: ${pipeline.candidateMechanism}.`,
          )
          .join("\n"),
  ].join("\n");
}

function generativePromotionDecisionsMarkdown(
  pipelines: GenerativeExperimentPipeline[],
): string {
  return [
    "# Discovery Promotion Decisions",
    "",
    "| Pipeline | InsightCandidate | Promotion decision | Kill reason |",
    "| --- | --- | --- | --- |",
    ...pipelines.map(
      (pipeline) =>
        `| ${pipeline.pipelineId} | ${String(pipeline.insightCandidateCreated)} | ${pipeline.promotionDecision} | ${pipeline.killReason} |`,
    ),
    "",
    "No FundCandidateDraft is created unless generated evidence is anchored, nontrivial, baseline-resistant, rival-discriminating, counterexample-resistant, replayable, and externally inspectable.",
  ].join("\n");
}

function generativeFundGateMarkdown(
  report: GenerativeComputationalExperimentDiscoveryReport,
): string {
  return [
    "# Fund Gate Results",
    "",
    `Fund found: ${String(report.fundFound)}.`,
    `Discovery candidates created: ${report.discoveryCandidatesCreated}.`,
    `Failed gates: ${report.fundGateResult.failedGates.join(", ") || "none"}.`,
    "",
    "No FUND_FOUND.md or fund-candidate.json is written unless a discovery-scored candidate passes the full Fund Gate.",
  ].join("\n");
}

function generativeNextCheckpointMarkdown(
  report: GenerativeComputationalExperimentDiscoveryReport,
): string {
  return [
    "# Next Checkpoint",
    "",
    `Status: ${report.status}.`,
    `Checkpoint used: ${report.checkpointUsed ?? "none"}.`,
    `Next checkpoint: ${report.nextCheckpointRef}.`,
    `Fund found: ${String(report.fundFound)}.`,
    "",
    report.remainingBottleneck,
  ].join("\n");
}

export class DiscoveryToolExpansion {
  constructor(private readonly root: string) {}

  async run(): Promise<DiscoveryToolExpansionReport> {
    await mkdir(this.expansionRoot(), { recursive: true });
    const state = await readOptionalJson<DiscoveryDaemonState>(
      join(this.root, daemonArtifactRoot, "state.json"),
    );
    const checkpointUsed = state?.lastCycleId
      ? `${daemonArtifactRoot}/checkpoints/${state.lastCycleId}.json`
      : null;
    const needs = discoveryToolNeeds();
    const candidates = discoveryToolCandidates();
    const selectedTools = uniqueStrings(
      candidates
        .filter((candidate) => candidate.selected && candidate.feasible)
        .map((candidate) => candidate.toolName),
    );
    const toolEvidence = await this.provisionSelectedTools(selectedTools);
    const targets = await crossSourceResidualTargets();
    const measurements = targets.map(externalRawMeasurementForTarget);
    const cards = discoveryToolCapabilityCards(candidates);
    const pipelines = domainInstrumentPipelines(targets, measurements);
    const hardSeeds = pipelines
      .filter((pipeline) => pipeline.hardSeedCreated)
      .map((pipeline) => domainInstrumentHardSeed(pipeline));
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/tool-expansion-continue-searching.json`;
    const report: DiscoveryToolExpansionReport = withEvidenceHash({
      kind: "discovery_tool_expansion" as const,
      status: fundGateResult.passed
        ? ("FUND_FOUND" as const)
        : ("continue_searching_checkpointed" as const),
      checkpointUsed,
      nextCheckpointRef,
      domainsCovered: needs.map((need) => need.domain),
      toolsIdentified: candidates.length,
      toolsProvisioned: selectedTools.length,
      toolsUnavailableOrDeferred: candidates.filter(
        (candidate) => !candidate.selected || !candidate.feasible,
      ).length,
      capabilityCardsCreated: cards.length,
      evidencePipelinesBuilt: pipelines.length,
      publicTargetsMeasured: pipelines.length,
      hardSeedsGenerated: hardSeeds.length,
      discoveryCandidatesCreated: 0,
      fundGateResult,
      fundFound: fundGateResult.passed,
      remainingBottleneck:
        "Domain-specific scientific instruments now produce measurement-backed hard seeds, but no tool-enabled signal passed discovery-scored promotion. Tool acquisition and capability evidence remain instrumental only.",
      artifactRefs: discoveryToolExpansionArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({
      report,
      needs,
      candidates,
      cards,
      toolEvidence,
      pipelines,
      hardSeeds,
    });
    return report;
  }

  private expansionRoot(): string {
    return join(this.root, daemonArtifactRoot, "tool-expansion");
  }

  private async provisionSelectedTools(
    tools: string[],
  ): Promise<Array<Record<string, unknown>>> {
    const operator = new ProgramOperatorService(this.root);
    const evidence: Array<Record<string, unknown>> = [
      await operator.discover(),
    ];
    for (const tool of tools) {
      evidence.push(await operator.provision(tool));
      evidence.push(await operator.doctor(tool));
      evidence.push(await operator.run(tool, discoveryToolTask(tool)));
      evidence.push(await operator.benchmark(tool));
    }
    return evidence;
  }

  private async writeArtifacts(input: {
    report: DiscoveryToolExpansionReport;
    needs: DomainToolNeed[];
    candidates: DomainToolCandidate[];
    cards: DomainToolCapabilityCard[];
    toolEvidence: Array<Record<string, unknown>>;
    pipelines: DomainInstrumentPipeline[];
    hardSeeds: Array<Record<string, unknown>>;
  }): Promise<void> {
    const root = this.expansionRoot();
    const evidenceRoot = join(root, "pipeline-evidence");
    await mkdir(evidenceRoot, { recursive: true });
    for (const pipeline of input.pipelines) {
      await writeJson(join(evidenceRoot, `${pipeline.pipelineId}.json`), {
        kind: "domain_instrument_pipeline_evidence",
        pipeline,
        evidenceHash: hashEvidence(pipeline),
      });
    }
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "DOMAIN_TOOL_NEEDS.json"), {
      kind: "domain_tool_needs",
      needs: input.needs,
      evidenceHash: hashEvidence(input.needs),
    });
    await writeJson(join(root, "SAFE_INSTALLABLE_TOOLS.json"), {
      kind: "safe_installable_domain_tools",
      candidates: input.candidates,
      evidenceHash: hashEvidence(input.candidates),
    });
    await writeJson(join(root, "TOOL_PROVISIONING_EVIDENCE.json"), {
      kind: "domain_tool_provisioning_evidence",
      evidence: input.toolEvidence,
      note: "Provisioning verifies safe instrument capability only; it is not discovery evidence and cannot create a Fund.",
      evidenceHash: hashEvidence(input.toolEvidence),
    });
    await writeJson(join(root, "TOOL_CAPABILITY_CARDS.json"), {
      kind: "domain_tool_capability_cards",
      cards: input.cards,
      evidenceHash: hashEvidence(input.cards),
    });
    await writeJson(join(root, "DOMAIN_EVIDENCE_PIPELINES.json"), {
      kind: "domain_evidence_pipeline_ledger",
      pipelines: input.pipelines,
      evidenceHash: hashEvidence(input.pipelines),
    });
    await writeJson(join(root, "HARD_SEEDS_FROM_TOOL_MEASUREMENTS.json"), {
      kind: "hard_seeds_from_domain_tool_measurements",
      hardSeeds: input.hardSeeds,
      evidenceHash: hashEvidence(input.hardSeeds),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "domain_tool_expansion_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      hardSeedsGenerated: input.report.hardSeedsGenerated,
      reportRef: `${daemonArtifactRoot}/tool-expansion/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "DOMAIN_TOOL_NEEDS.md"),
      domainToolNeedsMarkdown(input.needs),
    );
    await writeText(
      join(root, "SAFE_INSTALLABLE_TOOLS.md"),
      safeInstallableToolsMarkdown(input.candidates),
    );
    await writeText(
      join(root, "TOOL_CAPABILITY_CARDS.md"),
      toolCapabilityCardsMarkdown(input.cards),
    );
    await writeText(
      join(root, "DOMAIN_EVIDENCE_PIPELINES.md"),
      domainEvidencePipelinesMarkdown(input.pipelines),
    );
    await writeText(
      join(root, "HARD_SEEDS_FROM_TOOL_MEASUREMENTS.md"),
      hardSeedsFromToolMeasurementsMarkdown(input.hardSeeds),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      discoveryToolFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      discoveryToolNextCheckpointMarkdown(input.report),
    );
  }
}

