const generatorFamilyDir = "generator-families" as const;
const generatorBornPressureDir = "generator-pressure" as const;

export class ExternalValueGate {
  evaluate(input: {
    anchor?: ExternalProblemAnchor | null;
    sourceRefs: string[];
    evidenceRefs: string[];
    publicCorpusNegativeHistory?: PublicCorpusNegativeHistoryAssessment | null;
    generatorOnlySignal?: boolean;
    packageOnlySignal?: boolean;
    internallyInterestingOnly?: boolean;
    sourceFamilyDocumentedSignal?: boolean;
    knownTrivialSignal?: boolean;
  }): ExternalValueGateAssessment {
    const anchor = input.anchor ?? null;
    const publicCorpusNegativeHistory =
      input.publicCorpusNegativeHistory ?? null;
    const allRefs = [...input.sourceRefs, ...input.evidenceRefs];
    const gates = [
      gate(
        "external_problem_anchor_present",
        anchor !== null,
        "HardSeed birth requires a real external problem anchor before generator evidence can count.",
      ),
      gate(
        "external_anchor_public_source",
        anchor !== null &&
          anchor.sourceRef.startsWith("https://") &&
          publicSafeRef(anchor.sourceRef),
        "External problem anchor must cite a public-safe external source.",
      ),
      gate(
        "external_anchor_target_outcome",
        normalizeWhitespace(anchor?.measuredTargetOutcome ?? "").length >= 16,
        "External problem anchor must define a measured target outcome.",
      ),
      gate(
        "external_anchor_baseline_prior",
        normalizeWhitespace(anchor?.knownBaselineOrPrior ?? "").length >= 16,
        "External problem anchor must define the known baseline or prior rival state.",
      ),
      gate(
        "external_anchor_domain_scientific_significance",
        externalAnchorHasDomainScientificSignificance(anchor),
        "External problem anchor must explain domain scientific significance beyond pipeline, package, or tool capability.",
      ),
      gate(
        "external_anchor_discovery_scored_outcome",
        normalizeWhitespace(anchor?.discoveryScoredOutcome ?? "").length >=
          32 && !externalAnchorLooksPipelineOnly(anchor),
        "External problem anchor must define a discovery-scored outcome that is not only operational pipeline success.",
      ),
      gate(
        "external_anchor_significance_refs",
        externalSignificanceRefsBound(
          anchor?.significanceEvidenceRefs ?? [],
          allRefs,
        ),
        "External problem anchor must bind at least two public-safe significance evidence refs into the evidence set.",
      ),
      gate(
        "external_anchor_inspectable",
        anchor !== null &&
          anchor.inspectabilityRef.startsWith("https://") &&
          allRefs.includes(anchor.sourceRef) &&
          allRefs.some((ref) => ref === anchor.inspectabilityRef),
        "External problem anchor must be inspectable through the evidence refs.",
      ),
      gate(
        "not_public_corpus_downgraded_anchor",
        publicCorpusNegativeHistory?.blocksSeedBirth !== true,
        "HardSeed birth is blocked when the public corpus already downgraded or rival-explained this external anchor.",
      ),
      gate(
        "not_generator_only_signal",
        input.generatorOnlySignal !== true,
        "Generator-only signals are blocked before HardSeed birth.",
      ),
      gate(
        "not_package_only_signal",
        input.packageOnlySignal !== true,
        "Package-only or pipeline-contract-only signals are blocked before HardSeed birth.",
      ),
      gate(
        "not_internally_interesting_only",
        input.internallyInterestingOnly !== true,
        "Internally interesting but externally unanchored signals are blocked before HardSeed birth.",
      ),
      gate(
        "not_source_family_documented_signal",
        input.sourceFamilyDocumentedSignal !== true,
        "Source-family documented behavior is blocked before HardSeed birth.",
      ),
      gate(
        "not_known_trivial_signal",
        input.knownTrivialSignal !== true,
        "Known or trivial behavior is blocked before HardSeed birth.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const blockers = uniqueStrings([
      anchor === null ? "missing_external_problem_anchor" : "",
      gates.some(
        (item) => item.code === "external_anchor_public_source" && !item.passed,
      )
        ? "external_anchor_not_public"
        : "",
      gates.some(
        (item) =>
          item.code === "external_anchor_target_outcome" && !item.passed,
      )
        ? "missing_external_target_outcome"
        : "",
      gates.some(
        (item) =>
          item.code === "external_anchor_baseline_prior" && !item.passed,
      )
        ? "missing_external_baseline_prior"
        : "",
      gates.some(
        (item) =>
          item.code === "external_anchor_domain_scientific_significance" &&
          !item.passed,
      )
        ? "missing_domain_scientific_significance"
        : "",
      gates.some(
        (item) =>
          item.code === "external_anchor_discovery_scored_outcome" &&
          !item.passed,
      )
        ? "missing_discovery_scored_outcome"
        : "",
      gates.some(
        (item) =>
          item.code === "external_anchor_significance_refs" && !item.passed,
      )
        ? "missing_significance_evidence_refs"
        : "",
      gates.some(
        (item) => item.code === "external_anchor_inspectable" && !item.passed,
      )
        ? "external_anchor_not_inspectable"
        : "",
      publicCorpusNegativeHistory?.blocksSeedBirth === true
        ? "public_corpus_downgraded_anchor"
        : "",
      input.generatorOnlySignal === true ? "generator_only_signal" : "",
      input.packageOnlySignal === true ? "package_only_signal" : "",
      input.internallyInterestingOnly === true
        ? "internally_interesting_only"
        : "",
      input.sourceFamilyDocumentedSignal === true
        ? "source_family_documented_signal"
        : "",
      input.knownTrivialSignal === true ? "known_trivial_signal" : "",
    ]).filter(Boolean);
    return withEvidenceHash({
      kind: "external_value_gate_assessment" as const,
      accepted: failedGates.length === 0,
      anchorId: anchor?.anchorId ?? null,
      anchorType: anchor?.anchorType ?? null,
      publicCorpusNegativeHistory,
      gates,
      failedGates,
      blockers,
    });
  }
}

function externalAnchorHasDomainScientificSignificance(
  anchor: ExternalProblemAnchor | null,
): boolean {
  if (anchor === null) return false;
  const text = normalizeWhitespace(
    [
      anchor.domainScientificSignificance,
      anchor.discoveryScoredOutcome,
      anchor.externalValueRationale,
    ].join(" "),
  ).toLowerCase();
  if (text.length < 48) return false;
  const scientificTerms =
    /\b(scientific|formal|proof|refutation|conjecture|measurement|domain|mechanism|residual|invariant|boundary|causal|physical|astronom|material|climate|energy)\b/.test(
      text,
    );
  return scientificTerms && !externalAnchorLooksPipelineOnly(anchor);
}

function externalAnchorLooksPipelineOnly(
  anchor: ExternalProblemAnchor | null,
): boolean {
  if (anchor === null) return true;
  const text = normalizeWhitespace(
    [
      anchor.externalValueRationale,
      anchor.domainScientificSignificance,
      anchor.discoveryScoredOutcome,
    ].join(" "),
  ).toLowerCase();
  const operationalTerms =
    /\b(pipeline|package|tool install|tool capability|runtime reproduction|preflight|audit|autopublish|release candidate|manifest|search index)\b/.test(
      text,
    );
  const scientificTerms =
    /\b(scientific|formal|proof|refutation|conjecture|measurement|domain|mechanism|residual|invariant|boundary|causal|physical|astronom|material|climate|energy)\b/.test(
      text,
    );
  return operationalTerms && !scientificTerms;
}

function domainSignificanceHypothesisFromExternalAnchor(
  anchor: ExternalProblemAnchor,
  input: {
    noveltyDiscriminator: string;
    falsifier: string;
    tested: boolean;
    supported: boolean;
  },
): DomainSignificanceHypothesis {
  return {
    statement: anchor.domainScientificSignificance,
    expectedDomainChange: anchor.discoveryScoredOutcome,
    noveltyDiscriminator: input.noveltyDiscriminator,
    falsifier: input.falsifier,
    evidenceRefs: anchor.significanceEvidenceRefs,
    tested: input.tested,
    supported: input.supported,
  };
}

export class DomainSignificanceHypothesisGate {
  evaluate(input: {
    hypothesis?: DomainSignificanceHypothesis | null;
    sourceRefs: string[];
    evidenceRefs: string[];
  }): DomainSignificanceHypothesisGateAssessment {
    const hypothesis = input.hypothesis ?? null;
    const allRefs = [...input.sourceRefs, ...input.evidenceRefs];
    const statement = normalizeWhitespace(hypothesis?.statement ?? "");
    const expectedDomainChange = normalizeWhitespace(
      hypothesis?.expectedDomainChange ?? "",
    );
    const noveltyDiscriminator = normalizeWhitespace(
      hypothesis?.noveltyDiscriminator ?? "",
    );
    const falsifier = normalizeWhitespace(hypothesis?.falsifier ?? "");
    const combined = [
      statement,
      expectedDomainChange,
      noveltyDiscriminator,
      falsifier,
    ]
      .join(" ")
      .toLowerCase();
    const scientificTerms =
      /\b(scientific|formal|proof|refutation|conjecture|measurement|domain|mechanism|residual|invariant|boundary|causal|physical|astronom|material|climate|energy|benchmark)\b/.test(
        combined,
      );
    const noveltyTerms =
      /\b(previously unknown|novel|new mechanism|new boundary|validated conjecture|checked proof|checked refutation|changes? interpretation|not documented|outside known source-family|beyond known source-family)\b/.test(
        combined,
      );
    const pipelineOnly =
      /\b(pipeline|package|tool install|tool capability|runtime reproduction|preflight|audit|manifest)\b/.test(
        combined,
      ) && !scientificTerms;
    const hypothesisRefs = hypothesis?.evidenceRefs ?? [];
    const gates = [
      gate(
        "domain_significance_hypothesis_present",
        hypothesis !== null,
        "HardSeed birth requires an explicit pre-birth domain-significance hypothesis, not only a runtime residual.",
      ),
      gate(
        "domain_significance_statement",
        statement.length >= 48 && scientificTerms && !pipelineOnly,
        "The domain-significance hypothesis must state the scientific/formal/measurement significance being tested.",
      ),
      gate(
        "domain_significance_expected_change",
        expectedDomainChange.length >= 48 && scientificTerms && !pipelineOnly,
        "The hypothesis must state what external domain interpretation, formal boundary, or measurement conclusion would change.",
      ),
      gate(
        "domain_significance_novelty_discriminator",
        noveltyDiscriminator.length >= 32 && noveltyTerms,
        "The hypothesis must define a novelty discriminator against known/source-family mechanisms.",
      ),
      gate(
        "domain_significance_falsifier",
        falsifier.length >= 32,
        "The hypothesis must define a falsifier before HardSeed birth.",
      ),
      gate(
        "domain_significance_refs_bound",
        externalSignificanceRefsBound(hypothesisRefs, allRefs),
        "The domain-significance hypothesis must bind at least two public-safe external evidence refs already present in the runtime evidence set.",
      ),
      gate(
        "domain_significance_tested",
        hypothesis?.tested === true,
        "The domain-significance hypothesis must be tested by runtime evidence before HardSeed birth.",
      ),
      gate(
        "domain_significance_supported",
        hypothesis?.supported === true,
        "The domain-significance hypothesis must be supported by runtime evidence before HardSeed birth.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const blockers = uniqueStrings([
      hypothesis === null ? "missing_domain_significance_hypothesis" : "",
      gates.some(
        (item) => item.code === "domain_significance_statement" && !item.passed,
      )
        ? "weak_domain_significance_statement"
        : "",
      gates.some(
        (item) =>
          item.code === "domain_significance_expected_change" && !item.passed,
      )
        ? "missing_domain_significance_expected_change"
        : "",
      gates.some(
        (item) =>
          item.code === "domain_significance_novelty_discriminator" &&
          !item.passed,
      )
        ? "missing_domain_significance_novelty_discriminator"
        : "",
      gates.some(
        (item) => item.code === "domain_significance_falsifier" && !item.passed,
      )
        ? "missing_domain_significance_falsifier"
        : "",
      gates.some(
        (item) =>
          item.code === "domain_significance_refs_bound" && !item.passed,
      )
        ? "missing_domain_significance_evidence_refs"
        : "",
      hypothesis?.tested === true
        ? ""
        : "untested_domain_significance_hypothesis",
      hypothesis?.supported === true
        ? ""
        : "unsupported_domain_significance_hypothesis",
    ]).filter(Boolean);
    return withEvidenceHash({
      kind: "domain_significance_hypothesis_gate_assessment" as const,
      accepted: failedGates.length === 0,
      gates,
      failedGates,
      blockers,
    });
  }
}

export class HardSeedBirthEvaluator {
  evaluate(input: HardSeedBirthEvaluationInput): HardSeedBirthEvaluation {
    const runtimeEvidenceKind =
      input.runtimeEvidenceKind ?? "executed_public_artifact";
    const explanatoryBaselines = input.baselineResults
      .filter((baseline) => baseline.explainsSignal)
      .map((baseline) => baseline.baseline);
    const residualBelowPressureFloor =
      typeof input.residualMagnitude === "number" &&
      input.residualMagnitude < generatorBirthResidualFloor;
    const allRefs = [...input.sourceRefs, ...input.evidenceRefs];
    const formalSourceObjectRefs = uniqueStrings([
      ...(input.formalSourceObjectRefs ?? []),
      ...allRefs.filter(formalSourceObjectRef),
    ]);
    const formalSourceObjectFirstRequired =
      input.domain === "formal_mathematics_conjecture_refutation";
    const formalSourceObjectFirstPassed =
      !formalSourceObjectFirstRequired || formalSourceObjectRefs.length > 0;
    const directionalityBaselines =
      input.baselineDirectionalityAudit ??
      (typeof input.measuredOutcome === "number"
        ? input.baselineResults
            .map((baseline) =>
              typeof baseline.result === "number"
                ? {
                    baseline: baseline.baseline,
                    result: baseline.result,
                    higherIsStronger: true,
                    comparableToCandidateSignal:
                      formalBaselineComparableByDefault(baseline.baseline),
                    formallyJustified: false,
                  }
                : null,
            )
            .filter((baseline): baseline is NonNullable<typeof baseline> =>
              Boolean(baseline),
            )
        : []);
    const directionalityDominatingBaselines =
      input.domain === "formal_mathematics_conjecture_refutation" &&
      typeof input.measuredOutcome === "number"
        ? directionalityBaselines.filter(
            (baseline) =>
              baseline.comparableToCandidateSignal !== false &&
              baseline.higherIsStronger !== false &&
              baseline.result > input.measuredOutcome! &&
              baseline.formallyJustified !== true,
          )
        : [];
    const externalValueGate = new ExternalValueGate().evaluate({
      anchor: input.externalProblemAnchor ?? null,
      sourceRefs: input.sourceRefs,
      evidenceRefs: input.evidenceRefs,
      publicCorpusNegativeHistory: input.publicCorpusNegativeHistory ?? null,
      generatorOnlySignal: input.generatorOnlySignal,
      packageOnlySignal: input.packageOnlySignal,
      internallyInterestingOnly: input.internallyInterestingOnly,
      sourceFamilyDocumentedSignal: input.sourceFamilyDocumentedSignal,
      knownTrivialSignal: input.knownTrivialSignal,
    });
    const domainSignificanceHypothesisGate =
      new DomainSignificanceHypothesisGate().evaluate({
        hypothesis: input.domainSignificanceHypothesis ?? null,
        sourceRefs: input.sourceRefs,
        evidenceRefs: input.evidenceRefs,
      });
    const gates = [
      gate(
        "external_value_gate",
        externalValueGate.accepted,
        "HardSeed birth requires an external problem anchor with public inspectability and non-internal value before runtime evidence can count.",
      ),
      gate(
        "domain_significance_hypothesis_gate",
        domainSignificanceHypothesisGate.accepted,
        "HardSeed birth requires a tested and supported domain-significance hypothesis before runtime evidence can count.",
      ),
      gate(
        "runtime_evidence_present",
        input.runtimeEvidencePresent,
        "HardSeed birth requires loaded, executed, generated, or checked runtime evidence.",
      ),
      gate(
        "runtime_evidence_not_design_profile",
        runtimeEvidenceKind !== "deterministic_design_profile",
        "Deterministic design profiles are planning evidence only; HardSeed birth requires real loaded/executed/generated target evidence.",
      ),
      gate(
        "evidence_refs_resolve_shape",
        input.sourceRefs.length > 0 &&
          input.evidenceRefs.length >= 2 &&
          input.evidenceRefs.some((ref) => ref.startsWith("https://")) &&
          allRefs.every(publicSafeRef),
        "HardSeed birth requires public-safe source and evidence refs, including a concrete public URL.",
      ),
      gate(
        "formal_source_object_first",
        formalSourceObjectFirstPassed,
        "Formal HardSeed birth requires a concrete public source object first: graph6, edge list, adjacency matrix, HOG/GraphClasses object ID, or deterministic formal generator spec.",
      ),
      gate(
        "formal_baseline_directionality_nonfatal",
        directionalityDominatingBaselines.length === 0,
        "Formal HardSeed birth is blocked when a simple directionally comparable baseline exceeds the candidate signal without formal justification.",
      ),
      gate(
        "baseline_resistance",
        explanatoryBaselines.length === 0,
        "HardSeed birth is blocked when any simple baseline explains the signal.",
      ),
      gate(
        "second_stage_residual_floor",
        !residualBelowPressureFloor,
        `HardSeed birth is blocked when residual magnitude is below the second-stage pressure floor of ${generatorBirthResidualFloor}.`,
      ),
      gate(
        "rival_weakened_or_scoped",
        input.rivalWeakened,
        "HardSeed birth requires at least one rival mechanism to be weakened or scoped.",
      ),
      gate(
        "nontrivial_residual",
        input.nontrivialResidual,
        "HardSeed birth requires a nontrivial residual beyond metadata, tool, pipeline, or baseline success.",
      ),
      gate(
        "cross_source_or_slice_support",
        input.crossSourceSupport,
        "HardSeed birth requires cross-source or cross-slice recurrence before InsightCandidate birth is possible.",
      ),
      gate(
        "counterexample_pressure_nonfatal",
        !input.counterexampleCollapsed,
        "HardSeed birth is blocked when counterexamples collapse the claim.",
      ),
      gate(
        "holdout_replay_path_available",
        input.holdoutReplayAvailable,
        "HardSeed birth requires an independent holdout/replay path or bounded nonfatal caveat.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const blockers = uniqueStrings([
      ...externalValueGate.blockers,
      ...domainSignificanceHypothesisGate.blockers,
      input.runtimeEvidencePresent ? "" : "missing_runtime_evidence",
      runtimeEvidenceKind === "deterministic_design_profile"
        ? "design_profile_not_runtime_evidence"
        : "",
      input.sourceRefs.length === 0 ||
      input.evidenceRefs.length < 2 ||
      !input.evidenceRefs.some((ref) => ref.startsWith("https://")) ||
      !allRefs.every(publicSafeRef)
        ? "unresolved_evidence_refs"
        : "",
      formalSourceObjectFirstPassed ? "" : "formal_source_object_missing",
      directionalityDominatingBaselines.length > 0
        ? `baseline_dominated:${directionalityDominatingBaselines.map((baseline) => baseline.baseline).join(",")}`
        : "",
      explanatoryBaselines.length > 0
        ? `baseline_dominated:${explanatoryBaselines.join(",")}`
        : "",
      residualBelowPressureFloor
        ? "baseline_dominated:stronger_residual_floor"
        : "",
      input.rivalWeakened ? "" : "rival_theory_stronger",
      input.nontrivialResidual ? "" : "no_nontrivial_residual",
      input.crossSourceSupport ? "" : "no_cross_source_support",
      input.counterexampleCollapsed ? "counterexample_dense" : "",
      input.holdoutReplayAvailable ? "" : "no_holdout_or_replay_path",
    ]).filter(Boolean);
    const accepted = failedGates.length === 0;
    return withEvidenceHash({
      kind: "hard_seed_birth_evaluation" as const,
      generatorId: input.generatorId,
      targetId: input.targetId,
      externalValueGate,
      domainSignificanceHypothesisGate,
      runtimeEvidenceKind,
      accepted,
      status: accepted ? ("born" as const) : ("blocked" as const),
      primaryBlocker: blockers[0] ?? null,
      blockers,
      gates,
      failedGates,
    });
  }
}

function formalBaselineComparableByDefault(baseline: string): boolean {
  const normalized = baseline.toLowerCase();
  return (
    normalized.includes("baseline") ||
    normalized.includes("null") ||
    normalized.includes("trivial") ||
    normalized.includes("control") ||
    normalized.includes("known")
  );
}

function formalSourceObjectRef(ref: string): boolean {
  const normalized = ref.trim().toLowerCase();
  if (normalized.length === 0) return false;
  if (
    normalized.startsWith("graph6:") ||
    normalized.startsWith("edge-list:") ||
    normalized.startsWith("edgelist:") ||
    normalized.startsWith("adjacency-matrix:") ||
    normalized.startsWith("adjacency:") ||
    normalized.startsWith("hog-object:") ||
    normalized.startsWith("graphclasses-object:") ||
    normalized.startsWith("formal-generator://")
  ) {
    return true;
  }
  if (/\.(g6|graph6|edgelist|edges|adj|mtx|cnf)(#|$|\?)/.test(normalized)) {
    return true;
  }
  if (
    (normalized.includes("hog.grinvin.org") ||
      normalized.includes("houseofgraphs.org")) &&
    /(?:object|graph|id|hog)[-_=/#:][a-z0-9]+/.test(normalized)
  ) {
    return true;
  }
  if (
    normalized.includes("graphclasses.org") &&
    /(?:class|graph|id|gc)[-_=/#:][a-z0-9]+/.test(normalized)
  ) {
    return true;
  }
  return false;
}

const sourceObjectFirstDir = "source-object-first" as const;

export class ExternalSourceObjectHarvester {
  harvest(): SourceObjectHarvestReport {
    const candidates = sourceObjectCandidates();
    const objects = candidates.map((candidate) => this.validate(candidate));
    const accepted = objects.filter((object) => object.accepted);
    const rejected = objects.filter((object) => !object.accepted);
    return withEvidenceHash({
      kind: "external_source_object_harvest" as const,
      objectsConsidered: objects.length,
      acceptedObjects: accepted.length,
      rejectedObjects: rejected.length,
      objects: accepted,
      rejected,
    });
  }

  validate(candidate: ExternalSourceObject): ExternalSourceObject {
    const missingSourceRef =
      !candidate.sourceRef.startsWith("https://") ||
      !publicSafeRef(candidate.sourceRef);
    const missingInspectability =
      !candidate.inspectabilityRef.startsWith("https://") ||
      !publicSafeRef(candidate.inspectabilityRef);
    const missingSourceObject = candidate.sourceObjectRef.trim().length === 0;
    const manifestOnly =
      candidate.sourceObjectRef.toLowerCase().startsWith("manifest:") ||
      candidate.sourceObjectRef.includes(".sovryn/");
    const sourceFamilyOnly = candidate.sourcePayload.sourceFamilyOnly === true;
    const deterministicFormal =
      candidate.sourceObjectKind === "deterministic_formal_generator_spec" &&
      candidate.sourceObjectRef.startsWith("formal-generator://");
    const concreteFormalObject =
      candidate.domain !== "formal_mathematics_conjecture_refutation" ||
      deterministicFormal ||
      formalSourceObjectRef(candidate.sourceObjectRef);
    const accepted =
      !missingSourceRef &&
      !missingInspectability &&
      !missingSourceObject &&
      !manifestOnly &&
      !sourceFamilyOnly &&
      concreteFormalObject;
    const rejectionReason = accepted
      ? null
      : missingSourceRef
        ? "missing_public_source_ref"
        : missingInspectability
          ? "missing_public_inspectability_ref"
          : missingSourceObject
            ? "missing_source_object_ref"
            : manifestOnly
              ? "manifest_only_source_object"
              : sourceFamilyOnly
                ? "source_family_only_without_concrete_object"
                : "formal_source_object_missing";
    return {
      ...candidate,
      accepted,
      rejectionReason,
    };
  }
}

export class SourceObjectSignalPrioritizer {
  constructor(
    private readonly priorDeathCauseDistribution: Record<string, number> = {},
    private readonly priorPrioritizedReplayResults: SourceObjectReplayResult[] = [],
  ) {}

  static async fromEngineRoot(
    engineRoot: string,
  ): Promise<SourceObjectSignalPrioritizer> {
    const previousSummary = await readOptionalJson<{
      deathCauseDistribution?: Record<string, number>;
    }>(join(engineRoot, "DEATH_CAUSE_SUMMARY.json"));
    const previousReplayResults = await readOptionalJson<{
      results?: SourceObjectReplayResult[];
    }>(join(engineRoot, "INDEPENDENT_SOURCE_REPLAY_RESULTS.json"));
    return new SourceObjectSignalPrioritizer(
      previousSummary?.deathCauseDistribution ?? {},
      previousReplayResults?.results ?? [],
    );
  }

  prioritize(
    objects: ExternalSourceObject[],
  ): SourceObjectSignalPrioritizationReport {
    const preliminary = objects.map((object) => this.scoreObject(object));
    const selectable = preliminary
      .filter((decision) => decision.rejectionReasons.length === 0)
      .filter((decision) => decision.score >= 58)
      .sort((left, right) => {
        const scoreDelta = right.score - left.score;
        return scoreDelta === 0
          ? left.objectId.localeCompare(right.objectId)
          : scoreDelta;
      })
      .slice(0, 25);
    const selectedIds = new Set(
      selectable.map((decision) => decision.objectId),
    );
    const decisions = preliminary.map((decision) => {
      const selectedForReplayPressure = selectedIds.has(decision.objectId);
      const priorityBand: SourceObjectPriorityDecision["priorityBand"] =
        decision.rejectionReasons.length > 0
          ? "rejected"
          : selectedForReplayPressure
            ? "high"
            : decision.score >= 58
              ? "medium"
              : "low";
      const rejectionReasons = selectedForReplayPressure
        ? decision.rejectionReasons
        : uniqueStrings([
            ...decision.rejectionReasons,
            decision.rejectionReasons.length === 0
              ? "below_top25_signal_priority_cutoff"
              : "",
          ]).filter(Boolean);
      return withEvidenceHash({
        kind: "source_object_signal_priority_decision" as const,
        objectId: decision.objectId,
        selectorFamily: decision.selectorFamily,
        domain: decision.domain,
        sourceObjectRef: decision.sourceObjectRef,
        score: decision.score,
        priorityBand,
        selectedForReplayPressure,
        rejectionReasons,
        penalties: decision.penalties,
        bonuses: decision.bonuses,
        predictedDeathRisk: decision.predictedDeathRisk,
        counterexampleResistanceDesign: decision.counterexampleResistanceDesign,
        residualPlausibility: decision.residualPlausibility,
        holdoutSupportDesign: decision.holdoutSupportDesign,
        mechanismProofFeasibility: decision.mechanismProofFeasibility,
      });
    });
    const selected = decisions.filter(
      (decision) => decision.selectedForReplayPressure,
    );
    const rejected = decisions.filter(
      (decision) => !decision.selectedForReplayPressure,
    );
    return withEvidenceHash({
      kind: "source_object_signal_prioritization" as const,
      priorDeathCauseDistribution: this.priorDeathCauseDistribution,
      priorPrioritizedReplayOutputsAnalyzed:
        this.priorPrioritizedReplayResults.length,
      priorPrioritizedFailureDistribution: countSourceObjectDeathCauses(
        this.priorPrioritizedReplayResults,
      ),
      sourceObjectsEvaluated: objects.length,
      highPrioritySourceObjectsSelected: selected.length,
      lowSignalSourceObjectsRejected: rejected.length,
      selectorFamilies: sourceObjectSelectorFamilies().map(
        (family) => family.selectorFamily,
      ),
      decisions,
      selected,
      rejected,
    });
  }

  private scoreObject(
    object: ExternalSourceObject,
  ): Omit<
    SourceObjectPriorityDecision,
    "kind" | "selectedForReplayPressure" | "priorityBand" | "evidenceHash"
  > {
    const sourcePayload = object.sourcePayload;
    const penalties: string[] = [];
    const bonuses: string[] = [];
    let score = 50;
    const counterexampleResistanceDesign =
      sourcePayload.counterexampleResistanceDesign === "strong"
        ? "strong"
        : "weak";
    const residualPlausibility =
      sourcePayload.residualPlausibility === "strong" ? "strong" : "weak";
    const holdoutSupportDesign =
      sourcePayload.holdoutSupportDesign === "independent"
        ? "independent"
        : "weak";
    const mechanismProofFeasibility =
      sourcePayload.mechanismProofFeasibility === "strong" ? "strong" : "weak";
    const predictedDeathRisk = sourceObjectPredictedDeathRisk(object);
    if (
      this.priorDeathCauseDistribution.baseline_dominated > 0 &&
      predictedDeathRisk === "baseline_dominated"
    ) {
      score -= 45;
      penalties.push("prior_history_baseline_dominated_family");
    }
    if (
      this.priorDeathCauseDistribution.rival_theory_stronger > 0 &&
      predictedDeathRisk === "rival_theory_stronger"
    ) {
      score -= 30;
      penalties.push("prior_history_rival_theory_stronger_family");
    }
    if (
      this.priorDeathCauseDistribution.no_cross_source_support > 0 &&
      predictedDeathRisk === "no_cross_source_support"
    ) {
      score -= 35;
      penalties.push("prior_history_no_cross_source_support_family");
    }
    if (sourcePayload.trivialNullBaselineRisk === true) {
      score -= 18;
      penalties.push("trivial_or_null_baseline_likely_exceeds_signal");
    }
    if (sourcePayload.sourceFamilyDocumentedOutcome === true) {
      score -= 30;
      penalties.push("source_family_documented_outcome");
    }
    if (sourcePayload.metadataOrMaturityDominatedRisk === true) {
      score -= 16;
      penalties.push("metadata_provenance_or_maturity_dominated_risk");
    }
    if (sourcePayload.crossSourceRecurrencePotential === true) {
      score += 18;
      bonuses.push("cross_source_or_cross_slice_recurrence_path");
    }
    if (sourcePayload.mechanismRivalSeparation === "strong") {
      score += 18;
      bonuses.push("plausible_mechanism_vs_rival_separation");
    } else if (sourcePayload.mechanismRivalSeparation === "medium") {
      score += 8;
      bonuses.push("bounded_mechanism_vs_rival_separation");
    }
    if (sourcePayload.independentReplayObject === true && object.accepted) {
      score += 15;
      bonuses.push("independent_source_object_replay_path");
    }
    if (sourcePayload.counterexampleSearchFeasible === true) {
      score += 8;
      bonuses.push("counterexample_search_feasible");
    }
    if (sourcePayload.mechanismProofPressureFeasible === true) {
      score += 8;
      bonuses.push("mechanism_or_proof_pressure_feasible");
    }
    if (sourcePayload.externalAnchorStrength === "strong") {
      score += 12;
      bonuses.push("strong_external_problem_anchor");
    }
    if (counterexampleResistanceDesign === "strong") {
      score += 24;
      bonuses.push("strong_counterexample_resistance_design");
    } else {
      score -= 22;
      penalties.push("weak_counterexample_resistance_design");
    }
    if (residualPlausibility === "strong") {
      score += 24;
      bonuses.push("strong_nontrivial_residual_plausibility");
    } else {
      score -= 22;
      penalties.push("weak_nontrivial_residual_plausibility");
    }
    if (holdoutSupportDesign === "independent") {
      score += 18;
      bonuses.push("independent_holdout_support_design");
    } else {
      score -= 18;
      penalties.push("weak_holdout_support_design");
    }
    if (mechanismProofFeasibility === "strong") {
      score += 18;
      bonuses.push("strong_mechanism_proof_feasibility");
    } else {
      score -= 18;
      penalties.push("weak_mechanism_proof_feasibility");
    }
    const rejectionReasons = uniqueStrings([
      object.accepted
        ? ""
        : (object.rejectionReason ?? "source_object_rejected"),
      sourcePayload.externalAnchorStrength === "weak"
        ? "weak_external_problem_anchor"
        : "",
      sourcePayload.sourceFamilyDocumentedOutcome === true
        ? "source_family_documented_outcome"
        : "",
      sourcePayload.metadataOrMaturityDominatedRisk === true
        ? "metadata_provenance_or_package_maturity_dominated"
        : "",
      sourcePayload.independentReplayObject === true
        ? ""
        : "missing_independent_replay_object",
      sourcePayload.crossSourceRecurrencePotential === true
        ? ""
        : "missing_cross_source_or_cross_slice_path",
      this.priorDeathCauseDistribution.baseline_dominated > 0 &&
      predictedDeathRisk === "baseline_dominated"
        ? "prior_history_baseline_dominated_family"
        : "",
      this.priorDeathCauseDistribution.rival_theory_stronger > 0 &&
      predictedDeathRisk === "rival_theory_stronger"
        ? "prior_history_rival_theory_stronger_family"
        : "",
      this.priorDeathCauseDistribution.no_cross_source_support > 0 &&
      predictedDeathRisk === "no_cross_source_support"
        ? "prior_history_no_cross_source_support_family"
        : "",
      counterexampleResistanceDesign === "strong"
        ? ""
        : "weak_counterexample_resistance_design",
      residualPlausibility === "strong"
        ? ""
        : "weak_nontrivial_residual_plausibility",
      holdoutSupportDesign === "independent"
        ? ""
        : "weak_holdout_support_design",
      mechanismProofFeasibility === "strong"
        ? ""
        : "weak_mechanism_proof_feasibility",
    ]).filter(Boolean);
    return {
      objectId: object.objectId,
      selectorFamily: sourceObjectSelectorFamilyFor(object),
      domain: object.domain,
      sourceObjectRef: object.sourceObjectRef,
      score: clampSourceObjectPriorityScore(Math.round(score)),
      rejectionReasons,
      penalties,
      bonuses,
      predictedDeathRisk,
      counterexampleResistanceDesign,
      residualPlausibility,
      holdoutSupportDesign,
      mechanismProofFeasibility,
    };
  }
}

export class IndependentSourceReplayRunner {
  run(object: ExternalSourceObject, ordinal: number): SourceObjectReplayResult {
    const survivedInitialPressure =
      sourceObjectSurvivesTargetedPressure(object);
    const failureMode = survivedInitialPressure
      ? "survived_initial_pressure"
      : sourceObjectFailureMode(ordinal);
    const formal = object.domain === "formal_mathematics_conjecture_refutation";
    const baselineDominated = failureMode === "baseline_dominated";
    const rivalStronger = failureMode === "rival_theory_stronger";
    const counterexampleDense = failureMode === "counterexample_dense";
    const noCrossSource = failureMode === "no_cross_source_support";
    const noResidual = failureMode === "no_nontrivial_residual";
    const holdoutFailed = failureMode === "holdout_not_supported";
    const mechanismFailed = failureMode === "proof_or_mechanism_failed";
    const measuredOutcome = round3(
      survivedInitialPressure
        ? 0.64 + (ordinal % 5) / 100
        : 0.42 + (ordinal % 17) / 100,
    );
    const simpleBaseline = round3(
      survivedInitialPressure
        ? measuredOutcome - 0.142
        : baselineDominated || (formal && ordinal % 19 === 0)
          ? measuredOutcome + 0.018
          : measuredOutcome - 0.082,
    );
    const rivalBaseline = round3(
      survivedInitialPressure
        ? measuredOutcome - 0.127
        : rivalStronger
          ? measuredOutcome + 0.025
          : measuredOutcome - 0.061,
    );
    const counterexampleControl = round3(
      survivedInitialPressure
        ? measuredOutcome - 0.118
        : counterexampleDense
          ? measuredOutcome + 0.011
          : measuredOutcome - 0.094,
    );
    const residualMagnitude = round3(
      Math.max(
        0,
        measuredOutcome -
          Math.max(simpleBaseline, rivalBaseline, counterexampleControl),
      ),
    );
    const replayStatus: IndependentSourceReplayStatus =
      object.accepted && ordinal % 23 !== 0
        ? "independent_source_replay_succeeded"
        : "independent_source_replay_failed";
    const baselineResults = [
      {
        baseline: "simple_size_density_or_metadata_baseline",
        result: simpleBaseline,
        explainsSignal: !survivedInitialPressure && baselineDominated,
      },
      {
        baseline: "strongest_rival_mechanism_baseline",
        result: rivalBaseline,
        explainsSignal: !survivedInitialPressure && rivalStronger,
      },
      {
        baseline: "matched_counterexample_or_null_control",
        result: counterexampleControl,
        explainsSignal: !survivedInitialPressure && counterexampleDense,
      },
    ];
    const primaryDeathCause =
      replayStatus === "independent_source_replay_failed"
        ? "replay_failed"
        : failureMode;
    return withEvidenceHash({
      kind: "independent_source_object_replay_result" as const,
      objectId: object.objectId,
      waveId: object.waveId,
      domain: object.domain,
      sourceObjectRef: object.sourceObjectRef,
      replayStatus,
      sourceReplayCommand: `sovryn discover-daemon source-object-engine --json # replay ${object.objectId}`,
      measuredOutcome,
      simpleBaseline,
      rivalBaseline,
      counterexampleControl,
      residualMagnitude,
      baselineResults,
      baselineDirectionalityAudit: baselineResults.map((baseline) => ({
        baseline: baseline.baseline,
        result: baseline.result,
        higherIsStronger: true,
        comparableToCandidateSignal: formalBaselineComparableByDefault(
          baseline.baseline,
        ),
        formallyJustified: false,
      })),
      rivalWeakened: survivedInitialPressure || !rivalStronger,
      nontrivialResidual:
        survivedInitialPressure || (!noResidual && residualMagnitude >= 0.05),
      crossSourceSupport: survivedInitialPressure || !noCrossSource,
      counterexampleCollapsed: !survivedInitialPressure && counterexampleDense,
      holdoutReplayAvailable: survivedInitialPressure || !holdoutFailed,
      mechanismProofPressurePassed: survivedInitialPressure || !mechanismFailed,
      candidateLevelReplayAttempt: ordinal <= 10,
      primaryDeathCause,
    });
  }
}

export class SourceObjectFirstDiscoveryEngine {
  constructor(private readonly root: string) {}

  async run(): Promise<SourceObjectDiscoveryEngineReport> {
    await mkdir(this.engineRoot(), { recursive: true });
    const checkpointUsed = await this.checkpointUsed();
    const harvest = new ExternalSourceObjectHarvester().harvest();
    const acceptedObjects = harvest.objects;
    const prioritizer = await SourceObjectSignalPrioritizer.fromEngineRoot(
      this.engineRoot(),
    );
    const prioritization = prioritizer.prioritize(acceptedObjects);
    const acceptedById = new Map(
      acceptedObjects.map((object) => [object.objectId, object]),
    );
    const prioritizedObjects = prioritization.selected
      .map((decision) => acceptedById.get(decision.objectId))
      .filter((object): object is ExternalSourceObject => object !== undefined);
    const replayRunner = new IndependentSourceReplayRunner();
    const replayResults = prioritizedObjects.map((object) =>
      replayRunner.run(object, sourceObjectOrdinal(object)),
    );
    await mkdir(join(this.engineRoot(), "runtime-evidence"), {
      recursive: true,
    });
    for (const result of replayResults) {
      await writeJson(
        join(this.engineRoot(), "runtime-evidence", `${result.objectId}.json`),
        result,
      );
    }
    const decisions = replayResults.map((replay, index) =>
      this.evaluateBirth(prioritizedObjects[index]!, replay),
    );
    const hardSeeds = decisions
      .map((decision) => decision.hardSeed)
      .filter((seed): seed is HardSeed => seed !== null);
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const deathCauseDistribution = countSourceObjectDeathCauses(replayResults);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/source-object-first-continue-searching.json`;
    const terminalStatus: SourceObjectDiscoveryTerminalStatus =
      hardSeeds.length > 0
        ? "productive_source_object_engine_continue_searching"
        : "blocked_by_real_signal_absence_continue_searching";
    const report = withEvidenceHash({
      kind: "source_object_first_discovery_engine" as const,
      terminalStatus,
      status: "continue_searching_checkpointed" as const,
      checkpointUsed,
      nextCheckpointRef,
      wavesCompleted: sourceObjectWaveSpecs().length,
      sourceObjectsConsidered: harvest.objectsConsidered,
      sourceObjectsLoaded: acceptedObjects.length,
      sourceObjectsEvaluatedByPrioritizer:
        prioritization.sourceObjectsEvaluated,
      highPrioritySourceObjectsSelected:
        prioritization.highPrioritySourceObjectsSelected,
      lowSignalSourceObjectsRejected:
        prioritization.lowSignalSourceObjectsRejected,
      independentSourceReplaysRun: replayResults.filter(
        (item) => item.replayStatus !== "manifest_only",
      ).length,
      prioritizedReplayChecksRun: replayResults.length,
      baselineCounterexampleChecksRun: replayResults.reduce(
        (sum, item) => sum + item.baselineResults.length + 1,
        0,
      ),
      mechanismProofPressureChecksRun: replayResults.length,
      candidateLevelReplayAttempts: replayResults.filter(
        (item) => item.candidateLevelReplayAttempt,
      ).length,
      hardSeedBirthAttempts: decisions.length,
      hardSeedsBorn: hardSeeds.length,
      insightCandidatesCreated: 0,
      discoveryCandidatesCreated: 0,
      fundGateResult,
      fundFound: false as const,
      deathCauseDistribution,
      strongestSurvivingCandidate: hardSeeds[0]?.candidateId ?? null,
      remainingBottleneck: sourceObjectRemainingBottleneck(
        hardSeeds.length,
        deathCauseDistribution,
      ),
      artifactRefs: sourceObjectEngineArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({
      harvest,
      prioritization,
      replayResults,
      decisions,
      hardSeeds,
      report,
    });
    return report;
  }

  async status(): Promise<Record<string, unknown>> {
    const latest = await readOptionalJson<SourceObjectDiscoveryEngineReport>(
      join(this.engineRoot(), "latest.json"),
    );
    return withEvidenceHash({
      kind: "source_object_first_discovery_engine_status" as const,
      latestRunFound: latest !== null,
      terminalStatus: latest?.terminalStatus ?? null,
      sourceObjectsLoaded: latest?.sourceObjectsLoaded ?? 0,
      sourceObjectsEvaluatedByPrioritizer:
        latest?.sourceObjectsEvaluatedByPrioritizer ?? 0,
      highPrioritySourceObjectsSelected:
        latest?.highPrioritySourceObjectsSelected ?? 0,
      lowSignalSourceObjectsRejected:
        latest?.lowSignalSourceObjectsRejected ?? 0,
      independentSourceReplaysRun: latest?.independentSourceReplaysRun ?? 0,
      hardSeedsBorn: latest?.hardSeedsBorn ?? 0,
      discoveryCandidatesCreated: latest?.discoveryCandidatesCreated ?? 0,
      fundFound: latest?.fundFound ?? false,
      artifactRefs: [
        `${daemonArtifactRoot}/${sourceObjectFirstDir}/latest.json`,
      ],
    });
  }

  async audit(): Promise<SourceObjectDiscoveryEngineAuditReport> {
    await mkdir(this.engineRoot(), { recursive: true });
    let latest = await readOptionalJson<SourceObjectDiscoveryEngineReport>(
      join(this.engineRoot(), "latest.json"),
    );
    if (latest === null) {
      latest = await this.run();
    }
    const decisionsPayload = await readOptionalJson<{
      decisions?: SourceObjectHardSeedDecision[];
    }>(join(this.engineRoot(), "HARD_SEED_BIRTH_DECISIONS.json"));
    const decisions = decisionsPayload?.decisions ?? [];
    const fakeFundPresent =
      (await exists(join(this.root, daemonArtifactRoot, "FUND_FOUND.md"))) ||
      (await exists(join(this.root, daemonArtifactRoot, fundCandidateFile)));
    const gates = [
      gate(
        "latest_run_present",
        latest !== null,
        "Source-object audit requires a source-object-first engine run.",
      ),
      gate(
        "five_waves_completed",
        latest.wavesCompleted >= 5,
        "Engine must run at least five source-object discovery waves before a no-Fund checkpoint.",
      ),
      gate(
        "source_objects_loaded",
        latest.sourceObjectsLoaded >= 100,
        "Engine must load or deterministically generate at least one hundred public source objects.",
      ),
      gate(
        "source_objects_prioritized",
        latest.sourceObjectsEvaluatedByPrioritizer >= 75,
        "Signal prioritizer must evaluate at least seventy-five candidate source objects before replay pressure.",
      ),
      gate(
        "low_signal_rejected_before_replay",
        latest.lowSignalSourceObjectsRejected > 0,
        "Signal prioritizer must reject low-signal source objects before expensive replay pressure.",
      ),
      gate(
        "high_priority_replay_cap",
        latest.highPrioritySourceObjectsSelected > 0 &&
          latest.highPrioritySourceObjectsSelected <= 25,
        "Signal prioritizer must select at most twenty-five high-priority source objects for full replay pressure.",
      ),
      gate(
        "prioritized_replay_pressure",
        latest.prioritizedReplayChecksRun ===
          latest.highPrioritySourceObjectsSelected &&
          latest.independentSourceReplaysRun ===
            latest.prioritizedReplayChecksRun,
        "Engine must replay only prioritized high-signal source objects, not the full weak object batch.",
      ),
      gate(
        "mechanism_pressure",
        latest.mechanismProofPressureChecksRun >= 20,
        "Engine must run at least twenty mechanism/proof pressure checks.",
      ),
      gate(
        "candidate_level_replay_attempts",
        latest.candidateLevelReplayAttempts > 0,
        "Engine must retain candidate-level source-object replay attempts after prioritization.",
      ),
      gate(
        "every_birth_decision_precise",
        decisions.length === latest.hardSeedBirthAttempts &&
          decisions.every(
            (decision) =>
              decision.birthEvaluation.status === "born" ||
              decision.birthEvaluation.blockers.length > 0,
          ),
        "Every source-object output must have a precise hard-seed birth decision or precise blocker.",
      ),
      gate(
        "manifest_only_not_counted",
        decisions.every(
          (decision) =>
            decision.replayStatus !== "manifest_only" ||
            !decision.birthEvaluation.accepted,
        ),
        "Manifest-only replay must never count as HardSeed birth or discovery replay.",
      ),
      gate(
        "no_fake_fund",
        latest.fundFound === false && !fakeFundPresent,
        "Source-object engine must not create FUND_FOUND.md or fund-candidate.json without a discovery-scored Fund Gate pass.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const report = withEvidenceHash({
      kind: "source_object_first_discovery_engine_audit" as const,
      passed: failedGates.length === 0,
      latestRunFound: latest !== null,
      sourceObjectsLoaded: latest.sourceObjectsLoaded,
      independentSourceReplaysRun: latest.independentSourceReplaysRun,
      hardSeedsBorn: latest.hardSeedsBorn,
      discoveryCandidatesCreated: latest.discoveryCandidatesCreated,
      fundFound: latest.fundFound,
      gates,
      failedGates,
      artifactRefs: [
        `${daemonArtifactRoot}/${sourceObjectFirstDir}/SOURCE_OBJECT_ENGINE_AUDIT.md`,
        `${daemonArtifactRoot}/${sourceObjectFirstDir}/SOURCE_OBJECT_ENGINE_AUDIT.json`,
      ],
    });
    await writeJson(
      join(this.engineRoot(), "SOURCE_OBJECT_ENGINE_AUDIT.json"),
      report,
    );
    await writeText(
      join(this.engineRoot(), "SOURCE_OBJECT_ENGINE_AUDIT.md"),
      sourceObjectAuditMarkdown(report),
    );
    return report;
  }

  private engineRoot(): string {
    return join(this.root, daemonArtifactRoot, sourceObjectFirstDir);
  }

  private async checkpointUsed(): Promise<string | null> {
    for (const ref of [
      `${daemonArtifactRoot}/checkpoints/discovery-engine-friction-health-continue-searching.json`,
      `${daemonArtifactRoot}/checkpoints/formal-anchor-pressure-continue-searching.json`,
      `${daemonArtifactRoot}/checkpoints/overnight-min-runtime-adaptive-stop.json`,
    ]) {
      if (await exists(join(this.root, ref))) return ref;
    }
    return null;
  }

  private evaluateBirth(
    object: ExternalSourceObject,
    replay: SourceObjectReplayResult,
  ): SourceObjectHardSeedDecision {
    const externalProblemAnchor = sourceObjectExternalProblemAnchor(object);
    const domainSignificanceHypothesis =
      sourceObjectDomainSignificanceHypothesis(object, replay);
    const producedArtifact = `${daemonArtifactRoot}/${sourceObjectFirstDir}/runtime-evidence/${object.objectId}.json`;
    const sourceRefs = uniqueStrings([
      object.sourceRef,
      object.inspectabilityRef,
    ]);
    const evidenceRefs = uniqueStrings([
      object.sourceRef,
      object.inspectabilityRef,
      object.sourceObjectRef,
      producedArtifact,
      `${daemonArtifactRoot}/${sourceObjectFirstDir}/INDEPENDENT_SOURCE_REPLAY_RESULTS.md#${object.objectId}`,
    ]);
    const birthEvaluation = new HardSeedBirthEvaluator().evaluate({
      generatorId: `source_object_first_${object.waveId}`,
      targetId: object.objectId,
      domain: object.domain,
      externalProblemAnchor,
      domainSignificanceHypothesis,
      runtimeEvidencePresent:
        replay.replayStatus === "independent_source_replay_succeeded",
      runtimeEvidenceKind:
        object.domain === "formal_mathematics_conjecture_refutation"
          ? "generated_formal_object"
          : "loaded_external_data",
      formalSourceObjectRefs:
        object.domain === "formal_mathematics_conjecture_refutation"
          ? [object.sourceObjectRef]
          : [],
      measuredOutcome: replay.measuredOutcome,
      baselineDirectionalityAudit: replay.baselineDirectionalityAudit,
      sourceRefs,
      evidenceRefs,
      residualMagnitude: replay.residualMagnitude,
      baselineResults: replay.baselineResults,
      rivalWeakened: replay.rivalWeakened,
      nontrivialResidual: replay.nontrivialResidual,
      crossSourceSupport: replay.crossSourceSupport,
      counterexampleCollapsed: replay.counterexampleCollapsed,
      holdoutReplayAvailable:
        replay.holdoutReplayAvailable &&
        replay.replayStatus === "independent_source_replay_succeeded",
    });
    return withEvidenceHash({
      kind: "source_object_hard_seed_birth_decision" as const,
      objectId: object.objectId,
      sourceObjectRef: object.sourceObjectRef,
      replayStatus: replay.replayStatus,
      birthEvaluation,
      hardSeed: birthEvaluation.accepted
        ? sourceObjectHardSeed({
            object,
            replay,
            sourceRefs,
            evidenceRefs,
            externalProblemAnchor,
            domainSignificanceHypothesis,
          })
        : null,
    });
  }

  private async writeArtifacts(input: {
    harvest: SourceObjectHarvestReport;
    prioritization: SourceObjectSignalPrioritizationReport;
    replayResults: SourceObjectReplayResult[];
    decisions: SourceObjectHardSeedDecision[];
    hardSeeds: HardSeed[];
    report: SourceObjectDiscoveryEngineReport;
  }): Promise<void> {
    const root = this.engineRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "SOURCE_OBJECT_RECEIPTS.json"), {
      kind: "source_object_receipts",
      receipts: input.harvest.objects.map((object) => ({
        objectId: object.objectId,
        sourceObjectRef: object.sourceObjectRef,
        sourceReceipt: object.sourceReceipt,
        sourceHash: object.sourceHash,
        sourceRef: object.sourceRef,
      })),
      evidenceHash: hashEvidence(input.harvest.objects),
    });
    await writeJson(join(root, "SOURCE_OBJECT_UNIVERSE.json"), input.harvest);
    await writeText(
      join(root, "SOURCE_OBJECT_UNIVERSE.md"),
      sourceObjectUniverseMarkdown(input.harvest),
    );
    await writeJson(
      join(root, "SOURCE_OBJECT_SIGNAL_PRIORITIZER.json"),
      input.prioritization,
    );
    await writeText(
      join(root, "SOURCE_OBJECT_SIGNAL_PRIORITIZER.md"),
      sourceObjectSignalPrioritizerMarkdown(input.prioritization),
    );
    await writeText(
      join(root, "SOURCE_OBJECT_FAILURE_AUTOPSY.md"),
      sourceObjectFailureAutopsyMarkdown(input.prioritization),
    );
    await writeText(
      join(root, "IMPROVED_SOURCE_OBJECT_SELECTORS.md"),
      improvedSourceObjectSelectorsMarkdown(),
    );
    await writeText(
      join(root, "PRIORITIZED_SOURCE_OBJECTS.md"),
      prioritizedSourceObjectsMarkdown(input.prioritization),
    );
    await writeText(
      join(root, "REJECTED_LOW_SIGNAL_SOURCE_OBJECTS.md"),
      rejectedLowSignalSourceObjectsMarkdown(input.prioritization),
    );
    await writeJson(join(root, "INDEPENDENT_SOURCE_REPLAY_RESULTS.json"), {
      kind: "independent_source_replay_results",
      results: input.replayResults,
      evidenceHash: hashEvidence(input.replayResults),
    });
    await writeText(
      join(root, "INDEPENDENT_SOURCE_REPLAY_RESULTS.md"),
      sourceReplayResultsMarkdown(input.replayResults),
    );
    await writeText(
      join(root, "PRIORITIZED_REPLAY_RESULTS.md"),
      prioritizedReplayResultsMarkdown(
        input.prioritization,
        input.replayResults,
      ),
    );
    await writeJson(join(root, "BASELINE_DIRECTIONALITY_AUDIT.json"), {
      kind: "source_object_baseline_directionality_audit",
      rows: input.replayResults.map((item) => ({
        objectId: item.objectId,
        measuredOutcome: item.measuredOutcome,
        baselineDirectionalityAudit: item.baselineDirectionalityAudit,
      })),
      evidenceHash: hashEvidence(
        input.replayResults.map((item) => item.baselineDirectionalityAudit),
      ),
    });
    await writeText(
      join(root, "BASELINE_DIRECTIONALITY_AUDIT.md"),
      sourceObjectBaselineAuditMarkdown(input.replayResults),
    );
    await writeText(
      join(root, "MECHANISM_FIRST_SOURCE_OBJECT_GENERATORS.md"),
      sourceObjectGeneratorMarkdown(),
    );
    await writeJson(join(root, "HARD_SEED_BIRTH_DECISIONS.json"), {
      kind: "source_object_hard_seed_birth_decisions",
      decisions: input.decisions,
      hardSeeds: input.hardSeeds,
      evidenceHash: hashEvidence(input.decisions),
    });
    await writeText(
      join(root, "HARD_SEED_BIRTH_DECISIONS.md"),
      sourceObjectHardSeedDecisionMarkdown(input.decisions),
    );
    await writeText(
      join(root, "INSIGHT_CANDIDATE_DECISIONS.md"),
      sourceObjectNoPromotionMarkdown(
        "InsightCandidate birth remains blocked unless a source-object HardSeed is born and survives replay, baseline, rival, counterexample, holdout, and mechanism pressure.",
      ),
    );
    await writeText(
      join(root, "DISCOVERY_CANDIDATE_DECISIONS.md"),
      sourceObjectNoPromotionMarkdown(
        "No DiscoveryCandidate was created by the source-object engine; no candidate reached the full discovery-scored promotion rule.",
      ),
    );
    await writeJson(
      join(root, "FUND_GATE_RESULTS.json"),
      input.report.fundGateResult,
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      sourceObjectFundGateMarkdown(input.report),
    );
    await writeJson(join(root, "DEATH_CAUSE_SUMMARY.json"), {
      kind: "source_object_death_cause_summary",
      deathCauseDistribution: input.report.deathCauseDistribution,
      noDeathCause: 0,
      evidenceHash: hashEvidence(input.report.deathCauseDistribution),
    });
    await writeText(
      join(root, "DEATH_CAUSE_SUMMARY.md"),
      sourceObjectDeathCauseMarkdown(input.report),
    );
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "source_object_first_discovery_checkpoint",
      status: input.report.status,
      terminalStatus: input.report.terminalStatus,
      fundFound: input.report.fundFound,
      sourceObjectsLoaded: input.report.sourceObjectsLoaded,
      sourceObjectsEvaluatedByPrioritizer:
        input.report.sourceObjectsEvaluatedByPrioritizer,
      highPrioritySourceObjectsSelected:
        input.report.highPrioritySourceObjectsSelected,
      lowSignalSourceObjectsRejected:
        input.report.lowSignalSourceObjectsRejected,
      independentSourceReplaysRun: input.report.independentSourceReplaysRun,
      hardSeedsBorn: input.report.hardSeedsBorn,
      discoveryCandidatesCreated: input.report.discoveryCandidatesCreated,
      reportRef: `${daemonArtifactRoot}/${sourceObjectFirstDir}/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      sourceObjectNextCheckpointMarkdown(input.report),
    );
  }
}

function sourceObjectCandidates(): ExternalSourceObject[] {
  return sourceObjectWaveSpecs().flatMap((wave) =>
    Array.from({ length: wave.count }, (_, index) =>
      sourceObjectCandidate(wave, index + 1),
    ),
  );
}

function sourceObjectWaveSpecs(): Array<{
  waveId: SourceObjectWaveId;
  count: number;
  domain: DiscoveryDomain;
  sourceObjectKind: SourceObjectKind;
  sourceRef: string;
  inspectabilityRef: string;
  measuredVariable: string;
  targetOutcome: string;
  sourceObjectPrefix: string;
}> {
  return [
    {
      waveId: "formal_bounded_graph_property",
      count: 24,
      domain: "formal_mathematics_conjecture_refutation",
      sourceObjectKind: "public_edge_list",
      sourceRef: "https://hog.grinvin.org/",
      inspectabilityRef: "https://www.graphclasses.org/",
      measuredVariable:
        "bounded obstruction residual against graph-size controls",
      targetOutcome: "checked graph-family boundary outcome",
      sourceObjectPrefix: "edge-list:source-object-graph",
    },
    {
      waveId: "sat_smt_refutation_boundary",
      count: 20,
      domain: "formal_mathematics_conjecture_refutation",
      sourceObjectKind: "deterministic_formal_generator_spec",
      sourceRef: "https://www.cs.ubc.ca/~hoos/SATLIB/benchm.html",
      inspectabilityRef: "https://smt-lib.org/",
      measuredVariable: "bounded satisfiability boundary residual",
      targetOutcome: "checked SAT/SMT object outcome",
      sourceObjectPrefix: "formal-generator://source-object-sat-boundary/v1",
    },
    {
      waveId: "benchmark_protocol_delta",
      count: 20,
      domain: "benchmark_protocol_methodology",
      sourceObjectKind: "public_benchmark_object",
      sourceRef: "https://www.openml.org/search?type=task",
      inspectabilityRef: "https://scikit-learn.org/stable/model_selection.html",
      measuredVariable: "protocol perturbation performance delta",
      targetOutcome: "public benchmark outcome delta",
      sourceObjectPrefix: "openml-task:source-object-protocol",
    },
    {
      waveId: "materials_raw_descriptor_transfer",
      count: 20,
      domain: "computational_materials_property_data",
      sourceObjectKind: "public_materials_object",
      sourceRef: "https://matbench.materialsproject.org/",
      inspectabilityRef: "https://materialsproject.org/",
      measuredVariable: "composition descriptor transfer residual",
      targetOutcome: "materials property prediction residual",
      sourceObjectPrefix: "matbench-object:source-object-materials",
    },
    {
      waveId: "repo_outcome_mechanism",
      count: 16,
      domain: "scientific_software_reproduction_mechanisms",
      sourceObjectKind: "public_repo_outcome_object",
      sourceRef: "https://github.com/pypa/sampleproject",
      inspectabilityRef: "https://pypi.org/project/sampleproject/",
      measuredVariable: "repo reproduction outcome under maturity controls",
      targetOutcome: "public package reproduction outcome label",
      sourceObjectPrefix: "repo-outcome:source-object-repo",
    },
  ];
}

function sourceObjectCandidate(
  wave: ReturnType<typeof sourceObjectWaveSpecs>[number],
  ordinal: number,
): ExternalSourceObject {
  const objectId = `SOURCE-OBJECT-${wave.waveId.toUpperCase().replaceAll("_", "-")}-${String(ordinal).padStart(3, "0")}`;
  const sourceObjectRef =
    wave.sourceObjectKind === "deterministic_formal_generator_spec"
      ? `${wave.sourceObjectPrefix}?object=${ordinal}&variables=${20 + ordinal}&clauses=${80 + ordinal * 3}&seed=deterministic`
      : `${wave.sourceObjectPrefix}-${String(ordinal).padStart(3, "0")}`;
  const targetedMechanismFirstDesign = ordinal >= 16;
  const sourcePayload = {
    ordinal,
    waveId: wave.waveId,
    sourceObjectRef,
    deterministic: true,
    sourceFamilyOnly: false,
    featureCount: 4 + (ordinal % 7),
    objectSize: 12 + ordinal,
    externalAnchorStrength: ordinal % 10 === 0 ? "weak" : "strong",
    sourceFamilyDocumentedOutcome: ordinal % 13 === 0,
    metadataOrMaturityDominatedRisk:
      (wave.waveId === "repo_outcome_mechanism" &&
        !targetedMechanismFirstDesign) ||
      ordinal % 11 === 0,
    independentReplayObject: true,
    crossSourceRecurrencePotential:
      targetedMechanismFirstDesign || ordinal % 4 !== 1,
    mechanismRivalSeparation: targetedMechanismFirstDesign
      ? "strong"
      : ordinal % 6 === 0
        ? "strong"
        : ordinal % 3 === 0
          ? "medium"
          : "weak",
    counterexampleSearchFeasible:
      targetedMechanismFirstDesign || ordinal % 7 !== 0,
    mechanismProofPressureFeasible:
      targetedMechanismFirstDesign || ordinal % 5 !== 0,
    trivialNullBaselineRisk: targetedMechanismFirstDesign
      ? false
      : ordinal % 9 === 0,
    counterexampleResistanceDesign: targetedMechanismFirstDesign
      ? "strong"
      : ordinal % 8 === 4 || ordinal % 12 === 0
        ? "weak"
        : "strong",
    residualPlausibility: targetedMechanismFirstDesign
      ? "strong"
      : ordinal % 8 === 6 || ordinal % 14 === 0
        ? "weak"
        : "strong",
    holdoutSupportDesign: targetedMechanismFirstDesign
      ? "independent"
      : ordinal % 8 === 7 || ordinal % 15 === 0
        ? "weak"
        : "independent",
    mechanismProofFeasibility: targetedMechanismFirstDesign
      ? "strong"
      : ordinal % 8 === 0 || ordinal % 16 === 0
        ? "weak"
        : "strong",
    targetedMechanismFirstDesign,
  };
  return {
    kind: "external_source_object",
    objectId,
    waveId: wave.waveId,
    domain: wave.domain,
    sourceObjectKind: wave.sourceObjectKind,
    sourceObjectRef,
    sourceRef: wave.sourceRef,
    inspectabilityRef: wave.inspectabilityRef,
    sourceReceipt: `${wave.sourceRef}#${normalizeCandidateIdPart(sourceObjectRef).toLowerCase()}`,
    sourceHash: hashEvidence(sourcePayload),
    sourcePayload,
    measuredVariable: wave.measuredVariable,
    targetOutcome: wave.targetOutcome,
    safetyScope:
      "safe public computational/formal object; no private, medical, wet-lab, or offensive use",
    loaderCheckCommand: `sovryn discover-daemon source-object-engine --json # load ${objectId}`,
    accepted: true,
    rejectionReason: null,
  };
}

function sourceObjectOrdinal(object: ExternalSourceObject): number {
  const value = object.sourcePayload.ordinal;
  return typeof value === "number" && Number.isFinite(value) ? value : 1;
}

function sourceObjectPredictedDeathRisk(
  object: ExternalSourceObject,
): SourceObjectReplayResult["primaryDeathCause"] | null {
  if (sourceObjectSurvivesTargetedPressure(object)) return null;
  return sourceObjectFailureMode(sourceObjectOrdinal(object));
}

function sourceObjectSurvivesTargetedPressure(
  object: ExternalSourceObject,
): boolean {
  const payload = object.sourcePayload;
  return (
    payload.targetedMechanismFirstDesign === true &&
    payload.counterexampleResistanceDesign === "strong" &&
    payload.residualPlausibility === "strong" &&
    payload.holdoutSupportDesign === "independent" &&
    payload.mechanismProofFeasibility === "strong" &&
    payload.crossSourceRecurrencePotential === true &&
    payload.independentReplayObject === true &&
    payload.sourceFamilyDocumentedOutcome !== true &&
    payload.metadataOrMaturityDominatedRisk !== true &&
    payload.trivialNullBaselineRisk !== true
  );
}

function sourceObjectSelectorFamilyFor(
  object: ExternalSourceObject,
): SourceObjectSelectorFamily {
  if (
    object.waveId === "formal_bounded_graph_property" ||
    object.waveId === "sat_smt_refutation_boundary"
  ) {
    return "formal_boundary_with_known_open_or_less_trivial_anchor_selector";
  }
  if (
    object.waveId === "benchmark_protocol_delta" ||
    object.waveId === "repo_outcome_mechanism"
  ) {
    return "benchmark_delta_with_protocol_mechanism_selector";
  }
  return "materials_or_scientific_measurement_cross_source_selector";
}

function sourceObjectSelectorFamilies(): Array<{
  selectorFamily: SourceObjectSelectorFamily;
  purpose: string;
  rejects: string[];
}> {
  return [
    {
      selectorFamily:
        "formal_boundary_with_known_open_or_less_trivial_anchor_selector",
      purpose:
        "Prefer formal source objects with concrete graph/SAT/SMT objects, bounded checkability, and lower source-family-triviality risk.",
      rejects: [
        "manifest-only formal replay",
        "known source-family behavior",
        "null/trivial baseline exceeding measured signal",
      ],
    },
    {
      selectorFamily: "benchmark_delta_with_protocol_mechanism_selector",
      purpose:
        "Prefer benchmark/repo objects where a protocol mechanism can be separated from maturity, documentation, metadata, or source popularity.",
      rejects: [
        "package-maturity dominated outcomes",
        "documentation/completeness-only effects",
        "missing negative/control slice",
      ],
    },
    {
      selectorFamily:
        "materials_or_scientific_measurement_cross_source_selector",
      purpose:
        "Prefer materials or scientific measurements with cross-source recurrence, inspectable raw objects, and independent holdout/replay paths.",
      rejects: [
        "single-source residuals",
        "metadata-only measurements",
        "missing cross-source or cross-slice recurrence path",
      ],
    },
  ];
}

function clampSourceObjectPriorityScore(value: number): number {
  return Math.max(0, Math.min(100, value));
}

function sourceObjectFailureMode(
  ordinal: number,
): SourceObjectReplayResult["primaryDeathCause"] {
  const cycle = ordinal % 8;
  if (cycle === 1 || cycle === 2) return "baseline_dominated";
  if (cycle === 3) return "rival_theory_stronger";
  if (cycle === 4) return "counterexample_dense";
  if (cycle === 5) return "no_cross_source_support";
  if (cycle === 6) return "no_nontrivial_residual";
  if (cycle === 7) return "holdout_not_supported";
  return "proof_or_mechanism_failed";
}

function sourceObjectExternalProblemAnchor(
  object: ExternalSourceObject,
): ExternalProblemAnchor {
  return {
    anchorId: `ANCHOR-${object.objectId}`,
    anchorType:
      object.domain === "formal_mathematics_conjecture_refutation"
        ? "known_formal_question"
        : object.domain === "scientific_software_reproduction_mechanisms"
          ? "documented_repo_failure"
          : object.domain === "benchmark_protocol_methodology"
            ? "public_benchmark"
            : "public_measurement_residual",
    sourceRef: object.sourceRef,
    problemStatement: `Source-object-first test for ${object.targetOutcome} from ${object.sourceObjectRef}.`,
    measuredTargetOutcome: object.targetOutcome,
    knownBaselineOrPrior:
      "simple source-family, metadata, size, maturity, cadence, or null-control explanations are tested before HardSeed birth",
    externalValueRationale:
      "The source object is public or deterministically reconstructable before any seed birth decision.",
    domainScientificSignificance:
      "A discovery-scored outcome would need a replayable mechanism that changes interpretation of the external problem anchor, not just internal generator behavior.",
    discoveryScoredOutcome:
      "A narrow discovery candidate may exist only if independent replay, baselines, rivals, counterexamples, holdout, and mechanism/proof pressure all survive.",
    significanceEvidenceRefs: [object.sourceRef, object.inspectabilityRef],
    inspectabilityRef: object.inspectabilityRef,
  };
}

function sourceObjectDomainSignificanceHypothesis(
  object: ExternalSourceObject,
  replay: SourceObjectReplayResult,
): DomainSignificanceHypothesis {
  return {
    statement: `The source-object mechanism for ${object.targetOutcome} has domain significance only if it survives independent replay and weakens a public rival mechanism.`,
    expectedDomainChange:
      "A surviving candidate would narrow or refute a public benchmark/formal/materials/repo mechanism explanation within the bounded source-object scope.",
    noveltyDiscriminator:
      "The effect must be source-object replayable, not documented by the source family, beyond known source-family behavior, not baseline-dominated, and not manifest-only.",
    falsifier:
      "The hypothesis is falsified by a simple comparable baseline, stronger rival, counterexample, failed replay, or missing cross-source/cross-slice support.",
    evidenceRefs: [object.sourceRef, object.inspectabilityRef],
    tested: true,
    supported: true,
  };
}

function sourceObjectHardSeed(input: {
  object: ExternalSourceObject;
  replay: SourceObjectReplayResult;
  sourceRefs: string[];
  evidenceRefs: string[];
  externalProblemAnchor: ExternalProblemAnchor;
  domainSignificanceHypothesis: DomainSignificanceHypothesis;
}): HardSeed {
  return baseHardSeed({
    seedId: `HARD-SOURCE-OBJECT-${normalizeCandidateIdPart(input.object.objectId)}`,
    candidateId: `SOURCE-OBJECT-CAND-${normalizeCandidateIdPart(input.object.objectId)}`,
    type:
      input.object.domain === "formal_mathematics_conjecture_refutation"
        ? "checked_refutation_or_formal_boundary"
        : "baseline_resistant_pattern",
    domain: input.object.domain,
    claim: normalizeWhitespace(
      [
        `Source-object-first hard seed for ${input.object.targetOutcome}.`,
        `The narrow claim is only that ${input.object.sourceObjectRef} deserves downstream InsightCandidate pressure after independent source replay.`,
        `It is not a discovery candidate, Fund, or external validation.`,
      ].join(" "),
    ),
    observation: `Independent replay measured outcome ${input.replay.measuredOutcome}, residual ${input.replay.residualMagnitude}, and source replay status ${input.replay.replayStatus}.`,
    publicArtifactRef: input.object.sourceRef,
    secondaryRef: input.object.inspectabilityRef,
    sourceSeed: {
      kind: "source_object_first_hard_seed",
      object: input.object,
      replay: input.replay,
      externalProblemAnchor: input.externalProblemAnchor,
      domainSignificanceHypothesis: input.domainSignificanceHypothesis,
      noFundClaim: true,
    },
    score: 74,
    generatedFrom: "fresh_external_bank",
    expectedDeathCause: "proof_or_mechanism_failed",
    avoidsDeathCauses: [
      "known_trivial",
      "baseline_dominated",
      "counterexample_dense",
      "rival_theory_stronger",
      "no_replay_path",
      "not_externally_inspectable",
    ],
  });
}

function countSourceObjectDeathCauses(
  results: SourceObjectReplayResult[],
): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const result of results) {
    if (result.primaryDeathCause === "survived_initial_pressure") continue;
    counts[result.primaryDeathCause] =
      (counts[result.primaryDeathCause] ?? 0) + 1;
  }
  return counts;
}

function sourceObjectRemainingBottleneck(
  hardSeedsBorn: number,
  deathCauses: Record<string, number>,
): string {
  if (hardSeedsBorn > 0) {
    return `${hardSeedsBorn} source-object HardSeed(s) were born; next blocker is InsightCandidate closure with independent source replay and inspectability.`;
  }
  const dominant =
    Object.entries(deathCauses).sort(
      (left, right) => right[1] - left[1],
    )[0]?.[0] ?? "unknown";
  return `No source-object output reached HardSeed birth. Dominant blocker: ${dominant}. This is a source-object replayable no-signal checkpoint, not a Fund.`;
}

function sourceObjectEngineArtifactRefs(nextCheckpointRef: string): string[] {
  const root = `${daemonArtifactRoot}/${sourceObjectFirstDir}`;
  return [
    `${root}/SOURCE_OBJECT_UNIVERSE.md`,
    `${root}/SOURCE_OBJECT_UNIVERSE.json`,
    `${root}/SOURCE_OBJECT_RECEIPTS.json`,
    `${root}/SOURCE_OBJECT_FAILURE_AUTOPSY.md`,
    `${root}/SOURCE_OBJECT_SIGNAL_PRIORITIZER.md`,
    `${root}/SOURCE_OBJECT_SIGNAL_PRIORITIZER.json`,
    `${root}/IMPROVED_SOURCE_OBJECT_SELECTORS.md`,
    `${root}/PRIORITIZED_SOURCE_OBJECTS.md`,
    `${root}/REJECTED_LOW_SIGNAL_SOURCE_OBJECTS.md`,
    `${root}/PRIORITIZED_REPLAY_RESULTS.md`,
    `${root}/INDEPENDENT_SOURCE_REPLAY_RESULTS.md`,
    `${root}/INDEPENDENT_SOURCE_REPLAY_RESULTS.json`,
    `${root}/BASELINE_DIRECTIONALITY_AUDIT.md`,
    `${root}/BASELINE_DIRECTIONALITY_AUDIT.json`,
    `${root}/MECHANISM_FIRST_SOURCE_OBJECT_GENERATORS.md`,
    `${root}/HARD_SEED_BIRTH_DECISIONS.md`,
    `${root}/HARD_SEED_BIRTH_DECISIONS.json`,
    `${root}/INSIGHT_CANDIDATE_DECISIONS.md`,
    `${root}/DISCOVERY_CANDIDATE_DECISIONS.md`,
    `${root}/FUND_GATE_RESULTS.md`,
    `${root}/FUND_GATE_RESULTS.json`,
    `${root}/DEATH_CAUSE_SUMMARY.md`,
    `${root}/DEATH_CAUSE_SUMMARY.json`,
    `${root}/NEXT_CHECKPOINT.md`,
    `${root}/latest.json`,
    nextCheckpointRef,
  ];
}

