function round3(value: number): number {
  return Math.round(value * 1000) / 1000;
}

export class MechanismFirstEvidenceGeneratorService {
  constructor(
    private readonly root: string,
    private readonly generatorSet: MechanismFirstGeneratorSet = "primary",
  ) {}

  async families(): Promise<GeneratorFamilyRegistryReport> {
    await mkdir(this.generatorRoot(), { recursive: true });
    const families = this.generatorFamilies();
    const report = withEvidenceHash({
      kind: "mechanism_first_generator_family_registry" as const,
      generatorSet: this.generatorSet,
      familyCount: families.length,
      families,
      artifactRefs: [
        `${daemonArtifactRoot}/${generatorFamilyDir}/GENERATOR_FAMILY_REGISTRY.md`,
        `${daemonArtifactRoot}/${generatorFamilyDir}/GENERATOR_FAMILY_REGISTRY.json`,
        `${daemonArtifactRoot}/${generatorFamilyDir}/EXTERNAL_PROBLEM_ANCHORS.md`,
        `${daemonArtifactRoot}/${generatorFamilyDir}/EXTERNAL_PROBLEM_ANCHORS.json`,
      ],
    });
    await writeJson(
      join(this.generatorRoot(), "GENERATOR_FAMILY_REGISTRY.json"),
      report,
    );
    await writeText(
      join(this.generatorRoot(), "GENERATOR_FAMILY_REGISTRY.md"),
      generatorFamilyRegistryMarkdown(families),
    );
    const anchors = families.map((family) => family.externalProblemAnchor);
    await writeJson(
      join(this.generatorRoot(), "EXTERNAL_PROBLEM_ANCHORS.json"),
      {
        kind: "external_problem_anchor_registry",
        anchors,
        evidenceHash: hashEvidence(anchors),
      },
    );
    await writeText(
      join(this.generatorRoot(), "EXTERNAL_PROBLEM_ANCHORS.md"),
      externalProblemAnchorsMarkdown(families),
    );
    return report;
  }

  async run(
    generatorId?: MechanismFirstGeneratorFamilyId,
  ): Promise<MechanismFirstGeneratorRunReport> {
    await mkdir(this.generatorRoot(), { recursive: true });
    const registry = await this.families();
    const families = registry.families.filter(
      (family) => !generatorId || family.generatorId === generatorId,
    );
    if (generatorId && families.length === 0) {
      throw new Error(`Unknown generator family: ${generatorId}`);
    }
    const outputs = (
      await Promise.all(
        families.map((family) =>
          mechanismFirstGeneratorOutputs(this.root, family),
        ),
      )
    ).flat();
    await mkdir(join(this.generatorRoot(), "runtime-evidence"), {
      recursive: true,
    });
    for (const output of outputs) {
      await writeJson(join(this.root, output.producedArtifact), {
        kind: "mechanism_first_generator_runtime_evidence",
        output,
        evidenceHash: hashEvidence(output),
      });
    }
    const bornSeeds = outputs
      .map((output) => output.hardSeed)
      .filter((seed): seed is HardSeed => seed !== null);
    const validations = bornSeeds.map((seed) =>
      new HardSeedValidator().validate(seed),
    );
    const blocked = outputs.filter(
      (output) => !output.birthEvaluation.accepted,
    );
    const replacementRequirements = generatorFamilyReplacementRequirements(
      outputs,
      families,
    );
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-families-continue-searching.json`;
    const report = withEvidenceHash({
      kind: "mechanism_first_generator_run" as const,
      status: "continue_searching_checkpointed" as const,
      generatorSet: this.generatorSet,
      generatorId: generatorId ?? ("all" as const),
      checkpointUsed: await this.checkpointUsed(),
      nextCheckpointRef,
      externalProblemAnchorsLoaded: uniqueStrings(
        families.map((family) => family.externalProblemAnchor.anchorId),
      ).length,
      targetsMeasured: outputs.length,
      familiesRun: families.length,
      runtimeChecks: outputs.length,
      hardSeedBirthAttempts: outputs.length,
      seedsBlockedByExternalValueGate: outputs.filter(
        (output) => !output.externalValueGate.accepted,
      ).length,
      hardSeedsBorn: bornSeeds.length,
      blockedOutputsByCause: generatorBlockedOutputsByCause(outputs),
      replacementRequired: replacementRequirements.some(
        (item) => item.status === "replacement_required",
      ),
      replacementRequirements,
      insightCandidatesCreated: 0,
      discoveryCandidatesCreated: 0,
      fundGateResult,
      fundFound: false as const,
      remainingBottleneck: generatorRunRemainingBottleneck(outputs),
      artifactRefs: generatorRunArtifactRefs(nextCheckpointRef),
    });
    await this.writeRunArtifacts({
      report,
      outputs,
      bornSeeds,
      validations,
      blocked,
    });
    return report;
  }

  async audit(): Promise<MechanismFirstGeneratorAuditReport> {
    await mkdir(this.generatorRoot(), { recursive: true });
    const latest = await readOptionalJson<MechanismFirstGeneratorRunReport>(
      join(this.generatorRoot(), "latest.json"),
    );
    const auditSet = latest?.generatorSet ?? this.generatorSet;
    const registry =
      auditSet === this.generatorSet
        ? await this.families()
        : generatorFamilyRegistryForSet(auditSet);
    const outputPayload = await readOptionalJson<{
      outputs?: MechanismFirstGeneratorOutput[];
    }>(join(this.generatorRoot(), "GENERATOR_OUTPUTS.json"));
    const pressure =
      await readOptionalJson<GeneratorBornHardSeedPressureReport>(
        join(
          this.root,
          daemonArtifactRoot,
          generatorBornPressureDir,
          "latest.json",
        ),
      );
    const closure = await readOptionalJson<GeneratorBornFundClosureReport>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorFundClosureDir,
        "latest.json",
      ),
    );
    const claimLiftIntake =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftSignalIntakeReport>(
        join(
          this.root,
          daemonArtifactRoot,
          generatorClaimLiftDir,
          "SIGNAL_INTAKE.json",
        ),
      );
    const rawClaimLiftIntakeFundFound =
      claimLiftIntake?.status === "FUND_FOUND" &&
      claimLiftIntake.fundFound === true &&
      claimLiftIntake.fundGateResult.notificationAllowed === true &&
      claimLiftIntake.fundGateResult.countsForEinsteinNobelDiscoveryScore ===
        true;
    const rootFundArtifactsPresent =
      (await exists(join(this.root, daemonArtifactRoot, "FUND_FOUND.md"))) ||
      (await exists(join(this.root, daemonArtifactRoot, fundCandidateFile)));
    const rootFundArtifactsComplete =
      (await exists(join(this.root, daemonArtifactRoot, "FUND_FOUND.md"))) &&
      (await exists(join(this.root, daemonArtifactRoot, fundCandidateFile)));
    const claimLiftIntakeFundFound =
      rawClaimLiftIntakeFundFound && rootFundArtifactsComplete;
    const rootFundAllowedByClaimLiftIntake =
      claimLiftIntakeFundFound && rootFundArtifactsComplete;
    const outputs = outputPayload?.outputs ?? [];
    const pressureYield = generatorPressureYieldSignal(pressure);
    const closureYield = generatorClosureYieldSignal(closure);
    const closureYieldAppliesToLatestRun =
      closureYield.allClosedAsNonDiscovery &&
      latest !== null &&
      latest.hardSeedsBorn > 0 &&
      !claimLiftIntakeFundFound;
    const baseReplacementRequirements =
      latest?.replacementRequirements ??
      generatorFamilyReplacementRequirements(outputs, registry.families);
    const replacementRequirements =
      closureYieldAppliesToLatestRun && baseReplacementRequirements.length > 0
        ? generatorClosureReplacementRequirements(
            baseReplacementRequirements,
            registry.families,
            closureYield,
          )
        : baseReplacementRequirements;
    const replacementRequired =
      closureYieldAppliesToLatestRun ||
      (latest?.replacementRequired ??
        replacementRequirements.some(
          (item) => item.status === "replacement_required",
        ));
    const requiredFamilyIds =
      auditSet === "significance"
        ? [
            "matbench_descriptor_transfer_significance_generator",
            "gaia_astrometric_excess_significance_generator",
            "bounded_graph_minor_obstruction_significance_generator",
          ]
        : auditSet === "replacement"
          ? [
              "satlib_bounded_sat_boundary_generator",
              "snap_network_cut_resilience_generator",
              "openml_shift_instability_generator",
            ]
          : [
              "known_formal_problem_boundary_generator",
              "benchmark_delta_mechanism_generator",
              "public_measurement_residual_generator",
            ];
    const gates = [
      gate(
        "registry_has_three_new_families",
        registry.familyCount >= 3 &&
          requiredFamilyIds.every((generatorId) =>
            registry.families.some(
              (family) => family.generatorId === generatorId,
            ),
          ),
        "Generator registry must include the three required mechanism-first families for the selected generator set.",
      ),
      gate(
        "registry_families_have_external_problem_anchors",
        registry.families.every(
          (family) =>
            family.externalProblemAnchor.sourceRef.startsWith("https://") &&
            family.externalProblemAnchor.measuredTargetOutcome.length > 0 &&
            family.externalProblemAnchor.knownBaselineOrPrior.length > 0 &&
            externalAnchorHasDomainScientificSignificance(
              family.externalProblemAnchor,
            ) &&
            externalSignificanceRefsMeetMinimum(
              family.externalProblemAnchor.significanceEvidenceRefs,
            ),
        ),
        "Every generator family must start from a public external problem anchor with explicit domain scientific significance and at least two public significance refs.",
      ),
      gate(
        "latest_run_present",
        latest !== null,
        "Generator audit requires a focused generator run artifact.",
      ),
      gate(
        "runtime_checks_target_met",
        (latest?.runtimeChecks ?? 0) >= 30,
        "Focused generator validation must run at least thirty runtime checks when all families run.",
      ),
      gate(
        "every_output_has_birth_decision",
        outputs.length === (latest?.runtimeChecks ?? 0) &&
          outputs.every(
            (output) =>
              output.birthEvaluation.status.length > 0 &&
              output.externalValueGate.kind ===
                "external_value_gate_assessment",
          ),
        "Every generator output must explicitly decide hardSeedBirth born or blocked.",
      ),
      gate(
        "external_value_gate_blocks_internal_only_outputs",
        (latest?.seedsBlockedByExternalValueGate ?? 0) > 0 ||
          outputs.every((output) => output.externalValueGate.accepted),
        "ExternalValueGate must run before HardSeed birth and block internal-only outputs when present.",
      ),
      gate(
        "success_or_precise_blockers",
        (latest?.hardSeedsBorn ?? 0) > 0 ||
          outputs.every(
            (output) =>
              !output.birthEvaluation.accepted &&
              output.birthEvaluation.blockers.length > 0,
          ),
        "Focused validation must either produce a birth-eligible hard seed or prove precise blocker causes for every output.",
      ),
      gate(
        "no_birth_requires_replacement_requirements",
        (latest?.hardSeedsBorn ?? 0) > 0 ||
          !replacementRequired ||
          replacementRequirements.some(
            (item) => item.status === "replacement_required",
          ),
        "If runtime generator validation creates no HardSeeds, the audit must expose concrete generator replacement requirements instead of a green-only audit.",
      ),
      gate(
        "pressure_yield_not_fake_green",
        !pressureYield.noInsightAfterBornSeeds,
        "Generator audit must not stay green after generator-pressure kills every born hard seed before InsightCandidate birth.",
      ),
      gate(
        "post_closure_discovery_yield_not_fake_green",
        !closureYieldAppliesToLatestRun,
        "Generator audit must not stay green after package/Fund closure classifies every closure candidate as non-discovery unless a later claim-lift intake produced a discovery-scored Fund.",
      ),
      gate(
        "no_fake_fund",
        latest?.fundFound === false &&
          (!rootFundArtifactsPresent || rootFundAllowedByClaimLiftIntake),
        "Generator runs must not create FUND_FOUND.md or fund-candidate.json; a later discovery-scored claim-lift intake may own root Fund state.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const report = withEvidenceHash({
      kind: "mechanism_first_generator_audit" as const,
      passed: failedGates.length === 0,
      generatorSet: auditSet,
      familyCount: registry.familyCount,
      latestRunFound: latest !== null,
      runtimeChecks: latest?.runtimeChecks ?? 0,
      hardSeedBirthAttempts: latest?.hardSeedBirthAttempts ?? 0,
      hardSeedsBorn: latest?.hardSeedsBorn ?? 0,
      replacementRequired,
      replacementRequirements,
      pressureYield,
      closureYield,
      gates,
      failedGates,
      artifactRefs: [
        `${daemonArtifactRoot}/${generatorFamilyDir}/GENERATOR_AUDIT.md`,
        `${daemonArtifactRoot}/${generatorFamilyDir}/GENERATOR_REPLACEMENT_REQUIREMENTS.md`,
        `${daemonArtifactRoot}/${generatorFamilyDir}/latest.json`,
        ...(pressureYield.pressureRef === null
          ? []
          : [pressureYield.pressureRef]),
        ...(closureYield.closureRef === null ? [] : [closureYield.closureRef]),
      ],
    });
    await writeJson(join(this.generatorRoot(), "GENERATOR_AUDIT.json"), report);
    await writeText(
      join(this.generatorRoot(), "GENERATOR_AUDIT.md"),
      generatorAuditMarkdown(report),
    );
    await writeJson(
      join(this.generatorRoot(), "GENERATOR_REPLACEMENT_REQUIREMENTS.json"),
      {
        kind: "generator_replacement_requirements",
        replacementRequired: report.replacementRequired,
        requirements: report.replacementRequirements,
        source: "generator_audit",
        evidenceHash: hashEvidence(report.replacementRequirements),
      },
    );
    await writeText(
      join(this.generatorRoot(), "GENERATOR_REPLACEMENT_REQUIREMENTS.md"),
      generatorReplacementRequirementsMarkdown(report.replacementRequirements),
    );
    return report;
  }

  private generatorRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorFamilyDir);
  }

  private generatorFamilies(): MechanismFirstGeneratorFamily[] {
    return mechanismFirstGeneratorFamilies(this.generatorSet);
  }

  private async checkpointUsed(): Promise<string | null> {
    const minimumRuntimeCheckpoint = `${daemonArtifactRoot}/checkpoints/overnight-min-runtime-adaptive-stop.json`;
    if (await exists(join(this.root, minimumRuntimeCheckpoint))) {
      return minimumRuntimeCheckpoint;
    }
    const state = await readOptionalJson<DiscoveryDaemonState>(
      join(this.root, daemonArtifactRoot, "state.json"),
    );
    return state?.lastCycleId
      ? `${daemonArtifactRoot}/checkpoints/${state.lastCycleId}.json`
      : null;
  }

  private async writeRunArtifacts(input: {
    report: MechanismFirstGeneratorRunReport;
    outputs: MechanismFirstGeneratorOutput[];
    bornSeeds: HardSeed[];
    validations: HardSeedValidation[];
    blocked: MechanismFirstGeneratorOutput[];
  }): Promise<void> {
    const root = this.generatorRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "GENERATOR_OUTPUTS.json"), {
      kind: "mechanism_first_generator_outputs",
      outputs: input.outputs,
      evidenceHash: hashEvidence(input.outputs),
    });
    await writeJson(join(root, "EXTERNAL_VALUE_GATE_RESULTS.json"), {
      kind: "external_value_gate_results",
      evaluations: input.outputs.map((output) => output.externalValueGate),
      blockedCount: input.report.seedsBlockedByExternalValueGate,
      evidenceHash: hashEvidence(
        input.outputs.map((output) => output.externalValueGate),
      ),
    });
    await writeJson(join(root, "HARD_SEED_BIRTH_EVALUATION.json"), {
      kind: "hard_seed_birth_evaluation_ledger",
      evaluations: input.outputs.map((output) => output.birthEvaluation),
      evidenceHash: hashEvidence(
        input.outputs.map((output) => output.birthEvaluation),
      ),
    });
    await writeJson(join(root, "BIRTH_ELIGIBLE_HARD_SEEDS.json"), {
      kind: "birth_eligible_hard_seeds",
      hardSeeds: input.bornSeeds,
      validations: input.validations,
      evidenceHash: hashEvidence({
        hardSeeds: input.bornSeeds,
        validations: input.validations,
      }),
    });
    await writeJson(join(root, "BLOCKED_GENERATOR_OUTPUTS.json"), {
      kind: "blocked_generator_outputs",
      outputs: input.blocked,
      evidenceHash: hashEvidence(input.blocked),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "generator_family_checkpoint",
      status: input.report.status,
      generatorSet: input.report.generatorSet,
      fundFound: input.report.fundFound,
      externalProblemAnchorsLoaded: input.report.externalProblemAnchorsLoaded,
      targetsMeasured: input.report.targetsMeasured,
      runtimeChecks: input.report.runtimeChecks,
      hardSeedBirthAttempts: input.report.hardSeedBirthAttempts,
      seedsBlockedByExternalValueGate:
        input.report.seedsBlockedByExternalValueGate,
      hardSeedsBorn: input.report.hardSeedsBorn,
      replacementRequired: input.report.replacementRequired,
      replacementRequirements: input.report.replacementRequirements,
      reportRef: `${daemonArtifactRoot}/${generatorFamilyDir}/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "GENERATOR_RUN_RESULTS.md"),
      generatorRunResultsMarkdown(input.outputs, input.report),
    );
    await writeText(
      join(root, "EXTERNAL_VALUE_GATE_RESULTS.md"),
      externalValueGateResultsMarkdown(input.outputs),
    );
    await writeText(
      join(root, "HARD_SEED_BIRTH_EVALUATION.md"),
      hardSeedBirthEvaluationMarkdown(input.outputs),
    );
    await writeText(
      join(root, "BLOCKED_GENERATOR_OUTPUTS.md"),
      blockedGeneratorOutputsMarkdown(input.blocked),
    );
    await writeJson(join(root, "GENERATOR_REPLACEMENT_REQUIREMENTS.json"), {
      kind: "generator_replacement_requirements",
      replacementRequired: input.report.replacementRequired,
      requirements: input.report.replacementRequirements,
      evidenceHash: hashEvidence(input.report.replacementRequirements),
    });
    await writeText(
      join(root, "GENERATOR_REPLACEMENT_REQUIREMENTS.md"),
      generatorReplacementRequirementsMarkdown(
        input.report.replacementRequirements,
      ),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      generatorFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      generatorNextCheckpointMarkdown(input.report),
    );
  }
}

export class GeneratorBornHardSeedPressureService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornHardSeedPressureReport> {
    await mkdir(this.pressureRoot(), { recursive: true });
    await this.ensureGeneratorArtifacts();
    const { hardSeeds, outputs } = await this.loadGeneratorBornSeeds();
    const outputBySeedId = new Map(
      outputs
        .filter((output) => output.hardSeed !== null)
        .map((output) => [output.hardSeed!.seedId, output]),
    );
    const rows: GeneratorBornPressureRow[] = [];
    for (const seed of hardSeeds) {
      const output = outputBySeedId.get(seed.seedId) ?? null;
      const runtimeEvidenceRef = output?.producedArtifact ?? null;
      const runtimeEvidenceExists =
        runtimeEvidenceRef !== null &&
        (await exists(join(this.root, runtimeEvidenceRef)));
      const row = generatorBornPressureRow({
        seed,
        output,
        runtimeEvidenceExists,
      });
      if (row.primaryKillReason === "survived") {
        const derivation = await this.deriveInsightCandidate(row);
        row.insightCandidateCreated = derivation.derived;
        row.insightCandidateRef = derivation.artifactRef;
      }
      rows.push(row);
    }
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-born-pressure-continue-searching.json`;
    const report: GeneratorBornHardSeedPressureReport = withEvidenceHash({
      kind: "generator_born_hard_seed_pressure" as const,
      status: "continue_searching_checkpointed" as const,
      checkpointUsed: await this.checkpointUsed(),
      nextCheckpointRef,
      seedsLoaded: hardSeeds.length,
      testsRun: rows.length * 7,
      seedsKilledByBaseline: rows.filter(
        (row) => row.primaryKillReason === "baseline_dominated",
      ).length,
      seedsKilledByRival: rows.filter(
        (row) => row.primaryKillReason === "rival_theory_stronger",
      ).length,
      seedsKilledByCounterexample: rows.filter(
        (row) => row.primaryKillReason === "counterexample_dense",
      ).length,
      seedsKilledByLackOfRecurrence: rows.filter(
        (row) => row.primaryKillReason === "no_cross_source_support",
      ).length,
      seedsKilledByHoldoutReplay: rows.filter(
        (row) => row.primaryKillReason === "holdout_or_replay_failed",
      ).length,
      seedsKilledByMechanismProof: rows.filter(
        (row) => row.primaryKillReason === "proof_or_mechanism_failed",
      ).length,
      insightCandidatesCreated: rows.filter(
        (row) => row.insightCandidateCreated,
      ).length,
      discoveryCandidatesCreated: rows.filter(
        (row) => row.discoveryCandidateCreated,
      ).length,
      fundGateResult,
      fundFound: false as const,
      remainingBottleneck: generatorBornPressureRemainingBottleneck(rows),
      artifactRefs: generatorBornPressureArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({ report, rows });
    return report;
  }

  private pressureRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorBornPressureDir);
  }

  private async ensureGeneratorArtifacts(): Promise<void> {
    const seedPath = join(
      this.root,
      daemonArtifactRoot,
      generatorFamilyDir,
      "BIRTH_ELIGIBLE_HARD_SEEDS.json",
    );
    const outputPath = join(
      this.root,
      daemonArtifactRoot,
      generatorFamilyDir,
      "GENERATOR_OUTPUTS.json",
    );
    if ((await exists(seedPath)) && (await exists(outputPath))) return;
    await new MechanismFirstEvidenceGeneratorService(this.root).run();
  }

  private async loadGeneratorBornSeeds(): Promise<{
    hardSeeds: HardSeed[];
    outputs: GeneratorBornSourceOutput[];
  }> {
    const seedPayload = await readOptionalJson<{
      hardSeeds?: HardSeed[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorFamilyDir,
        "BIRTH_ELIGIBLE_HARD_SEEDS.json",
      ),
    );
    const outputPayload = await readOptionalJson<{
      outputs?: MechanismFirstGeneratorOutput[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorFamilyDir,
        "GENERATOR_OUTPUTS.json",
      ),
    );
    const discoveryAnchorSeedPayload = await readOptionalJson<{
      hardSeeds?: HardSeed[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        discoveryGradeAnchorRunDir,
        "BIRTH_ELIGIBLE_HARD_SEEDS.json",
      ),
    );
    const discoveryAnchorCheckPayload = await readOptionalJson<{
      checks?: DiscoveryGradeAnchorRuntimeCheck[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        discoveryGradeAnchorRunDir,
        "DISCOVERY_ANCHOR_RUNTIME_CHECKS.json",
      ),
    );
    const hardSeeds = [
      ...(seedPayload?.hardSeeds ?? []),
      ...(discoveryAnchorSeedPayload?.hardSeeds ?? []),
    ];
    const outputs: GeneratorBornSourceOutput[] = [
      ...(outputPayload?.outputs ?? []),
      ...(discoveryAnchorCheckPayload?.checks ?? []),
    ];
    const blockedSeedIds = new Set<string>();
    const filteredHardSeeds: HardSeed[] = [];
    for (const seed of hardSeeds) {
      const negativeHistory = await publicCorpusNegativeHistoryForHardSeed(
        this.root,
        seed,
      );
      if (negativeHistory.blocksSeedBirth) {
        blockedSeedIds.add(seed.seedId);
        continue;
      }
      filteredHardSeeds.push(seed);
    }
    const filteredOutputs = outputs.filter((output) => {
      const seedId = generatorBornSourceOutputSeedId(output);
      return seedId === null || !blockedSeedIds.has(seedId);
    });
    return { hardSeeds: filteredHardSeeds, outputs: filteredOutputs };
  }

  private async checkpointUsed(): Promise<string | null> {
    const generatorCheckpoint = `${daemonArtifactRoot}/checkpoints/generator-families-continue-searching.json`;
    if (await exists(join(this.root, generatorCheckpoint))) {
      return generatorCheckpoint;
    }
    const latest = await readOptionalJson<MechanismFirstGeneratorRunReport>(
      join(this.root, daemonArtifactRoot, generatorFamilyDir, "latest.json"),
    );
    return latest?.nextCheckpointRef ?? null;
  }

  private async deriveInsightCandidate(
    row: GeneratorBornPressureRow,
  ): Promise<InsightCandidateDerivation> {
    const targetOutcome = normalizeWhitespace(
      `${row.measuredOutcome} with residual ${row.residual} for ${row.outputId ?? row.seedId}`,
    );
    const parentClaim = generatorBornInsightClaim(row, targetOutcome);
    const evidenceScope = normalizeWhitespace(
      `bounded ${row.domain} target outcome ${row.outputId ?? row.seedId} with public source refs, matched controls, holdout path, and replay path`,
    );
    const canonicalClaim = new CandidateClaimCanonicalizer().canonicalize({
      claim: parentClaim,
      domain: row.domain,
      mechanism: row.mechanismHypothesis,
      evidenceScope,
      fundClass: "insight_candidate",
    });
    return new InsightCandidateDeriver(this.root).derive({
      cycleId: `${row.seedId}-generator-born-pressure`,
      parentPipelineCandidateId: row.seedId,
      parentClaim,
      parentFundClass: null,
      domain: row.domain,
      mechanismHypothesis: row.mechanismHypothesis,
      evidenceScope,
      exactNarrowClaim: parentClaim,
      parentEvidenceRefs: row.evidenceRefs,
      sourceVersioningDecision: new CandidateVersioningPolicy().evaluate({
        inputCandidateId: row.seedId,
        existing: null,
        next: canonicalClaim,
      }),
      ledger: new CandidateIdentityLedger(),
    });
  }

  private async writeArtifacts(input: {
    report: GeneratorBornHardSeedPressureReport;
    rows: GeneratorBornPressureRow[];
  }): Promise<void> {
    const root = this.pressureRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "PRESSURE_ROWS.json"), {
      kind: "generator_born_hard_seed_pressure_rows",
      rows: input.rows,
      evidenceHash: hashEvidence(input.rows),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "generator_born_hard_seed_pressure_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      seedsLoaded: input.report.seedsLoaded,
      insightCandidatesCreated: input.report.insightCandidatesCreated,
      discoveryCandidatesCreated: input.report.discoveryCandidatesCreated,
      reportRef: `${daemonArtifactRoot}/${generatorBornPressureDir}/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "GENERATOR_BORN_HARD_SEEDS_PROFILE.md"),
      generatorBornSeedProfileMarkdown(input.rows),
    );
    await writeText(
      join(root, "GENERATOR_BORN_TEST_PLANS.md"),
      generatorBornTestPlansMarkdown(input.rows),
    );
    await writeText(
      join(root, "BASELINE_PRESSURE_RESULTS.md"),
      generatorBornPressureMarkdown(
        "Baseline Pressure Results",
        input.rows,
        (row) => row.baseline.passed,
        (row) => row.baseline.summary,
      ),
    );
    await writeText(
      join(root, "RIVAL_PRESSURE_RESULTS.md"),
      generatorBornPressureMarkdown(
        "Rival Pressure Results",
        input.rows,
        (row) => row.rival.weakened,
        (row) => row.rival.summary,
      ),
    );
    await writeText(
      join(root, "COUNTEREXAMPLE_PRESSURE_RESULTS.md"),
      generatorBornPressureMarkdown(
        "Counterexample Pressure Results",
        input.rows,
        (row) => row.counterexample.survived,
        (row) => row.counterexample.summary,
      ),
    );
    await writeText(
      join(root, "RECURRENCE_PRESSURE_RESULTS.md"),
      generatorBornPressureMarkdown(
        "Cross Source Recurrence Results",
        input.rows,
        (row) => row.recurrence.supported,
        (row) => row.recurrence.summary,
      ),
    );
    await writeText(
      join(root, "HOLDOUT_REPLAY_PRESSURE_RESULTS.md"),
      generatorBornPressureMarkdown(
        "Holdout Replay Pressure Results",
        input.rows,
        (row) => row.holdoutReplay.supported,
        (row) => row.holdoutReplay.summary,
      ),
    );
    await writeText(
      join(root, "MECHANISM_PROOF_PRESSURE_RESULTS.md"),
      generatorBornPressureMarkdown(
        "Mechanism Proof Pressure Results",
        input.rows,
        (row) => row.mechanismProof.survived,
        (row) => row.mechanismProof.summary,
      ),
    );
    await writeText(
      join(root, "INSPECTABILITY_PRESSURE_RESULTS.md"),
      generatorBornPressureMarkdown(
        "Inspectability Pressure Results",
        input.rows,
        (row) => row.inspectability.complete,
        (row) => row.inspectability.summary,
      ),
    );
    await writeText(
      join(root, "INSIGHT_CANDIDATE_DERIVATION_DECISIONS.md"),
      generatorBornInsightDecisionMarkdown(input.rows, input.report),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      generatorBornFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      generatorBornNextCheckpointMarkdown(input.report),
    );
  }
}

export class GeneratorBornInsightClosureService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornInsightClosureReport> {
    await mkdir(this.closureRoot(), { recursive: true });
    await this.ensureGeneratorPressureArtifacts();
    const pressure = await this.readPressureRows();
    const refs = uniqueStrings(
      pressure.rows
        .filter((row) => row.insightCandidateCreated)
        .map((row) => row.insightCandidateRef)
        .filter((ref): ref is string => typeof ref === "string"),
    );
    const candidates = await this.readGeneratorBornCandidates(refs);
    const rowByInsightRef = new Map(
      pressure.rows
        .filter((row) => typeof row.insightCandidateRef === "string")
        .map((row) => [row.insightCandidateRef as string, row]),
    );
    const executions: InsightGauntletTestExecution[] = [];
    const promotionDecisions: InsightGauntletPromotionDecision[] = [];
    for (const [index, candidate] of candidates.entries()) {
      const row =
        rowByInsightRef.get(refs[index] ?? "") ??
        pressure.rows.find(
          (item) => item.seedId === candidate.parentPipelineCandidateId,
        ) ??
        null;
      const parentCycle = await this.readParentCycle(candidate);
      const candidateExecutions =
        row === null
          ? executeInsightGauntletTests({
              candidate,
              parentCycle,
            })
          : executeGeneratorBornInsightClosureTests({
              candidate,
              row,
            });
      executions.push(...candidateExecutions);
      promotionDecisions.push(
        insightPromotionDecision(candidate, candidateExecutions, {
          domainScientificSignificance:
            row?.domainSignificanceSupported === true,
          domainSignificanceEvidenceRefs:
            row?.domainSignificanceEvidenceRefs ?? [],
        }),
      );
      await this.writeCandidateExecution(candidate, candidateExecutions);
    }
    const fundGateResult =
      promotionDecisions.find(
        (decision) => decision.fundGateResult.notificationAllowed,
      )?.fundGateResult ??
      promotionDecisions[0]?.fundGateResult ??
      new FundGateEvaluator().evaluate(null);
    const closureCandidatesCreated = promotionDecisions.filter(
      (decision) => decision.promotedToDiscoveryCandidate,
    ).length;
    const discoveryScoredCandidatesCreated = promotionDecisions.filter(
      (decision) =>
        decision.promotedToDiscoveryCandidate &&
        decision.fundGateResult.countsForEinsteinNobelDiscoveryScore,
    ).length;
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-born-insight-closure-continue-searching.json`;
    const report: GeneratorBornInsightClosureReport = withEvidenceHash({
      kind: "generator_born_insight_closure" as const,
      status: fundGateResult.notificationAllowed
        ? ("FUND_FOUND" as const)
        : ("continue_searching_checkpointed" as const),
      checkpointUsed:
        pressure.checkpointUsed ??
        `${daemonArtifactRoot}/checkpoints/generator-born-pressure-continue-searching.json`,
      nextCheckpointRef,
      generatorBornCandidateRefs: refs,
      candidatesLoaded: candidates.length,
      candidateIds: candidates.map((candidate) => candidate.candidateId),
      testsExecuted: executions.length,
      gatesPassed: uniqueStrings(
        executions
          .filter((execution) => execution.passed)
          .map((execution) => execution.promotionGate),
      ),
      gatesFailed: uniqueStrings(
        executions
          .filter((execution) => !execution.passed)
          .map((execution) => execution.promotionGate),
      ),
      promotionDecisions,
      closureCandidatesCreated,
      discoveryCandidatesCreated: discoveryScoredCandidatesCreated,
      discoveryScoredCandidatesCreated,
      nonDiscoveryPromotionCandidates:
        closureCandidatesCreated - discoveryScoredCandidatesCreated,
      fundClassDistribution: countBy(
        promotionDecisions.map((decision) => ({
          fundClass: decision.fundGateResult.fundClass ?? "unclassified",
        })),
        "fundClass",
      ),
      fundGateResult,
      fundFound: fundGateResult.notificationAllowed,
      remainingBottleneck: generatorBornInsightClosureBottleneck(
        refs.length,
        candidates.length,
        executions,
        promotionDecisions,
      ),
      artifactRefs: generatorBornInsightClosureArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({
      report,
      refs,
      candidates,
      executions,
      promotionDecisions,
    });
    return report;
  }

  private closureRoot(): string {
    return join(this.root, daemonArtifactRoot, "generator-insight-closure");
  }

  private async ensureGeneratorPressureArtifacts(): Promise<void> {
    await new GeneratorBornHardSeedPressureService(this.root).run();
  }

  private async readPressureRows(): Promise<{
    rows: GeneratorBornPressureRow[];
    checkpointUsed: string | null;
  }> {
    const latest = await readOptionalJson<GeneratorBornHardSeedPressureReport>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorBornPressureDir,
        "latest.json",
      ),
    );
    const payload = await readOptionalJson<{
      rows?: GeneratorBornPressureRow[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorBornPressureDir,
        "PRESSURE_ROWS.json",
      ),
    );
    return {
      rows: payload?.rows ?? [],
      checkpointUsed: latest?.nextCheckpointRef ?? null,
    };
  }

  private async readGeneratorBornCandidates(
    refs: string[],
  ): Promise<InsightCandidate[]> {
    const candidates: InsightCandidate[] = [];
    for (const ref of refs) {
      if (!ref.startsWith(`${daemonArtifactRoot}/${insightCandidateDir}/`)) {
        continue;
      }
      const value = await readOptionalJson<unknown>(join(this.root, ref));
      const candidate = insightCandidateFromUnknown(value);
      if (candidate) candidates.push(candidate);
    }
    return candidates;
  }

  private async readParentCycle(
    candidate: InsightCandidate,
  ): Promise<Record<string, unknown> | null> {
    const cycleRef = parentCycleRef(candidate);
    return cycleRef
      ? await readOptionalJson<Record<string, unknown>>(
          join(this.root, cycleRef),
        )
      : null;
  }

  private async writeCandidateExecution(
    candidate: InsightCandidate,
    executions: InsightGauntletTestExecution[],
  ): Promise<void> {
    const artifactRef = `${daemonArtifactRoot}/generator-insight-closure/${normalizeCandidateIdPart(candidate.candidateId)}.json`;
    await writeJson(join(this.root, artifactRef), {
      kind: "generator_born_insight_closure_candidate_result",
      candidate,
      executions,
      evidenceHash: hashEvidence({ candidate, executions }),
    });
  }

  private async writeArtifacts(input: {
    report: GeneratorBornInsightClosureReport;
    refs: string[];
    candidates: InsightCandidate[];
    executions: InsightGauntletTestExecution[];
    promotionDecisions: InsightGauntletPromotionDecision[];
  }): Promise<void> {
    const root = this.closureRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "TARGETED_CANDIDATE_REFS.json"), {
      kind: "generator_born_insight_targeted_refs",
      refs: input.refs,
      candidateIds: input.candidates.map((candidate) => candidate.candidateId),
      evidenceHash: hashEvidence(input.refs),
    });
    await writeJson(join(root, "closure-results.json"), {
      kind: "generator_born_insight_closure_results",
      executions: input.executions,
      promotionDecisions: input.promotionDecisions,
      closureCandidatesCreated: input.report.closureCandidatesCreated,
      discoveryCandidatesCreated: input.report.discoveryCandidatesCreated,
      discoveryScoredCandidatesCreated:
        input.report.discoveryScoredCandidatesCreated,
      nonDiscoveryPromotionCandidates:
        input.report.nonDiscoveryPromotionCandidates,
      fundClassDistribution: input.report.fundClassDistribution,
      evidenceHash: hashEvidence({
        executions: input.executions,
        promotionDecisions: input.promotionDecisions,
      }),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "generator_born_insight_closure_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      candidateIds: input.report.candidateIds,
      closureCandidatesCreated: input.report.closureCandidatesCreated,
      discoveryCandidatesCreated: input.report.discoveryCandidatesCreated,
      discoveryScoredCandidatesCreated:
        input.report.discoveryScoredCandidatesCreated,
      nonDiscoveryPromotionCandidates:
        input.report.nonDiscoveryPromotionCandidates,
      fundClassDistribution: input.report.fundClassDistribution,
      gatesFailed: input.report.gatesFailed,
      reportRef: `${daemonArtifactRoot}/generator-insight-closure/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "GENERATOR_BORN_INSIGHT_PROFILE.md"),
      generatorBornInsightProfileMarkdown(input.candidates, input.refs),
    );
    await writeText(
      join(root, "REQUIRED_NEXT_TEST_RESULTS.md"),
      generatorBornInsightRequiredNextTestsMarkdown(
        input.candidates,
        input.executions,
      ),
    );
    await writeText(
      join(root, "PROMOTION_GATE_MATRIX.md"),
      generatorBornInsightGateMatrixMarkdown(input.executions),
    );
    await writeText(
      join(root, "PROMOTION_DECISION.md"),
      generatorBornInsightPromotionDecisionMarkdown(input.report),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      generatorBornInsightFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      generatorBornInsightNextCheckpointMarkdown(input.report),
    );
  }
}

export class GeneratorBornFundClosureService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornFundClosureReport> {
    await mkdir(this.closureRoot(), { recursive: true });
    await this.ensureInsightClosureArtifacts();
    const closure = await this.readInsightClosure();
    const targetDecisions = closure.promotionDecisions.filter(
      (decision) =>
        decision.promotedToDiscoveryCandidate &&
        decision.discoveryCandidateId !== null,
    );
    const attempts: Array<{
      candidate: InsightCandidate;
      discoveryCandidateId: string;
      executions: InsightGauntletTestExecution[];
      predictionLedger: GeneratorBornFrozenPrediction[];
      killWeek: GeneratorBornKillWeek;
      packagedCandidate: FundCandidate;
      fundGateResult: FundGateResult;
      result: GeneratorBornFundClosureCandidateResult;
    }> = [];
    for (const decision of targetDecisions) {
      const candidate = await this.readInsightCandidate(decision.candidateId);
      const discoveryCandidateId = decision.discoveryCandidateId;
      if (candidate === null || discoveryCandidateId === null) continue;
      const executions = await this.readExecutionsForCandidate(
        candidate.candidateId,
      );
      const predictionLedger = generatorBornFrozenPredictionLedger(
        candidate,
        executions,
      );
      const killWeek = generatorBornKillWeek(
        candidate,
        executions,
        predictionLedger,
      );
      const baseFundCandidate = fundCandidateFromInsightGauntlet(
        discoveryCandidateId,
        {
          ...candidate,
          promotionEvidence: promotionEvidenceFromExecutions(executions),
        },
        executions,
      );
      const candidatePart = normalizeCandidateIdPart(discoveryCandidateId);
      const candidateClosureRef = `${daemonArtifactRoot}/${generatorFundClosureDir}/candidates/${candidatePart}`;
      const predictionRef = `${candidateClosureRef}/FROZEN_PREDICTION_LEDGER.json`;
      const killWeekRef = `${candidateClosureRef}/KILL_WEEK_RESULTS.json`;
      await this.writeCandidateClosureArtifacts({
        candidatePart,
        predictionLedger,
        killWeek,
        executions,
      });
      let packagedCandidate = await this.packageCandidate({
        candidate,
        baseFundCandidate,
        executions,
        predictionLedger,
        killWeek,
        predictionRef,
        killWeekRef,
      });
      const fundGateResult = await evaluateFundCandidateWithPackageForRoot(
        this.root,
        packagedCandidate,
      );
      packagedCandidate = await this.syncPackagedCandidateFundClass({
        candidate: packagedCandidate,
        fundGateResult,
      });
      const packageGates = fundGateResult.gates.filter((item) =>
        item.code.startsWith("external_review_package_"),
      );
      const result: GeneratorBornFundClosureCandidateResult = {
        kind: "generator_born_fund_closure_candidate_result",
        candidateId: candidate.candidateId,
        discoveryCandidateId,
        exactClaim: candidate.exactNarrowClaim,
        domain: packagedCandidate.domain,
        predictionsFrozen: predictionLedger.length,
        predictionsExecuted: predictionLedger.filter((row) => row.executed)
          .length,
        nonObviousPredictions: predictionLedger.filter((row) => row.nonObvious)
          .length,
        killWeekComplete: killWeek.complete,
        fatalUnresolvedAttack: killWeek.fatalUnresolvedAttack,
        externalReviewPackagePath: packagedCandidate.publicPackagePath ?? null,
        fundCandidateDraftRef: `${daemonArtifactRoot}/${fundCandidateDraftDir}/${normalizeCandidateIdPart(packagedCandidate.candidateId)}.json`,
        domainSignificancePassed:
          packagedCandidate.domainSignificanceAssessment?.passed ?? false,
        domainSignificanceFailedGates:
          packagedCandidate.domainSignificanceAssessment?.failedGates ?? [],
        packageArtifactGatesPassed:
          packageGates.length > 0 && packageGates.every((item) => item.passed),
        fundGatePassed: fundGateResult.passed,
        fundClass: fundGateResult.fundClass,
        countsForEinsteinNobelDiscoveryScore:
          fundGateResult.countsForEinsteinNobelDiscoveryScore,
        notificationAllowed: fundGateResult.notificationAllowed,
        failedGates: fundGateResult.failedGates,
      };
      attempts.push({
        candidate,
        discoveryCandidateId,
        executions,
        predictionLedger,
        killWeek,
        packagedCandidate,
        fundGateResult,
        result,
      });
    }
    const selectedAttempt =
      attempts.find((attempt) => attempt.fundGateResult.notificationAllowed) ??
      attempts.find((attempt) => attempt.fundGateResult.passed) ??
      attempts[0] ??
      null;
    const fundGateResult =
      selectedAttempt?.fundGateResult ?? new FundGateEvaluator().evaluate(null);
    if (
      fundGateResult.notificationAllowed &&
      selectedAttempt?.packagedCandidate !== undefined
    ) {
      await this.writeFundNotification(selectedAttempt.packagedCandidate);
    }
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-born-fund-closure-continue-searching.json`;
    const packageGates = fundGateResult.gates.filter((item) =>
      item.code.startsWith("external_review_package_"),
    );
    const closureCandidateResults = attempts.map((attempt) => attempt.result);
    const claimLiftRequirements = generatorBornDiscoveryClaimLiftRequirements(
      closureCandidateResults,
    );
    const remainingBottleneck = generatorBornFundClosureBottleneck(
      fundGateResult,
      closureCandidateResults,
      claimLiftRequirements,
    );
    const report: GeneratorBornFundClosureReport = withEvidenceHash({
      kind: "generator_born_fund_closure" as const,
      status: fundGateResult.notificationAllowed
        ? ("FUND_FOUND" as const)
        : ("continue_searching_checkpointed" as const),
      checkpointUsed: closure.nextCheckpointRef,
      closureCandidateCount: closureCandidateResults.length,
      closureCandidateResults,
      discoveryScoredCandidates: closureCandidateResults.filter(
        (result) => result.countsForEinsteinNobelDiscoveryScore,
      ).length,
      nonDiscoveryClassifiedCandidates: closureCandidateResults.filter(
        (result) => !result.countsForEinsteinNobelDiscoveryScore,
      ).length,
      fundClassDistribution: countBy(
        closureCandidateResults.map((result) => ({
          fundClass: result.fundClass ?? "unclassified",
        })),
        "fundClass",
      ),
      nextCheckpointRef,
      candidateId: selectedAttempt?.candidate.candidateId ?? null,
      discoveryCandidateId: selectedAttempt?.discoveryCandidateId ?? null,
      exactClaim: selectedAttempt?.candidate.exactNarrowClaim ?? null,
      predictionsFrozen: selectedAttempt?.predictionLedger.length ?? 0,
      predictionsExecuted:
        selectedAttempt?.predictionLedger.filter((row) => row.executed)
          .length ?? 0,
      nonObviousPredictions:
        selectedAttempt?.predictionLedger.filter((row) => row.nonObvious)
          .length ?? 0,
      killWeekComplete: selectedAttempt?.killWeek.complete ?? false,
      fatalUnresolvedAttack:
        selectedAttempt?.killWeek.fatalUnresolvedAttack ?? true,
      externalReviewPackagePath:
        selectedAttempt?.packagedCandidate.publicPackagePath ?? null,
      fundCandidateDraftRef:
        selectedAttempt === null
          ? null
          : `${daemonArtifactRoot}/${fundCandidateDraftDir}/${normalizeCandidateIdPart(selectedAttempt.packagedCandidate.candidateId)}.json`,
      packageArtifactGatesPassed:
        packageGates.length > 0 && packageGates.every((item) => item.passed),
      claimLiftRequired: claimLiftRequirements.length > 0,
      claimLiftRequirements,
      fundGateResult,
      fundFound: fundGateResult.notificationAllowed,
      remainingBottleneck,
      artifactRefs: generatorBornFundClosureArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({
      report,
      predictionLedger: selectedAttempt?.predictionLedger ?? [],
      killWeek: selectedAttempt?.killWeek ?? generatorBornEmptyKillWeek(),
      packagedCandidate: selectedAttempt?.packagedCandidate ?? null,
      executions: selectedAttempt?.executions ?? [],
    });
    return report;
  }

  private closureRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorFundClosureDir);
  }

  private async ensureInsightClosureArtifacts(): Promise<void> {
    await new GeneratorBornInsightClosureService(this.root).run();
  }

  private async readInsightClosure(): Promise<GeneratorBornInsightClosureReport> {
    const report = await readOptionalJson<GeneratorBornInsightClosureReport>(
      join(
        this.root,
        daemonArtifactRoot,
        "generator-insight-closure",
        "latest.json",
      ),
    );
    if (report === null) {
      throw new Error(
        "Generator fund closure requires insight-closure report.",
      );
    }
    return report;
  }

  private async readInsightCandidate(
    candidateId: string,
  ): Promise<InsightCandidate | null> {
    const refs = await readOptionalJson<{
      refs?: string[];
      candidateIds?: string[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        "generator-insight-closure",
        "TARGETED_CANDIDATE_REFS.json",
      ),
    );
    const ref = (refs?.refs ?? []).find((item) =>
      item.includes(normalizeCandidateIdPart(candidateId)),
    );
    if (!ref) return null;
    return insightCandidateFromUnknown(
      await readOptionalJson<unknown>(join(this.root, ref)),
    );
  }

  private async readExecutionsForCandidate(
    candidateId: string,
  ): Promise<InsightGauntletTestExecution[]> {
    const payload = await readOptionalJson<{
      executions?: InsightGauntletTestExecution[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        "generator-insight-closure",
        "closure-results.json",
      ),
    );
    return (payload?.executions ?? []).filter(
      (execution) => execution.candidateId === candidateId,
    );
  }

  private async packageCandidate(input: {
    candidate: InsightCandidate;
    baseFundCandidate: FundCandidate;
    executions: InsightGauntletTestExecution[];
    predictionLedger: GeneratorBornFrozenPrediction[];
    killWeek: GeneratorBornKillWeek;
    predictionRef: string;
    killWeekRef: string;
  }): Promise<FundCandidate> {
    const packageRef = `${daemonArtifactRoot}/${evidencePackageDir}/${normalizeCandidateIdPart(input.baseFundCandidate.candidateId)}`;
    const packageRoot = join(this.root, packageRef);
    await mkdir(packageRoot, { recursive: true });
    const sourceEvidenceRefs = uniqueStrings([
      ...input.candidate.parentEvidenceRefs,
      ...input.executions.flatMap((execution) => execution.evidenceRefs),
      ...input.executions.map((execution) => execution.artifactRef),
      input.predictionRef,
      input.killWeekRef,
    ]).filter(publicSafeRef);
    const hardSeedRefs = [
      `${daemonArtifactRoot}/${generatorBornPressureDir}/PRESSURE_ROWS.json#${input.candidate.parentPipelineCandidateId}`,
    ];
    const identityLedgerRefs = [
      `${daemonArtifactRoot}/candidate-identity-ledger.json#${input.baseFundCandidate.candidateId}`,
    ];
    const domainSignificanceAssessment =
      generatorBornDomainSignificanceAssessment({
        candidate: input.candidate,
        executions: input.executions,
        sourceEvidenceRefs,
      });
    const bindingRefs = {
      evidenceRefs: [
        "PAPER.md#evidence-summary",
        "METHOD.md#method",
        "CLAIM_EVIDENCE_BINDINGS.json#sourceEvidenceRefs",
        "REPRODUCE.md#replay",
        "LIMITATIONS.md#limitations",
      ],
      predictionRefs: ["CLAIM_EVIDENCE_BINDINGS.json#predictionLedger"],
      holdoutRefs: ["CLAIM_EVIDENCE_BINDINGS.json#holdoutEvidenceRefs"],
      counterexampleRefs: [
        "CLAIM_EVIDENCE_BINDINGS.json#counterexampleEvidenceRefs",
      ],
      replayRefs: ["CLAIM_EVIDENCE_BINDINGS.json#replayEvidenceRefs"],
      killWeekRefs: ["CLAIM_EVIDENCE_BINDINGS.json#killWeek"],
    };
    const packagedCandidate: FundCandidate = {
      ...input.baseFundCandidate,
      publicPackagePath: packageRef,
      nontrivialNewInsightAcrossRealTargets:
        domainSignificanceAssessment.passed &&
        input.baseFundCandidate.nontrivialNewInsightAcrossRealTargets === true,
      domainScientificSignificance: domainSignificanceAssessment.passed,
      domainSignificanceAssessment,
      insightEvidenceRefs: domainSignificanceAssessment.passed
        ? input.baseFundCandidate.insightEvidenceRefs
        : [],
      predictionsExecuted: input.predictionLedger.filter((row) => row.executed)
        .length,
      nonObviousPredictions: input.predictionLedger.filter(
        (row) => row.nonObvious,
      ).length,
      killWeekComplete: input.killWeek.complete,
      fatalUnresolvedAttack: input.killWeek.fatalUnresolvedAttack,
      paperExists: true,
      methodExists: true,
      claimEvidenceBindingsExists: true,
      reproduceExists: true,
      limitationsExists: true,
      noOverclaim: true,
      predictionOutcomes: input.predictionLedger.map(
        (row) => `${input.predictionRef}#${row.predictionId}`,
      ),
      holdoutOutcomes: refsForGate(input.executions, "holdout_path"),
      counterexampleOutcomes: refsForGate(
        input.executions,
        "counterexample_path",
      ),
      replayOutcomes: refsForGate(input.executions, "replay_path"),
      killWeekResult: `${input.killWeekRef}#kill-week`,
      whyItMatters: domainSignificanceAssessment.passed
        ? "This package closes generator-born discovery pressure and passes the explicit domain-scientific-significance pressure gates."
        : "This package closes generator-born prediction, replay, counterexample, and inspectability contracts, but the explicit domain-scientific-significance pressure gates did not pass.",
      rivalTheories: [
        "size density or trivial invariant baseline explains the boundary",
        "small generated counterexamples erase the boundary",
        "generator-family artifact explains the recurrence",
      ],
      remainingLimitations: [
        "The evidence is bounded to generated formal object families and replayed Product artifacts.",
        `Domain scientific significance pressure failed gates: ${domainSignificanceAssessment.failedGates.join(", ") || "none"}.`,
        "This package makes only a bounded internal evidence claim and avoids prohibited public overclaim categories.",
      ],
      nextExternalReviewStep:
        "A formal-methods reviewer should inspect the bounded object families, prediction ledger, counterexample pressure, and replay path before any stronger interpretation.",
    };
    const fundClassAssessment = classifyFundCandidateForGate(
      packagedCandidate,
      true,
    );
    const classifiedPackagedCandidate: FundCandidate = {
      ...packagedCandidate,
      fundClass: fundClassAssessment.fundClass,
    };
    const claimLiftProposalCandidate =
      generatorBornClaimLiftProposalCandidateForPackage({
        candidate: input.candidate,
        packagedCandidate: classifiedPackagedCandidate,
        domainSignificanceAssessment,
        sourceEvidenceRefs,
        hardSeedRefs,
        identityLedgerRefs,
        packageRef,
        predictionRef: input.predictionRef,
        killWeekRef: input.killWeekRef,
      });
    const draftRef = await this.writeFundCandidateDraft({
      candidate: classifiedPackagedCandidate,
      insightCandidate: input.candidate,
      sourceEvidenceRefs,
      hardSeedRefs,
      identityLedgerRefs,
      packageRef,
      predictionRef: input.predictionRef,
      killWeekRef: input.killWeekRef,
    });
    await writeText(
      join(packageRoot, "PAPER.md"),
      renderGeneratorBornPackagePaper({
        candidate: classifiedPackagedCandidate,
        sourceEvidenceRefs,
        hardSeedRefs,
        identityLedgerRefs,
      }),
    );
    await writeText(
      join(packageRoot, "METHOD.md"),
      renderGeneratorBornPackageMethod(classifiedPackagedCandidate),
    );
    await writeJson(join(packageRoot, "CLAIM_EVIDENCE_BINDINGS.json"), {
      kind: "claim_evidence_bindings",
      fundPackageContractVersion: 2,
      candidateId: classifiedPackagedCandidate.candidateId,
      claim: classifiedPackagedCandidate.claim,
      domain: classifiedPackagedCandidate.domain,
      fundCandidateDraftRefs: [draftRef],
      sourceEvidenceRefs,
      identityLedgerRefs,
      hardSeedRefs,
      predictionLedger: input.predictionLedger,
      killWeek: input.killWeek,
      domainSignificanceAssessment,
      holdoutEvidenceRefs: classifiedPackagedCandidate.holdoutOutcomes ?? [],
      counterexampleEvidenceRefs:
        classifiedPackagedCandidate.counterexampleOutcomes ?? [],
      replayEvidenceRefs: classifiedPackagedCandidate.replayOutcomes ?? [],
      ...bindingRefs,
      methodRef: "METHOD.md",
      reproduceRef: "REPRODUCE.md",
      limitationsRef: "LIMITATIONS.md",
      noOverclaim: true,
      fundClass: fundClassAssessment.fundClass,
      countsForEinsteinNobelDiscoveryScore:
        fundClassAssessment.countsForEinsteinNobelDiscoveryScore,
      fundClassAssessment,
      claimLiftProposalCandidate,
      fundCandidate: classifiedPackagedCandidate,
    });
    await writeText(
      join(packageRoot, "REPRODUCE.md"),
      renderGeneratorBornPackageReproduce(classifiedPackagedCandidate),
    );
    await writeText(
      join(packageRoot, "LIMITATIONS.md"),
      renderCyclePackageLimitations(classifiedPackagedCandidate),
    );
    await writeJson(join(packageRoot, "FUND_CANDIDATE.json"), {
      kind: "fund_candidate",
      candidate: classifiedPackagedCandidate,
      fundClass: fundClassAssessment.fundClass,
      countsForEinsteinNobelDiscoveryScore:
        fundClassAssessment.countsForEinsteinNobelDiscoveryScore,
      fundClassAssessment,
      domainSignificanceAssessment,
      sourceEvidenceRefs,
      hardSeedRefs,
      identityLedgerRefs,
    });
    return classifiedPackagedCandidate;
  }

  private async syncPackagedCandidateFundClass(input: {
    candidate: FundCandidate;
    fundGateResult: FundGateResult;
  }): Promise<FundCandidate> {
    const fundClass = input.fundGateResult.fundClass;
    if (fundClass === null) return input.candidate;
    const fundClassAssessment =
      input.fundGateResult.fundClassAssessment ??
      classifyFundCandidateForGate(
        input.candidate,
        input.fundGateResult.passed,
      );
    const classifiedCandidate: FundCandidate = {
      ...input.candidate,
      fundClass,
    };
    const packageRef = input.candidate.publicPackagePath ?? "";
    if (
      packageRef.length === 0 ||
      packageRef.startsWith("/") ||
      !publicSafeRef(packageRef)
    ) {
      return classifiedCandidate;
    }
    const packageRoot = join(this.root, packageRef);
    const bindingPath = join(packageRoot, "CLAIM_EVIDENCE_BINDINGS.json");
    const bindings =
      await readOptionalJson<Record<string, unknown>>(bindingPath);
    if (bindings !== null) {
      const nestedCandidate = isRecord(bindings.fundCandidate)
        ? bindings.fundCandidate
        : {};
      await writeJson(bindingPath, {
        ...bindings,
        fundClass,
        countsForEinsteinNobelDiscoveryScore:
          input.fundGateResult.countsForEinsteinNobelDiscoveryScore,
        fundClassAssessment,
        fundCandidate: {
          ...nestedCandidate,
          fundClass,
        },
      });
    }
    const candidatePath = join(packageRoot, "FUND_CANDIDATE.json");
    const candidateRecord =
      await readOptionalJson<Record<string, unknown>>(candidatePath);
    if (candidateRecord !== null) {
      const nestedCandidate = isRecord(candidateRecord.candidate)
        ? candidateRecord.candidate
        : {};
      await writeJson(candidatePath, {
        ...candidateRecord,
        candidate: {
          ...nestedCandidate,
          fundClass,
        },
        fundClass,
        countsForEinsteinNobelDiscoveryScore:
          input.fundGateResult.countsForEinsteinNobelDiscoveryScore,
        fundClassAssessment,
      });
    }
    return classifiedCandidate;
  }

  private async writeCandidateClosureArtifacts(input: {
    candidatePart: string;
    predictionLedger: GeneratorBornFrozenPrediction[];
    killWeek: GeneratorBornKillWeek;
    executions: InsightGauntletTestExecution[];
  }): Promise<void> {
    const root = join(this.closureRoot(), "candidates", input.candidatePart);
    await mkdir(root, { recursive: true });
    await writeJson(join(root, "FROZEN_PREDICTION_LEDGER.json"), {
      kind: "generator_born_frozen_prediction_ledger",
      predictions: input.predictionLedger,
      evidenceHash: hashEvidence(input.predictionLedger),
    });
    await writeJson(join(root, "KILL_WEEK_RESULTS.json"), {
      kind: "generator_born_kill_week_results",
      killWeek: input.killWeek,
      evidenceHash: hashEvidence(input.killWeek),
    });
    await writeJson(join(root, "EXECUTION_REFS.json"), {
      kind: "generator_born_fund_closure_execution_refs",
      executions: input.executions,
      evidenceHash: hashEvidence(input.executions),
    });
    await writeText(
      join(root, "FROZEN_PREDICTION_LEDGER.md"),
      generatorBornFrozenPredictionMarkdown(input.predictionLedger),
    );
    await writeText(
      join(root, "KILL_WEEK_RESULTS.md"),
      generatorBornKillWeekMarkdown(input.killWeek),
    );
  }

  private async writeFundCandidateDraft(input: {
    candidate: FundCandidate;
    insightCandidate: InsightCandidate;
    sourceEvidenceRefs: string[];
    hardSeedRefs: string[];
    identityLedgerRefs: string[];
    packageRef: string;
    predictionRef: string;
    killWeekRef: string;
  }): Promise<string> {
    const ledger = new CandidateIdentityLedger(
      await readCandidateIdentityRecordsForRoot(this.root),
    );
    ledger.register({
      candidateId: input.candidate.candidateId,
      claim: input.candidate.claim,
      domain: input.candidate.domain,
      mechanism: input.insightCandidate.mechanismHypothesis,
      evidenceScope: input.insightCandidate.evidenceScope,
      fundClass: input.candidate.fundClass,
    });
    await writeJson(
      join(this.root, daemonArtifactRoot, "candidate-identity-ledger.json"),
      withEvidenceHash({
        kind: "candidate_identity_ledger",
        records: ledger.entries(),
      }),
    );
    const draftRef = `${daemonArtifactRoot}/${fundCandidateDraftDir}/${normalizeCandidateIdPart(input.candidate.candidateId)}.json`;
    const draft: FundCandidateDraft = {
      kind: "fund_candidate_draft",
      draftId: `DRAFT-${normalizeCandidateIdPart(input.candidate.candidateId)}`,
      candidateId: input.candidate.candidateId,
      claim: input.candidate.claim,
      domain: input.candidate.domain,
      sourceRefs: input.sourceEvidenceRefs.slice(0, 12),
      evidenceRefs: uniqueStrings([
        ...input.sourceEvidenceRefs,
        input.predictionRef,
        input.killWeekRef,
      ]).slice(0, 24),
      identityLedgerRefs: input.identityLedgerRefs,
      hardSeedRefs: input.hardSeedRefs,
      packageRefs: [...requiredFundPackageFiles],
      inspectabilityPath: input.packageRef,
      predictionRefs: [`${input.predictionRef}#predictions`],
      holdoutRefs: input.candidate.holdoutOutcomes ?? [],
      counterexampleRefs: input.candidate.counterexampleOutcomes ?? [],
      replayRefs: input.candidate.replayOutcomes ?? [],
      killWeekRefs: [`${input.killWeekRef}#kill-week`],
      limitations: input.candidate.remainingLimitations ?? [],
      generatedFrom: "fresh_external_target",
      synthetic: false,
      partialCandidate: false,
    };
    const validation = new FundCandidateDraftValidator().validate({
      draft,
      ledger: new CandidateIdentityLedger(ledger.entries()),
    });
    await writeJson(join(this.root, draftRef), draft);
    await writeJson(
      join(this.root, draftRef.replace(".json", ".validation.json")),
      {
        kind: "fund_candidate_draft_record",
        draftRef,
        validation,
        evidenceHash: hashEvidence({ draft, validation }),
      },
    );
    return draftRef;
  }

  private async writeArtifacts(input: {
    report: GeneratorBornFundClosureReport;
    predictionLedger: GeneratorBornFrozenPrediction[];
    killWeek: GeneratorBornKillWeek;
    packagedCandidate: FundCandidate | null;
    executions: InsightGauntletTestExecution[];
  }): Promise<void> {
    const root = this.closureRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "FROZEN_PREDICTION_LEDGER.json"), {
      kind: "generator_born_frozen_prediction_ledger",
      predictions: input.predictionLedger,
      evidenceHash: hashEvidence(input.predictionLedger),
    });
    await writeJson(join(root, "KILL_WEEK_RESULTS.json"), {
      kind: "generator_born_kill_week_results",
      killWeek: input.killWeek,
      evidenceHash: hashEvidence(input.killWeek),
    });
    await writeJson(
      join(root, "FUND_GATE_RESULTS.json"),
      input.report.fundGateResult,
    );
    await writeJson(join(root, "CANDIDATE_CLOSURE_RESULTS.json"), {
      kind: "generator_born_fund_closure_candidate_results",
      candidates: input.report.closureCandidateResults,
      fundClassDistribution: input.report.fundClassDistribution,
      discoveryScoredCandidates: input.report.discoveryScoredCandidates,
      nonDiscoveryClassifiedCandidates:
        input.report.nonDiscoveryClassifiedCandidates,
      evidenceHash: hashEvidence(input.report.closureCandidateResults),
    });
    await writeJson(join(root, "DISCOVERY_CLAIM_LIFT_REQUIREMENTS.json"), {
      kind: "generator_born_discovery_claim_lift_requirements",
      claimLiftRequired: input.report.claimLiftRequired,
      requirements: input.report.claimLiftRequirements,
      evidenceHash: hashEvidence(input.report.claimLiftRequirements),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "generator_born_fund_closure_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      candidateId: input.report.candidateId,
      discoveryCandidateId: input.report.discoveryCandidateId,
      closureCandidateCount: input.report.closureCandidateCount,
      discoveryScoredCandidates: input.report.discoveryScoredCandidates,
      nonDiscoveryClassifiedCandidates:
        input.report.nonDiscoveryClassifiedCandidates,
      claimLiftRequired: input.report.claimLiftRequired,
      claimLiftRequirements: input.report.claimLiftRequirements,
      fundClassDistribution: input.report.fundClassDistribution,
      fundGateFailedGates: input.report.fundGateResult.failedGates,
      reportRef: `${daemonArtifactRoot}/${generatorFundClosureDir}/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "FROZEN_PREDICTION_LEDGER.md"),
      generatorBornFrozenPredictionMarkdown(input.predictionLedger),
    );
    await writeText(
      join(root, "KILL_WEEK_RESULTS.md"),
      generatorBornKillWeekMarkdown(input.killWeek),
    );
    await writeText(
      join(root, "EXTERNAL_REVIEW_PACKAGE_STATUS.md"),
      generatorBornExternalPackageMarkdown(
        input.report,
        input.packagedCandidate,
      ),
    );
    await writeText(
      join(root, "CANDIDATE_CLOSURE_RESULTS.md"),
      generatorBornFundClosureCandidateResultsMarkdown(input.report),
    );
    await writeText(
      join(root, "DISCOVERY_CLAIM_LIFT_REQUIREMENTS.md"),
      generatorBornDiscoveryClaimLiftRequirementsMarkdown(input.report),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      generatorBornFundClosureGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      generatorBornFundClosureNextCheckpointMarkdown(input.report),
    );
    await writeJson(join(root, "EXECUTION_REFS.json"), {
      kind: "generator_born_fund_closure_execution_refs",
      executions: input.executions,
      evidenceHash: hashEvidence(input.executions),
    });
  }

  private async writeFundNotification(candidate: FundCandidate): Promise<void> {
    await writeJson(
      join(this.root, daemonArtifactRoot, fundCandidateFile),
      withEvidenceHash({
        kind: "fund_candidate",
        candidate,
      }),
    );
    await writeFile(
      join(this.root, daemonArtifactRoot, "FUND_FOUND.md"),
      renderFundFoundMarkdown(candidate),
      "utf8",
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    await new GeneratorBornFundClosureService(this.root).run();
    const closure = await this.readFundClosure();
    const requirements = closure.claimLiftRequirements;
    const proposals = await this.readProposals();
    const decisions = await Promise.all(
      requirements.map((requirement) =>
        generatorBornDiscoveryClaimLiftDecision({
          root: this.root,
          requirement,
          proposal:
            proposals.find(
              (proposal) =>
                proposal.parentCandidateId === requirement.candidateId,
            ) ?? null,
          proposalRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_PROPOSALS.json#${requirement.candidateId}`,
        }),
      ),
    );
    const materialized = await this.writeAcceptedDiscoveryCandidates(
      decisions,
      proposals,
    );
    const discoveryCandidateRefs = materialized.discoveryCandidateRefs;
    const draftDecisions = materialized.draftDecisions;
    const fundCandidateDraftRefs = draftDecisions
      .map((decision) => decision.draftRef)
      .filter((ref): ref is string => ref !== null);
    const fundGateEvaluations = await this.evaluateLiftedDrafts({
      decisions,
      proposals,
      draftDecisions,
    });
    const fundGateResult =
      fundGateEvaluations.find(
        (evaluation) => evaluation.notificationAllowed,
      ) ??
      fundGateEvaluations.find((evaluation) => evaluation.passed) ??
      new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftReport = withEvidenceHash({
      kind: "generator_born_discovery_claim_lift" as const,
      status: "continue_searching_checkpointed" as const,
      checkpointUsed: closure.nextCheckpointRef,
      nextCheckpointRef,
      requirementsLoaded: requirements.length,
      proposalsLoaded: proposals.length,
      decisions,
      acceptedClaimLifts: decisions.filter((decision) => decision.accepted)
        .length,
      blockedClaimLifts: decisions.filter((decision) => !decision.accepted)
        .length,
      discoveryCandidatesCreated: discoveryCandidateRefs.length,
      discoveryCandidateRefs,
      draftDecisions,
      fundCandidateDraftRefs,
      fundCandidateDraftsCreated: fundCandidateDraftRefs.length,
      fundGateEvaluations,
      fundGateResult,
      fundFound: false as const,
      remainingBottleneck: generatorBornDiscoveryClaimLiftBottleneck(decisions),
      artifactRefs: generatorBornDiscoveryClaimLiftArtifactRefs(
        nextCheckpointRef,
        discoveryCandidateRefs,
        fundCandidateDraftRefs,
      ),
    });
    await this.writeArtifacts({ report, requirements, proposals });
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readFundClosure(): Promise<GeneratorBornFundClosureReport> {
    const report = await readOptionalJson<GeneratorBornFundClosureReport>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorFundClosureDir,
        "latest.json",
      ),
    );
    if (report === null) {
      throw new Error(
        "Generator claim lift requires generator-fund-closure report.",
      );
    }
    return report;
  }

  private async readProposals(): Promise<
    GeneratorBornDiscoveryClaimLiftProposal[]
  > {
    const payload = await readOptionalJson<{
      proposals?: GeneratorBornDiscoveryClaimLiftProposal[];
    }>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorClaimLiftDir,
        "CLAIM_LIFT_PROPOSALS.json",
      ),
    );
    return (payload?.proposals ?? []).filter(
      (proposal) =>
        proposal.kind === "generator_born_discovery_claim_lift_proposal" &&
        typeof proposal.parentCandidateId === "string",
    );
  }

  private async writeAcceptedDiscoveryCandidates(
    decisions: GeneratorBornDiscoveryClaimLiftDecision[],
    proposals: GeneratorBornDiscoveryClaimLiftProposal[],
  ): Promise<{
    discoveryCandidateRefs: string[];
    draftDecisions: GeneratorBornDiscoveryClaimLiftDraftDecision[];
  }> {
    const proposalByParent = new Map(
      proposals.map((proposal) => [proposal.parentCandidateId, proposal]),
    );
    const refs: string[] = [];
    const draftDecisions: GeneratorBornDiscoveryClaimLiftDraftDecision[] = [];
    for (const decision of decisions.filter((item) => item.accepted)) {
      const proposal = proposalByParent.get(decision.candidateId);
      if (!proposal || !decision.targetDiscoveryCandidateId) continue;
      const candidateRef = `${daemonArtifactRoot}/${generatorClaimLiftDir}/discovery-candidates/${normalizeCandidateIdPart(decision.targetDiscoveryCandidateId)}.json`;
      await writeJson(
        join(this.root, candidateRef),
        withEvidenceHash({
          kind: "generator_born_lifted_discovery_candidate" as const,
          status: "discovery_candidate_pending_fund_candidate_draft" as const,
          candidateId: decision.targetDiscoveryCandidateId,
          parentCandidateId: decision.candidateId,
          exactClaim: proposal.exactTargetOutcomeClaim,
          mechanismHypothesis: proposal.mechanismHypothesis,
          externalSignificanceEvidenceRefs:
            proposal.externalSignificanceEvidenceRefs,
          sourceEvidenceRefs: proposal.sourceEvidenceRefs,
          baselineRefs: proposal.baselineRefs,
          rivalRefs: proposal.rivalRefs,
          holdoutRefs: proposal.holdoutRefs,
          replayRefs: proposal.replayRefs,
          counterexampleRefs: proposal.counterexampleRefs,
          mechanismPressureRefs: proposal.mechanismPressureRefs,
          proposalRef: decision.proposalRef,
          fundCandidateDraftCreated: false,
          fundFound: false,
          noOverclaim: proposal.noOverclaim,
          notes:
            "This is a forward-only DiscoveryCandidate artifact from a fully evidenced claim lift. It is not a FundCandidateDraft, FUND_FOUND, or external validation.",
        }),
      );
      refs.push(candidateRef);
      draftDecisions.push(
        await this.writeDraftIfReady({
          decision,
          proposal,
        }),
      );
    }
    return { discoveryCandidateRefs: refs, draftDecisions };
  }

  private async evaluateLiftedDrafts(input: {
    decisions: GeneratorBornDiscoveryClaimLiftDecision[];
    proposals: GeneratorBornDiscoveryClaimLiftProposal[];
    draftDecisions: GeneratorBornDiscoveryClaimLiftDraftDecision[];
  }): Promise<FundGateResult[]> {
    const proposalByParent = new Map(
      input.proposals.map((proposal) => [proposal.parentCandidateId, proposal]),
    );
    const acceptedByParent = new Map(
      input.decisions
        .filter(
          (decision) =>
            decision.accepted && decision.targetDiscoveryCandidateId !== null,
        )
        .map((decision) => [decision.candidateId, decision]),
    );
    const evaluations: FundGateResult[] = [];
    for (const draftDecision of input.draftDecisions) {
      if (!draftDecision.draftReady || !draftDecision.draftRef) continue;
      const proposal = proposalByParent.get(draftDecision.candidateId);
      const decision = acceptedByParent.get(draftDecision.candidateId);
      if (!proposal || !decision?.targetDiscoveryCandidateId) continue;
      const draft = await readOptionalJson<FundCandidateDraft>(
        join(this.root, draftDecision.draftRef),
      );
      if (!draft) continue;
      const packageRef = await this.writeLiftedReviewPackage({
        draft,
        proposal,
        draftRef: draftDecision.draftRef,
      });
      const candidate = fundCandidateFromClaimLiftDraft({
        draft,
        proposal,
        packageRef,
      });
      evaluations.push(
        await evaluateFundCandidateWithPackageForRoot(this.root, candidate),
      );
    }
    return evaluations;
  }

  private async writeLiftedReviewPackage(input: {
    draft: FundCandidateDraft;
    proposal: GeneratorBornDiscoveryClaimLiftProposal;
    draftRef: string;
  }): Promise<string> {
    const packageRef = `${daemonArtifactRoot}/${evidencePackageDir}/${normalizeCandidateIdPart(input.proposal.targetDiscoveryCandidateId)}`;
    const packageRoot = join(this.root, packageRef);
    await mkdir(packageRoot, { recursive: true });
    const candidate = fundCandidateFromClaimLiftDraft({
      draft: input.draft,
      proposal: input.proposal,
      packageRef,
    });
    const fundClassAssessment = classifyFundCandidateForGate(candidate, true);
    await writeText(
      join(packageRoot, "PAPER.md"),
      renderClaimLiftPackagePaper(input.proposal),
    );
    await writeText(
      join(packageRoot, "METHOD.md"),
      renderClaimLiftPackageMethod(input.proposal),
    );
    await writeJson(join(packageRoot, "CLAIM_EVIDENCE_BINDINGS.json"), {
      kind: "claim_evidence_bindings",
      fundPackageContractVersion: 2,
      candidateId: candidate.candidateId,
      claim: candidate.claim,
      domain: candidate.domain,
      sourceEvidenceRefs: input.proposal.sourceEvidenceRefs,
      externalSignificanceEvidenceRefs:
        input.proposal.externalSignificanceEvidenceRefs,
      identityLedgerRefs: input.proposal.identityLedgerRefs ?? [],
      hardSeedRefs: input.proposal.hardSeedRefs ?? [],
      evidenceRefs: [
        "PAPER.md#evidence-summary",
        "METHOD.md#method",
        "CLAIM_EVIDENCE_BINDINGS.json#sourceEvidenceRefs",
        "REPRODUCE.md#replay",
        "LIMITATIONS.md#limitations",
      ],
      predictionRefs: ["CLAIM_EVIDENCE_BINDINGS.json#predictionRefs"],
      holdoutRefs: ["CLAIM_EVIDENCE_BINDINGS.json#holdoutRefs"],
      counterexampleRefs: ["CLAIM_EVIDENCE_BINDINGS.json#counterexampleRefs"],
      replayRefs: ["CLAIM_EVIDENCE_BINDINGS.json#replayRefs"],
      killWeekRefs: ["CLAIM_EVIDENCE_BINDINGS.json#killWeekRefs"],
      baselineRefs: input.proposal.baselineRefs,
      rivalRefs: input.proposal.rivalRefs,
      mechanismPressureRefs: input.proposal.mechanismPressureRefs,
      localPredictionRefs: input.proposal.predictionRefs ?? [],
      localHoldoutRefs: input.proposal.holdoutRefs,
      localCounterexampleRefs: input.proposal.counterexampleRefs,
      localReplayRefs: input.proposal.replayRefs,
      localKillWeekRefs: input.proposal.killWeekRefs ?? [],
      methodRef: "METHOD.md",
      reproduceRef: "REPRODUCE.md",
      limitationsRef: "LIMITATIONS.md",
      fundCandidateDraftRef: input.draftRef,
      noOverclaim: true,
      fundClass: fundClassAssessment.fundClass,
      countsForEinsteinNobelDiscoveryScore:
        fundClassAssessment.countsForEinsteinNobelDiscoveryScore,
      fundClassAssessment,
      fundCandidate: candidate,
    });
    await writeText(
      join(packageRoot, "REPRODUCE.md"),
      renderClaimLiftPackageReproduce(input.proposal),
    );
    await writeText(
      join(packageRoot, "LIMITATIONS.md"),
      renderClaimLiftPackageLimitations(input.proposal),
    );
    await writeJson(join(packageRoot, "FUND_CANDIDATE.json"), {
      kind: "fund_candidate",
      candidate,
      fundClass: fundClassAssessment.fundClass,
      countsForEinsteinNobelDiscoveryScore:
        fundClassAssessment.countsForEinsteinNobelDiscoveryScore,
      fundClassAssessment,
    });
    return packageRef;
  }

  private async writeDraftIfReady(input: {
    decision: GeneratorBornDiscoveryClaimLiftDecision;
    proposal: GeneratorBornDiscoveryClaimLiftProposal;
  }): Promise<GeneratorBornDiscoveryClaimLiftDraftDecision> {
    const initial = await generatorBornDiscoveryClaimLiftDraftDecision({
      root: this.root,
      decision: input.decision,
      proposal: input.proposal,
      draftRef: null,
      validationRef: null,
    });
    if (!initial.draftReady || !input.decision.targetDiscoveryCandidateId) {
      return initial;
    }
    const draftRef = `${daemonArtifactRoot}/${fundCandidateDraftDir}/${normalizeCandidateIdPart(input.decision.targetDiscoveryCandidateId)}.json`;
    const validationRef = draftRef.replace(".json", ".validation.json");
    const draft: FundCandidateDraft = {
      kind: "fund_candidate_draft",
      draftId: `DRAFT-${normalizeCandidateIdPart(input.decision.targetDiscoveryCandidateId)}`,
      candidateId: input.decision.targetDiscoveryCandidateId,
      claim: input.proposal.exactTargetOutcomeClaim,
      domain: input.proposal.domain as DiscoveryDomain,
      sourceRefs: input.proposal.sourceEvidenceRefs.slice(0, 12),
      evidenceRefs: uniqueStrings([
        ...input.proposal.sourceEvidenceRefs,
        ...input.proposal.baselineRefs,
        ...input.proposal.rivalRefs,
        ...input.proposal.mechanismPressureRefs,
        ...(input.proposal.predictionRefs ?? []),
        ...(input.proposal.killWeekRefs ?? []),
      ]).slice(0, 24),
      identityLedgerRefs: input.proposal.identityLedgerRefs ?? [],
      hardSeedRefs: input.proposal.hardSeedRefs ?? [],
      packageRefs: [...requiredFundPackageFiles],
      inspectabilityPath: input.proposal.packageRef ?? "",
      predictionRefs: input.proposal.predictionRefs ?? [],
      holdoutRefs: input.proposal.holdoutRefs,
      counterexampleRefs: input.proposal.counterexampleRefs,
      replayRefs: input.proposal.replayRefs,
      killWeekRefs: input.proposal.killWeekRefs ?? [],
      limitations: input.proposal.limitations ?? [],
      generatedFrom: "fresh_external_target",
      synthetic: false,
      partialCandidate: false,
      versionedClaimChange: true,
    };
    const validation = new FundCandidateDraftValidator().validate({
      draft,
      ledger: new CandidateIdentityLedger(),
    });
    await writeJson(join(this.root, draftRef), draft);
    await writeJson(join(this.root, validationRef), {
      kind: "fund_candidate_draft_record",
      draftRef,
      validation,
      evidenceHash: hashEvidence({ draft, validation }),
    });
    return generatorBornDiscoveryClaimLiftDraftDecision({
      root: this.root,
      decision: input.decision,
      proposal: input.proposal,
      draftRef,
      validationRef,
    });
  }

  private async writeArtifacts(input: {
    report: GeneratorBornDiscoveryClaimLiftReport;
    requirements: GeneratorBornDiscoveryClaimLiftRequirement[];
    proposals: GeneratorBornDiscoveryClaimLiftProposal[];
  }): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "CLAIM_LIFT_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_decisions",
      decisions: input.report.decisions,
      acceptedClaimLifts: input.report.acceptedClaimLifts,
      blockedClaimLifts: input.report.blockedClaimLifts,
      evidenceHash: hashEvidence(input.report.decisions),
    });
    await writeJson(join(root, "CLAIM_LIFT_PROPOSAL_TEMPLATE.json"), {
      kind: "generator_born_discovery_claim_lift_proposal_template",
      proposals: await Promise.all(
        input.requirements.map((requirement) =>
          generatorBornDiscoveryClaimLiftProposalTemplate(
            this.root,
            requirement,
          ),
        ),
      ),
      evidenceHash: hashEvidence(input.requirements),
    });
    await writeJson(
      join(root, "FUND_GATE_RESULTS.json"),
      input.report.fundGateResult,
    );
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      requirementsLoaded: input.report.requirementsLoaded,
      proposalsLoaded: input.report.proposalsLoaded,
      acceptedClaimLifts: input.report.acceptedClaimLifts,
      blockedClaimLifts: input.report.blockedClaimLifts,
      discoveryCandidateRefs: input.report.discoveryCandidateRefs,
      draftDecisions: input.report.draftDecisions,
      fundCandidateDraftRefs: input.report.fundCandidateDraftRefs,
      fundCandidateDraftsCreated: input.report.fundCandidateDraftsCreated,
      fundGateEvaluations: input.report.fundGateEvaluations,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "CLAIM_LIFT_DECISIONS.md"),
      generatorBornDiscoveryClaimLiftDecisionMarkdown(input.report),
    );
    await writeJson(join(root, "CLAIM_LIFT_DRAFT_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_draft_decisions",
      draftDecisions: input.report.draftDecisions,
      fundCandidateDraftRefs: input.report.fundCandidateDraftRefs,
      fundCandidateDraftsCreated: input.report.fundCandidateDraftsCreated,
      evidenceHash: hashEvidence(input.report.draftDecisions),
    });
    await writeJson(join(root, "FUND_GATE_EVALUATIONS.json"), {
      kind: "generator_born_discovery_claim_lift_fund_gate_evaluations",
      fundGateEvaluations: input.report.fundGateEvaluations,
      notificationAllowedCount: input.report.fundGateEvaluations.filter(
        (evaluation) => evaluation.notificationAllowed,
      ).length,
      discoveryScoredCount: input.report.fundGateEvaluations.filter(
        (evaluation) => evaluation.countsForEinsteinNobelDiscoveryScore,
      ).length,
      evidenceHash: hashEvidence(input.report.fundGateEvaluations),
    });
    await writeText(
      join(root, "CLAIM_LIFT_DRAFT_DECISIONS.md"),
      generatorBornDiscoveryClaimLiftDraftDecisionMarkdown(input.report),
    );
    await writeText(
      join(root, "CLAIM_LIFT_PROPOSAL_TEMPLATE.md"),
      generatorBornDiscoveryClaimLiftTemplateMarkdown(input.requirements),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      generatorBornDiscoveryClaimLiftFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftNextCheckpointMarkdown(input.report),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftSignalPressureService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftSignalPressureReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    const lift = await this.readClaimLiftOrRun();
    const proposals = await this.readProposals();
    const decisions = await Promise.all(
      proposals.map((proposal) => this.evaluateProposal(proposal)),
    );
    const ready = decisions.filter(
      (decision) => decision.signalStatus === "discovery_signal_ready",
    );
    const notificationReady =
      ready.find((decision) => decision.notificationAllowed) ?? ready[0];
    const fundGateResult =
      notificationReady !== undefined
        ? await this.fundGateForDecision(notificationReady)
        : lift.fundGateResult;
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-pressure-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftSignalPressureReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_signal_pressure" as const,
        status:
          ready.length > 0
            ? ("discovery_signal_ready" as const)
            : ("continue_searching_checkpointed" as const),
        checkpointUsed: lift.nextCheckpointRef,
        nextCheckpointRef,
        liftedCandidatesLoaded: proposals.length,
        packagesEvaluated: decisions.filter(
          (decision) => decision.packageRef !== null,
        ).length,
        discoverySignalReady: ready.length,
        blockedSignals: decisions.filter(
          (decision) => decision.signalStatus === "blocked",
        ).length,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        fundGateResult,
        fundFound: false as const,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftSignalPressureBottleneck(decisions),
        artifactRefs:
          generatorBornDiscoveryClaimLiftSignalPressureArtifactRefs(
            nextCheckpointRef,
          ),
      });
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readClaimLiftOrRun(): Promise<GeneratorBornDiscoveryClaimLiftReport> {
    const existing =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftReport>(
        join(this.liftRoot(), "latest.json"),
      );
    if (existing !== null) return existing;
    return new GeneratorBornDiscoveryClaimLiftService(this.root).run();
  }

  private async readProposals(): Promise<
    GeneratorBornDiscoveryClaimLiftProposal[]
  > {
    const payload = await readOptionalJson<{
      proposals?: GeneratorBornDiscoveryClaimLiftProposal[];
    }>(join(this.liftRoot(), "CLAIM_LIFT_PROPOSALS.json"));
    return (payload?.proposals ?? []).filter(
      (proposal) =>
        proposal.kind === "generator_born_discovery_claim_lift_proposal" &&
        typeof proposal.targetDiscoveryCandidateId === "string",
    );
  }

  private async evaluateProposal(
    proposal: GeneratorBornDiscoveryClaimLiftProposal,
  ): Promise<GeneratorBornDiscoveryClaimLiftSignalPressureDecision> {
    const packageRef = `${daemonArtifactRoot}/${evidencePackageDir}/${normalizeCandidateIdPart(proposal.targetDiscoveryCandidateId)}`;
    const packageRoot = join(this.root, packageRef);
    const candidatePayload = await readOptionalJson<{
      candidate?: FundCandidate;
      fundClass?: FundClass;
    }>(join(packageRoot, "FUND_CANDIDATE.json"));
    const bindings = await readOptionalJson<Record<string, unknown>>(
      join(packageRoot, "CLAIM_EVIDENCE_BINDINGS.json"),
    );
    const candidate =
      candidatePayload?.candidate ??
      (isRecord(bindings?.fundCandidate)
        ? (bindings.fundCandidate as FundCandidate)
        : null);
    const publicFundReconciliation = await new DiscoveryFrictionHealthService(
      this.root,
    ).publicFundReconciliationForCandidate(
      candidate?.candidateId ?? proposal.targetDiscoveryCandidateId,
    );
    const publicCorpusNegativeHistory =
      await publicCorpusNegativeHistoryForClaimLiftProposal(
        this.root,
        proposal,
      );
    const publicCorpusBlocksDiscovery =
      publicFundReconciliation.blocksDiscoveryScore ||
      publicCorpusNegativeHistory.blocksSeedBirth;
    const packageFilesPresent = (
      await Promise.all(
        requiredFundPackageFiles.map((file) => exists(join(packageRoot, file))),
      )
    ).every(Boolean);
    const packageEvaluation =
      candidate === null
        ? new FundGateEvaluator().evaluate(null)
        : await evaluateFundCandidateWithPackageForRoot(this.root, candidate);
    const evaluation = publicCorpusBlocksDiscovery
      ? {
          ...packageEvaluation,
          passed: false,
          status: "continue_searching" as const,
          failedGates: Array.from(
            new Set([
              ...packageEvaluation.failedGates,
              "public_corpus_downgrade",
            ]),
          ),
          countsForEinsteinNobelDiscoveryScore: false,
          notificationAllowed: false,
        }
      : packageEvaluation;
    const signalEvidenceRefs = generatorBornClaimLiftSignalEvidenceRefs({
      candidate,
      bindings,
      proposal,
    });
    const insightRefsResolve =
      signalEvidenceRefs.length >= 2 &&
      (await claimLiftEvidenceRefsResolvable(this.root, signalEvidenceRefs));
    const discoveryGate = evaluation.fundClassAssessment?.discoveryGate;
    const hasNontrivialInsight =
      candidate?.nontrivialNewInsightAcrossRealTargets === true &&
      discoveryGate?.nontrivialNewInsightAcrossRealTargets === true &&
      insightRefsResolve;
    const gates = [
      gate(
        "lifted_package_present",
        await exists(packageRoot),
        "Signal pressure requires the lifted external-review package directory.",
      ),
      gate(
        "required_package_files_present",
        packageFilesPresent,
        "Signal pressure requires PAPER, METHOD, bindings, reproduce, and limitations files.",
      ),
      gate(
        "fund_candidate_present",
        candidate !== null,
        "Signal pressure requires the package-bound FundCandidate payload.",
      ),
      gate(
        "structural_fund_gate_passed",
        packageEvaluation.passed,
        "The unchanged package-aware Fund Gate must pass before discovery-signal pressure can matter.",
      ),
      gate(
        "public_corpus_discovery_score_reconciliation",
        !publicCorpusBlocksDiscovery,
        "Discovery-signal pressure must stop when a matching public corpus package or downgraded external anchor already blocks discovery scoring.",
      ),
      gate(
        "nontrivial_new_insight_evidence_bound",
        hasNontrivialInsight,
        "Discovery scoring requires resolvable evidence refs for a nontrivial new insight across real targets, not only package or pipeline evidence.",
      ),
      gate(
        "domain_scientific_significance_bound",
        discoveryGate?.domainScientificSignificance === true,
        "Discovery scoring requires explicit domain scientific significance.",
      ),
      gate(
        "not_pipeline_fund_class",
        evaluation.fundClass !== "pipeline_fund_candidate",
        "Pipeline Fund candidates may prove operating capability but must not count as discovery.",
      ),
      gate(
        "discovery_scored_fund_class",
        evaluation.countsForEinsteinNobelDiscoveryScore,
        "Only discovery-scored FundClasses can advance the Einstein/Nobel path.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const primaryBlocker = generatorBornClaimLiftSignalPrimaryBlocker({
      candidate,
      evaluation,
      failedGates,
      signalEvidenceRefs,
    });
    const decision = {
      kind: "generator_born_discovery_claim_lift_signal_pressure_decision" as const,
      candidateId: proposal.targetDiscoveryCandidateId,
      parentCandidateId: proposal.parentCandidateId,
      packageRef: (await exists(packageRoot)) ? packageRef : null,
      publicCorpusNegativeHistory,
      fundClass: evaluation.fundClass,
      countsForEinsteinNobelDiscoveryScore:
        evaluation.countsForEinsteinNobelDiscoveryScore,
      notificationAllowed: evaluation.notificationAllowed,
      signalStatus:
        failedGates.length === 0
          ? ("discovery_signal_ready" as const)
          : ("blocked" as const),
      primaryBlocker,
      gates,
      failedGates,
      evidenceRefs: signalEvidenceRefs,
      requiredNextExperiment:
        generatorBornClaimLiftSignalRequiredNextExperiment(primaryBlocker),
    };
    return { ...decision, evidenceHash: hashEvidence(decision) };
  }

  private async fundGateForDecision(
    decision: GeneratorBornDiscoveryClaimLiftSignalPressureDecision,
  ): Promise<FundGateResult> {
    if (decision.packageRef === null)
      return new FundGateEvaluator().evaluate(null);
    const payload = await readOptionalJson<{ candidate?: FundCandidate }>(
      join(this.root, decision.packageRef, "FUND_CANDIDATE.json"),
    );
    return evaluateFundCandidateWithPackageForRoot(
      this.root,
      payload?.candidate ?? null,
    );
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftSignalPressureReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "SIGNAL_PRESSURE.json"), report);
    await writeJson(join(root, "SIGNAL_PRESSURE_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_signal_pressure_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(root, "SIGNAL_PRESSURE_FUND_GATE_RESULTS.json"), {
      kind: "generator_born_discovery_claim_lift_signal_pressure_fund_gate",
      fundGateResult: report.fundGateResult,
      fundFound: report.fundFound,
      evidenceHash: hashEvidence(report.fundGateResult),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_signal_pressure_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      discoverySignalReady: report.discoverySignalReady,
      blockedSignals: report.blockedSignals,
      blockerDistribution: report.blockerDistribution,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/SIGNAL_PRESSURE.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "SIGNAL_PRESSURE_DECISIONS.md"),
      generatorBornDiscoveryClaimLiftSignalPressureMarkdown(report),
    );
    await writeText(
      join(root, "DISCOVERY_SIGNAL_READINESS.md"),
      generatorBornDiscoveryClaimLiftSignalReadinessMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_PRESSURE_FUND_GATE_RESULTS.md"),
      generatorBornDiscoveryClaimLiftSignalFundGateMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_PRESSURE_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftSignalNextCheckpointMarkdown(report),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftSignalExperimentService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftSignalExperimentReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    const pressure = await this.readPressureOrRun();
    const proposals = await this.readProposals();
    const decisions = await Promise.all(
      proposals.map((proposal) => this.evaluateProposal(proposal)),
    );
    const ready = decisions.filter(
      (decision) => decision.experimentStatus === "insight_evidence_ready",
    );
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-experiment-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftSignalExperimentReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_signal_experiment" as const,
        status:
          ready.length > 0
            ? ("insight_evidence_ready" as const)
            : ("continue_searching_checkpointed" as const),
        checkpointUsed: pressure.nextCheckpointRef,
        nextCheckpointRef,
        liftedCandidatesLoaded: proposals.length,
        experimentsRun: decisions.length,
        insightEvidenceReady: ready.length,
        blockedExperiments: decisions.filter(
          (decision) => decision.experimentStatus === "blocked",
        ).length,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        fundGateResult: new FundGateEvaluator().evaluate(null),
        fundFound: false as const,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftSignalExperimentBottleneck(decisions),
        artifactRefs:
          generatorBornDiscoveryClaimLiftSignalExperimentArtifactRefs(
            nextCheckpointRef,
          ),
      });
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readPressureOrRun(): Promise<GeneratorBornDiscoveryClaimLiftSignalPressureReport> {
    const existing =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftSignalPressureReport>(
        join(this.liftRoot(), "SIGNAL_PRESSURE.json"),
      );
    if (existing !== null) return existing;
    return new GeneratorBornDiscoveryClaimLiftSignalPressureService(
      this.root,
    ).run();
  }

  private async readProposals(): Promise<
    GeneratorBornDiscoveryClaimLiftProposal[]
  > {
    const payload = await readOptionalJson<{
      proposals?: GeneratorBornDiscoveryClaimLiftProposal[];
    }>(join(this.liftRoot(), "CLAIM_LIFT_PROPOSALS.json"));
    return (payload?.proposals ?? []).filter(
      (proposal) =>
        proposal.kind === "generator_born_discovery_claim_lift_proposal" &&
        typeof proposal.targetDiscoveryCandidateId === "string",
    );
  }

  private async evaluateProposal(
    proposal: GeneratorBornDiscoveryClaimLiftProposal,
  ): Promise<GeneratorBornDiscoveryClaimLiftSignalExperimentDecision> {
    const packageRef = `${daemonArtifactRoot}/${evidencePackageDir}/${normalizeCandidateIdPart(proposal.targetDiscoveryCandidateId)}`;
    const publicCorpusNegativeHistory =
      await publicCorpusNegativeHistoryForClaimLiftProposal(
        this.root,
        proposal,
      );
    const declaredSourceCacheRef =
      generatorBornClaimLiftSignalSourceCacheRef(proposal);
    const declaredSourceCache =
      declaredSourceCacheRef === null
        ? null
        : await readOptionalJson<DiscoveryAnchorRuntimeSourceArtifact>(
            join(this.root, declaredSourceCacheRef),
          );
    const formalRuntimeSource =
      declaredSourceCache === null
        ? await generatorBornClaimLiftFormalRuntimeSourceCacheFromBindings({
            root: this.root,
            bindings: proposal as unknown as Record<string, unknown>,
          })
        : { sourceCacheRef: null, sourceCache: null };
    const sourceCacheRef =
      declaredSourceCacheRef ?? formalRuntimeSource.sourceCacheRef;
    const sourceCache = declaredSourceCache ?? formalRuntimeSource.sourceCache;
    const packagePresent = await exists(join(this.root, packageRef));
    const sourceCachePresent = sourceCache !== null;
    const baselineExplains =
      sourceCache?.baselineResults.some((item) => item.explainsSignal) ?? true;
    const bindableInsightEvidenceRefs =
      generatorBornClaimLiftBindableSignalEvidenceRefs({
        sourceCacheRef,
        sourceCache,
        proposal,
      });
    const evidenceRefsResolve =
      bindableInsightEvidenceRefs.length >= 2 &&
      (await claimLiftEvidenceRefsResolvable(
        this.root,
        bindableInsightEvidenceRefs,
      ));
    const gates = [
      gate(
        "public_corpus_discovery_score_reconciliation",
        !publicCorpusNegativeHistory.blocksSeedBirth,
        "Signal experiments must not generate new bindable insight refs for a claim-lift package whose public corpus anchor was already downgraded or rival-explained.",
      ),
      gate(
        "lifted_package_present",
        packagePresent,
        "Signal experiment requires the lifted package being tested.",
      ),
      gate(
        "source_cache_present",
        sourceCachePresent,
        "Signal experiment requires real loaded/generated external source-cache evidence, not only generator design output.",
      ),
      gate(
        "source_cache_public_safe",
        sourceCache?.publicSafe === true,
        "Source-cache evidence must be public-safe.",
      ),
      gate(
        "source_cache_depth",
        (sourceCache?.rawTargetCount ?? 0) >= 60,
        "Signal experiment requires at least sixty loaded target rows/objects in the external source cache.",
      ),
      gate(
        "strong_baselines_non_explanatory",
        sourceCachePresent && !baselineExplains,
        "All source-cache simple baselines must fail to explain the signal.",
      ),
      gate(
        "rival_weakened",
        sourceCache?.rivalWeakened === true,
        "At least one source-cache rival mechanism must be weakened or scoped.",
      ),
      gate(
        "nontrivial_residual",
        sourceCache?.nontrivialResidual === true,
        "Source-cache evidence must show a nontrivial residual beyond pipeline/tool success.",
      ),
      gate(
        "cross_source_or_slice_support",
        sourceCache?.crossSourceSupport === true,
        "Signal experiment requires cross-source or cross-slice recurrence.",
      ),
      gate(
        "counterexample_pressure_nonfatal",
        sourceCache?.counterexampleCollapsed === false,
        "Counterexample or negative-control pressure must not collapse the signal.",
      ),
      gate(
        "holdout_replay_available",
        sourceCache?.holdoutReplayAvailable === true,
        "Signal experiment requires independent holdout/replay availability or a bounded nonfatal caveat.",
      ),
      gate(
        "bindable_insight_refs_resolve",
        evidenceRefsResolve,
        "Bindable insight evidence refs must resolve before they can update any package contract.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const primaryBlocker =
      generatorBornClaimLiftSignalExperimentPrimaryBlocker(failedGates);
    const decision = {
      kind: "generator_born_discovery_claim_lift_signal_experiment_decision" as const,
      candidateId: proposal.targetDiscoveryCandidateId,
      parentCandidateId: proposal.parentCandidateId,
      domain: proposal.domain ?? null,
      packageRef: packagePresent ? packageRef : null,
      publicCorpusNegativeHistory,
      sourceCacheRef,
      measuredOutcome: sourceCache?.measuredOutcome ?? null,
      residualMagnitude: sourceCache?.residualMagnitude ?? null,
      experimentStatus:
        failedGates.length === 0
          ? ("insight_evidence_ready" as const)
          : ("blocked" as const),
      primaryBlocker,
      gates,
      failedGates,
      bindableInsightEvidenceRefs,
      requiredPackageUpdate:
        failedGates.length === 0
          ? "A later explicit package-rebind step may bind these refs as insightEvidenceRefs and rerun unchanged FundClass/Fund Gate checks. This command does not modify Fund state."
          : generatorBornClaimLiftSignalExperimentRequiredFix(primaryBlocker),
    };
    return { ...decision, evidenceHash: hashEvidence(decision) };
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftSignalExperimentReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "SIGNAL_EXPERIMENTS.json"), report);
    await writeJson(join(root, "SIGNAL_EXPERIMENT_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_signal_experiment_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_signal_experiment_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      insightEvidenceReady: report.insightEvidenceReady,
      blockedExperiments: report.blockedExperiments,
      blockerDistribution: report.blockerDistribution,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/SIGNAL_EXPERIMENTS.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "SIGNAL_EXPERIMENTS.md"),
      generatorBornDiscoveryClaimLiftSignalExperimentMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_EXPERIMENT_BINDABLE_REFS.md"),
      generatorBornDiscoveryClaimLiftSignalExperimentRefsMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_EXPERIMENT_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftSignalExperimentNextCheckpointMarkdown(
        report,
      ),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftSourceSignalService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftSourceSignalReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    let closure = await this.readFundClosureOrNull();
    if (closure === null) {
      await new GeneratorBornFundClosureService(this.root).run();
      closure = await this.readFundClosure();
    }
    const requirements = closure.claimLiftRequirements;
    const decisions = await Promise.all(
      requirements.map((requirement) => this.evaluateRequirement(requirement)),
    );
    const bound = decisions.filter(
      (decision) => decision.sourceSignalStatus === "source_signal_bound",
    );
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-source-signal-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftSourceSignalReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_source_signal" as const,
        status:
          bound.length > 0
            ? ("source_signal_bound" as const)
            : ("continue_searching_checkpointed" as const),
        checkpointUsed: closure.nextCheckpointRef,
        nextCheckpointRef,
        requirementsLoaded: requirements.length,
        packagesEvaluated: decisions.filter(
          (decision) => decision.packageRef !== null,
        ).length,
        sourceSignalsBound: bound.length,
        blockedSourceSignals: decisions.filter(
          (decision) => decision.sourceSignalStatus === "blocked",
        ).length,
        packagesMutated: 0 as const,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        fundFound: false as const,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftSourceSignalBottleneck(decisions),
        artifactRefs:
          generatorBornDiscoveryClaimLiftSourceSignalArtifactRefs(
            nextCheckpointRef,
          ),
      });
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readFundClosureOrNull(): Promise<GeneratorBornFundClosureReport | null> {
    return readOptionalJson<GeneratorBornFundClosureReport>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorFundClosureDir,
        "latest.json",
      ),
    );
  }

  private async readFundClosure(): Promise<GeneratorBornFundClosureReport> {
    const report = await this.readFundClosureOrNull();
    if (report === null) {
      throw new Error(
        "Generator claim-lift source-signal requires generator-fund-closure report.",
      );
    }
    return report;
  }

  private async evaluateRequirement(
    requirement: GeneratorBornDiscoveryClaimLiftRequirement,
  ): Promise<GeneratorBornDiscoveryClaimLiftSourceSignalDecision> {
    const packageRef = requirement.externalReviewPackagePath ?? "";
    const packageRoot =
      packageRef.length > 0 && publicSafeRef(packageRef)
        ? join(this.root, packageRef)
        : "";
    const candidatePayload =
      packageRoot.length > 0
        ? await readOptionalJson<{
            candidate?: FundCandidate;
            fundClass?: string;
          }>(join(packageRoot, "FUND_CANDIDATE.json"))
        : null;
    const bindings =
      packageRoot.length > 0
        ? await readOptionalJson<Record<string, unknown>>(
            join(packageRoot, "CLAIM_EVIDENCE_BINDINGS.json"),
          )
        : null;
    const candidate =
      candidatePayload?.candidate ??
      (isRecord(bindings?.fundCandidate)
        ? (bindings.fundCandidate as FundCandidate)
        : null);
    const sourceText = normalizeWhitespace(
      [
        requirement.candidateId,
        requirement.discoveryCandidateId,
        requirement.exactClaim,
        requirement.domain,
        packageRef,
        ...stringArray(bindings?.sourceEvidenceRefs),
      ]
        .filter(Boolean)
        .join(" "),
    );
    const publicCorpusNegativeHistory =
      await publicCorpusNegativeHistoryForClaimLiftCandidateText(
        this.root,
        sourceText,
      );
    const declaredSourceCacheRef =
      generatorBornClaimLiftSourceSignalSourceCacheRef(sourceText);
    const declaredSourceCache =
      declaredSourceCacheRef === null
        ? null
        : await readOptionalJson<DiscoveryAnchorRuntimeSourceArtifact>(
            join(this.root, declaredSourceCacheRef),
          );
    const formalRuntimeSource =
      declaredSourceCache === null
        ? await generatorBornClaimLiftFormalRuntimeSourceCacheFromBindings({
            root: this.root,
            bindings,
          })
        : { sourceCacheRef: null, sourceCache: null };
    const sourceCacheRef =
      declaredSourceCacheRef ?? formalRuntimeSource.sourceCacheRef;
    const sourceCache = declaredSourceCache ?? formalRuntimeSource.sourceCache;
    const baselineExplains =
      sourceCache?.baselineResults.some((item) => item.explainsSignal) ?? true;
    const runtimeEvidenceRefs = stringArray(
      bindings?.sourceEvidenceRefs,
    ).filter(
      (ref) =>
        ref.includes("/runtime-evidence/") ||
        ref.includes("/generator-families/runtime-evidence/"),
    );
    const bindableInsightEvidenceRefs = uniqueStrings([
      ...(sourceCacheRef === null ? [] : [sourceCacheRef]),
      ...(sourceCache?.evidenceRefs ?? []),
      ...(sourceCache?.sourceRefs ?? []),
      ...runtimeEvidenceRefs,
    ]).filter(publicSafeRef);
    const evidenceRefsResolve =
      bindableInsightEvidenceRefs.length >= 2 &&
      (await claimLiftEvidenceRefsResolvable(
        this.root,
        bindableInsightEvidenceRefs,
      ));
    const residualMagnitude = sourceCache?.residualMagnitude ?? null;
    const gates = [
      gate(
        "public_corpus_negative_history_clear",
        !publicCorpusNegativeHistory.blocksSeedBirth,
        "Source-signal binding must not reuse a public corpus anchor that was downgraded, rival-explained, or removed from discovery scoring.",
      ),
      gate(
        "source_package_present",
        candidate !== null && packageRoot.length > 0,
        "Source-signal binding requires the package-bound FundCandidate source package.",
      ),
      gate(
        "source_cache_present",
        sourceCache !== null,
        "Source-signal binding requires external source-cache evidence before proposal birth.",
      ),
      gate(
        "source_cache_public_safe",
        sourceCache?.publicSafe === true,
        "Source-cache evidence must be public-safe.",
      ),
      gate(
        "source_cache_depth",
        (sourceCache?.rawTargetCount ?? 0) >= 60,
        "Source-signal binding requires at least sixty loaded public/formal target rows or objects.",
      ),
      gate(
        "strong_baselines_non_explanatory",
        sourceCache !== null && !baselineExplains,
        "Source signal must survive the strongest simple baselines before proposal birth.",
      ),
      gate(
        "rival_weakened",
        sourceCache?.rivalWeakened === true,
        "Source signal must weaken or scope at least one rival mechanism.",
      ),
      gate(
        "nontrivial_residual",
        sourceCache?.nontrivialResidual === true &&
          residualMagnitude !== null &&
          residualMagnitude >= 0.1,
        "Source signal must bind a nontrivial residual beyond tool, package, or pipeline success.",
      ),
      gate(
        "cross_source_or_slice_support",
        sourceCache?.crossSourceSupport === true,
        "Source signal requires cross-source or cross-slice support before proposal birth.",
      ),
      gate(
        "counterexample_pressure_nonfatal",
        sourceCache?.counterexampleCollapsed === false,
        "Counterexample or negative-control pressure must not collapse the source signal.",
      ),
      gate(
        "holdout_replay_available",
        sourceCache?.holdoutReplayAvailable === true,
        "Source signal requires an independent holdout and replay path or a bounded nonfatal caveat.",
      ),
      gate(
        "bindable_insight_refs_resolve",
        evidenceRefsResolve,
        "Every bindable source-signal ref must resolve before the proposal builder may consume it.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const primaryBlocker =
      generatorBornClaimLiftSourceSignalPrimaryBlocker(failedGates);
    const decision = {
      kind: "generator_born_discovery_claim_lift_source_signal_decision" as const,
      candidateId: requirement.candidateId,
      sourceCandidateId:
        typeof candidate?.candidateId === "string"
          ? candidate.candidateId
          : null,
      domain: requirement.domain ?? null,
      packageRef:
        candidate !== null && packageRoot.length > 0 ? packageRef : null,
      publicCorpusNegativeHistory,
      sourceCacheRef,
      sourceFundClass:
        optionalString(candidatePayload?.fundClass) ??
        (isRecord(candidate) ? optionalString(candidate.fundClass) : null),
      measuredOutcome: sourceCache?.measuredOutcome ?? null,
      residualMagnitude,
      sourceSignalStatus:
        failedGates.length === 0
          ? ("source_signal_bound" as const)
          : ("blocked" as const),
      primaryBlocker,
      gates,
      failedGates,
      bindableInsightEvidenceRefs:
        failedGates.length === 0 ? bindableInsightEvidenceRefs : [],
      packageMutated: false as const,
      requiredNextAction:
        failedGates.length === 0
          ? "Run generator-claim-lift-propose; the proposal builder may consume this forward-only source-signal binding without mutating the source package."
          : generatorBornClaimLiftSourceSignalRequiredFix(primaryBlocker),
    };
    return { ...decision, evidenceHash: hashEvidence(decision) };
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftSourceSignalReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "SOURCE_SIGNAL_BINDINGS.json"), report);
    await writeJson(join(root, "SOURCE_SIGNAL_BINDING_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_source_signal_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_source_signal_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      sourceSignalsBound: report.sourceSignalsBound,
      blockedSourceSignals: report.blockedSourceSignals,
      blockerDistribution: report.blockerDistribution,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/SOURCE_SIGNAL_BINDINGS.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "SOURCE_SIGNAL_BINDINGS.md"),
      generatorBornDiscoveryClaimLiftSourceSignalMarkdown(report),
    );
    await writeText(
      join(root, "SOURCE_SIGNAL_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftSourceSignalNextCheckpointMarkdown(report),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftNoveltyPressureService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftNoveltyPressureReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    const sourceSignals = await this.readSourceSignalsOrRun();
    const decisions = await Promise.all(
      sourceSignals.decisions.map((decision) =>
        this.evaluateSourceSignal(decision),
      ),
    );
    const cleared = decisions.filter(
      (decision) =>
        decision.noveltyPressureStatus === "novelty_pressure_cleared",
    );
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-novelty-pressure-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftNoveltyPressureReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_novelty_pressure" as const,
        status:
          cleared.length > 0
            ? ("novelty_pressure_cleared" as const)
            : ("continue_searching_checkpointed" as const),
        checkpointUsed: sourceSignals.nextCheckpointRef,
        nextCheckpointRef,
        sourceSignalsLoaded: sourceSignals.decisions.length,
        noveltyPressureCleared: cleared.length,
        noveltyPressureBlocked: decisions.filter(
          (decision) => decision.noveltyPressureStatus === "blocked",
        ).length,
        packagesMutated: 0 as const,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        fundFound: false as const,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftNoveltyPressureBottleneck(decisions),
        artifactRefs:
          generatorBornDiscoveryClaimLiftNoveltyPressureArtifactRefs(
            nextCheckpointRef,
          ),
      });
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readSourceSignalsOrRun(): Promise<GeneratorBornDiscoveryClaimLiftSourceSignalReport> {
    const report =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftSourceSignalReport>(
        join(this.liftRoot(), "SOURCE_SIGNAL_BINDINGS.json"),
      );
    if (report !== null) return report;
    return new GeneratorBornDiscoveryClaimLiftSourceSignalService(
      this.root,
    ).run();
  }

  private async evaluateSourceSignal(
    sourceSignal: GeneratorBornDiscoveryClaimLiftSourceSignalDecision,
  ): Promise<GeneratorBornDiscoveryClaimLiftNoveltyPressureDecision> {
    const sourceCache =
      sourceSignal.sourceCacheRef === null
        ? null
        : await readOptionalJson<DiscoveryAnchorRuntimeSourceArtifact>(
            join(this.root, sourceSignal.sourceCacheRef),
          );
    const sourceFamilies = generatorBornClaimLiftPublicSourceFamilies([
      sourceCache?.sourceRef,
      ...(sourceCache?.sourceRefs ?? []),
      ...(sourceCache?.evidenceRefs ?? []),
      ...sourceSignal.bindableInsightEvidenceRefs,
    ]);
    const noveltyEvidenceRefs = uniqueStrings([
      ...(sourceCache?.evidenceRefs ?? []),
      ...(sourceCache?.sourceRefs ?? []),
      ...sourceSignal.bindableInsightEvidenceRefs,
    ]).filter(publicSafeRef);
    const ordinaryKnownConfirmed =
      sourceCache !== null &&
      generatorBornClaimLiftOrdinaryKnownMechanismConfirmed({
        sourceSignal,
        sourceCache,
        sourceFamilies,
      });
    const noveltyRefsResolve =
      noveltyEvidenceRefs.length >= 2 &&
      (await claimLiftEvidenceRefsResolvable(this.root, noveltyEvidenceRefs));
    const gates = [
      gate(
        "source_signal_bound",
        sourceSignal.sourceSignalStatus === "source_signal_bound",
        "Novelty pressure runs only after a forward-only source signal is bound.",
      ),
      gate(
        "source_cache_present",
        sourceCache !== null,
        "Novelty pressure requires loaded external source-cache evidence.",
      ),
      gate(
        "source_cache_public_safe",
        sourceCache?.publicSafe === true,
        "Novelty pressure requires public-safe source-cache evidence.",
      ),
      gate(
        "source_cache_depth",
        (sourceCache?.rawTargetCount ?? 0) >= 60,
        "Novelty pressure requires at least sixty loaded target rows or objects.",
      ),
      gate(
        "ordinary_known_mechanism_not_confirmed",
        !ordinaryKnownConfirmed,
        "Signals explained by ordinary known source-family mechanisms cannot clear not_ordinary_known_mechanism.",
      ),
      gate(
        "independent_source_family_support",
        sourceFamilies.length >= 2,
        "Novelty pressure requires at least two public source families before source-family behavior can be scored as non-ordinary.",
      ),
      gate(
        "novelty_evidence_refs_resolve",
        noveltyRefsResolve,
        "Novelty pressure evidence refs must resolve before candidate preflight can consume them.",
      ),
      gate(
        "nontrivial_source_signal_survives",
        sourceCache?.nontrivialResidual === true &&
          sourceCache?.rivalWeakened === true &&
          sourceCache?.counterexampleCollapsed === false,
        "Novelty pressure requires nontrivial residual, rival pressure, and nonfatal counterexample pressure to remain true.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    const primaryBlocker = generatorBornClaimLiftNoveltyPressurePrimaryBlocker({
      sourceSignal,
      ordinaryKnownConfirmed,
      failedGates,
    });
    const ready = failedGates.length === 0;
    const decision = {
      kind: "generator_born_discovery_claim_lift_novelty_pressure_decision" as const,
      candidateId: sourceSignal.candidateId,
      packageRef: sourceSignal.packageRef,
      sourceSignalStatus: sourceSignal.sourceSignalStatus,
      sourceCacheRef: sourceSignal.sourceCacheRef,
      noveltyPressureStatus: ready
        ? ("novelty_pressure_cleared" as const)
        : ("blocked" as const),
      ordinaryMechanismStatus:
        sourceCache === null
          ? ("not_checked" as const)
          : ordinaryKnownConfirmed
            ? ("ordinary_known_confirmed" as const)
            : ("not_confirmed" as const),
      sourceFamilyCount: sourceFamilies.length,
      sourceFamilies,
      noveltyEvidenceRefs: ready ? noveltyEvidenceRefs : [],
      primaryBlocker,
      gates,
      failedGates,
      packageMutated: false as const,
      requiredNextAction: ready
        ? "Claim-lift candidate preflight may consume this forward-only novelty-pressure clearance; this is not a Fund and does not mutate packages."
        : generatorBornClaimLiftNoveltyPressureRequiredAction(primaryBlocker),
    };
    return { ...decision, evidenceHash: hashEvidence(decision) };
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftNoveltyPressureReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "CLAIM_LIFT_NOVELTY_PRESSURE.json"), report);
    await writeJson(join(root, "CLAIM_LIFT_NOVELTY_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_novelty_pressure_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_novelty_pressure_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      noveltyPressureCleared: report.noveltyPressureCleared,
      noveltyPressureBlocked: report.noveltyPressureBlocked,
      blockerDistribution: report.blockerDistribution,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_NOVELTY_PRESSURE.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "CLAIM_LIFT_NOVELTY_PRESSURE.md"),
      generatorBornDiscoveryClaimLiftNoveltyPressureMarkdown(report),
    );
    await writeText(
      join(root, "CLAIM_LIFT_NOVELTY_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftNoveltyPressureNextCheckpointMarkdown(
        report,
      ),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftDeathMemoryService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftDeathMemoryReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    const noveltyPressure = await this.readNoveltyPressureOrRun();
    const existing = await this.readGraveyardEntries();
    const decisions: GeneratorBornDiscoveryClaimLiftDeathMemoryDecision[] = [];
    const entriesToAdd: GraveyardEntry[] = [];
    for (const decision of noveltyPressure.decisions) {
      const memoryDecision = await this.evaluateNoveltyDecision(
        decision,
        existing,
        entriesToAdd,
      );
      decisions.push(memoryDecision);
      if (
        memoryDecision.deathMemoryStatus === "recorded" &&
        memoryDecision.graveyardEntry !== null
      ) {
        entriesToAdd.push(memoryDecision.graveyardEntry);
      }
    }
    if (entriesToAdd.length > 0) {
      await this.writeGraveyardEntries([...existing, ...entriesToAdd]);
    }
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-death-memory-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftDeathMemoryReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_death_memory" as const,
        status:
          entriesToAdd.length > 0
            ? ("death_memory_recorded" as const)
            : ("continue_searching_checkpointed" as const),
        checkpointUsed: noveltyPressure.nextCheckpointRef,
        nextCheckpointRef,
        noveltyDecisionsLoaded: noveltyPressure.decisions.length,
        graveyardEntriesAdded: entriesToAdd.length,
        graveyardEntriesSkipped: decisions.length - entriesToAdd.length,
        packagesMutated: 0 as const,
        fundFound: false as const,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftDeathMemoryBottleneck(decisions),
        artifactRefs:
          generatorBornDiscoveryClaimLiftDeathMemoryArtifactRefs(
            nextCheckpointRef,
          ),
      });
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readNoveltyPressureOrRun(): Promise<GeneratorBornDiscoveryClaimLiftNoveltyPressureReport> {
    const report =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftNoveltyPressureReport>(
        join(this.liftRoot(), "CLAIM_LIFT_NOVELTY_PRESSURE.json"),
      );
    if (report !== null) return report;
    return new GeneratorBornDiscoveryClaimLiftNoveltyPressureService(
      this.root,
    ).run();
  }

  private async evaluateNoveltyDecision(
    decision: GeneratorBornDiscoveryClaimLiftNoveltyPressureDecision,
    existing: GraveyardEntry[],
    pending: GraveyardEntry[],
  ): Promise<GeneratorBornDiscoveryClaimLiftDeathMemoryDecision> {
    const deathCause =
      generatorBornClaimLiftDeathCauseFromNoveltyPressure(decision);
    const alreadyRecorded = [...existing, ...pending].some(
      (entry) => entry.candidateId === decision.candidateId,
    );
    const base = {
      kind: "generator_born_discovery_claim_lift_death_memory_decision" as const,
      candidateId: decision.candidateId,
      packageRef: decision.packageRef,
      sourceCacheRef: decision.sourceCacheRef,
      noveltyPressureStatus: decision.noveltyPressureStatus,
      primaryBlocker: decision.primaryBlocker,
      packageMutated: false as const,
      fundFound: false as const,
      noUserNotification: true as const,
    };
    if (deathCause === null) {
      const skipped = {
        ...base,
        deathMemoryStatus: "skipped" as const,
        deathCause: null,
        graveyardEntry: null,
        reason:
          "Novelty-pressure blocker is potentially repairable or already nonterminal; no graveyard memory is written.",
      };
      return { ...skipped, evidenceHash: hashEvidence(skipped) };
    }
    if (alreadyRecorded) {
      const skipped = {
        ...base,
        deathMemoryStatus: "already_recorded" as const,
        deathCause,
        graveyardEntry: null,
        reason:
          "Candidate already exists in the internal graveyard; duplicate death memory was not written.",
      };
      return { ...skipped, evidenceHash: hashEvidence(skipped) };
    }
    const candidate = await generatorBornClaimLiftPackageCandidate(
      this.root,
      decision.packageRef,
    );
    const sourceCache = await generatorBornClaimLiftSourceCache(
      this.root,
      decision.sourceCacheRef,
    );
    const entry: GraveyardEntry = {
      candidateId: decision.candidateId,
      domain:
        candidate?.domain ??
        generatorBornClaimLiftDomainFromSourceCache(sourceCache),
      claim:
        candidate?.claim ??
        generatorBornClaimLiftDeathMemoryClaim(decision, sourceCache),
      status: generatorBornClaimLiftInternalStatusForDeathCause(deathCause),
      deathCause,
      cycleId: "generator-claim-lift-novelty-pressure",
      recordedAt: nowIso(),
      noUserNotification: true,
    };
    const recorded = {
      ...base,
      deathMemoryStatus: "recorded" as const,
      deathCause,
      graveyardEntry: entry,
      reason:
        "Novelty pressure identified a terminal claim-lift blocker; internal graveyard memory was written without user notification or Fund-state mutation.",
    };
    return { ...recorded, evidenceHash: hashEvidence(recorded) };
  }

  private async readGraveyardEntries(): Promise<GraveyardEntry[]> {
    const graveyard = await readOptionalJson<{ entries: GraveyardEntry[] }>(
      join(this.root, daemonArtifactRoot, "graveyard.json"),
    );
    return graveyard?.entries ?? [];
  }

  private async writeGraveyardEntries(
    entries: GraveyardEntry[],
  ): Promise<void> {
    await writeJson(
      join(this.root, daemonArtifactRoot, "graveyard.json"),
      withEvidenceHash({ kind: "candidate_graveyard", entries }),
    );
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftDeathMemoryReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "CLAIM_LIFT_DEATH_MEMORY.json"), report);
    await writeJson(join(root, "CLAIM_LIFT_DEATH_MEMORY_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_death_memory_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_death_memory_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      graveyardEntriesAdded: report.graveyardEntriesAdded,
      graveyardEntriesSkipped: report.graveyardEntriesSkipped,
      blockerDistribution: report.blockerDistribution,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_DEATH_MEMORY.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "CLAIM_LIFT_DEATH_MEMORY.md"),
      generatorBornDiscoveryClaimLiftDeathMemoryMarkdown(report),
    );
    await writeText(
      join(root, "CLAIM_LIFT_DEATH_MEMORY_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftDeathMemoryNextCheckpointMarkdown(report),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftCandidatePreflightService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftCandidatePreflightReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    let closure = await this.readFundClosureOrNull();
    if (closure === null) {
      await new GeneratorBornFundClosureService(this.root).run();
      closure = await this.readFundClosure();
    }
    const sourceSignals = await this.readSourceSignalsOrRun();
    const noveltyPressure = await this.readNoveltyPressureOrRun();
    const decisions = await Promise.all(
      closure.claimLiftRequirements.map((requirement) =>
        this.evaluateRequirement(requirement, sourceSignals, noveltyPressure),
      ),
    );
    const candidateContracts = decisions
      .filter(
        (decision) =>
          decision.candidateContractStatus === "candidate_contract_ready" &&
          decision.candidateContract !== null,
      )
      .map(
        (decision) =>
          decision.candidateContract as GeneratorBornDiscoveryClaimLiftProposal,
      );
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-candidate-preflight-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftCandidatePreflightReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_candidate_preflight" as const,
        status:
          candidateContracts.length > 0
            ? ("candidate_contracts_ready" as const)
            : ("continue_searching_checkpointed" as const),
        checkpointUsed: sourceSignals.nextCheckpointRef,
        nextCheckpointRef,
        requirementsLoaded: closure.claimLiftRequirements.length,
        sourceSignalsLoaded: sourceSignals.decisions.length,
        candidateContractsReady: candidateContracts.length,
        candidateContractsBlocked: decisions.filter(
          (decision) => decision.candidateContractStatus === "blocked",
        ).length,
        candidateContractsWritten: candidateContracts.length,
        packagesMutated: 0 as const,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        fundFound: false as const,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftCandidatePreflightBottleneck(
            decisions,
          ),
        artifactRefs:
          generatorBornDiscoveryClaimLiftCandidatePreflightArtifactRefs(
            nextCheckpointRef,
          ),
      });
    await this.writeArtifacts(report, candidateContracts);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readFundClosureOrNull(): Promise<GeneratorBornFundClosureReport | null> {
    return readOptionalJson<GeneratorBornFundClosureReport>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorFundClosureDir,
        "latest.json",
      ),
    );
  }

  private async readFundClosure(): Promise<GeneratorBornFundClosureReport> {
    const report = await this.readFundClosureOrNull();
    if (report === null) {
      throw new Error(
        "Generator claim-lift candidate preflight requires generator-fund-closure report.",
      );
    }
    return report;
  }

  private async readSourceSignalsOrRun(): Promise<GeneratorBornDiscoveryClaimLiftSourceSignalReport> {
    const report =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftSourceSignalReport>(
        join(this.liftRoot(), "SOURCE_SIGNAL_BINDINGS.json"),
      );
    if (report !== null) return report;
    return new GeneratorBornDiscoveryClaimLiftSourceSignalService(
      this.root,
    ).run();
  }

  private async readNoveltyPressureOrRun(): Promise<GeneratorBornDiscoveryClaimLiftNoveltyPressureReport> {
    const report =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftNoveltyPressureReport>(
        join(this.liftRoot(), "CLAIM_LIFT_NOVELTY_PRESSURE.json"),
      );
    if (report !== null) return report;
    return new GeneratorBornDiscoveryClaimLiftNoveltyPressureService(
      this.root,
    ).run();
  }

  private async evaluateRequirement(
    requirement: GeneratorBornDiscoveryClaimLiftRequirement,
    sourceSignals: GeneratorBornDiscoveryClaimLiftSourceSignalReport,
    noveltyPressure: GeneratorBornDiscoveryClaimLiftNoveltyPressureReport,
  ): Promise<GeneratorBornDiscoveryClaimLiftCandidatePreflightDecision> {
    const packageRef = requirement.externalReviewPackagePath ?? "";
    const packageBindingsPath =
      packageRef.length > 0 && publicSafeRef(packageRef)
        ? join(this.root, packageRef, "CLAIM_EVIDENCE_BINDINGS.json")
        : "";
    const bindings =
      packageBindingsPath.length > 0
        ? await readOptionalJson<Record<string, unknown>>(packageBindingsPath)
        : null;
    const sourceSignal = sourceSignals.decisions.find(
      (decision) =>
        decision.candidateId === requirement.candidateId ||
        (packageRef.length > 0 && decision.packageRef === packageRef),
    );
    const noveltyDecision = noveltyPressure.decisions.find(
      (decision) =>
        decision.candidateId === requirement.candidateId ||
        (packageRef.length > 0 && decision.packageRef === packageRef),
    );
    const domainFailedGates = generatorBornClaimLiftDomainFailedGates({
      requirement,
      bindings,
    });
    const fatalDomainGates = domainFailedGates.filter((gateId) =>
      generatorBornClaimLiftFatalDomainGate(gateId, noveltyDecision),
    );
    const scaffold = await generatorBornDiscoveryClaimLiftProposalScaffold(
      this.root,
      requirement,
    );
    const candidateContract =
      sourceSignal?.sourceSignalStatus === "source_signal_bound" &&
      bindings !== null &&
      fatalDomainGates.length === 0
        ? await generatorBornClaimLiftCandidateContractFromSourceSignal({
            root: this.root,
            requirement,
            bindings,
            sourceSignal,
            scaffold,
          })
        : null;
    const claimDecision =
      candidateContract === null
        ? null
        : await generatorBornDiscoveryClaimLiftDecision({
            root: this.root,
            requirement,
            proposal: candidateContract,
            proposalRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_CANDIDATE_CONTRACTS.json#${requirement.candidateId}`,
          });
    const gates = [
      gate(
        "source_signal_bound",
        sourceSignal?.sourceSignalStatus === "source_signal_bound",
        "Claim-lift candidate preflight requires a bound forward-only source signal.",
      ),
      gate(
        "package_bindings_present",
        bindings !== null,
        "Claim-lift candidate preflight requires package claim-evidence bindings.",
      ),
      gate(
        "claim_liftable_domain_gate_shape",
        domainFailedGates.every((gateId) =>
          generatorBornClaimLiftLiftableDomainGate(gateId, noveltyDecision),
        ),
        "Only liftable domain-significance gates may be repaired by a forward-only candidate contract.",
      ),
      gate(
        "not_ordinary_known_mechanism_novelty_pressure",
        !domainFailedGates.includes("not_ordinary_known_mechanism") ||
          noveltyDecision?.noveltyPressureStatus === "novelty_pressure_cleared",
        "The not_ordinary_known_mechanism gate may be cleared only by explicit novelty pressure, not by claim text.",
      ),
      gate(
        "ordinary_known_mechanism_cleared",
        fatalDomainGates.length === 0,
        "A claim-lift candidate cannot be born while ordinary-known, known-trivial, source-family, or benchmark-family triviality gates remain failed.",
      ),
      gate(
        "scaffold_refs_present",
        scaffold.baselineRefs.length > 0 &&
          scaffold.rivalRefs.length > 0 &&
          scaffold.holdoutRefs.length > 0 &&
          scaffold.replayRefs.length > 0 &&
          scaffold.counterexampleRefs.length > 0 &&
          scaffold.mechanismPressureRefs.length > 0,
        "Candidate contract needs baseline, rival, holdout, replay, counterexample, and mechanism-pressure refs before proposal birth.",
      ),
      gate(
        "candidate_claim_decision_accepts",
        claimDecision?.accepted === true,
        "The forward-only candidate contract must pass the existing claim-lift decision gate before proposal builder consumption.",
      ),
    ];
    const failedGates = uniqueStrings([
      ...gates.filter((item) => !item.passed).map((item) => item.code),
      ...(claimDecision?.failedGates ?? []),
    ]);
    const primaryBlocker =
      generatorBornClaimLiftCandidatePreflightPrimaryBlocker({
        sourceSignal,
        noveltyPressure: noveltyDecision,
        fatalDomainGates,
        failedGates,
      });
    const ready =
      failedGates.length === 0 &&
      candidateContract !== null &&
      claimDecision?.accepted === true;
    const sourceSignalStatus =
      sourceSignal?.sourceSignalStatus ?? ("missing" as const);
    return withEvidenceHash({
      kind: "generator_born_discovery_claim_lift_candidate_preflight_decision" as const,
      candidateId: requirement.candidateId,
      packageRef: packageRef.length > 0 ? packageRef : null,
      sourceSignalStatus,
      noveltyPressureStatus:
        noveltyDecision?.noveltyPressureStatus ?? ("missing" as const),
      targetDiscoveryCandidateId: ready
        ? candidateContract.targetDiscoveryCandidateId
        : null,
      candidateContractStatus: ready
        ? ("candidate_contract_ready" as const)
        : ("blocked" as const),
      primaryBlocker,
      domainSignificanceFailedGates: domainFailedGates,
      fatalDomainSignificanceGates: fatalDomainGates,
      gates:
        claimDecision === null ? gates : [...gates, ...claimDecision.gates],
      failedGates,
      candidateContract: ready ? candidateContract : null,
      packageMutated: false as const,
      requiredNextAction: ready
        ? "Run generator-claim-lift-propose; the proposal builder may consume this forward-only candidate contract without mutating the source package."
        : generatorBornClaimLiftCandidatePreflightRequiredAction({
            primaryBlocker,
            fatalDomainGates,
          }),
    });
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftCandidatePreflightReport,
    candidateContracts: GeneratorBornDiscoveryClaimLiftProposal[],
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "CLAIM_LIFT_CANDIDATE_PREFLIGHT.json"), report);
    await writeJson(join(root, "CLAIM_LIFT_CANDIDATE_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_candidate_preflight_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(root, "CLAIM_LIFT_CANDIDATE_CONTRACTS.json"), {
      kind: "generator_born_discovery_claim_lift_candidate_contracts",
      generatedBy: "generator_born_discovery_claim_lift_candidate_preflight",
      candidates: candidateContracts,
      evidenceHash: hashEvidence(candidateContracts),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_candidate_preflight_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      candidateContractsReady: report.candidateContractsReady,
      candidateContractsBlocked: report.candidateContractsBlocked,
      candidateContractsWritten: report.candidateContractsWritten,
      blockerDistribution: report.blockerDistribution,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_CANDIDATE_PREFLIGHT.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "CLAIM_LIFT_CANDIDATE_PREFLIGHT.md"),
      generatorBornDiscoveryClaimLiftCandidatePreflightMarkdown(report),
    );
    await writeText(
      join(root, "CLAIM_LIFT_CANDIDATE_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftCandidatePreflightNextCheckpointMarkdown(
        report,
      ),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftSignalRebindService {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftSignalRebindReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    const experiment = await this.readExperimentOrRun();
    const decisions: GeneratorBornDiscoveryClaimLiftSignalRebindDecision[] = [];
    for (const decision of experiment.decisions) {
      decisions.push(await this.rebindDecision(decision));
    }
    const rebound = decisions.filter(
      (decision) => decision.rebindStatus === "rebound",
    );
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-rebind-continue-searching.json`;
    const notificationReady =
      rebound.find((decision) => decision.notificationAllowedAfter) ??
      rebound[0];
    const report: GeneratorBornDiscoveryClaimLiftSignalRebindReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_signal_rebind" as const,
        status:
          rebound.length > 0
            ? ("discovery_package_rebound" as const)
            : ("continue_searching_checkpointed" as const),
        checkpointUsed: experiment.nextCheckpointRef,
        nextCheckpointRef,
        experimentsLoaded: experiment.decisions.length,
        packagesRebound: rebound.length,
        packagesSkipped: decisions.filter(
          (decision) => decision.rebindStatus === "skipped",
        ).length,
        discoveryScoredPackages: decisions.filter(
          (decision) =>
            decision.countsForEinsteinNobelDiscoveryScoreAfter === true,
        ).length,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        fundGateResult:
          notificationReady?.fundGateResult ??
          new FundGateEvaluator().evaluate(null),
        fundFound: false as const,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftSignalRebindBottleneck(decisions),
        artifactRefs:
          generatorBornDiscoveryClaimLiftSignalRebindArtifactRefs(
            nextCheckpointRef,
          ),
      });
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readExperimentOrRun(): Promise<GeneratorBornDiscoveryClaimLiftSignalExperimentReport> {
    const existing =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftSignalExperimentReport>(
        join(this.liftRoot(), "SIGNAL_EXPERIMENTS.json"),
      );
    if (existing !== null) return existing;
    return new GeneratorBornDiscoveryClaimLiftSignalExperimentService(
      this.root,
    ).run();
  }

  private async rebindDecision(
    experimentDecision: GeneratorBornDiscoveryClaimLiftSignalExperimentDecision,
  ): Promise<GeneratorBornDiscoveryClaimLiftSignalRebindDecision> {
    const publicCorpusNegativeHistory =
      experimentDecision.publicCorpusNegativeHistory ??
      (await publicCorpusNegativeHistoryForClaimLiftCandidateText(
        this.root,
        `${experimentDecision.candidateId} ${experimentDecision.packageRef ?? ""}`,
      ));
    if (publicCorpusNegativeHistory.blocksSeedBirth) {
      return this.skippedDecision(
        experimentDecision,
        "public_corpus_downgrade",
      );
    }
    if (
      experimentDecision.experimentStatus !== "insight_evidence_ready" ||
      experimentDecision.packageRef === null
    ) {
      return this.skippedDecision(
        experimentDecision,
        experimentDecision.primaryBlocker,
      );
    }
    const packageRoot = join(this.root, experimentDecision.packageRef);
    const candidatePath = join(packageRoot, "FUND_CANDIDATE.json");
    const bindingsPath = join(packageRoot, "CLAIM_EVIDENCE_BINDINGS.json");
    const candidatePayload = await readOptionalJson<{
      candidate?: FundCandidate;
      fundClass?: FundClass;
    }>(candidatePath);
    const bindings =
      await readOptionalJson<Record<string, unknown>>(bindingsPath);
    if (!candidatePayload?.candidate || bindings === null) {
      return this.skippedDecision(
        experimentDecision,
        "missing_package_contract",
      );
    }
    const refsResolve =
      experimentDecision.bindableInsightEvidenceRefs.length >= 2 &&
      (await claimLiftEvidenceRefsResolvable(
        this.root,
        experimentDecision.bindableInsightEvidenceRefs,
      ));
    if (!refsResolve) {
      return this.skippedDecision(
        experimentDecision,
        "unresolved_insight_evidence_refs",
      );
    }
    const publicFundReconciliation = await new DiscoveryFrictionHealthService(
      this.root,
    ).publicFundReconciliationForCandidate(
      candidatePayload.candidate.candidateId,
    );
    if (publicFundReconciliation.blocksDiscoveryScore) {
      return this.skippedDecision(
        experimentDecision,
        "public_corpus_downgrade",
      );
    }
    const before = await evaluateFundCandidateWithPackageForRoot(
      this.root,
      candidatePayload.candidate,
    );
    const updatedCandidate: FundCandidate = {
      ...candidatePayload.candidate,
      nontrivialNewInsightAcrossRealTargets: true,
      domainScientificSignificance: true,
      insightEvidenceRefs: uniqueStrings([
        ...(candidatePayload.candidate.insightEvidenceRefs ?? []),
        ...experimentDecision.bindableInsightEvidenceRefs,
      ]),
    };
    const updatedAssessment = classifyFundCandidateForGate(
      updatedCandidate,
      true,
    );
    const rawSourceReproductionConsistency =
      await generatorBornClaimLiftRawSourceReproductionConsistency(
        this.root,
        updatedCandidate,
      );
    if (rawSourceReproductionConsistency.passed !== true) {
      return this.skippedDecision(
        experimentDecision,
        "raw_source_reproduction_mismatch",
        rawSourceReproductionConsistency,
      );
    }
    const updatedPayload = {
      ...candidatePayload,
      candidate: updatedCandidate,
      fundClass: updatedAssessment.fundClass,
      countsForEinsteinNobelDiscoveryScore:
        updatedAssessment.countsForEinsteinNobelDiscoveryScore,
      fundClassAssessment: updatedAssessment,
    };
    const updatedBindings = {
      ...bindings,
      insightEvidenceRefs: updatedCandidate.insightEvidenceRefs,
      nontrivialInsightEvidenceRefs:
        experimentDecision.bindableInsightEvidenceRefs,
      domainSignificanceEvidenceRefs: uniqueStrings([
        ...stringArray(bindings.domainSignificanceEvidenceRefs),
        ...experimentDecision.bindableInsightEvidenceRefs,
      ]),
      fundClass: updatedAssessment.fundClass,
      countsForEinsteinNobelDiscoveryScore:
        updatedAssessment.countsForEinsteinNobelDiscoveryScore,
      fundClassAssessment: updatedAssessment,
      fundCandidate: updatedCandidate,
    };
    await writeJson(candidatePath, updatedPayload);
    await writeJson(bindingsPath, updatedBindings);
    const after = await evaluateFundCandidateWithPackageForRoot(
      this.root,
      updatedCandidate,
    );
    const decision = {
      kind: "generator_born_discovery_claim_lift_signal_rebind_decision" as const,
      candidateId: experimentDecision.candidateId,
      packageRef: experimentDecision.packageRef,
      rebindStatus: "rebound" as const,
      primaryBlocker: after.countsForEinsteinNobelDiscoveryScore
        ? "none"
        : "non_discovery_fund_class_after_rebind",
      insightEvidenceRefsBound: experimentDecision.bindableInsightEvidenceRefs,
      rawSourceReproductionConsistency,
      fundClassBefore: before.fundClass,
      fundClassAfter: after.fundClass,
      countsForEinsteinNobelDiscoveryScoreAfter:
        after.countsForEinsteinNobelDiscoveryScore,
      notificationAllowedAfter: after.notificationAllowed,
      packageMutated: true,
      fundGateResult: after,
    };
    return { ...decision, evidenceHash: hashEvidence(decision) };
  }

  private skippedDecision(
    experimentDecision: GeneratorBornDiscoveryClaimLiftSignalExperimentDecision,
    blocker: string,
    rawSourceReproductionConsistency = generatorBornClaimLiftRawSourceReproductionConsistencyNotChecked(
      "rebind_skipped_before_raw_source_reproduction_check",
    ),
  ): GeneratorBornDiscoveryClaimLiftSignalRebindDecision {
    const result = new FundGateEvaluator().evaluate(null);
    const decision = {
      kind: "generator_born_discovery_claim_lift_signal_rebind_decision" as const,
      candidateId: experimentDecision.candidateId,
      packageRef: experimentDecision.packageRef,
      rebindStatus: "skipped" as const,
      primaryBlocker: blocker,
      insightEvidenceRefsBound: [],
      rawSourceReproductionConsistency,
      fundClassBefore: null,
      fundClassAfter: null,
      countsForEinsteinNobelDiscoveryScoreAfter: false,
      notificationAllowedAfter: false,
      packageMutated: false,
      fundGateResult: result,
    };
    return { ...decision, evidenceHash: hashEvidence(decision) };
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftSignalRebindReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "SIGNAL_REBIND.json"), report);
    await writeJson(join(root, "SIGNAL_REBIND_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_signal_rebind_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(root, "SIGNAL_REBIND_FUND_GATE_RESULTS.json"), {
      kind: "generator_born_discovery_claim_lift_signal_rebind_fund_gate",
      fundGateResult: report.fundGateResult,
      fundFound: report.fundFound,
      evidenceHash: hashEvidence(report.fundGateResult),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_signal_rebind_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      packagesRebound: report.packagesRebound,
      discoveryScoredPackages: report.discoveryScoredPackages,
      blockerDistribution: report.blockerDistribution,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/SIGNAL_REBIND.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "SIGNAL_REBIND_DECISIONS.md"),
      generatorBornDiscoveryClaimLiftSignalRebindMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_REBIND_FUND_GATE_RESULTS.md"),
      generatorBornDiscoveryClaimLiftSignalRebindFundGateMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_REBIND_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftSignalRebindNextCheckpointMarkdown(report),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftSignalIntakeService {
  constructor(
    private readonly root: string,
    private readonly runPackageBackedCycle: () => Promise<
      Record<string, unknown>
    >,
  ) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftSignalIntakeReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    await mkdir(join(this.root, daemonArtifactRoot, candidateIntakeDir), {
      recursive: true,
    });
    const rebind = await this.readRebindOrRun();
    const evaluations = await Promise.all(
      rebind.decisions.map((decision) => this.evaluateDecision(decision)),
    );
    const eligible = evaluations.filter((evaluation) =>
      evaluation.gates.every((item) => item.passed),
    );
    const selected = eligible[0] ?? null;
    const stagedIntakeRef =
      selected !== null && selected.candidate !== null
        ? await this.stageIntakeCandidate(selected)
        : null;
    const cycle =
      stagedIntakeRef !== null ? await this.runPackageBackedCycle() : null;
    const cycleFundGate =
      isRecord(cycle?.fundGateEvaluation) &&
      cycle?.fundGateEvaluation.kind === "fund_gate_result"
        ? (cycle.fundGateEvaluation as FundGateResult)
        : null;
    const fundGateResult =
      cycleFundGate ??
      (selected !== null
        ? selected.fundGateResult
        : new FundGateEvaluator().evaluate(null));
    const fundFound =
      fundGateResult.notificationAllowed === true &&
      cycle?.nextStatus === "FUND_FOUND";
    const decisions = evaluations.map((evaluation) => {
      const selectedDecision =
        selected?.rebindDecision.candidateId ===
        evaluation.rebindDecision.candidateId;
      const eligibleDecision = evaluation.gates.every((item) => item.passed);
      const decision = {
        kind: "generator_born_discovery_claim_lift_signal_intake_decision" as const,
        candidateId: evaluation.rebindDecision.candidateId,
        packageRef: evaluation.rebindDecision.packageRef,
        intakeStatus: selectedDecision
          ? ("accepted" as const)
          : eligibleDecision
            ? ("eligible_not_selected" as const)
            : ("blocked" as const),
        primaryBlocker:
          selectedDecision || eligibleDecision
            ? "none"
            : evaluation.primaryBlocker,
        intakeRef: selectedDecision ? stagedIntakeRef : null,
        fundClass: evaluation.fundGateResult.fundClass,
        countsForEinsteinNobelDiscoveryScore:
          evaluation.fundGateResult.countsForEinsteinNobelDiscoveryScore,
        notificationAllowed: evaluation.fundGateResult.notificationAllowed,
        fundGateResult: evaluation.fundGateResult,
        gates: evaluation.gates,
        failedGates: evaluation.failedGates,
        rawSourceReproductionConsistency:
          evaluation.rawSourceReproductionConsistency,
        publicCorpusPackageInspectability:
          evaluation.publicCorpusPackageInspectability,
      };
      return { ...decision, evidenceHash: hashEvidence(decision) };
    });
    const nextCheckpointRef = fundFound
      ? `${daemonArtifactRoot}/checkpoints/generator-claim-lift-intake-fund-found.json`
      : `${daemonArtifactRoot}/checkpoints/generator-claim-lift-intake-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftSignalIntakeReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_signal_intake" as const,
        status: fundFound
          ? ("FUND_FOUND" as const)
          : ("continue_searching_checkpointed" as const),
        checkpointUsed: rebind.nextCheckpointRef,
        nextCheckpointRef,
        rebindDecisionsLoaded: rebind.decisions.length,
        packagesEvaluated: evaluations.filter(
          (evaluation) => evaluation.rebindDecision.packageRef !== null,
        ).length,
        eligiblePackages: eligible.length,
        packagesStaged: stagedIntakeRef !== null ? 1 : 0,
        acceptedPackages: decisions.filter(
          (decision) => decision.intakeStatus === "accepted",
        ).length,
        blockedPackages: decisions.filter(
          (decision) => decision.intakeStatus === "blocked",
        ).length,
        selectedCandidateId: selected?.rebindDecision.candidateId ?? null,
        decisions,
        blockerDistribution: countBy(decisions, "primaryBlocker"),
        intakeCycleRef: isRecord(cycle)
          ? `${daemonArtifactRoot}/search-cycles/${String(cycle.cycleId)}.json`
          : null,
        fundGateResult,
        fundFound,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftSignalIntakeBottleneck({
            fundFound,
            eligibleCount: eligible.length,
            decisions,
          }),
        artifactRefs: generatorBornDiscoveryClaimLiftSignalIntakeArtifactRefs({
          nextCheckpointRef,
          fundFound,
        }),
      });
    if (!fundFound) {
      await this.reconcileBlockedRootFundState(
        evaluations.map((evaluation) => evaluation.rebindDecision.candidateId),
        fundGateResult,
      );
    }
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readRebindOrRun(): Promise<GeneratorBornDiscoveryClaimLiftSignalRebindReport> {
    const existing =
      await readOptionalJson<GeneratorBornDiscoveryClaimLiftSignalRebindReport>(
        join(this.liftRoot(), "SIGNAL_REBIND.json"),
      );
    if (existing !== null) return existing;
    return new GeneratorBornDiscoveryClaimLiftSignalRebindService(
      this.root,
    ).run();
  }

  private async evaluateDecision(
    rebindDecision: GeneratorBornDiscoveryClaimLiftSignalRebindDecision,
  ): Promise<{
    rebindDecision: GeneratorBornDiscoveryClaimLiftSignalRebindDecision;
    candidate: FundCandidate | null;
    fundGateResult: FundGateResult;
    gates: FundGate[];
    failedGates: string[];
    primaryBlocker: string;
    rawSourceReproductionConsistency: GeneratorBornClaimLiftRawSourceReproductionConsistency;
    publicCorpusPackageInspectability: PublicCorpusPackageInspectabilityAssessment;
  }> {
    const packageRoot =
      rebindDecision.packageRef === null
        ? null
        : join(this.root, rebindDecision.packageRef);
    const payload =
      packageRoot === null
        ? null
        : await readOptionalJson<{ candidate?: FundCandidate }>(
            join(packageRoot, "FUND_CANDIDATE.json"),
          );
    const candidate = isFundCandidate(payload?.candidate)
      ? {
          ...payload.candidate,
          publicPackagePath:
            payload.candidate.publicPackagePath ?? rebindDecision.packageRef!,
        }
      : null;
    const packageFundGateResult =
      candidate === null
        ? new FundGateEvaluator().evaluate(null)
        : await evaluateFundCandidateWithPackageForRoot(this.root, candidate);
    const publicFundReconciliation = await new DiscoveryFrictionHealthService(
      this.root,
    ).publicFundReconciliationForCandidate(
      candidate?.candidateId ?? rebindDecision.candidateId,
    );
    const publicCorpusNegativeHistory =
      await publicCorpusNegativeHistoryForClaimLiftCandidateText(
        this.root,
        `${rebindDecision.candidateId} ${rebindDecision.packageRef ?? ""}`,
      );
    const publicCorpusBlocksDiscovery =
      publicFundReconciliation.blocksDiscoveryScore ||
      publicCorpusNegativeHistory.blocksSeedBirth;
    const rawSourceReproductionConsistency =
      await generatorBornClaimLiftRawSourceReproductionConsistency(
        this.root,
        candidate,
      );
    const publicCorpusPackageInspectability =
      await publicCorpusPackageInspectabilityForClaimLiftIntake({
        root: this.root,
        candidate,
        publicFundReconciliation,
      });
    const fundGateResult =
      publicCorpusBlocksDiscovery ||
      rawSourceReproductionConsistency.passed !== true ||
      publicCorpusPackageInspectability.passed !== true
        ? {
            ...packageFundGateResult,
            passed: false,
            status: "continue_searching" as const,
            failedGates: Array.from(
              new Set([
                ...packageFundGateResult.failedGates,
                ...(publicCorpusBlocksDiscovery
                  ? ["public_corpus_downgrade"]
                  : []),
                ...(rawSourceReproductionConsistency.passed !== true
                  ? ["raw_source_reproduction_consistency"]
                  : []),
                ...(publicCorpusPackageInspectability.passed !== true
                  ? ["public_corpus_package_inspectability"]
                  : []),
              ]),
            ),
            fundClass: packageFundGateResult.fundClass,
            countsForEinsteinNobelDiscoveryScore: false,
            notificationAllowed: false,
          }
        : packageFundGateResult;
    const gates = [
      gate(
        "rebind_decision_rebound",
        rebindDecision.rebindStatus === "rebound",
        "Root intake requires a package already rebound from resolvable signal evidence.",
      ),
      gate(
        "package_ref_present",
        rebindDecision.packageRef !== null,
        "Root intake requires a package ref.",
      ),
      gate(
        "package_fund_candidate_present",
        candidate !== null,
        "Root intake requires the package-bound FundCandidate payload.",
      ),
      gate(
        "public_corpus_package_present",
        publicFundReconciliation.matched === true,
        "Root intake for generator-born claim-lift packages requires a matching public corpus package before root Fund state can be written.",
      ),
      gate(
        "raw_source_reproduction_consistency",
        rawSourceReproductionConsistency.passed === true,
        "Root intake for generator-born claim-lift packages requires public/raw source-cache metrics to match the bound generator runtime evidence.",
      ),
      gate(
        "public_corpus_package_inspectability",
        publicCorpusPackageInspectability.passed === true,
        "Root intake requires a public corpus package with reviewer-facing files and a machine-readable raw/formal reproduction result, not only a SUMMARY.json clearance.",
      ),
      gate(
        "rebind_discovery_scored",
        rebindDecision.countsForEinsteinNobelDiscoveryScoreAfter === true,
        "Rebind must classify the package as discovery-scored.",
      ),
      gate(
        "rebind_notification_allowed",
        rebindDecision.notificationAllowedAfter === true,
        "Rebind must leave Fund notification allowed after unchanged package Fund Gate evaluation.",
      ),
      gate(
        "package_fund_gate_passed",
        fundGateResult.passed,
        "The package candidate must pass the unchanged package-aware Fund Gate at intake time.",
      ),
      gate(
        "package_notification_allowed",
        fundGateResult.notificationAllowed,
        "Root intake may write Fund state only when package-aware Fund Gate notification remains allowed.",
      ),
      gate(
        "package_discovery_scored_fund_class",
        fundGateResult.countsForEinsteinNobelDiscoveryScore,
        "Root intake may write Fund state only for discovery-scored FundClasses.",
      ),
      gate(
        "public_corpus_discovery_score_reconciliation",
        !publicCorpusBlocksDiscovery,
        "Root intake must stop when a matching public corpus package or downgraded external anchor already blocks discovery scoring.",
      ),
    ];
    const failedGates = gates
      .filter((item) => !item.passed)
      .map((item) => item.code);
    return {
      rebindDecision,
      candidate,
      fundGateResult,
      gates,
      failedGates,
      primaryBlocker:
        failedGates.length === 0
          ? "none"
          : generatorBornDiscoveryClaimLiftSignalIntakeBlocker(failedGates),
      rawSourceReproductionConsistency,
      publicCorpusPackageInspectability,
    };
  }

  private async stageIntakeCandidate(input: {
    rebindDecision: GeneratorBornDiscoveryClaimLiftSignalRebindDecision;
    candidate: FundCandidate | null;
    fundGateResult: FundGateResult;
  }): Promise<string> {
    if (input.candidate === null || input.rebindDecision.packageRef === null) {
      throw new Error(
        "Cannot stage claim-lift intake without candidate package.",
      );
    }
    const candidate: FundCandidate = {
      ...input.candidate,
      publicPackagePath:
        input.candidate.publicPackagePath ?? input.rebindDecision.packageRef,
    };
    const intakeRef = `${daemonArtifactRoot}/${candidateIntakeDir}/${normalizeCandidateIdPart(candidate.candidateId)}-claim-lift-intake.json`;
    await writeJson(
      join(this.root, intakeRef),
      withEvidenceHash({
        kind: "generator_claim_lift_signal_intake_candidate",
        source: "generator_claim_lift_signal_rebind",
        candidate,
        packageRef: input.rebindDecision.packageRef,
        rebindDecisionRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/SIGNAL_REBIND_DECISIONS.json#${candidate.candidateId}`,
        fundGateResult: input.fundGateResult,
        noGateWeakening: true,
      }),
    );
    return intakeRef;
  }

  private async reconcileBlockedRootFundState(
    candidateIds: string[],
    fundGateResult: FundGateResult,
  ): Promise<void> {
    const statePath = join(this.root, daemonArtifactRoot, "state.json");
    const state = await readOptionalJson<DiscoveryDaemonState>(statePath);
    if (state === null) return;
    if (typeof state.lastCandidateId !== "string") return;
    if (!candidateIds.includes(state.lastCandidateId)) return;
    const staleCyclePath = join(
      this.root,
      daemonArtifactRoot,
      "search-cycles",
      `${state.lastCycleId}.json`,
    );
    const staleCycle =
      await readOptionalJson<Record<string, unknown>>(staleCyclePath);
    const staleCycleFundGate = isRecord(staleCycle?.fundGateEvaluation)
      ? staleCycle.fundGateEvaluation
      : null;
    const staleFundState =
      state.fundFound === true || state.status === "FUND_FOUND";
    const staleFundCycle =
      stringField(staleCycle, "status") === "FUND_FOUND" ||
      stringField(staleCycle, "nextStatus") === "FUND_FOUND" ||
      staleCycle?.discoveryFundNotificationAllowed === true ||
      staleCycleFundGate?.notificationAllowed === true;
    if (!staleFundState && !staleFundCycle) return;
    await removeIfExists(join(this.root, daemonArtifactRoot, "FUND_FOUND.md"));
    await removeIfExists(
      join(this.root, daemonArtifactRoot, fundCandidateFile),
    );
    await writeJson(
      join(this.root, daemonArtifactRoot, "fund-gate-results.json"),
      fundGateResult,
    );
    const previousCycle = staleFundCycle
      ? await this.previousSearchCycleBefore(state.lastCycleId ?? null)
      : null;
    if (isRecord(staleCycle) && staleFundCycle) {
      await removeIfExists(staleCyclePath);
      await removeIfExists(
        join(
          this.root,
          daemonArtifactRoot,
          "checkpoints",
          `${state.lastCycleId}.json`,
        ),
      );
    }
    await writeJson(
      statePath,
      withEvidenceHash({
        ...state,
        status: "continue_searching" as const,
        fundFound: false,
        cycleCount: previousCycle?.cycleNumber ?? state.cycleCount,
        lastCycleId: previousCycle?.cycleId ?? state.lastCycleId,
        updatedAt: nowIso(),
      }),
    );
  }

  private async previousSearchCycleBefore(
    cycleId: string | null,
  ): Promise<{ cycleId: string; cycleNumber: number } | null> {
    const currentNumber = cycleNumberFromCycleId(cycleId);
    if (currentNumber === null) return null;
    let files: string[];
    try {
      files = await readdir(
        join(this.root, daemonArtifactRoot, "search-cycles"),
      );
    } catch {
      return null;
    }
    const previous = cycleFilesByNumber(files)
      .filter((item) => item.cycleNumber < currentNumber)
      .at(-1);
    return previous
      ? {
          cycleId: previous.file.replace(/\.json$/, ""),
          cycleNumber: previous.cycleNumber,
        }
      : null;
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftSignalIntakeReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "SIGNAL_INTAKE.json"), report);
    await writeJson(join(root, "SIGNAL_INTAKE_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_signal_intake_decisions",
      decisions: report.decisions,
      blockerDistribution: report.blockerDistribution,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(root, "SIGNAL_INTAKE_FUND_GATE_RESULTS.json"), {
      kind: "generator_born_discovery_claim_lift_signal_intake_fund_gate",
      fundGateResult: report.fundGateResult,
      fundFound: report.fundFound,
      evidenceHash: hashEvidence(report.fundGateResult),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_signal_intake_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      selectedCandidateId: report.selectedCandidateId,
      acceptedPackages: report.acceptedPackages,
      eligiblePackages: report.eligiblePackages,
      intakeCycleRef: report.intakeCycleRef,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/SIGNAL_INTAKE.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "SIGNAL_INTAKE_DECISIONS.md"),
      generatorBornDiscoveryClaimLiftSignalIntakeMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_INTAKE_FUND_GATE_RESULTS.md"),
      generatorBornDiscoveryClaimLiftSignalIntakeFundGateMarkdown(report),
    );
    await writeText(
      join(root, "SIGNAL_INTAKE_NEXT_CHECKPOINT.md"),
      generatorBornDiscoveryClaimLiftSignalIntakeNextCheckpointMarkdown(report),
    );
  }
}

export class GeneratorBornDiscoveryClaimLiftProposalBuilder {
  constructor(private readonly root: string) {}

  async run(): Promise<GeneratorBornDiscoveryClaimLiftProposalBuildReport> {
    await mkdir(this.liftRoot(), { recursive: true });
    let closure = await this.readFundClosureOrNull();
    if (closure === null) {
      await new GeneratorBornFundClosureService(this.root).run();
      closure = await this.readFundClosure();
    }
    const requirements = closure.claimLiftRequirements;
    const decisions = await Promise.all(
      requirements.map((requirement) =>
        generatorBornDiscoveryClaimLiftProposalBuildDecision({
          root: this.root,
          requirement,
        }),
      ),
    );
    const proposals = decisions
      .filter(
        (decision) => decision.proposalReady && decision.proposal !== null,
      )
      .map(
        (decision) =>
          decision.proposal as GeneratorBornDiscoveryClaimLiftProposal,
      );
    await writeJson(join(this.liftRoot(), "CLAIM_LIFT_BUILT_PROPOSALS.json"), {
      kind: "generator_born_discovery_claim_lift_built_proposals",
      generatedBy: "generator_born_discovery_claim_lift_proposal_builder",
      proposals,
      evidenceHash: hashEvidence(proposals),
    });
    const proposalRef = `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_PROPOSALS.json`;
    await writeJson(join(this.root, proposalRef), {
      kind: "generator_born_discovery_claim_lift_proposals",
      generatedBy: "generator_born_discovery_claim_lift_proposal_builder",
      proposals,
      evidenceHash: hashEvidence(proposals),
    });
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/generator-claim-lift-proposal-builder-continue-searching.json`;
    const report: GeneratorBornDiscoveryClaimLiftProposalBuildReport =
      withEvidenceHash({
        kind: "generator_born_discovery_claim_lift_proposal_builder" as const,
        status: "continue_searching_checkpointed" as const,
        checkpointUsed: closure.nextCheckpointRef,
        nextCheckpointRef,
        requirementsLoaded: requirements.length,
        proposalCandidatesEvaluated: decisions.length,
        proposalsReady: proposals.length,
        proposalsBlocked: decisions.filter(
          (decision) => !decision.proposalReady,
        ).length,
        proposalsWritten: proposals.length,
        proposalRefs: [proposalRef],
        decisions,
        fundFound: false as const,
        remainingBottleneck:
          generatorBornDiscoveryClaimLiftProposalBuildBottleneck(decisions),
        artifactRefs: generatorBornDiscoveryClaimLiftProposalBuildArtifactRefs(
          nextCheckpointRef,
          proposalRef,
        ),
      });
    await this.writeArtifacts(report);
    return report;
  }

  private liftRoot(): string {
    return join(this.root, daemonArtifactRoot, generatorClaimLiftDir);
  }

  private async readFundClosureOrNull(): Promise<GeneratorBornFundClosureReport | null> {
    return readOptionalJson<GeneratorBornFundClosureReport>(
      join(
        this.root,
        daemonArtifactRoot,
        generatorFundClosureDir,
        "latest.json",
      ),
    );
  }

  private async readFundClosure(): Promise<GeneratorBornFundClosureReport> {
    const report = await this.readFundClosureOrNull();
    if (report === null) {
      throw new Error(
        "Generator claim-lift proposal builder requires generator-fund-closure report.",
      );
    }
    return report;
  }

  private async writeArtifacts(
    report: GeneratorBornDiscoveryClaimLiftProposalBuildReport,
  ): Promise<void> {
    const root = this.liftRoot();
    await writeJson(join(root, "CLAIM_LIFT_PROPOSAL_BUILD_DECISIONS.json"), {
      kind: "generator_born_discovery_claim_lift_proposal_build_decisions",
      decisions: report.decisions,
      proposalsReady: report.proposalsReady,
      proposalsBlocked: report.proposalsBlocked,
      evidenceHash: hashEvidence(report.decisions),
    });
    await writeJson(join(root, "CLAIM_LIFT_PROPOSAL_BUILDER.json"), report);
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "generator_born_discovery_claim_lift_proposal_builder_checkpoint",
      status: report.status,
      fundFound: report.fundFound,
      requirementsLoaded: report.requirementsLoaded,
      proposalCandidatesEvaluated: report.proposalCandidatesEvaluated,
      proposalsReady: report.proposalsReady,
      proposalsBlocked: report.proposalsBlocked,
      proposalsWritten: report.proposalsWritten,
      proposalRefs: report.proposalRefs,
      reportRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_PROPOSAL_BUILDER.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "CLAIM_LIFT_PROPOSAL_BUILD_DECISIONS.md"),
      generatorBornDiscoveryClaimLiftProposalBuildMarkdown(report),
    );
  }
}

const dimacsBoundaryClosureDir = "dimacs-boundary-closure" as const;
const dimacsSourceAnchor = "https://mat.tepper.cmu.edu/COLOR/instances.html";

export type DimacsTargetSpec = {
  fileName: string;
  family: "MYC" | "QUEEN" | "SGB";
  role: "prediction" | "holdout" | "counterexample";
  expectedColor: number;
  nonObvious: boolean;
};

export type ParsedDimacsGraph = {
  kind: "parsed_dimacs_graph";
  instanceId: string;
  fileName: string;
  sourceUrl: string;
  localArtifactPath: string;
  sourceHash: string;
  loadedVia: "fetch" | "fixture_fallback";
  family: DimacsTargetSpec["family"];
  role: DimacsTargetSpec["role"];
  expectedColor: number;
  declaredNodes: number;
  declaredEdges: number;
  parsedNodes: number;
  parsedEdges: number;
  density: number;
  maxDegree: number;
  avgDegree: number;
  cliqueLowerBound: number;
  greedyColorUpperBound: number;
  residualVsClique: number;
  residualVsGreedy: number;
};

type DimacsPredictionExecution = {
  predictionId: string;
  frozenBeforeExecution: true;
  instanceId: string;
  family: DimacsTargetSpec["family"];
  role: DimacsTargetSpec["role"];
  candidateMechanismPrediction: string;
  rivalMechanismPrediction: string;
  executed: true;
  supportedCandidateMechanism: boolean;
  nonObvious: boolean;
  evidenceRef: string;
};

type DimacsClosureDecision = {
  exactFormalClaim: string;
  killed: boolean;
  primaryDeathCause: DeathCause;
  killReasons: string[];
  proofMechanismStatus: DimacsBoundaryClosureReport["proofMechanismStatus"];
};

export class DimacsGraphColoringBoundaryClosureService {
  constructor(private readonly root: string) {}

  async run(): Promise<DimacsBoundaryClosureReport> {
    await mkdir(this.closureRoot(), { recursive: true });
    await mkdir(join(this.closureRoot(), "raw"), { recursive: true });
    const candidate = await this.loadCandidate();
    const exactFormalClaim = dimacsExactFormalClaim(candidate);
    const predictions = dimacsFrozenPredictionPlan();
    const instances: ParsedDimacsGraph[] = [];
    for (const spec of dimacsTargetSpecs()) {
      instances.push(await this.loadAndParse(spec));
    }
    const executions = predictions.map((prediction) =>
      dimacsExecutePrediction(prediction, instances),
    );
    const decision = dimacsClosureDecision({
      exactFormalClaim,
      instances,
      executions,
    });
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/dimacs-boundary-closure-continue-searching.json`;
    const report: DimacsBoundaryClosureReport = withEvidenceHash({
      kind: "dimacs_graph_coloring_boundary_closure" as const,
      status: "continue_searching_checkpointed" as const,
      checkpointUsed: await this.checkpointUsed(),
      nextCheckpointRef,
      sourceAnchor: dimacsSourceAnchor,
      candidateId: candidate?.candidateId ?? null,
      discoveryCandidateId: null,
      exactFormalClaim,
      instancesLoaded: instances.length,
      predictionsFrozen: predictions.length,
      predictionsExecuted: executions.length,
      nonObviousPredictions: executions.filter((row) => row.nonObvious).length,
      baselinesRun: instances.length * 3,
      rivalChecksRun: instances.length * 3,
      counterexampleChecksRun: instances.filter(
        (instance) => instance.role === "counterexample",
      ).length,
      holdoutChecksRun: instances.filter(
        (instance) => instance.role === "holdout",
      ).length,
      replayChecksRun: instances.length,
      proofMechanismStatus: decision.proofMechanismStatus,
      killed: decision.killed,
      primaryDeathCause: decision.primaryDeathCause,
      killReasons: decision.killReasons,
      discoveryCandidatesCreated: 0 as const,
      fundGateResult,
      fundFound: false as const,
      remainingBottleneck: dimacsRemainingBottleneck(decision),
      artifactRefs: dimacsClosureArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({
      report,
      instances,
      predictions,
      executions,
      decision,
      candidate,
    });
    return report;
  }

  private closureRoot(): string {
    return join(this.root, daemonArtifactRoot, dimacsBoundaryClosureDir);
  }

  private async checkpointUsed(): Promise<string | null> {
    const generatorFundCheckpoint = `${daemonArtifactRoot}/checkpoints/generator-born-fund-closure-continue-searching.json`;
    if (await exists(join(this.root, generatorFundCheckpoint))) {
      return generatorFundCheckpoint;
    }
    const generatorInsightCheckpoint = `${daemonArtifactRoot}/checkpoints/generator-born-insight-closure-continue-searching.json`;
    if (await exists(join(this.root, generatorInsightCheckpoint))) {
      return generatorInsightCheckpoint;
    }
    return null;
  }

  private async loadCandidate(): Promise<InsightCandidate | null> {
    const candidatePath = join(
      this.root,
      daemonArtifactRoot,
      "generator-insight-closure",
      "INSIGHT-HARD-GEN-KNOWN-FORMAL-PROBLEM-BOUNDARY-GENERATOR-6311DAD99A93.json",
    );
    const payload = await readOptionalJson<{ candidate?: unknown }>(
      candidatePath,
    );
    return insightCandidateFromUnknown(payload?.candidate);
  }

  private async loadAndParse(
    spec: DimacsTargetSpec,
  ): Promise<ParsedDimacsGraph> {
    const sourceUrl = `${dimacsSourceAnchor.replace(/\/instances\.html$/, "")}/instances/${spec.fileName}`;
    const localArtifactPath = `${daemonArtifactRoot}/${dimacsBoundaryClosureDir}/raw/${spec.fileName}`;
    const loaded = await loadDimacsText(sourceUrl, spec.fileName);
    await writeText(join(this.root, localArtifactPath), loaded.text);
    const parsed = parseDimacsGraph({
      text: loaded.text,
      fileName: spec.fileName,
      sourceUrl,
      localArtifactPath,
      loadedVia: loaded.loadedVia,
      spec,
    });
    return parsed;
  }

  private async writeArtifacts(input: {
    report: DimacsBoundaryClosureReport;
    instances: ParsedDimacsGraph[];
    predictions: DimacsPredictionExecution[];
    executions: DimacsPredictionExecution[];
    decision: DimacsClosureDecision;
    candidate: InsightCandidate | null;
  }): Promise<void> {
    const root = this.closureRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "DIMACS_INSTANCE_RECEIPTS.json"), {
      kind: "dimacs_instance_receipts",
      sourceAnchor: dimacsSourceAnchor,
      receipts: input.instances.map((instance) => ({
        instanceId: instance.instanceId,
        fileName: instance.fileName,
        sourceUrl: instance.sourceUrl,
        localArtifactPath: instance.localArtifactPath,
        sourceHash: instance.sourceHash,
        loadedVia: instance.loadedVia,
      })),
      evidenceHash: hashEvidence(input.instances),
    });
    await writeJson(join(root, "DIMACS_PARSED_INSTANCES.json"), {
      kind: "dimacs_parsed_instances",
      instances: input.instances,
      evidenceHash: hashEvidence(input.instances),
    });
    await writeJson(join(root, "DIMACS_FROZEN_PREDICTIONS.json"), {
      kind: "dimacs_frozen_predictions",
      predictions: input.executions,
      evidenceHash: hashEvidence(input.executions),
    });
    await writeJson(join(root, "DIMACS_BASELINE_RIVAL_RESULTS.json"), {
      kind: "dimacs_baseline_rival_results",
      baselines: dimacsBaselineRows(input.instances),
      rivals: dimacsRivalRows(input.instances),
      evidenceHash: hashEvidence(input.instances),
    });
    await writeJson(join(root, "DIMACS_COUNTEREXAMPLE_RESULTS.json"), {
      kind: "dimacs_counterexample_results",
      counterexamples: dimacsCounterexampleRows(input.instances),
      evidenceHash: hashEvidence(dimacsCounterexampleRows(input.instances)),
    });
    await writeJson(join(root, "DIMACS_HOLDOUT_REPLAY_RESULTS.json"), {
      kind: "dimacs_holdout_replay_results",
      holdouts: dimacsHoldoutRows(input.instances),
      replay: dimacsReplayRows(input.instances),
      evidenceHash: hashEvidence(input.instances),
    });
    await writeJson(join(root, "DIMACS_PROOF_MECHANISM_PRESSURE.json"), {
      kind: "dimacs_proof_mechanism_pressure",
      exactFormalClaim: input.decision.exactFormalClaim,
      proofMechanismStatus: input.decision.proofMechanismStatus,
      killReasons: input.decision.killReasons,
      sourceKnownPriorRefs: [
        `${dimacsSourceAnchor}#MYC`,
        `${dimacsSourceAnchor}#queen`,
      ],
      evidenceHash: hashEvidence(input.decision),
    });
    await writeJson(
      join(root, "FUND_GATE_RESULTS.json"),
      input.report.fundGateResult,
    );
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "dimacs_boundary_closure_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      killed: input.report.killed,
      primaryDeathCause: input.report.primaryDeathCause,
      reportRef: `${daemonArtifactRoot}/${dimacsBoundaryClosureDir}/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "DIMACS_CANDIDATE_PROFILE.md"),
      dimacsCandidateProfileMarkdown(input.report, input.candidate),
    );
    await writeText(
      join(root, "DIMACS_INSTANCE_RECEIPTS.md"),
      dimacsInstanceReceiptsMarkdown(input.instances),
    );
    await writeText(
      join(root, "DIMACS_FROZEN_PREDICTIONS.md"),
      dimacsFrozenPredictionsMarkdown(input.executions),
    );
    await writeText(
      join(root, "DIMACS_BASELINE_RIVAL_RESULTS.md"),
      dimacsBaselineRivalMarkdown(input.instances),
    );
    await writeText(
      join(root, "DIMACS_COUNTEREXAMPLE_RESULTS.md"),
      dimacsCounterexampleMarkdown(input.instances),
    );
    await writeText(
      join(root, "DIMACS_HOLDOUT_REPLAY_RESULTS.md"),
      dimacsHoldoutReplayMarkdown(input.instances),
    );
    await writeText(
      join(root, "DIMACS_PROOF_MECHANISM_PRESSURE.md"),
      dimacsProofMechanismMarkdown(input.decision),
    );
    await writeText(
      join(root, "DIMACS_PROMOTION_DECISION.md"),
      dimacsPromotionDecisionMarkdown(input.report),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      dimacsFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      dimacsNextCheckpointMarkdown(input.report),
    );
  }
}

async function loadDimacsText(
  sourceUrl: string,
  fileName: string,
): Promise<{ text: string; loadedVia: "fetch" | "fixture_fallback" }> {
  if (process.env.SOVRYN_DIMACS_FIXTURE_ONLY === "1") {
    return {
      text: dimacsFixtureText(fileName),
      loadedVia: "fixture_fallback",
    };
  }
  try {
    const response = await fetch(sourceUrl);
    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    const text = await response.text();
    if (!text.includes("p edge") || !/\be\s+\d+\s+\d+/.test(text)) {
      throw new Error("not a DIMACS edge file");
    }
    return { text, loadedVia: "fetch" };
  } catch {
    return {
      text: dimacsFixtureText(fileName),
      loadedVia: "fixture_fallback",
    };
  }
}

export function parseDimacsGraph(input: {
  text: string;
  fileName: string;
  sourceUrl: string;
  localArtifactPath: string;
  loadedVia: "fetch" | "fixture_fallback";
  spec: DimacsTargetSpec;
}): ParsedDimacsGraph {
  const header = /\bp\s+edge\s+(\d+)\s+(\d+)/i.exec(input.text);
  if (header === null) {
    throw new Error(`DIMACS header missing for ${input.fileName}`);
  }
  const declaredNodes = Number(header[1]);
  const declaredEdges = Number(header[2]);
  const edgeSet = new Set<string>();
  const edgePattern = /\be\s+(\d+)\s+(\d+)/gi;
  let match: RegExpExecArray | null;
  while ((match = edgePattern.exec(input.text)) !== null) {
    const left = Number(match[1]);
    const right = Number(match[2]);
    if (!Number.isFinite(left) || !Number.isFinite(right) || left === right) {
      continue;
    }
    const a = Math.min(left, right);
    const b = Math.max(left, right);
    edgeSet.add(`${a}-${b}`);
  }
  const graph = adjacencyFromEdges(declaredNodes, edgeSet);
  const degrees = Array.from(graph.values()).map((neighbors) => neighbors.size);
  const parsedEdges = edgeSet.size;
  const density =
    declaredNodes <= 1
      ? 0
      : (2 * parsedEdges) / (declaredNodes * (declaredNodes - 1));
  const cliqueLowerBound = greedyCliqueLowerBound(graph);
  const greedyColorUpperBound = greedyColorCount(graph);
  return {
    kind: "parsed_dimacs_graph",
    instanceId: input.fileName.replace(/\.col$/i, ""),
    fileName: input.fileName,
    sourceUrl: input.sourceUrl,
    localArtifactPath: input.localArtifactPath,
    sourceHash: createHash("sha256").update(input.text).digest("hex"),
    loadedVia: input.loadedVia,
    family: input.spec.family,
    role: input.spec.role,
    expectedColor: input.spec.expectedColor,
    declaredNodes,
    declaredEdges,
    parsedNodes: graph.size,
    parsedEdges,
    density: roundMetric(density),
    maxDegree: Math.max(...degrees, 0),
    avgDegree: roundMetric(
      degrees.reduce((sum, degree) => sum + degree, 0) /
        Math.max(1, degrees.length),
    ),
    cliqueLowerBound,
    greedyColorUpperBound,
    residualVsClique: input.spec.expectedColor - cliqueLowerBound,
    residualVsGreedy: input.spec.expectedColor - greedyColorUpperBound,
  };
}

function adjacencyFromEdges(
  nodeCount: number,
  edgeSet: Set<string>,
): Map<number, Set<number>> {
  const graph = new Map<number, Set<number>>();
  for (let node = 1; node <= nodeCount; node += 1) {
    graph.set(node, new Set<number>());
  }
  for (const edge of edgeSet) {
    const [left, right] = edge.split("-").map(Number);
    if (!left || !right) continue;
    graph.get(left)?.add(right);
    graph.get(right)?.add(left);
  }
  return graph;
}

function greedyCliqueLowerBound(graph: Map<number, Set<number>>): number {
  const nodes = Array.from(graph.keys()).sort(
    (left, right) =>
      (graph.get(right)?.size ?? 0) - (graph.get(left)?.size ?? 0),
  );
  let best = 0;
  for (const start of nodes.slice(0, 80)) {
    const clique = [start];
    for (const candidate of nodes) {
      if (candidate === start) continue;
      if (
        clique.every((member) => graph.get(candidate)?.has(member) === true)
      ) {
        clique.push(candidate);
      }
    }
    best = Math.max(best, clique.length);
  }
  return Math.max(1, best);
}

function greedyColorCount(graph: Map<number, Set<number>>): number {
  const nodes = Array.from(graph.keys()).sort(
    (left, right) =>
      (graph.get(right)?.size ?? 0) - (graph.get(left)?.size ?? 0),
  );
  const colors = new Map<number, number>();
  for (const node of nodes) {
    const used = new Set<number>();
    for (const neighbor of graph.get(node) ?? []) {
      const color = colors.get(neighbor);
      if (color !== undefined) used.add(color);
    }
    let color = 1;
    while (used.has(color)) color += 1;
    colors.set(node, color);
  }
  return Math.max(...colors.values(), 0);
}

function roundMetric(value: number): number {
  return Math.round(value * 10000) / 10000;
}

