async function generatorBornDiscoveryClaimLiftDecision(input: {
  root: string;
  requirement: GeneratorBornDiscoveryClaimLiftRequirement;
  proposal: GeneratorBornDiscoveryClaimLiftProposal | null;
  proposalRef: string;
}): Promise<GeneratorBornDiscoveryClaimLiftDecision> {
  const proposal = input.proposal;
  const claim = normalizeWhitespace(proposal?.exactTargetOutcomeClaim ?? "");
  const claimLower = claim.toLowerCase();
  const allEvidenceRefs = proposal
    ? uniqueStrings([
        ...proposal.externalSignificanceEvidenceRefs,
        ...proposal.sourceEvidenceRefs,
        ...proposal.baselineRefs,
        ...proposal.rivalRefs,
        ...proposal.holdoutRefs,
        ...proposal.replayRefs,
        ...proposal.counterexampleRefs,
        ...proposal.mechanismPressureRefs,
      ])
    : [];
  const antiDiscoveryText =
    /\bnot (a )?discovery fund\b|\bnot fund_found\b|\bnot einstein\b|\bnot nobel\b|\bthis remains an insightcandidate only\b|\bdeserves downstream\b/.test(
      claimLower,
    );
  const pipelineScopeOnly =
    /\bgenerator-born\b|\bruntime evidence\b|\bpipeline success\b|\bpipeline evidence\b/.test(
      claimLower,
    );
  const overclaimText =
    /\bnobel\b|\beinstein\b|\bbreakthrough\b|\bexternal validation\b|\bexternal adoption\b|\bagi\b|\bhuman-level science\b|\buniversal truth\b/.test(
      claimLower,
    );
  const explicitDomainSignificance =
    /\bdomain scientific significance\b|\bscientific significance\b|\bchanges? interpretation\b|\bpreviously unknown\b|\bnovel scientific\b|\bnew mechanism across real targets\b|\bvalidated conjecture\b|\bchecked proof\b|\bchecked refutation\b/.test(
      claimLower,
    );
  const externalRefs = proposal?.externalSignificanceEvidenceRefs ?? [];
  const gates = [
    gate(
      "claim_lift_proposal_present",
      proposal !== null,
      "A claim lift requires an explicit proposal artifact; generated closure rows alone cannot create a DiscoveryCandidate.",
    ),
    gate(
      "new_stable_discovery_candidate_id",
      proposal !== null &&
        proposal.targetDiscoveryCandidateId.startsWith("DISCOVERY-LIFT-") &&
        proposal.targetDiscoveryCandidateId !== input.requirement.candidateId &&
        proposal.targetDiscoveryCandidateId !==
          input.requirement.discoveryCandidateId,
      "Semantic claim lift must create a new stable DiscoveryCandidate ID, not reuse the InsightCandidate or prior closure candidate ID.",
    ),
    gate(
      "exact_target_outcome_claim",
      claim.length >= 120 &&
        !antiDiscoveryText &&
        !pipelineScopeOnly &&
        explicitDomainSignificance,
      "The lifted claim must be a precise target-outcome claim with explicit domain significance and no anti-discovery or pipeline-scope caveat.",
    ),
    gate(
      "external_significance_evidence_refs",
      externalSignificanceRefsMeetMinimum(externalRefs),
      "Claim lift requires at least two external public significance refs, not only local generator closure artifacts.",
    ),
    gate(
      "runtime_and_source_evidence_refs",
      proposal !== null &&
        proposal.createdFromRuntimeEvidence === true &&
        proposal.sourceEvidenceRefs.length >= 3 &&
        allEvidenceRefs.every(publicSafeRef),
      "Claim lift must bind runtime/source evidence refs that are public-safe and were created from real runtime evidence.",
    ),
    gate(
      "claim_lift_evidence_refs_resolve",
      proposal !== null &&
        (await claimLiftEvidenceRefsResolvable(input.root, allEvidenceRefs)),
      "All non-URL claim-lift evidence refs must resolve to local artifacts before DiscoveryCandidate creation.",
    ),
    gate(
      "baseline_rival_holdout_replay_counterexample_mechanism_refs",
      proposal !== null &&
        proposal.baselineRefs.length > 0 &&
        proposal.rivalRefs.length > 0 &&
        proposal.holdoutRefs.length > 0 &&
        proposal.replayRefs.length > 0 &&
        proposal.counterexampleRefs.length > 0 &&
        proposal.mechanismPressureRefs.length > 0,
      "Claim lift must bind baseline, rival, holdout, replay, counterexample, and mechanism-pressure refs before DiscoveryCandidate creation.",
    ),
    gate(
      "no_text_only_lift",
      allEvidenceRefs.filter(
        (ref) => !ref.includes(`/${generatorFundClosureDir}/`),
      ).length >= 6,
      "A text rewrite of the generator closure package is not enough; the lift needs independent evidence refs outside the closure ledger.",
    ),
    gate(
      "no_overclaim",
      proposal !== null && proposal.noOverclaim === true && !overclaimText,
      "The lifted claim must avoid Nobel, Einstein, breakthrough, external-validation, AGI, and universal-truth language.",
    ),
  ];
  const failedGates = gates
    .filter((item) => !item.passed)
    .map((item) => item.code);
  const decision = {
    kind: "generator_born_discovery_claim_lift_decision" as const,
    candidateId: input.requirement.candidateId,
    priorDiscoveryCandidateId: input.requirement.discoveryCandidateId,
    targetDiscoveryCandidateId: proposal?.targetDiscoveryCandidateId ?? null,
    accepted: failedGates.length === 0,
    status:
      failedGates.length === 0
        ? ("ready_for_discovery_candidate" as const)
        : ("blocked" as const),
    gates,
    failedGates,
    requiredChange:
      failedGates.length === 0
        ? "Claim lift is ready for the next DiscoveryCandidate/FundCandidateDraft construction step; Fund Gate remains unchanged and has not been notified."
        : input.requirement.requiredChange,
    proposalRef: proposal === null ? null : input.proposalRef,
    evidenceHash: "",
  };
  return { ...decision, evidenceHash: hashEvidence(decision) };
}

async function generatorBornDiscoveryClaimLiftProposalBuildDecision(input: {
  root: string;
  requirement: GeneratorBornDiscoveryClaimLiftRequirement;
}): Promise<GeneratorBornDiscoveryClaimLiftProposalBuildDecision> {
  const packageRef = input.requirement.externalReviewPackagePath ?? "";
  const packageBindingsPath =
    packageRef.length > 0 && publicSafeRef(packageRef)
      ? join(input.root, packageRef, "CLAIM_EVIDENCE_BINDINGS.json")
      : "";
  const bindings =
    packageBindingsPath.length > 0
      ? await readOptionalJson<Record<string, unknown>>(packageBindingsPath)
      : null;
  const forwardSourceSignalRefs =
    await generatorBornClaimLiftForwardSourceSignalRefs({
      root: input.root,
      packageRef,
      candidateId: input.requirement.candidateId,
    });
  const forwardCandidateContract =
    await generatorBornClaimLiftForwardCandidateContract({
      root: input.root,
      packageRef,
      candidateId: input.requirement.candidateId,
    });
  const proposalCandidate = isRecord(bindings?.claimLiftProposalCandidate)
    ? bindings.claimLiftProposalCandidate
    : forwardCandidateContract;
  const scaffold = await generatorBornDiscoveryClaimLiftProposalScaffold(
    input.root,
    input.requirement,
  );
  const exactTargetOutcomeClaim = normalizeWhitespace(
    String(proposalCandidate?.exactTargetOutcomeClaim ?? ""),
  );
  const mechanismHypothesis = normalizeWhitespace(
    String(proposalCandidate?.mechanismHypothesis ?? ""),
  );
  const proposal: GeneratorBornDiscoveryClaimLiftProposal | null =
    proposalCandidate === null
      ? null
      : {
          kind: "generator_born_discovery_claim_lift_proposal" as const,
          parentCandidateId: input.requirement.candidateId,
          targetDiscoveryCandidateId:
            typeof proposalCandidate.targetDiscoveryCandidateId === "string"
              ? proposalCandidate.targetDiscoveryCandidateId
              : generatorBornDiscoveryClaimLiftTargetId(input.requirement),
          domain: scaffold.domain,
          exactTargetOutcomeClaim,
          mechanismHypothesis,
          externalSignificanceEvidenceRefs: uniqueStrings([
            ...stringArray(proposalCandidate.externalSignificanceEvidenceRefs),
            ...scaffold.externalSignificanceEvidenceRefs,
          ]),
          sourceEvidenceRefs: uniqueStrings([
            ...stringArray(proposalCandidate.sourceEvidenceRefs),
            ...scaffold.sourceEvidenceRefs,
          ]),
          baselineRefs: uniqueStrings([
            ...stringArray(proposalCandidate.baselineRefs),
            ...scaffold.baselineRefs,
          ]),
          rivalRefs: uniqueStrings([
            ...stringArray(proposalCandidate.rivalRefs),
            ...scaffold.rivalRefs,
          ]),
          holdoutRefs: uniqueStrings([
            ...stringArray(proposalCandidate.holdoutRefs),
            ...scaffold.holdoutRefs,
          ]),
          replayRefs: uniqueStrings([
            ...stringArray(proposalCandidate.replayRefs),
            ...scaffold.replayRefs,
          ]),
          counterexampleRefs: uniqueStrings([
            ...stringArray(proposalCandidate.counterexampleRefs),
            ...scaffold.counterexampleRefs,
          ]),
          mechanismPressureRefs: uniqueStrings([
            ...stringArray(proposalCandidate.mechanismPressureRefs),
            ...scaffold.mechanismPressureRefs,
          ]),
          nontrivialInsightEvidenceRefs: uniqueStrings([
            ...stringArray(proposalCandidate.nontrivialInsightEvidenceRefs),
            ...stringArray(bindings?.nontrivialInsightEvidenceRefs),
            ...stringArray(bindings?.insightEvidenceRefs),
            ...forwardSourceSignalRefs,
          ]),
          domainSignificanceEvidenceRefs: uniqueStrings([
            ...stringArray(proposalCandidate.domainSignificanceEvidenceRefs),
            ...stringArray(bindings?.domainSignificanceEvidenceRefs),
            ...forwardSourceSignalRefs,
          ]),
          identityLedgerRefs: uniqueStrings([
            ...stringArray(proposalCandidate.identityLedgerRefs),
            ...scaffold.identityLedgerRefs,
          ]),
          hardSeedRefs: uniqueStrings([
            ...stringArray(proposalCandidate.hardSeedRefs),
            ...scaffold.hardSeedRefs,
          ]),
          packageRef: scaffold.packageRef,
          predictionRefs: uniqueStrings([
            ...stringArray(proposalCandidate.predictionRefs),
            ...scaffold.predictionRefs,
          ]),
          killWeekRefs: uniqueStrings([
            ...stringArray(proposalCandidate.killWeekRefs),
            ...scaffold.killWeekRefs,
          ]),
          limitations: uniqueStrings([
            ...stringArray(proposalCandidate.limitations),
            ...scaffold.limitations,
          ]),
          createdFromRuntimeEvidence:
            proposalCandidate.createdFromRuntimeEvidence === true,
          noOverclaim: proposalCandidate.noOverclaim === true,
        };
  const claimDecision =
    proposal === null
      ? null
      : await generatorBornDiscoveryClaimLiftDecision({
          root: input.root,
          requirement: input.requirement,
          proposal,
          proposalRef: `${daemonArtifactRoot}/${generatorClaimLiftDir}/CLAIM_LIFT_BUILT_PROPOSALS.json#${input.requirement.candidateId}`,
        });
  const publicCorpusNegativeHistory =
    proposal === null
      ? await publicCorpusNegativeHistoryForClaimLiftCandidateText(
          input.root,
          normalizeWhitespace(
            [
              input.requirement.candidateId,
              input.requirement.discoveryCandidateId,
              input.requirement.exactClaim,
              input.requirement.externalReviewPackagePath,
            ].join(" "),
          ),
        )
      : await publicCorpusNegativeHistoryForClaimLiftProposal(
          input.root,
          proposal,
        );
  const sourceSignal =
    await generatorBornDiscoveryClaimLiftSourceSignalAssessment({
      root: input.root,
      packageRef,
      bindings,
      proposal,
      candidateId: input.requirement.candidateId,
    });
  const gates = [
    gate(
      "package_ref_present",
      packageRef.length > 0 && publicSafeRef(packageRef),
      "Proposal builder requires the generator-born external-review package path.",
    ),
    gate(
      "package_bindings_present",
      bindings !== null,
      "Proposal builder requires CLAIM_EVIDENCE_BINDINGS.json from the package.",
    ),
    gate(
      "explicit_package_claim_lift_candidate_present",
      proposalCandidate !== null,
      "Proposal builder cannot infer a DiscoveryCandidate from a failed frozen claim; the package or forward-only candidate preflight must bind an explicit claimLiftProposalCandidate.",
    ),
    gate(
      "new_claim_not_failed_frozen_claim",
      exactTargetOutcomeClaim.length > 0 &&
        exactTargetOutcomeClaim !==
          normalizeWhitespace(input.requirement.exactClaim),
      "Proposal builder must not recycle the frozen InsightCandidate claim that already failed domain-significance pressure.",
    ),
    gate(
      "candidate_claim_decision_accepts",
      claimDecision?.accepted === true,
      "The generated proposal must pass the full claim-lift decision gate before it can be written for DiscoveryCandidate creation.",
    ),
    gate(
      "public_corpus_negative_history_clear",
      !publicCorpusNegativeHistory.blocksSeedBirth,
      "Proposal builder must not write claim-lift proposals for external anchors already downgraded, rival-explained, or marked non-discovery in the public corpus.",
    ),
    gate(
      "source_package_lift_signal_bound",
      sourceSignal.liftSignalBound,
      "Proposal builder must not write a claim-lift proposal from a package that lacks explicit nontrivial-insight and domain-significance evidence refs.",
    ),
  ];
  const failedGates = gates
    .filter((item) => !item.passed)
    .map((item) => item.code);
  const ready = failedGates.length === 0 && proposal !== null;
  return withEvidenceHash({
    kind: "generator_born_discovery_claim_lift_proposal_build_decision" as const,
    candidateId: input.requirement.candidateId,
    targetDiscoveryCandidateId: ready
      ? (proposal?.targetDiscoveryCandidateId ?? null)
      : null,
    publicCorpusNegativeHistory,
    sourceSignal,
    proposalReady: ready,
    proposal: ready ? proposal : null,
    gates: claimDecision === null ? gates : [...gates, ...claimDecision.gates],
    failedGates: uniqueStrings([
      ...failedGates,
      ...(claimDecision?.failedGates ?? []),
    ]),
    requiredChange: ready
      ? "Proposal is evidence-backed and may be consumed by generator-claim-lift; it is not a Fund and does not notify."
      : publicCorpusNegativeHistory.blocksSeedBirth
        ? "Retire this claim-lift proposal source; the public corpus already downgraded, rival-explained, or removed discovery-score eligibility for the matching external anchor."
        : !sourceSignal.liftSignalBound
          ? `Run a mechanism-specific lift experiment before proposal birth; current source package blocker is ${sourceSignal.primaryBlocker ?? "missing_lift_signal"}.`
          : "Bind an explicit package claimLiftProposalCandidate or forward-only candidate preflight contract with a new stable DiscoveryCandidate ID, exact target-outcome claim, real external significance refs, runtime/source refs, and downstream gate refs. The builder must not infer this from failed frozen claim text.",
  });
}

async function generatorBornClaimLiftForwardSourceSignalRefs(input: {
  root: string;
  packageRef: string;
  candidateId: string | null;
}): Promise<string[]> {
  if (input.packageRef.length === 0 && input.candidateId === null) return [];
  const report =
    await readOptionalJson<GeneratorBornDiscoveryClaimLiftSourceSignalReport>(
      join(
        input.root,
        daemonArtifactRoot,
        generatorClaimLiftDir,
        "SOURCE_SIGNAL_BINDINGS.json",
      ),
    );
  if (report === null) return [];
  const match = report.decisions.find(
    (decision) =>
      decision.sourceSignalStatus === "source_signal_bound" &&
      ((input.packageRef.length > 0 &&
        decision.packageRef === input.packageRef) ||
        (input.candidateId !== null &&
          decision.candidateId === input.candidateId) ||
        (input.candidateId !== null &&
          decision.sourceCandidateId === input.candidateId)),
  );
  return match?.bindableInsightEvidenceRefs ?? [];
}

async function generatorBornClaimLiftForwardCandidateContract(input: {
  root: string;
  packageRef: string;
  candidateId: string | null;
}): Promise<Record<string, unknown> | null> {
  if (input.packageRef.length === 0 && input.candidateId === null) return null;
  const report =
    await readOptionalJson<GeneratorBornDiscoveryClaimLiftCandidatePreflightReport>(
      join(
        input.root,
        daemonArtifactRoot,
        generatorClaimLiftDir,
        "CLAIM_LIFT_CANDIDATE_PREFLIGHT.json",
      ),
    );
  if (report === null) return null;
  const match = report.decisions.find(
    (decision) =>
      decision.candidateContractStatus === "candidate_contract_ready" &&
      decision.candidateContract !== null &&
      ((input.packageRef.length > 0 &&
        decision.packageRef === input.packageRef) ||
        (input.candidateId !== null &&
          decision.candidateId === input.candidateId)),
  );
  return match?.candidateContract ?? null;
}

function generatorBornClaimLiftDomainFailedGates(input: {
  requirement: GeneratorBornDiscoveryClaimLiftRequirement;
  bindings: Record<string, unknown> | null;
}): string[] {
  const domainAssessment = isRecord(
    input.bindings?.domainSignificanceAssessment,
  )
    ? input.bindings.domainSignificanceAssessment
    : null;
  return uniqueStrings([
    ...input.requirement.failedDomainSignificanceGates,
    ...stringArray(domainAssessment?.failedGates),
  ]);
}

function generatorBornClaimLiftLiftableDomainGate(
  gateId: string,
  noveltyPressure?:
    | GeneratorBornDiscoveryClaimLiftNoveltyPressureDecision
    | undefined,
): boolean {
  if (
    gateId === "not_ordinary_known_mechanism" &&
    noveltyPressure?.noveltyPressureStatus === "novelty_pressure_cleared"
  ) {
    return true;
  }
  return [
    "no_anti_discovery_claim_text",
    "explicit_domain_significance_claim",
  ].includes(gateId);
}

function generatorBornClaimLiftFatalDomainGate(
  gateId: string,
  noveltyPressure?:
    | GeneratorBornDiscoveryClaimLiftNoveltyPressureDecision
    | undefined,
): boolean {
  if (
    gateId === "not_ordinary_known_mechanism" &&
    noveltyPressure?.noveltyPressureStatus === "novelty_pressure_cleared"
  ) {
    return false;
  }
  return [
    "not_ordinary_known_mechanism",
    "known_trivial",
    "known_source_family_mechanism",
    "source_family_triviality",
    "benchmark_family_triviality",
    "rival_stronger",
    "rival_theory_stronger",
  ].includes(gateId);
}

async function generatorBornClaimLiftCandidateContractFromSourceSignal(input: {
  root: string;
  requirement: GeneratorBornDiscoveryClaimLiftRequirement;
  bindings: Record<string, unknown>;
  sourceSignal: GeneratorBornDiscoveryClaimLiftSourceSignalDecision;
  scaffold: GeneratorBornDiscoveryClaimLiftProposalScaffold;
}): Promise<GeneratorBornDiscoveryClaimLiftProposal | null> {
  const sourceCache =
    input.sourceSignal.sourceCacheRef === null
      ? null
      : await readOptionalJson<DiscoveryAnchorRuntimeSourceArtifact>(
          join(input.root, input.sourceSignal.sourceCacheRef),
        );
  const sourceRefs = uniqueStrings([
    ...input.sourceSignal.bindableInsightEvidenceRefs,
    ...input.scaffold.sourceEvidenceRefs,
  ]);
  const externalRefs = uniqueStrings([
    ...input.scaffold.externalSignificanceEvidenceRefs,
    ...sourceRefs.filter(externalSignificanceRef),
  ]).slice(0, 8);
  if (!externalSignificanceRefsMeetMinimum(externalRefs)) return null;
  const targetOutcome = normalizeWhitespace(
    optionalString(sourceCache?.targetOutcome) ??
      optionalString(sourceCache?.measuredVariable) ??
      input.requirement.exactClaim,
  );
  const residual =
    typeof sourceCache?.residualMagnitude === "number"
      ? ` with residual magnitude ${sourceCache.residualMagnitude}`
      : "";
  const exactTargetOutcomeClaim = normalizeWhitespace(
    `The measured public ${input.requirement.domain ?? "scientific"} target outcome shows domain scientific significance: ${targetOutcome}${residual} remains after the recorded baseline, rival, holdout, replay, counterexample, recurrence, and mechanism-pressure checks. The claim is limited to the cited public targets, recorded measurement scope, and the evidence package refs, and it requires independent external review before any broader interpretation.`,
  );
  const mechanismHypothesis = normalizeWhitespace(
    optionalString(sourceCache?.measuredVariable) ??
      "The candidate mechanism predicts the measured target outcome better than the named rival mechanisms within the bounded public target slice.",
  );
  return {
    kind: "generator_born_discovery_claim_lift_proposal",
    parentCandidateId: input.requirement.candidateId,
    targetDiscoveryCandidateId: generatorBornDiscoveryClaimLiftTargetId(
      input.requirement,
    ),
    domain: input.scaffold.domain,
    exactTargetOutcomeClaim,
    mechanismHypothesis,
    externalSignificanceEvidenceRefs: externalRefs,
    sourceEvidenceRefs: sourceRefs,
    baselineRefs: input.scaffold.baselineRefs,
    rivalRefs: input.scaffold.rivalRefs,
    holdoutRefs: input.scaffold.holdoutRefs,
    replayRefs: input.scaffold.replayRefs,
    counterexampleRefs: input.scaffold.counterexampleRefs,
    mechanismPressureRefs: input.scaffold.mechanismPressureRefs,
    nontrivialInsightEvidenceRefs: sourceRefs,
    domainSignificanceEvidenceRefs: externalRefs,
    identityLedgerRefs: input.scaffold.identityLedgerRefs,
    hardSeedRefs: input.scaffold.hardSeedRefs,
    packageRef: input.scaffold.packageRef,
    predictionRefs: input.scaffold.predictionRefs,
    killWeekRefs: input.scaffold.killWeekRefs,
    limitations: uniqueStrings([
      ...input.scaffold.limitations,
      "Forward-only claim-lift candidate contract; not a Fund, not externally validated, and blocked if ordinary-known mechanism pressure is unresolved.",
    ]),
    createdFromRuntimeEvidence: true,
    noOverclaim: true,
  };
}

async function generatorBornDiscoveryClaimLiftSourceSignalAssessment(input: {
  root: string;
  packageRef: string;
  bindings: Record<string, unknown> | null;
  proposal: GeneratorBornDiscoveryClaimLiftProposal | null;
  candidateId?: string;
}): Promise<GeneratorBornDiscoveryClaimLiftSourceSignalAssessment> {
  const packageCandidatePath =
    input.packageRef.length > 0 && publicSafeRef(input.packageRef)
      ? join(input.root, input.packageRef, "FUND_CANDIDATE.json")
      : "";
  const payload =
    packageCandidatePath.length > 0
      ? await readOptionalJson<{
          candidate?: FundCandidate;
          fundClass?: string;
        }>(packageCandidatePath)
      : null;
  const boundCandidate = isRecord(input.bindings?.fundCandidate)
    ? (input.bindings.fundCandidate as FundCandidate)
    : null;
  const candidate = payload?.candidate ?? boundCandidate;
  const forwardSourceSignalRefs =
    await generatorBornClaimLiftForwardSourceSignalRefs({
      root: input.root,
      packageRef: input.packageRef,
      candidateId:
        input.candidateId ??
        (typeof candidate?.candidateId === "string"
          ? candidate.candidateId
          : null),
    });
  const insightEvidenceRefs = uniqueStrings([
    ...(candidate?.insightEvidenceRefs ?? []),
    ...stringArray(input.bindings?.insightEvidenceRefs),
    ...stringArray(input.bindings?.nontrivialInsightEvidenceRefs),
    ...stringArray(input.bindings?.domainSignificanceEvidenceRefs),
    ...(input.proposal?.nontrivialInsightEvidenceRefs ?? []),
    ...(input.proposal?.domainSignificanceEvidenceRefs ?? []),
    ...forwardSourceSignalRefs,
  ]).filter(publicSafeRef);
  const insightEvidenceRefsResolve =
    insightEvidenceRefs.length >= 2 &&
    (await claimLiftEvidenceRefsResolvable(input.root, insightEvidenceRefs));
  const nontrivialNewInsightAcrossRealTargets =
    candidate?.nontrivialNewInsightAcrossRealTargets === true ||
    optionalBoolean(input.bindings?.nontrivialNewInsightAcrossRealTargets) ===
      true ||
    insightEvidenceRefs.length >= 2;
  const domainScientificSignificance =
    candidate?.domainScientificSignificance === true ||
    optionalBoolean(input.bindings?.domainScientificSignificance) === true ||
    (input.proposal?.domainSignificanceEvidenceRefs ?? []).length > 0 ||
    forwardSourceSignalRefs.length >= 2;
  const sourceCandidateId =
    typeof candidate?.candidateId === "string" ? candidate.candidateId : null;
  const sourceFundClass =
    optionalString(payload?.fundClass) ??
    (isRecord(candidate) ? optionalString(candidate.fundClass) : null);
  const primaryBlocker =
    candidate === null
      ? "missing_source_package_candidate"
      : !nontrivialNewInsightAcrossRealTargets
        ? "missing_nontrivial_new_insight_evidence"
        : !domainScientificSignificance
          ? "missing_domain_scientific_significance"
          : !insightEvidenceRefsResolve
            ? "unresolved_or_missing_lift_signal_refs"
            : null;
  const assessment = {
    kind: "generator_born_discovery_claim_lift_source_signal_assessment" as const,
    packageRef:
      input.packageRef.length > 0 && publicSafeRef(input.packageRef)
        ? input.packageRef
        : null,
    sourceCandidateId,
    sourceFundClass,
    nontrivialNewInsightAcrossRealTargets,
    domainScientificSignificance,
    insightEvidenceRefs,
    insightEvidenceRefsResolve,
    liftSignalBound: primaryBlocker === null,
    primaryBlocker,
    evidenceHash: "",
  };
  return { ...assessment, evidenceHash: hashEvidence(assessment) };
}

async function claimLiftEvidenceRefsResolvable(
  root: string,
  refs: string[],
): Promise<boolean> {
  if (refs.length === 0) return false;
  for (const ref of refs) {
    if (!publicSafeRef(ref)) return false;
    if (ref.startsWith("https://")) continue;
    const pathPart = ref.split("#")[0]?.trim() ?? "";
    if (pathPart.length === 0 || pathPart.startsWith("/")) return false;
    if (!(await exists(join(root, pathPart)))) return false;
  }
  return true;
}

async function generatorBornDiscoveryClaimLiftDraftDecision(input: {
  root: string;
  decision: GeneratorBornDiscoveryClaimLiftDecision;
  proposal: GeneratorBornDiscoveryClaimLiftProposal;
  draftRef: string | null;
  validationRef: string | null;
}): Promise<GeneratorBornDiscoveryClaimLiftDraftDecision> {
  const draftEvidenceRefs = uniqueStrings([
    ...input.proposal.sourceEvidenceRefs,
    ...input.proposal.baselineRefs,
    ...input.proposal.rivalRefs,
    ...input.proposal.holdoutRefs,
    ...input.proposal.replayRefs,
    ...input.proposal.counterexampleRefs,
    ...input.proposal.mechanismPressureRefs,
    ...(input.proposal.predictionRefs ?? []),
    ...(input.proposal.killWeekRefs ?? []),
  ]);
  const identityLedgerRefs = input.proposal.identityLedgerRefs ?? [];
  const hardSeedRefs = input.proposal.hardSeedRefs ?? [];
  const packageRef = input.proposal.packageRef ?? "";
  const limitations = input.proposal.limitations ?? [];
  const gates = [
    gate(
      "accepted_claim_lift",
      input.decision.accepted,
      "FundCandidateDraft construction requires a fully accepted claim lift.",
    ),
    gate(
      "draft_domain_present",
      input.proposal.domain !== undefined &&
        discoveryDaemonDomains().includes(input.proposal.domain),
      "Draft-ready claim lifts must declare a valid discovery daemon domain.",
    ),
    gate(
      "draft_evidence_refs_resolve",
      await claimLiftEvidenceRefsResolvable(input.root, draftEvidenceRefs),
      "Draft-ready claim lifts must resolve runtime, baseline, rival, holdout, replay, counterexample, prediction, mechanism, and kill-week refs.",
    ),
    gate(
      "draft_identity_refs_resolve",
      identityLedgerRefs.length > 0 &&
        (await claimLiftEvidenceRefsResolvable(input.root, identityLedgerRefs)),
      "Draft-ready claim lifts must bind resolvable candidate identity ledger refs.",
    ),
    gate(
      "draft_hard_seed_refs_resolve",
      hardSeedRefs.length > 0 &&
        (await claimLiftEvidenceRefsResolvable(input.root, hardSeedRefs)),
      "Draft-ready claim lifts must bind resolvable hard-seed refs.",
    ),
    gate(
      "draft_package_ref_resolves",
      await claimLiftPackageRefResolvable(input.root, packageRef),
      "Draft-ready claim lifts must bind an inspectability package containing all required package files.",
    ),
    gate(
      "draft_prediction_refs_present",
      (input.proposal.predictionRefs ?? []).length > 0,
      "Draft-ready claim lifts must bind frozen prediction refs.",
    ),
    gate(
      "draft_kill_week_refs_present",
      (input.proposal.killWeekRefs ?? []).length > 0,
      "Draft-ready claim lifts must bind kill-week refs.",
    ),
    gate(
      "draft_limitations_present",
      limitations.length >= 2,
      "Draft-ready claim lifts must carry explicit limitations.",
    ),
  ];
  const failedGates = gates
    .filter((item) => !item.passed)
    .map((item) => item.code);
  return withEvidenceHash({
    kind: "generator_born_discovery_claim_lift_draft_decision" as const,
    candidateId: input.decision.candidateId,
    targetDiscoveryCandidateId: input.decision.targetDiscoveryCandidateId,
    draftReady: failedGates.length === 0,
    draftRef: failedGates.length === 0 ? input.draftRef : null,
    validationRef: failedGates.length === 0 ? input.validationRef : null,
    gates,
    failedGates,
  });
}

async function claimLiftPackageRefResolvable(
  root: string,
  packageRef: string,
): Promise<boolean> {
  if (!publicSafeRef(packageRef) || packageRef.startsWith("/")) return false;
  for (const file of requiredFundPackageFiles) {
    if (!(await exists(join(root, packageRef, file)))) return false;
  }
  return true;
}

function generatorBornClaimLiftSignalEvidenceRefs(input: {
  candidate: FundCandidate | null;
  bindings: Record<string, unknown> | null;
  proposal: GeneratorBornDiscoveryClaimLiftProposal;
}): string[] {
  return uniqueStrings([
    ...(input.candidate?.insightEvidenceRefs ?? []),
    ...stringArray(input.bindings?.insightEvidenceRefs),
    ...stringArray(input.bindings?.nontrivialInsightEvidenceRefs),
    ...stringArray(input.bindings?.domainSignificanceEvidenceRefs),
    ...(input.proposal.nontrivialInsightEvidenceRefs ?? []),
    ...(input.proposal.domainSignificanceEvidenceRefs ?? []),
    ...input.proposal.externalSignificanceEvidenceRefs,
  ]).filter(publicSafeRef);
}

function generatorBornClaimLiftSignalPrimaryBlocker(input: {
  candidate: FundCandidate | null;
  evaluation: FundGateResult;
  failedGates: string[];
  signalEvidenceRefs: string[];
}): string {
  if (input.candidate === null) return "missing_fund_candidate_package";
  if (
    input.failedGates.includes("public_corpus_discovery_score_reconciliation")
  ) {
    return "public_corpus_downgrade";
  }
  if (input.failedGates.includes("structural_fund_gate_passed")) {
    return "fund_gate_structural_blocker";
  }
  if (
    input.failedGates.includes("nontrivial_new_insight_evidence_bound") ||
    input.signalEvidenceRefs.length < 2
  ) {
    return "missing_nontrivial_new_insight_evidence";
  }
  if (input.failedGates.includes("domain_scientific_significance_bound")) {
    return "missing_domain_scientific_significance";
  }
  if (
    input.evaluation.fundClass === "pipeline_fund_candidate" ||
    input.failedGates.includes("not_pipeline_fund_class")
  ) {
    return "pipeline_fund_candidate";
  }
  if (input.failedGates.includes("discovery_scored_fund_class")) {
    return "non_discovery_fund_class";
  }
  return input.failedGates[0] ?? "none";
}

function generatorBornClaimLiftSignalRequiredNextExperiment(
  blocker: string,
): string {
  switch (blocker) {
    case "missing_nontrivial_new_insight_evidence":
      return "Run a mechanism-specific lift experiment that binds new insightEvidenceRefs showing a nontrivial target-outcome pattern across real targets after baseline, rival, holdout, replay, counterexample, and mechanism pressure.";
    case "missing_domain_scientific_significance":
      return "Bind external domain-significance evidence showing why the measured target-outcome pattern changes scientific interpretation rather than only package inspectability.";
    case "pipeline_fund_candidate":
    case "non_discovery_fund_class":
      return "Keep the package as pipeline capability evidence and generate a new externally anchored target-outcome experiment before attempting discovery scoring.";
    case "fund_gate_structural_blocker":
      return "Repair the package or draft contract without changing Fund Gate semantics, then rerun signal pressure.";
    case "missing_fund_candidate_package":
      return "Create the forward-only package-bound FundCandidate artifact from a valid FundCandidateDraft before signal pressure.";
    case "public_corpus_downgrade":
      return "Do not re-score this package internally while the public corpus has downgraded the matching candidate from discovery scoring; create a new raw-reproducible package or repair the public package first.";
    default:
      return "Continue searching with exact blocker carried into the candidate graveyard.";
  }
}

function generatorBornDiscoveryClaimLiftSignalPressureBottleneck(
  decisions: GeneratorBornDiscoveryClaimLiftSignalPressureDecision[],
): string {
  if (decisions.length === 0) {
    return "No lifted claim packages are available for discovery-signal pressure; create package-backed claim lifts first.";
  }
  const ready = decisions.filter(
    (decision) => decision.signalStatus === "discovery_signal_ready",
  );
  if (ready.length > 0) {
    return `${ready.length} lifted claim package(s) are discovery-signal ready; run the explicit Fund notification path only if unchanged Fund Gate notification remains allowed.`;
  }
  const distribution = countBy(decisions, "primaryBlocker");
  return `All ${decisions.length} lifted claim package(s) remain blocked before discovery scoring. Dominant blockers: ${Object.entries(
    distribution,
  )
    .map(([blocker, count]) => `${blocker}=${count}`)
    .join(", ")}.`;
}

