function generatorBornDiscoveryClaimLiftSignalIntakeBlocker(
  failedGates: string[],
): string {
  if (failedGates.includes("rebind_decision_rebound")) {
    return "package_not_rebound";
  }
  if (
    failedGates.includes("package_ref_present") ||
    failedGates.includes("package_fund_candidate_present")
  ) {
    return "missing_package_candidate";
  }
  if (failedGates.includes("public_corpus_package_present")) {
    return "public_corpus_package_missing";
  }
  if (failedGates.includes("public_corpus_discovery_score_reconciliation")) {
    return "public_corpus_downgrade";
  }
  if (failedGates.includes("raw_source_reproduction_consistency")) {
    return "raw_source_reproduction_mismatch";
  }
  if (failedGates.includes("public_corpus_package_inspectability")) {
    return "public_corpus_package_incomplete";
  }
  if (
    failedGates.includes("rebind_discovery_scored") ||
    failedGates.includes("package_discovery_scored_fund_class")
  ) {
    return "non_discovery_fund_class";
  }
  if (
    failedGates.includes("rebind_notification_allowed") ||
    failedGates.includes("package_notification_allowed")
  ) {
    return "notification_not_allowed";
  }
  if (failedGates.includes("package_fund_gate_passed")) {
    return "package_fund_gate_failed";
  }
  return failedGates[0] ?? "unknown_requires_manual_review";
}

function generatorBornDiscoveryClaimLiftSignalIntakeBottleneck(input: {
  fundFound: boolean;
  eligibleCount: number;
  decisions: GeneratorBornDiscoveryClaimLiftSignalIntakeDecision[];
}): string {
  if (input.fundFound) {
    return "A package-backed claim-lift candidate was ingested through the existing package-backed cycle path; root Fund state was written only after unchanged Fund Gate notification remained allowed.";
  }
  if (input.eligibleCount > 0) {
    return "At least one package was eligible for root intake, but the package-backed cycle did not produce a discovery-scored Fund notification. Inspect SIGNAL_INTAKE_FUND_GATE_RESULTS.json.";
  }
  if (
    input.decisions.some(
      (decision) =>
        decision.primaryBlocker === "public_corpus_package_incomplete",
    )
  ) {
    return "A rebound package has discovery-scored internal evidence, but root intake requires a complete public corpus review package with machine-readable raw/formal reproduction evidence before Fund state can be written.";
  }
  if (input.decisions.length === 0) {
    return "No signal-rebind decisions are available for root package intake.";
  }
  const distribution = countBy(input.decisions, "primaryBlocker");
  const blockerSummary = Object.entries(distribution)
    .map(([blocker, count]) => `${blocker}=${count}`)
    .join(", ");
  const rawMetricMismatches = input.decisions.filter(
    (decision) =>
      decision.rawSourceReproductionConsistency.reason ===
      "raw_source_metrics_do_not_match_generator_runtime_evidence",
  ).length;
  if (rawMetricMismatches > 0) {
    return `No rebound package is eligible for root Fund intake. Blockers: ${blockerSummary}. Raw-source reproduction mismatch is already visible for ${rawMetricMismatches} package(s); public-package work cannot promote these until source-cache metrics match the bound generator runtime evidence.`;
  }
  return `No rebound package is eligible for root Fund intake. Blockers: ${blockerSummary}.`;
}

