function generatorBornPressureRow(input: {
  seed: HardSeed;
  output: GeneratorBornSourceOutput | null;
  runtimeEvidenceExists: boolean;
}): GeneratorBornPressureRow {
  const { seed, output } = input;
  const residual = output?.residualMagnitude ?? seed.confidenceScore / 100;
  const generatorId = String(
    seed.sourceSeed.generatorId ??
      seed.sourceSeed.anchorId ??
      generatorBornOutputId(output) ??
      "unknown",
  );
  const outputId = String(
    seed.sourceSeed.outputId ?? seed.sourceSeed.checkId ?? seed.seedId,
  );
  const runtimeEvidenceRef = output?.producedArtifact ?? null;
  const evidenceRefs = uniqueStrings([
    ...seed.sourceRefs,
    ...seed.evidenceRefs,
    ...seed.baselineRefs,
    ...seed.rivalRefs,
    ...seed.holdoutRefs,
    ...seed.replayRefs,
    ...seed.counterexampleRefs,
    runtimeEvidenceRef ?? "",
  ]).filter(Boolean);
  const publicUrls = evidenceRefs.filter((ref) => ref.startsWith("https://"));
  const localRefs = evidenceRefs.filter((ref) => ref.startsWith(".sovryn/"));
  const strongerBaselineExplains =
    output === null ||
    output.baselineResults.some((result) => result.explainsSignal) ||
    residual < 0.1;
  const rivalWeakened =
    output !== null &&
    output.rivalWeakened &&
    (seed.type === "checked_refutation_or_formal_boundary" || residual >= 0.1);
  const counterexampleSurvived =
    output !== null &&
    !output.counterexampleCollapsed &&
    seed.counterexampleRefs.length > 0;
  const recurrenceSupported =
    output !== null && output.crossSourceSupport && publicUrls.length >= 2;
  const domainSignificanceSupported =
    output?.birthEvaluation.domainSignificanceHypothesisGate?.accepted === true;
  const domainSignificanceEvidenceRefs = domainSignificanceRefsForOutput(
    output,
    publicUrls,
  );
  const holdoutReplaySupported =
    output !== null &&
    output.holdoutReplayAvailable &&
    seed.holdoutRefs.length > 0 &&
    seed.replayRefs.length > 0;
  const mechanismProofSurvived =
    seed.type === "checked_refutation_or_formal_boundary" ||
    (output !== null && residual >= 0.12);
  const anchor = seed.sourceSeed.externalProblemAnchor as
    | ExternalProblemAnchor
    | undefined;
  const externalProblemAnchored =
    anchor !== undefined &&
    typeof anchor.sourceRef === "string" &&
    anchor.sourceRef.startsWith("https://") &&
    evidenceRefs.includes(anchor.sourceRef);
  const inspectabilityComplete =
    input.runtimeEvidenceExists &&
    localRefs.length > 0 &&
    publicUrls.length > 0 &&
    evidenceRefs.every(publicSafeRef);
  const primaryKillReason = strongerBaselineExplains
    ? "baseline_dominated"
    : !rivalWeakened
      ? "rival_theory_stronger"
      : !counterexampleSurvived
        ? "counterexample_dense"
        : !recurrenceSupported
          ? "no_cross_source_support"
          : !holdoutReplaySupported
            ? "holdout_or_replay_failed"
            : !mechanismProofSurvived
              ? "proof_or_mechanism_failed"
              : !externalProblemAnchored
                ? "missing_external_problem_anchor"
                : !inspectabilityComplete
                  ? "not_externally_inspectable"
                  : "survived";
  return {
    seedId: seed.seedId,
    candidateId: seed.candidateId,
    domain: seed.domain,
    generatorId,
    outputId,
    exactClaim: seed.claim,
    evidenceRefs,
    runtimeEvidenceRef,
    measuredOutcome: output?.measuredOutcome ?? seed.confidenceScore,
    residual,
    mechanismHypothesis: generatorBornMechanismHypothesis(seed, output),
    rivalHypothesis: generatorBornRivalHypothesis(seed, output),
    domainSignificanceSupported,
    domainSignificanceEvidenceRefs,
    baseline: {
      passed: !strongerBaselineExplains,
      strongestBaseline:
        output?.baselineResults.find((result) => result.explainsSignal)
          ?.baseline ??
        output?.baselineResults[0]?.baseline ??
        "stronger_residual_floor_baseline",
      summary: strongerBaselineExplains
        ? "Second-stage pressure killed the hard seed before InsightCandidate birth because the residual is too small or a stronger simple baseline still explains it."
        : "The hard seed remains baseline-resistant under the second-stage residual floor and recorded simple baselines.",
    },
    rival: {
      weakened: rivalWeakened,
      summary: rivalWeakened
        ? "At least one rival mechanism remains weakened or scope-limited after second-stage pressure."
        : "The strongest rival mechanism remains too strong for InsightCandidate birth.",
    },
    counterexample: {
      survived: counterexampleSurvived,
      summary: counterexampleSurvived
        ? "Counterexample/control pressure did not collapse the narrow hard-seed claim."
        : "Counterexample/control pressure collapses or is missing for the narrow hard-seed claim.",
    },
    recurrence: {
      supported: recurrenceSupported,
      summary: recurrenceSupported
        ? "The hard seed retains cross-source or cross-slice support with at least two public refs."
        : "The hard seed lacks enough independent recurrence support after second-stage pressure.",
    },
    holdoutReplay: {
      supported: holdoutReplaySupported,
      summary: holdoutReplaySupported
        ? "Holdout and replay paths are both bound before InsightCandidate birth."
        : "Holdout or replay path is missing or only weakly bounded.",
    },
    mechanismProof: {
      survived: mechanismProofSurvived,
      summary: mechanismProofSurvived
        ? "Mechanism/proof pressure is nonfatal for the narrow evidence scope."
        : "Mechanism/proof pressure is fatal or underpowered for the proposed mechanism.",
    },
    inspectability: {
      complete: inspectabilityComplete,
      summary: inspectabilityComplete
        ? "Runtime evidence, local artifacts, and public-safe refs are inspectable enough for an InsightCandidate artifact."
        : "Inspectability is incomplete because runtime evidence or public-safe evidence refs are missing.",
    },
    primaryKillReason,
    insightCandidateCreated: false,
    insightCandidateRef: null,
    discoveryCandidateCreated: false,
  };
}

function generatorBornMechanismHypothesis(
  seed: HardSeed,
  output: GeneratorBornSourceOutput | null,
): string {
  if (isDiscoveryAnchorRuntimeCheck(output)) {
    return normalizeWhitespace(output.frozenPrediction);
  }
  if (output?.generatorId === "known_formal_problem_boundary_generator") {
    return "public-benchmark-anchored bounded formal boundary survives size density clique and trivial-rule controls across generated graph families";
  }
  if (output?.generatorId === "benchmark_delta_mechanism_generator") {
    return "public benchmark protocol perturbation delta survives split metric class-balance and stronger-model controls";
  }
  if (output?.generatorId === "public_measurement_residual_generator") {
    return "public measurement residual recurs after seasonality cadence missingness and source-family controls";
  }
  if (output?.generatorId === "satlib_bounded_sat_boundary_generator") {
    return "public SAT outcome boundary residual survives clause-variable ratio unit-propagation random-CNF and planted-control rivals";
  }
  if (output?.generatorId === "snap_network_cut_resilience_generator") {
    return "public network cut-resilience residual survives degree-sequence density component-size and random-rewire controls";
  }
  if (output?.generatorId === "openml_shift_instability_generator") {
    return "public benchmark dataset-shift instability residual survives class-imbalance metric split shuffled-label and stronger-model controls";
  }
  if (
    output?.generatorId ===
    "matbench_descriptor_transfer_significance_generator"
  ) {
    return "public materials descriptor-transfer residual survives composition formula-size target-family split-leakage and shuffled-target controls";
  }
  if (
    output?.generatorId === "gaia_astrometric_excess_significance_generator"
  ) {
    return "public Gaia astrometric residual survives magnitude color crowding scan-law and catalog-quality controls across independent slices";
  }
  if (
    output?.generatorId ===
    "bounded_graph_minor_obstruction_significance_generator"
  ) {
    return "public graph-minor obstruction residual survives size density degree-sequence treewidth-proxy known-family and generated-counterexample controls";
  }
  return normalizeMechanism(seed.claim);
}

function generatorBornRivalHypothesis(
  seed: HardSeed,
  output: GeneratorBornSourceOutput | null,
): string {
  if (isDiscoveryAnchorRuntimeCheck(output)) {
    return normalizeWhitespace(output.rivalPrediction);
  }
  if (output?.generatorId === "known_formal_problem_boundary_generator") {
    return "size density clique lower bound or small bounded counterexamples explain the apparent boundary";
  }
  if (output?.generatorId === "benchmark_delta_mechanism_generator") {
    return "class balance split leakage task maturity or stronger-model controls explain the benchmark delta";
  }
  if (output?.generatorId === "public_measurement_residual_generator") {
    return "seasonality cadence missingness station-family or instrumentation artifacts explain the public measurement residual";
  }
  if (output?.generatorId === "satlib_bounded_sat_boundary_generator") {
    return "clause-variable ratio unit propagation pure literal or random-CNF phase behavior explains the SAT boundary residual";
  }
  if (output?.generatorId === "snap_network_cut_resilience_generator") {
    return "degree sequence density component size source family or random rewiring explains the network resilience residual";
  }
  if (output?.generatorId === "openml_shift_instability_generator") {
    return "class imbalance metric choice split leakage task maturity or stronger-model baselines explain the evaluation-instability residual";
  }
  if (
    output?.generatorId ===
    "matbench_descriptor_transfer_significance_generator"
  ) {
    return "composition formula-size element prevalence task-family split leakage or shuffled-target controls explain the property residual";
  }
  if (
    output?.generatorId === "gaia_astrometric_excess_significance_generator"
  ) {
    return "magnitude color crowding scan-law source-family or catalog-quality flags explain the astrometric residual";
  }
  if (
    output?.generatorId ===
    "bounded_graph_minor_obstruction_significance_generator"
  ) {
    return "size density degree sequence treewidth proxies known graph-family membership or small generated counterexamples explain the obstruction boundary";
  }
  return `stronger rival for ${seed.domain}`;
}

function domainSignificanceRefsForOutput(
  output: GeneratorBornSourceOutput | null,
  publicUrls: string[],
): string[] {
  if (output === null) return [];
  if (isDiscoveryAnchorRuntimeCheck(output)) {
    return output.birthEvaluation.domainSignificanceHypothesisGate?.accepted ===
      true
      ? publicUrls
      : [];
  }
  return output.domainSignificanceHypothesis.evidenceRefs;
}

function isDiscoveryAnchorRuntimeCheck(
  output: GeneratorBornSourceOutput | null,
): output is DiscoveryGradeAnchorRuntimeCheck {
  return output !== null && "checkId" in output && "anchorId" in output;
}

function generatorBornSourceOutputSeedId(
  output: GeneratorBornSourceOutput | null,
): string | null {
  return output?.hardSeed?.seedId ?? null;
}

function generatorBornOutputId(
  output: GeneratorBornSourceOutput | null,
): string | null {
  if (output === null) return null;
  return isDiscoveryAnchorRuntimeCheck(output)
    ? output.anchorId
    : output.generatorId;
}

function generatorBornPressureRemainingBottleneck(
  rows: GeneratorBornPressureRow[],
): string {
  if (rows.length === 0) {
    return "No generator-born hard seeds were available for pressure. Remaining bottleneck is upstream generator quality before HardSeed birth.";
  }
  const insights = rows.filter((row) => row.insightCandidateCreated).length;
  const discovery = rows.filter((row) => row.discoveryCandidateCreated).length;
  if (insights > 0 && discovery === 0) {
    return `${insights} generator-born hard seed(s) reached InsightCandidate birth, but none became a discovery-scored candidate. Remaining bottleneck is required-next-test closure and external-review package pressure.`;
  }
  const counts = generatorBornKillCounts(rows);
  const top =
    Object.entries(counts).sort((left, right) => right[1] - left[1])[0]?.[0] ??
    "unknown";
  return `No generator-born hard seed reached InsightCandidate birth. Dominant blocker: ${top}.`;
}

function generatorBornInsightClaim(
  row: GeneratorBornPressureRow,
  targetOutcome: string,
): string {
  if (row.domainSignificanceSupported) {
    return normalizeWhitespace(
      [
        `In ${row.domain}, the externally anchored target outcome ${targetOutcome} supports a domain scientific significance hypothesis: ${row.mechanismHypothesis}.`,
        `The narrow claim is that this mechanism remains not documented outside known source-family behavior under the bound evidence scope after baseline, rival, counterexample, recurrence, holdout, replay, and mechanism pressure.`,
        `This changes interpretation only for the measured public target-outcome slice represented by ${row.outputId ?? row.seedId}.`,
      ].join(" "),
    );
  }
  return normalizeWhitespace(
    [
      `In ${row.domain}, ${row.mechanismHypothesis} retains measured target-outcome evidence: ${targetOutcome}.`,
      `Recorded pressure includes baseline, rival, counterexample, recurrence, holdout, replay, and mechanism checks for ${row.outputId ?? row.seedId}.`,
    ].join(" "),
  );
}

function generatorBornKillCounts(
  rows: GeneratorBornPressureRow[],
): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const row of rows) {
    if (row.primaryKillReason === "survived") continue;
    counts[row.primaryKillReason] = (counts[row.primaryKillReason] ?? 0) + 1;
  }
  return counts;
}

