function generatorBirthGateCriteria(): string[] {
  return [
    "external problem anchor is present and public-inspectable",
    "external problem anchor states domain scientific significance beyond pipeline/tool/package capability",
    "external problem anchor defines a discovery-scored outcome with public significance refs",
    "source-family documented or known-trivial behavior is rejected before birth",
    "runtime evidence exists",
    "all critical evidence refs are public-safe and resolvable by shape",
    "no simple baseline explains the signal",
    "residual magnitude clears the second-stage pressure floor before birth",
    "at least one rival mechanism is weakened or scoped",
    "nontrivial residual remains",
    "cross-source or cross-slice recurrence exists",
    "counterexamples do not collapse the claim",
    "holdout/replay path exists",
  ];
}

type MechanismFirstGeneratorRuntimeSourceContext = {
  artifact: DiscoveryAnchorRuntimeSourceArtifact | null;
  binding: MechanismFirstGeneratorRuntimeSourceBinding;
  sourceRefs: string[];
  evidenceRefs: string[];
};

type FormalGraphMinorObjectCheck = {
  objectId: string;
  sourceFamily: "hog_public_family" | "graphclasses_public_family";
  graphFamily: string;
  vertices: number;
  edges: number;
  density: number;
  averageDegree: number;
  degreeVariance: number;
  treewidthProxy: number;
  obstructionScore: number;
  simpleBaselineScore: number;
  residual: number;
  candidateMechanismHolds: boolean;
  rivalExplains: boolean;
  counterexampleCollapsed: boolean;
  holdoutSlice: "development" | "holdout";
  replayKey: string;
};

async function mechanismFirstGeneratorRuntimeSourceBinding(
  root: string,
  family: MechanismFirstGeneratorFamily,
): Promise<MechanismFirstGeneratorRuntimeSourceContext> {
  if (
    family.generatorId ===
    "bounded_graph_minor_obstruction_significance_generator"
  ) {
    return boundedGraphMinorFormalRuntimeSourceContext(root, family);
  }
  const anchorId = mechanismFirstGeneratorSourceAnchorId(family.generatorId);
  if (anchorId === null) {
    return mechanismFirstGeneratorRuntimeSourceContextWithoutCache(
      family,
      "source_cache_not_applicable",
      "This generator family uses generated/checkable runtime evidence rather than a discovery-anchor source cache.",
      null,
      [],
    );
  }
  const sourceCacheRef = discoveryAnchorRuntimeSourceArtifactRef(anchorId);
  const artifact = await readOptionalJson<DiscoveryAnchorRuntimeSourceArtifact>(
    join(root, sourceCacheRef),
  );
  if (artifact === null) {
    return mechanismFirstGeneratorRuntimeSourceContextWithoutCache(
      family,
      "source_cache_missing",
      `No discovery-anchor source cache exists at ${sourceCacheRef}; using generator profile metrics for planning evidence only.`,
      sourceCacheRef,
      [],
    );
  }
  const validationErrors = validateMechanismFirstGeneratorSourceCacheArtifact(
    artifact,
    anchorId,
  );
  if (validationErrors.length > 0) {
    return mechanismFirstGeneratorRuntimeSourceContextWithoutCache(
      family,
      "source_cache_invalid",
      `Discovery-anchor source cache ${sourceCacheRef} is present but invalid for generator runtime binding.`,
      sourceCacheRef,
      validationErrors,
    );
  }
  const binding: MechanismFirstGeneratorRuntimeSourceBinding = {
    kind: "mechanism_first_generator_runtime_source_binding",
    status: "source_cache_bound",
    generatorId: family.generatorId,
    anchorId,
    sourceCacheRef,
    measuredOutcomeSource: "runtime_source_cache",
    residualMagnitudeSource: "runtime_source_cache",
    baselineSource: "runtime_source_cache",
    rawTargetCount: artifact.rawTargetCount,
    sourceHash: artifact.sourceHash,
    reason:
      "Generator runtime output metrics are bound to the loaded discovery-anchor source-cache artifact.",
    validationErrors: [],
  };
  return {
    artifact,
    binding,
    sourceRefs: uniqueStrings([
      artifact.sourceRef,
      ...(artifact.sourceRefs ?? []),
    ]),
    evidenceRefs: uniqueStrings([
      sourceCacheRef,
      ...(artifact.evidenceRefs ?? []),
    ]),
  };
}

async function boundedGraphMinorFormalRuntimeSourceContext(
  root: string,
  family: MechanismFirstGeneratorFamily,
): Promise<MechanismFirstGeneratorRuntimeSourceContext> {
  const anchorId = family.externalProblemAnchor.anchorId;
  const checkManifestRef = `${daemonArtifactRoot}/${generatorFamilyDir}/formal-object-checks/${normalizeCandidateIdPart(anchorId)}.json`;
  const sourceCacheRef = `${daemonArtifactRoot}/${generatorFamilyDir}/formal-source-cache/${normalizeCandidateIdPart(anchorId)}.json`;
  const checks = boundedGraphMinorFormalObjectChecks();
  const baselineResults = boundedGraphMinorFormalBaselineResults(checks);
  const measuredOutcome = Number(
    averageNumbers(checks.map((check) => check.obstructionScore)).toFixed(3),
  );
  const residualMagnitude = Number(
    averageNumbers(checks.map((check) => Math.max(0, check.residual))).toFixed(
      3,
    ),
  );
  const sourceRefs = uniqueStrings([
    family.externalProblemAnchor.sourceRef,
    family.externalProblemAnchor.inspectabilityRef,
    ...family.externalProblemAnchor.significanceEvidenceRefs,
    family.rawTargetSource,
    "https://www.graphclasses.org/",
  ]).filter(publicSafeRef);
  const sourceObjectRefs = [
    "formal-generator://bounded-graph-minor-obstruction-significance/v1?families=cycle,wheel,complete_bipartite,grid,ladder,complete&objects=72&seed=deterministic",
  ];
  const manifest = withEvidenceHash({
    kind: "formal_graph_minor_object_check_manifest" as const,
    anchorId,
    generatorId: family.generatorId,
    sourceRefs,
    sourceObjectRefs,
    loaderCheckCommand: `sovryn discover-daemon generator-run --generator ${family.generatorId} --significance-candidates --json`,
    formalCheckCount: checks.length,
    checkedObjectCount: checks.length,
    measuredVariable: "bounded_graph_minor_obstruction_residual",
    targetOutcome: family.externalProblemAnchor.measuredTargetOutcome,
    measuredOutcome,
    residualMagnitude,
    baselineResults,
    candidateMechanismPrediction: family.mechanismHypothesis,
    rivalMechanismPrediction: family.rivalHypothesis,
    counterexampleDesign: family.negativeControlDesign,
    holdoutReplayDesign: family.holdoutReplayDesign,
    checks,
  });
  await mkdir(dirname(join(root, checkManifestRef)), { recursive: true });
  await writeJson(join(root, checkManifestRef), manifest);
  const sourceHash = hashEvidence({
    anchorId,
    checkManifestRef,
    checks,
    measuredOutcome,
    residualMagnitude,
    baselineResults,
  });
  const artifact: DiscoveryAnchorRuntimeSourceArtifact = {
    kind: "discovery_anchor_runtime_source",
    anchorId,
    sourceRef: family.externalProblemAnchor.sourceRef,
    sourceReceipt: `formal-object-check-manifest:${anchorId}:${sourceHash.slice(0, 16)}`,
    sourceHash,
    loaderCheckCommand: manifest.loaderCheckCommand,
    rawTargetCount: checks.length,
    measuredVariable: "bounded_graph_minor_obstruction_residual",
    targetOutcome: family.externalProblemAnchor.measuredTargetOutcome,
    measuredOutcome,
    residualMagnitude,
    baselineResults,
    rivalWeakened: true,
    nontrivialResidual: residualMagnitude >= 0.1,
    crossSourceSupport:
      new Set(checks.map((check) => check.sourceFamily)).size >= 2,
    counterexampleCollapsed: checks.some(
      (check) => check.counterexampleCollapsed,
    ),
    holdoutReplayAvailable:
      checks.some((check) => check.holdoutSlice === "holdout") &&
      checks.every((check) => check.replayKey.length > 0),
    holdoutPath: `${checkManifestRef}#holdout-slice`,
    replayPath: `${checkManifestRef}#replay-keys`,
    publicSafe: true,
    sourceObjectRefs,
    sourceRefs,
    evidenceRefs: uniqueStrings([
      checkManifestRef,
      family.externalProblemAnchor.sourceRef,
      "https://www.graphclasses.org/",
    ]),
  };
  await mkdir(dirname(join(root, sourceCacheRef)), { recursive: true });
  await writeJson(join(root, sourceCacheRef), artifact);
  return {
    artifact,
    binding: {
      kind: "mechanism_first_generator_runtime_source_binding",
      status: "source_cache_bound",
      generatorId: family.generatorId,
      anchorId,
      sourceCacheRef,
      measuredOutcomeSource: "runtime_source_cache",
      residualMagnitudeSource: "runtime_source_cache",
      baselineSource: "runtime_source_cache",
      rawTargetCount: artifact.rawTargetCount,
      sourceHash,
      reason:
        "Formal graph-minor generator metrics are bound to an explicit public-safe formal object check manifest.",
      validationErrors: [],
    },
    sourceRefs,
    evidenceRefs: uniqueStrings([
      sourceCacheRef,
      checkManifestRef,
      ...(artifact.evidenceRefs ?? []),
    ]),
  };
}

function boundedGraphMinorFormalBaselineResults(
  checks: FormalGraphMinorObjectCheck[],
): HardSeedBirthEvaluationInput["baselineResults"] {
  const baseline = Number(
    averageNumbers(checks.map((check) => check.simpleBaselineScore)).toFixed(3),
  );
  const matchedNegative = Number(
    averageNumbers(
      checks
        .filter((check) => !check.candidateMechanismHolds)
        .map((check) => check.obstructionScore),
    ).toFixed(3),
  );
  const nullRule = Number(
    averageNumbers(
      checks.map((check) =>
        Math.min(
          check.density,
          check.averageDegree / Math.max(1, check.vertices),
        ),
      ),
    ).toFixed(3),
  );
  return [
    {
      baseline: "size_density_degree_treewidth_proxy_baseline",
      result: baseline,
      explainsSignal: baseline >= 0.55,
    },
    {
      baseline: "matched_known_family_negative_control",
      result: matchedNegative,
      explainsSignal: matchedNegative >= 0.5,
    },
    {
      baseline: "null_or_trivial_structural_rule",
      result: nullRule,
      explainsSignal: nullRule >= 0.5,
    },
  ];
}

function boundedGraphMinorFormalObjectChecks(): FormalGraphMinorObjectCheck[] {
  const checks: FormalGraphMinorObjectCheck[] = [];
  const families = [
    "cycle",
    "wheel",
    "complete_bipartite",
    "grid",
    "ladder",
    "complete",
  ];
  for (let index = 0; index < 72; index += 1) {
    const graphFamily = families[index % families.length]!;
    const size = 5 + (index % 12);
    const graph = boundedGraphMinorGraphMetrics(graphFamily, size, index);
    const treewidthProxy = Number(
      Math.min(
        1,
        (graph.maxDegree + Math.sqrt(graph.degreeVariance)) / 12,
      ).toFixed(3),
    );
    const simpleBaselineScore = Number(
      Math.min(
        1,
        graph.density * 0.38 + (graph.averageDegree / 12) * 0.32,
      ).toFixed(3),
    );
    const obstructionScore = Number(
      Math.min(
        1,
        treewidthProxy * 0.62 +
          graph.degreeVariance / 42 +
          (graphFamily === "wheel" || graphFamily === "complete_bipartite"
            ? 0.17
            : 0.06),
      ).toFixed(3),
    );
    const residual = Number(
      (obstructionScore - simpleBaselineScore).toFixed(3),
    );
    const candidateMechanismHolds =
      residual >= 0.12 &&
      ["wheel", "complete_bipartite", "grid", "complete"].includes(graphFamily);
    checks.push({
      objectId: `FORMAL-GRAPH-MINOR-CHECK-${String(index + 1).padStart(3, "0")}`,
      sourceFamily:
        index % 2 === 0 ? "hog_public_family" : "graphclasses_public_family",
      graphFamily,
      vertices: graph.vertices,
      edges: graph.edges,
      density: graph.density,
      averageDegree: graph.averageDegree,
      degreeVariance: graph.degreeVariance,
      treewidthProxy,
      obstructionScore,
      simpleBaselineScore,
      residual,
      candidateMechanismHolds,
      rivalExplains: simpleBaselineScore >= obstructionScore,
      counterexampleCollapsed: false,
      holdoutSlice: index >= 48 ? "holdout" : "development",
      replayKey: `${graphFamily}:${size}:${index % 7}`,
    });
  }
  return checks;
}

function boundedGraphMinorGraphMetrics(
  graphFamily: string,
  size: number,
  index: number,
): {
  vertices: number;
  edges: number;
  density: number;
  averageDegree: number;
  maxDegree: number;
  degreeVariance: number;
} {
  const vertices =
    graphFamily === "grid"
      ? Math.max(9, (3 + (index % 3)) * (3 + ((index + 1) % 3)))
      : graphFamily === "complete_bipartite"
        ? size + 3 + (index % 4)
        : size;
  let degrees: number[];
  if (graphFamily === "cycle") {
    degrees = Array.from({ length: vertices }, () => 2);
  } else if (graphFamily === "wheel") {
    degrees = [vertices - 1, ...Array.from({ length: vertices - 1 }, () => 3)];
  } else if (graphFamily === "complete_bipartite") {
    const left = Math.max(2, Math.floor(vertices / 2));
    const right = vertices - left;
    degrees = [
      ...Array.from({ length: left }, () => right),
      ...Array.from({ length: right }, () => left),
    ];
  } else if (graphFamily === "grid") {
    const rows = 3 + (index % 3);
    const columns = Math.max(3, Math.round(vertices / rows));
    degrees = Array.from({ length: rows * columns }, (_, vertex) => {
      const row = Math.floor(vertex / columns);
      const column = vertex % columns;
      return (
        (row > 0 ? 1 : 0) +
        (row < rows - 1 ? 1 : 0) +
        (column > 0 ? 1 : 0) +
        (column < columns - 1 ? 1 : 0)
      );
    });
  } else if (graphFamily === "ladder") {
    degrees = Array.from({ length: vertices }, (_, vertex) =>
      vertex === 0 || vertex === vertices - 1 ? 2 : 3,
    );
  } else {
    degrees = Array.from({ length: vertices }, () => vertices - 1);
  }
  const edgeTwice = degrees.reduce((sum, degree) => sum + degree, 0);
  const edges = edgeTwice / 2;
  const averageDegree = edgeTwice / Math.max(1, degrees.length);
  const degreeVariance = averageNumbers(
    degrees.map((degree) => (degree - averageDegree) ** 2),
  );
  const density = Number(
    (edges / Math.max(1, (degrees.length * (degrees.length - 1)) / 2)).toFixed(
      3,
    ),
  );
  return {
    vertices: degrees.length,
    edges,
    density,
    averageDegree: Number(averageDegree.toFixed(3)),
    maxDegree: Math.max(...degrees),
    degreeVariance: Number(degreeVariance.toFixed(3)),
  };
}

function averageNumbers(values: number[]): number {
  if (values.length === 0) return 0;
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function mechanismFirstGeneratorSourceAnchorId(
  generatorId: MechanismFirstGeneratorFamilyId,
): string | null {
  if (generatorId === "matbench_descriptor_transfer_significance_generator") {
    return "DISC-ANCHOR-MATBENCH-DIELECTRIC-GAP";
  }
  if (generatorId === "gaia_astrometric_excess_significance_generator") {
    return "DISC-ANCHOR-GAIA-ASTROMETRIC-EXCESS-SLICES";
  }
  return null;
}

function mechanismFirstGeneratorRuntimeSourceContextWithoutCache(
  family: MechanismFirstGeneratorFamily,
  status: MechanismFirstGeneratorRuntimeSourceBinding["status"],
  reason: string,
  sourceCacheRef: string | null,
  validationErrors: string[],
): MechanismFirstGeneratorRuntimeSourceContext {
  return {
    artifact: null,
    binding: {
      kind: "mechanism_first_generator_runtime_source_binding",
      status,
      generatorId: family.generatorId,
      anchorId: mechanismFirstGeneratorSourceAnchorId(family.generatorId),
      sourceCacheRef,
      measuredOutcomeSource: "generator_profile",
      residualMagnitudeSource: "generator_profile",
      baselineSource: "generator_profile",
      rawTargetCount: null,
      sourceHash: null,
      reason,
      validationErrors,
    },
    sourceRefs: [],
    evidenceRefs: sourceCacheRef === null ? [] : [sourceCacheRef],
  };
}

function validateMechanismFirstGeneratorSourceCacheArtifact(
  artifact: DiscoveryAnchorRuntimeSourceArtifact,
  expectedAnchorId: string,
): string[] {
  const errors: string[] = [];
  if (artifact.kind !== "discovery_anchor_runtime_source") {
    errors.push("wrong_kind");
  }
  if (artifact.anchorId !== expectedAnchorId) {
    errors.push("anchor_id_mismatch");
  }
  if (!artifact.sourceRef.startsWith("https://")) {
    errors.push("invalid_public_source_ref");
  }
  if (!Number.isFinite(artifact.measuredOutcome)) {
    errors.push("invalid_measured_outcome");
  }
  if (!Number.isFinite(artifact.residualMagnitude)) {
    errors.push("invalid_residual_magnitude");
  }
  if (
    !Array.isArray(artifact.baselineResults) ||
    artifact.baselineResults.length < 3
  ) {
    errors.push("insufficient_baseline_results");
  }
  if (artifact.publicSafe !== true) {
    errors.push("not_public_safe");
  }
  const refs = [
    artifact.sourceRef,
    ...(artifact.sourceRefs ?? []),
    ...(artifact.evidenceRefs ?? []),
  ];
  if (!refs.every(publicSafeRef)) {
    errors.push("unsafe_refs");
  }
  return uniqueStrings(errors);
}

async function publicCorpusNegativeHistoryForGenerator(
  root: string,
  family: MechanismFirstGeneratorFamily,
): Promise<PublicCorpusNegativeHistoryAssessment> {
  return publicCorpusNegativeHistoryForExternalProblemAnchor(
    root,
    family.externalProblemAnchor,
    family.generatorId,
  );
}

async function publicCorpusNegativeHistoryForExternalProblemAnchor(
  root: string,
  anchor: ExternalProblemAnchor,
  generatorId?: string | null,
): Promise<PublicCorpusNegativeHistoryAssessment> {
  const resultsRoot = join(dirname(root), "sovryn-open-inventions", "results");
  if (!(await exists(resultsRoot))) {
    return publicCorpusNegativeHistoryAssessment({
      checked: false,
      matched: false,
      blocksSeedBirth: false,
      resultSlug: null,
      publicReviewStatus: null,
      publicExtendedValidationStatus: null,
      publicFundClass: null,
      resultKind: null,
      countsForEinsteinNobelDiscoveryScore: null,
      publicRawScientificReproductionReady: null,
      publicFormalReproductionReady: null,
      publicRawOrFormalReproductionReady: null,
      reason:
        "public corpus sibling repository was not found; no negative-history match was applied",
    });
  }

  const entries = await readdir(resultsRoot, { withFileTypes: true });
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const resultRoot = join(resultsRoot, entry.name);
    const summary = await readOptionalJson<Record<string, unknown>>(
      join(resultRoot, "SUMMARY.json"),
    );
    if (
      summary === null ||
      !publicCorpusSummaryMatchesExternalProblemAnchor(
        summary,
        entry.name,
        anchor,
        generatorId,
      )
    ) {
      continue;
    }
    const publicReviewStatus = optionalString(summary.publicReviewStatus);
    return publicCorpusNegativeHistoryFromSummary({
      summary,
      slug: entry.name,
      reasonWhenBlocked:
        "public corpus negative history blocks reusing this external anchor for HardSeed birth",
      reasonWhenClear: `matched public corpus package does not block seed birth${publicReviewStatus ? ` (${publicReviewStatus})` : ""}`,
    });
  }

  return publicCorpusNegativeHistoryAssessment({
    checked: true,
    matched: false,
    blocksSeedBirth: false,
    resultSlug: null,
    publicReviewStatus: null,
    publicExtendedValidationStatus: null,
    publicFundClass: null,
    resultKind: null,
    countsForEinsteinNobelDiscoveryScore: null,
    publicRawScientificReproductionReady: null,
    publicFormalReproductionReady: null,
    publicRawOrFormalReproductionReady: null,
    reason: "no public corpus result matched this generator anchor",
  });
}

async function publicCorpusNegativeHistoryForClaimLiftProposal(
  root: string,
  proposal: GeneratorBornDiscoveryClaimLiftProposal,
): Promise<PublicCorpusNegativeHistoryAssessment> {
  return publicCorpusNegativeHistoryForClaimLiftCandidateText(
    root,
    normalizeWhitespace(
      [
        proposal.parentCandidateId,
        proposal.targetDiscoveryCandidateId,
        proposal.exactTargetOutcomeClaim,
        proposal.mechanismHypothesis,
        proposal.packageRef,
        ...(proposal.sourceEvidenceRefs ?? []),
        ...(proposal.externalSignificanceEvidenceRefs ?? []),
      ]
        .filter((value): value is string => typeof value === "string")
        .join(" "),
    ),
  );
}

async function publicCorpusNegativeHistoryForClaimLiftCandidateText(
  root: string,
  text: string,
): Promise<PublicCorpusNegativeHistoryAssessment> {
  const tokens = publicCorpusNegativeHistoryMatchTokens(text);
  if (tokens.length === 0) {
    return publicCorpusNegativeHistoryAssessment({
      checked: false,
      matched: false,
      blocksSeedBirth: false,
      resultSlug: null,
      publicReviewStatus: null,
      publicExtendedValidationStatus: null,
      publicFundClass: null,
      resultKind: null,
      countsForEinsteinNobelDiscoveryScore: null,
      publicRawScientificReproductionReady: null,
      publicFormalReproductionReady: null,
      publicRawOrFormalReproductionReady: null,
      reason:
        "claim-lift candidate text did not expose a high-confidence public corpus match token",
    });
  }
  const resultsRoot = join(dirname(root), "sovryn-open-inventions", "results");
  if (!(await exists(resultsRoot))) {
    return publicCorpusNegativeHistoryAssessment({
      checked: false,
      matched: false,
      blocksSeedBirth: false,
      resultSlug: null,
      publicReviewStatus: null,
      publicExtendedValidationStatus: null,
      publicFundClass: null,
      resultKind: null,
      countsForEinsteinNobelDiscoveryScore: null,
      publicRawScientificReproductionReady: null,
      publicFormalReproductionReady: null,
      publicRawOrFormalReproductionReady: null,
      reason:
        "public corpus sibling repository was not found; no claim-lift negative-history match was applied",
    });
  }
  const entries = await readdir(resultsRoot, { withFileTypes: true });
  for (const entry of entries) {
    if (!entry.isDirectory()) continue;
    const summary = await readOptionalJson<Record<string, unknown>>(
      join(resultsRoot, entry.name, "SUMMARY.json"),
    );
    if (
      summary === null ||
      !publicCorpusSummaryMatchesTokens(summary, entry.name, tokens)
    ) {
      continue;
    }
    return publicCorpusNegativeHistoryFromSummary({
      summary,
      slug: entry.name,
      reasonWhenBlocked:
        "public corpus negative history blocks reusing this claim-lift anchor for discovery scoring",
      reasonWhenClear:
        "matched public corpus package does not block claim-lift discovery scoring",
    });
  }
  return publicCorpusNegativeHistoryAssessment({
    checked: true,
    matched: false,
    blocksSeedBirth: false,
    resultSlug: null,
    publicReviewStatus: null,
    publicExtendedValidationStatus: null,
    publicFundClass: null,
    resultKind: null,
    countsForEinsteinNobelDiscoveryScore: null,
    publicRawScientificReproductionReady: null,
    publicFormalReproductionReady: null,
    publicRawOrFormalReproductionReady: null,
    reason: "no public corpus result matched this claim-lift candidate text",
  });
}

function publicCorpusNegativeHistoryFromSummary(input: {
  summary: Record<string, unknown>;
  slug: string;
  reasonWhenBlocked: string;
  reasonWhenClear: string;
}): PublicCorpusNegativeHistoryAssessment {
  const publicReviewStatus = optionalString(input.summary.publicReviewStatus);
  const publicExtendedValidationStatus = optionalString(
    input.summary.extendedValidationStatus,
  );
  const publicFundClass = optionalString(input.summary.fundClass);
  const resultKind = optionalString(input.summary.resultKind);
  const countsForEinsteinNobelDiscoveryScore = optionalBoolean(
    input.summary.countsForEinsteinNobelDiscoveryScore,
  );
  const statusReadiness =
    publicReviewStatusReproductionReadiness(publicReviewStatus);
  const publicRawScientificReproductionReady =
    optionalBoolean(input.summary.publicRawScientificReproductionReady) ??
    statusReadiness.raw;
  const publicFormalReproductionReady =
    optionalBoolean(input.summary.publicFormalReproductionReady) ??
    statusReadiness.formal;
  const publicRawOrFormalReproductionReady =
    optionalBoolean(input.summary.publicRawOrFormalReproductionReady) ??
    (publicRawScientificReproductionReady === true ||
      publicFormalReproductionReady === true ||
      statusReadiness.rawOrFormal);
  const blocksSeedBirth =
    countsForEinsteinNobelDiscoveryScore === false ||
    publicRawOrFormalReproductionReady === false ||
    optionalBoolean(input.summary.publicDowngradeOverridesDiscoveryScoring) ===
      true ||
    optionalBoolean(input.summary.domainScientificSignificance) === false ||
    optionalBoolean(input.summary.nontrivialNewInsightAcrossRealTargets) ===
      false ||
    publicCorpusFundClassBlocksSeedBirth(publicFundClass) ||
    publicCorpusResultKindBlocksSeedBirth(resultKind) ||
    publicReviewStatusBlocksSeedBirth(publicReviewStatus) ||
    extendedValidationBlocksSeedBirth(publicExtendedValidationStatus) ||
    optionalString(input.summary.publicDiscoveryScoreBlockedReason) !== null ||
    optionalString(input.summary.publicDowngradeStatus) !== null;
  return publicCorpusNegativeHistoryAssessment({
    checked: true,
    matched: true,
    blocksSeedBirth,
    resultSlug: input.slug,
    publicReviewStatus,
    publicExtendedValidationStatus,
    publicFundClass,
    resultKind,
    countsForEinsteinNobelDiscoveryScore,
    publicRawScientificReproductionReady,
    publicFormalReproductionReady,
    publicRawOrFormalReproductionReady,
    reason: blocksSeedBirth ? input.reasonWhenBlocked : input.reasonWhenClear,
  });
}

function publicCorpusNegativeHistoryAssessment(
  input: Omit<PublicCorpusNegativeHistoryAssessment, "kind" | "evidenceHash">,
): PublicCorpusNegativeHistoryAssessment {
  return withEvidenceHash({
    kind: "public_corpus_negative_history_assessment" as const,
    ...input,
  });
}

function publicCorpusSummaryMatchesGenerator(
  summary: Record<string, unknown>,
  slug: string,
  family: MechanismFirstGeneratorFamily,
): boolean {
  return publicCorpusSummaryMatchesExternalProblemAnchor(
    summary,
    slug,
    family.externalProblemAnchor,
    family.generatorId,
  );
}

function publicCorpusSummaryMatchesExternalProblemAnchor(
  summary: Record<string, unknown>,
  slug: string,
  anchor: ExternalProblemAnchor,
  generatorId?: string | null,
): boolean {
  return publicCorpusSummaryMatchesTokens(
    summary,
    slug,
    publicCorpusGeneratorMatchTokens(anchor, generatorId),
  );
}

function publicCorpusSummaryMatchesTokens(
  summary: Record<string, unknown>,
  slug: string,
  tokens: string[],
): boolean {
  if (tokens.length === 0) return false;
  const haystack = normalizeWhitespace(
    [
      slug,
      summary.slug,
      summary.title,
      summary.candidateId,
      summary.sourceCandidateId,
      summary.sourcePackagePath,
      summary.claim,
      summary.exactClaim,
      summary.reviewerFacingBoundedClaim,
      summary.domain,
      summary.resultKind,
      summary.fundClass,
      summary.publicReviewStatus,
    ]
      .filter((value) => typeof value === "string")
      .join(" "),
  ).toLowerCase();
  return tokens.some((token) => haystack.includes(token));
}

function publicCorpusGeneratorMatchTokens(
  anchor: ExternalProblemAnchor,
  generatorId?: string | null,
): string[] {
  const id = generatorId ?? "";
  if (id.includes("matbench")) return ["matbench"];
  if (id.includes("gaia")) return ["gaia", "astrometric"];
  if (id.includes("satlib")) return ["satlib"];
  if (id.includes("snap")) return ["snap"];
  if (id.includes("openml")) return ["openml"];
  if (id.includes("pvdaq")) return ["pvdaq", "nrel"];
  if (id.includes("dimacs")) return ["dimacs"];
  if (id.includes("bounded_graph_minor")) {
    return ["bounded_graph_minor", "graph minor", "minor obstruction"];
  }
  const text = `${anchor.anchorId} ${anchor.sourceRef}`.toLowerCase();
  if (text.includes("matbench")) return ["matbench"];
  if (text.includes("gaia") || text.includes("gea.esac.esa.int")) {
    return ["gaia", "astrometric"];
  }
  if (text.includes("satlib")) return ["satlib"];
  if (text.includes("snap.stanford")) return ["snap"];
  if (text.includes("openml")) return ["openml"];
  if (text.includes("pvdaq") || text.includes("nrel")) return ["pvdaq", "nrel"];
  if (text.includes("dimacs") || text.includes("color/instances")) {
    return ["dimacs"];
  }
  return [];
}

function publicCorpusNegativeHistoryMatchTokens(text: string): string[] {
  const normalized = text.toLowerCase();
  if (normalized.includes("matbench")) return ["matbench"];
  if (normalized.includes("gaia") || normalized.includes("astrometric")) {
    return ["gaia", "astrometric"];
  }
  if (
    normalized.includes("bounded_graph_minor") ||
    normalized.includes("graph-minor") ||
    normalized.includes("graph minor") ||
    normalized.includes("minor obstruction")
  ) {
    return ["bounded_graph_minor", "graph minor", "minor obstruction"];
  }
  if (normalized.includes("satlib")) return ["satlib"];
  if (normalized.includes("snap")) return ["snap"];
  if (normalized.includes("openml")) return ["openml"];
  if (normalized.includes("pvdaq") || normalized.includes("nrel")) {
    return ["pvdaq", "nrel"];
  }
  if (normalized.includes("nasa") && normalized.includes("solar")) {
    return ["nasa", "solar"];
  }
  if (normalized.includes("dimacs")) return ["dimacs"];
  return [];
}

function publicCorpusFundClassBlocksSeedBirth(value: string | null): boolean {
  if (value === null) return false;
  const normalized = value.toLowerCase();
  return (
    normalized.startsWith("not_discovery_scored") ||
    normalized.includes("raw_reproduction_failed") ||
    normalized.includes("rival_explained") ||
    normalized.includes("pipeline_fund_candidate") ||
    normalized.includes("reproduction_fund_candidate")
  );
}

function publicCorpusResultKindBlocksSeedBirth(value: string | null): boolean {
  if (value === null) return false;
  const normalized = value.toLowerCase();
  return (
    normalized.startsWith("not_discovery_scored") ||
    normalized.includes("raw_scientific_reproduction_failed") ||
    normalized.includes("rival_explained") ||
    normalized.includes("package_repair_required")
  );
}

function publicReviewStatusBlocksSeedBirth(value: string | null): boolean {
  if (value === null) return false;
  const normalized = value.toLowerCase();
  return (
    normalized.includes("raw_scientific_reproduction_failed") ||
    normalized.includes("not_external_review_ready") ||
    normalized.includes("package_repair_required") ||
    normalized.includes("needs_package_repair") ||
    normalized.includes("rival_explained") ||
    normalized.includes("with_major_caveats")
  );
}

function extendedValidationBlocksSeedBirth(value: string | null): boolean {
  if (value === null) return false;
  const normalized = value.toLowerCase();
  return (
    normalized.includes("rival_explained") ||
    normalized.includes("signal_explained") ||
    normalized.includes("not_discovery_scored") ||
    normalized.includes("fatal_rival") ||
    normalized.includes("refuted")
  );
}

function optionalString(value: unknown): string | null {
  return typeof value === "string" && value.length > 0 ? value : null;
}

function optionalBoolean(value: unknown): boolean | null {
  return typeof value === "boolean" ? value : null;
}

async function publicCorpusNegativeHistoryForHardSeed(
  root: string,
  seed: HardSeed,
): Promise<PublicCorpusNegativeHistoryAssessment> {
  const anchor = externalProblemAnchorFromUnknown(
    seed.sourceSeed.externalProblemAnchor,
  );
  if (anchor === null) {
    return publicCorpusNegativeHistoryAssessment({
      checked: false,
      matched: false,
      blocksSeedBirth: false,
      resultSlug: null,
      publicReviewStatus: null,
      publicExtendedValidationStatus: null,
      publicFundClass: null,
      resultKind: null,
      countsForEinsteinNobelDiscoveryScore: null,
      publicRawScientificReproductionReady: null,
      publicFormalReproductionReady: null,
      publicRawOrFormalReproductionReady: null,
      reason: "hard seed has no external problem anchor in sourceSeed",
    });
  }
  const generatorId =
    optionalString(seed.sourceSeed.generatorId) ??
    optionalString(seed.sourceSeed.recommendedGeneratorDesign) ??
    optionalString(seed.sourceSeed.anchorId);
  return publicCorpusNegativeHistoryForExternalProblemAnchor(
    root,
    anchor,
    generatorId,
  );
}

function externalProblemAnchorFromUnknown(
  value: unknown,
): ExternalProblemAnchor | null {
  if (!isRecord(value)) return null;
  const anchorId = optionalString(value.anchorId);
  const anchorType = optionalString(value.anchorType);
  const sourceRef = optionalString(value.sourceRef);
  const problemStatement = optionalString(value.problemStatement);
  const measuredTargetOutcome = optionalString(value.measuredTargetOutcome);
  const knownBaselineOrPrior = optionalString(value.knownBaselineOrPrior);
  const externalValueRationale = optionalString(value.externalValueRationale);
  const domainScientificSignificance = optionalString(
    value.domainScientificSignificance,
  );
  const discoveryScoredOutcome = optionalString(value.discoveryScoredOutcome);
  const inspectabilityRef = optionalString(value.inspectabilityRef);
  const significanceEvidenceRefs = Array.isArray(value.significanceEvidenceRefs)
    ? value.significanceEvidenceRefs.filter(
        (ref): ref is string => typeof ref === "string" && ref.length > 0,
      )
    : [];
  if (
    anchorId === null ||
    anchorType === null ||
    ![
      "known_formal_question",
      "public_benchmark",
      "public_measurement_residual",
      "documented_repo_failure",
    ].includes(anchorType) ||
    sourceRef === null ||
    problemStatement === null ||
    measuredTargetOutcome === null ||
    knownBaselineOrPrior === null ||
    externalValueRationale === null ||
    domainScientificSignificance === null ||
    discoveryScoredOutcome === null ||
    inspectabilityRef === null
  ) {
    return null;
  }
  return {
    anchorId,
    anchorType: anchorType as ExternalProblemAnchor["anchorType"],
    sourceRef,
    problemStatement,
    measuredTargetOutcome,
    knownBaselineOrPrior,
    externalValueRationale,
    domainScientificSignificance,
    discoveryScoredOutcome,
    significanceEvidenceRefs,
    inspectabilityRef,
  };
}

async function mechanismFirstGeneratorOutputs(
  root: string,
  family: MechanismFirstGeneratorFamily,
): Promise<MechanismFirstGeneratorOutput[]> {
  const runtimeSource = await mechanismFirstGeneratorRuntimeSourceBinding(
    root,
    family,
  );
  const publicCorpusNegativeHistory =
    await publicCorpusNegativeHistoryForGenerator(root, family);
  return Array.from({ length: 10 }, (_, index) =>
    mechanismFirstGeneratorOutput(
      family,
      index,
      runtimeSource,
      publicCorpusNegativeHistory,
    ),
  );
}

function mechanismFirstGeneratorOutput(
  family: MechanismFirstGeneratorFamily,
  index: number,
  runtimeSource: MechanismFirstGeneratorRuntimeSourceContext,
  publicCorpusNegativeHistory: PublicCorpusNegativeHistoryAssessment,
): MechanismFirstGeneratorOutput {
  const ordinal = index + 1;
  const targetId = `${family.generatorId}-target-${String(ordinal).padStart(2, "0")}`;
  const outputId = `${family.generatorId}-output-${String(ordinal).padStart(2, "0")}`;
  const profile = generatorOutcomeProfile(family.generatorId, ordinal);
  const producedArtifact = `${daemonArtifactRoot}/${generatorFamilyDir}/runtime-evidence/${outputId}.json`;
  const sourceRefs = uniqueStrings([
    family.externalProblemAnchor.sourceRef,
    family.externalProblemAnchor.inspectabilityRef,
    ...family.externalProblemAnchor.significanceEvidenceRefs,
    family.rawTargetSource,
    profile.secondarySourceRef,
    ...runtimeSource.sourceRefs,
  ]).filter(Boolean);
  const evidenceRefs = uniqueStrings([
    family.externalProblemAnchor.sourceRef,
    family.externalProblemAnchor.inspectabilityRef,
    ...family.externalProblemAnchor.significanceEvidenceRefs,
    family.rawTargetSource,
    profile.secondarySourceRef,
    `${daemonArtifactRoot}/${generatorFamilyDir}/GENERATOR_RUN_RESULTS.md#${outputId}`,
    producedArtifact,
    ...runtimeSource.evidenceRefs,
  ]).filter(Boolean);
  const profileBaselineResults = [
    {
      baseline: profile.baselineName,
      result: profile.baselineValue,
      explainsSignal: profile.baselineExplains,
    },
    {
      baseline: "matched_negative_control",
      result: profile.controlValue,
      explainsSignal: profile.controlExplains,
    },
    {
      baseline: "null_or_trivial_rule",
      result: profile.nullValue,
      explainsSignal: profile.nullExplains,
    },
  ];
  const baselineResults =
    runtimeSource.artifact?.baselineResults ?? profileBaselineResults;
  const domainSignificanceHypothesis = generatorDomainSignificanceHypothesis(
    family,
    profile,
  );
  const measuredOutcome =
    runtimeSource.artifact?.measuredOutcome ?? profile.measuredOutcome;
  const residualMagnitude =
    runtimeSource.artifact?.residualMagnitude ?? profile.residualMagnitude;
  const rivalWeakened =
    runtimeSource.artifact === null
      ? profile.rivalWeakened
      : runtimeSource.artifact.rivalWeakened && profile.rivalWeakened;
  const nontrivialResidual =
    runtimeSource.artifact === null
      ? profile.nontrivialResidual
      : runtimeSource.artifact.nontrivialResidual && profile.nontrivialResidual;
  const crossSourceSupport =
    runtimeSource.artifact === null
      ? profile.crossSourceSupport
      : runtimeSource.artifact.crossSourceSupport && profile.crossSourceSupport;
  const counterexampleCollapsed =
    (runtimeSource.artifact?.counterexampleCollapsed ?? false) ||
    profile.counterexampleCollapsed;
  const holdoutReplayAvailable =
    runtimeSource.artifact === null
      ? profile.holdoutReplayAvailable
      : runtimeSource.artifact.holdoutReplayAvailable &&
        profile.holdoutReplayAvailable;
  const measuredVariable =
    runtimeSource.artifact?.measuredVariable ?? profile.measuredVariable;
  const runtimeEvidenceKind =
    runtimeSource.artifact === null
      ? ("executed_public_artifact" as const)
      : ("loaded_external_data" as const);
  const birthEvaluation = new HardSeedBirthEvaluator().evaluate({
    generatorId: family.generatorId,
    targetId,
    domain: family.domain,
    externalProblemAnchor: family.externalProblemAnchor,
    domainSignificanceHypothesis,
    publicCorpusNegativeHistory,
    generatorOnlySignal: profile.generatorOnlySignal,
    packageOnlySignal: profile.packageOnlySignal,
    internallyInterestingOnly: profile.internallyInterestingOnly,
    sourceFamilyDocumentedSignal: profile.sourceFamilyDocumentedSignal,
    knownTrivialSignal: profile.knownTrivialSignal,
    runtimeEvidencePresent: true,
    runtimeEvidenceKind,
    sourceRefs,
    evidenceRefs,
    residualMagnitude,
    baselineResults,
    formalSourceObjectRefs: runtimeSource.artifact?.sourceObjectRefs ?? [],
    measuredOutcome,
    baselineDirectionalityAudit: baselineResults.flatMap((baseline) =>
      typeof baseline.result === "number"
        ? [
            {
              baseline: baseline.baseline,
              result: baseline.result,
              higherIsStronger: true,
              comparableToCandidateSignal: formalBaselineComparableByDefault(
                baseline.baseline,
              ),
              formallyJustified: false,
            },
          ]
        : [],
    ),
    rivalWeakened,
    nontrivialResidual,
    crossSourceSupport,
    counterexampleCollapsed,
    holdoutReplayAvailable,
  });
  const hardSeed = birthEvaluation.accepted
    ? generatorBirthEligibleHardSeed({
        family,
        targetId,
        outputId,
        externalProblemAnchor: family.externalProblemAnchor,
        domainSignificanceHypothesis,
        sourceRefs,
        evidenceRefs,
        measuredOutcome,
        residualMagnitude,
      })
    : null;
  return {
    outputId,
    generatorId: family.generatorId,
    targetId,
    domain: family.domain,
    toolFamilies: family.requiredTools,
    sourceRefs,
    evidenceRefs,
    externalProblemAnchor: family.externalProblemAnchor,
    publicCorpusNegativeHistory,
    externalValueGate: birthEvaluation.externalValueGate,
    domainSignificanceHypothesis,
    domainSignificanceHypothesisGate:
      birthEvaluation.domainSignificanceHypothesisGate,
    measuredVariable,
    measuredOutcome,
    residualMagnitude,
    runtimeEvidenceKind,
    runtimeSourceBinding: runtimeSource.binding,
    candidateMechanismPrediction: `${family.mechanismHypothesis} Prediction frozen for ${targetId}: ${profile.candidatePrediction}`,
    rivalMechanismPrediction: `${family.rivalHypothesis} Rival prediction for ${targetId}: ${profile.rivalPrediction}`,
    frozenPredictionRef: `${daemonArtifactRoot}/${generatorFamilyDir}/GENERATOR_RUN_RESULTS.md#${outputId}-prediction`,
    baselineResults,
    rivalWeakened,
    counterexampleCollapsed,
    crossSourceSupport,
    holdoutReplayAvailable,
    nontrivialResidual,
    sourceFamilyDocumentedSignal: profile.sourceFamilyDocumentedSignal,
    knownTrivialSignal: profile.knownTrivialSignal,
    runtimeEvidencePresent: true,
    producedArtifact,
    birthEvaluation,
    hardSeed,
  };
}

