function generatorDomainSignificanceHypothesis(
  family: MechanismFirstGeneratorFamily,
  profile: ReturnType<typeof generatorOutcomeProfile>,
): DomainSignificanceHypothesis {
  return {
    statement: family.externalProblemAnchor.domainScientificSignificance,
    expectedDomainChange: family.externalProblemAnchor.discoveryScoredOutcome,
    noveltyDiscriminator: normalizeWhitespace(
      [
        "The claimed signal must be not documented outside known source-family behavior and must change interpretation of the external target outcome.",
        `Candidate prediction: ${profile.candidatePrediction}.`,
        `Rival prediction: ${profile.rivalPrediction}.`,
      ].join(" "),
    ),
    falsifier: normalizeWhitespace(
      [
        "The significance claim is falsified if source-family, metadata, simple baseline, or negative-control mechanisms erase the residual.",
        profile.rivalPrediction,
      ].join(" "),
    ),
    evidenceRefs: family.externalProblemAnchor.significanceEvidenceRefs,
    tested: profile.domainSignificanceTested,
    supported: profile.domainSignificanceSupported,
  };
}

function generatorBirthEligibleHardSeed(input: {
  family: MechanismFirstGeneratorFamily;
  targetId: string;
  outputId: string;
  externalProblemAnchor: ExternalProblemAnchor;
  domainSignificanceHypothesis: DomainSignificanceHypothesis;
  sourceRefs: string[];
  evidenceRefs: string[];
  measuredOutcome: number;
  residualMagnitude: number;
}): HardSeed {
  const claim = normalizeWhitespace(
    [
      `Mechanism-first generator ${input.family.generatorId} produced a birth-eligible hard seed for ${input.family.measurableOutcome}.`,
      `Domain scientific significance hypothesis: ${input.domainSignificanceHypothesis.statement}`,
      `Expected domain change: ${input.domainSignificanceHypothesis.expectedDomainChange}`,
      `Novelty discriminator: ${input.domainSignificanceHypothesis.noveltyDiscriminator}`,
      `The narrow seed says only that target ${input.targetId} deserves downstream InsightCandidate pressure because the runtime evidence survived simple baselines, rivals, counterexamples, cross-source support, holdout/replay availability, and the pre-birth domain-significance hypothesis gate.`,
    ].join(" "),
  );
  return baseHardSeed({
    seedId: `HARD-GEN-${normalizeCandidateIdPart(input.outputId)}`,
    candidateId: `GEN-CAND-${normalizeCandidateIdPart(input.outputId)}`,
    type:
      input.family.domain === "formal_mathematics_conjecture_refutation"
        ? "checked_refutation_or_formal_boundary"
        : "baseline_resistant_pattern",
    domain: input.family.domain,
    claim,
    observation: `Runtime generator evidence measured ${input.family.measurableOutcome} with outcome ${input.measuredOutcome} and residual magnitude ${input.residualMagnitude}; this is a hard seed only, not a discovery candidate or Fund.`,
    publicArtifactRef:
      input.sourceRefs.find((ref) => ref.startsWith("https://")) ??
      publicCorpusBaseRef,
    secondaryRef: input.evidenceRefs[2] ?? input.sourceRefs[0]!,
    sourceSeed: {
      kind: "mechanism_first_generator_output",
      generatorId: input.family.generatorId,
      targetId: input.targetId,
      outputId: input.outputId,
      externalProblemAnchor: input.externalProblemAnchor,
      domainSignificanceHypothesis: input.domainSignificanceHypothesis,
      noFundClaim: true,
    },
    score: 72,
    generatedFrom: "fresh_external_bank",
    expectedDeathCause: "proof_or_mechanism_failed",
    avoidsDeathCauses: [
      "not_externally_inspectable",
      "baseline_dominated",
      "known_trivial",
      "rival_theory_stronger",
      "counterexample_dense",
      "no_holdout_path",
      "no_replay_path",
    ],
  });
}

function generatorBlockedOutputsByCause(
  outputs: MechanismFirstGeneratorOutput[],
): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const output of outputs) {
    if (output.birthEvaluation.accepted) continue;
    const cause = output.birthEvaluation.primaryBlocker ?? "unknown";
    counts[cause] = (counts[cause] ?? 0) + 1;
  }
  return counts;
}

function generatorFamilyReplacementRequirements(
  outputs: MechanismFirstGeneratorOutput[],
  families: MechanismFirstGeneratorFamily[],
): GeneratorFamilyReplacementRequirement[] {
  return families.map((family) => {
    const familyOutputs = outputs.filter(
      (output) => output.generatorId === family.generatorId,
    );
    const born = familyOutputs.filter(
      (output) => output.birthEvaluation.accepted,
    );
    const blockerCounts = generatorBlockedOutputsByCause(familyOutputs);
    const dominantBlocker =
      Object.entries(blockerCounts)
        .filter(([, count]) => count > 0)
        .sort((left, right) => right[1] - left[1])[0]?.[0] ?? null;
    const replacementRequired = familyOutputs.length > 0 && born.length === 0;
    return {
      generatorId: family.generatorId,
      status: replacementRequired
        ? ("replacement_required" as const)
        : ("productive_or_not_run" as const),
      runtimeChecks: familyOutputs.length,
      hardSeedsBorn: born.length,
      blockedOutputs: familyOutputs.length - born.length,
      dominantBlocker,
      blockerCounts,
      requiredChange: replacementRequired
        ? generatorReplacementRequiredChange(dominantBlocker, family)
        : "No replacement required from the latest run.",
    };
  });
}

function generatorClosureReplacementRequirements(
  requirements: GeneratorFamilyReplacementRequirement[],
  families: MechanismFirstGeneratorFamily[],
  closureYield: GeneratorClosureYieldSignal,
): GeneratorFamilyReplacementRequirement[] {
  const dominantBlocker = `post_closure_non_discovery:${closureYield.dominantFundClass ?? "non_discovery"}`;
  const byGenerator = new Map(
    requirements.map((requirement) => [requirement.generatorId, requirement]),
  );
  const familyIds: MechanismFirstGeneratorFamilyId[] =
    families.length > 0
      ? families.map((family) => family.generatorId)
      : requirements.map((requirement) => requirement.generatorId);
  return Array.from(new Set(familyIds)).map((generatorId) => {
    const current = byGenerator.get(generatorId);
    const blockerCounts = {
      ...(current?.blockerCounts ?? {}),
      [dominantBlocker]: closureYield.nonDiscoveryClassifiedCandidates,
    };
    return {
      generatorId,
      status: "replacement_required" as const,
      runtimeChecks: current?.runtimeChecks ?? 0,
      hardSeedsBorn: current?.hardSeedsBorn ?? 0,
      blockedOutputs: current?.blockedOutputs ?? 0,
      dominantBlocker,
      blockerCounts,
      requiredChange: closureYield.claimLiftRequired
        ? "Closure classified every generator-born candidate as a non-discovery FundClass because the frozen InsightCandidate scope still carries anti-discovery or pipeline-scope caveats; create a new stable DiscoveryCandidate claim-lift contract with explicit external scientific significance before another long run."
        : "Closure classified every generator-born candidate as a non-discovery FundClass; redesign the external problem anchor, measurable outcome, and mechanism-vs-rival test so born seeds can plausibly produce discovery-scored evidence before another long run.",
    };
  });
}

function generatorReplacementRequiredChange(
  dominantBlocker: string | null,
  family: MechanismFirstGeneratorFamily,
): string {
  if (
    dominantBlocker === "source_family_documented_signal" ||
    dominantBlocker === "known_trivial_signal"
  ) {
    return "Replace the external problem anchor or target family; the current signal is source-family documented or known-trivial before birth.";
  }
  if (dominantBlocker === "public_corpus_downgraded_anchor") {
    return "Retire or replace this external anchor; the public corpus already downgraded, rival-explained, or marked the matched result as not discovery-scored.";
  }
  if (dominantBlocker?.startsWith("baseline_dominated")) {
    return "Redesign the measurement so the mechanism prediction produces a residual above the second-stage pressure floor before HardSeed birth.";
  }
  if (dominantBlocker === "rival_theory_stronger") {
    return "Redesign the frozen prediction around a rival-discriminating measurement where the rival mechanism can be weakened before birth.";
  }
  if (dominantBlocker === "no_cross_source_support") {
    return "Add independent source-family or cross-slice recurrence before birth; same-source recurrence is insufficient.";
  }
  if (dominantBlocker === "counterexample_dense") {
    return "Replace or narrow the mechanism hypothesis so bounded counterexample/control slices do not collapse the claim before birth.";
  }
  if (
    dominantBlocker === "generator_only_signal" ||
    dominantBlocker === "package_only_signal" ||
    dominantBlocker === "internally_interesting_only"
  ) {
    return "Choose a public external problem anchor with target-outcome evidence; generator-only or package-only interest cannot create a HardSeed.";
  }
  if (dominantBlocker === "missing_runtime_evidence") {
    return "Add a real loader/check execution path that writes canonical runtime evidence before any birth decision.";
  }
  if (dominantBlocker === "no_nontrivial_residual") {
    return "Replace the target outcome or mechanism prediction; current evidence has no nontrivial residual beyond simple controls.";
  }
  if (
    dominantBlocker === "missing_domain_significance_hypothesis" ||
    dominantBlocker === "unsupported_domain_significance_hypothesis" ||
    dominantBlocker === "untested_domain_significance_hypothesis"
  ) {
    return "Redesign the generator so runtime evidence tests and supports an explicit domain-scientific-significance hypothesis before HardSeed birth; residual survival alone is insufficient.";
  }
  return `Redesign ${family.generatorId} around a stronger external target outcome, explicit rival falsifier, independent recurrence, and replayable runtime evidence.`;
}

function generatorRunRemainingBottleneck(
  outputs: MechanismFirstGeneratorOutput[],
): string {
  const born = outputs.filter((output) => output.birthEvaluation.accepted);
  if (born.length > 0) {
    return `${born.length} birth-eligible hard seed(s) were produced, but no InsightCandidate or DiscoveryCandidate was created. Next bottleneck is downstream InsightCandidate pressure from generator-born seeds.`;
  }
  const causes = generatorBlockedOutputsByCause(outputs);
  const topCause =
    Object.entries(causes).sort((left, right) => right[1] - left[1])[0]?.[0] ??
    "unknown";
  return `No generator output reached hard-seed birth. Dominant blocker: ${topCause}. Generator-family replacement is required before rerunning long campaigns on this search surface.`;
}

