function generatorPressureYieldSignal(
  pressure: GeneratorBornHardSeedPressureReport | null,
): GeneratorPressureYieldSignal {
  if (pressure === null) {
    return {
      pressureRunFound: false,
      seedsLoaded: 0,
      testsRun: 0,
      seedsKilledByBaseline: 0,
      insightCandidatesCreated: 0,
      discoveryCandidatesCreated: 0,
      noInsightAfterBornSeeds: false,
      dominantBlocker: null,
      recommendedAction:
        "run discover-daemon generator-pressure after generator-run before treating generator births as productive evidence",
      pressureRef: null,
    };
  }
  const blockerCounts: Record<string, number> = {
    baseline_dominated: pressure.seedsKilledByBaseline,
    rival_theory_stronger: pressure.seedsKilledByRival,
    counterexample_dense: pressure.seedsKilledByCounterexample,
    no_cross_source_support: pressure.seedsKilledByLackOfRecurrence,
    holdout_or_replay_failed: pressure.seedsKilledByHoldoutReplay,
    proof_or_mechanism_failed: pressure.seedsKilledByMechanismProof,
  };
  const dominantBlocker =
    Object.entries(blockerCounts)
      .filter(([, count]) => count > 0)
      .sort((left, right) => right[1] - left[1])[0]?.[0] ?? null;
  const noInsightAfterBornSeeds =
    pressure.seedsLoaded > 0 &&
    pressure.insightCandidatesCreated === 0 &&
    pressure.discoveryCandidatesCreated === 0;
  return {
    pressureRunFound: true,
    seedsLoaded: pressure.seedsLoaded,
    testsRun: pressure.testsRun,
    seedsKilledByBaseline: pressure.seedsKilledByBaseline,
    insightCandidatesCreated: pressure.insightCandidatesCreated,
    discoveryCandidatesCreated: pressure.discoveryCandidatesCreated,
    noInsightAfterBornSeeds,
    dominantBlocker,
    recommendedAction: noInsightAfterBornSeeds
      ? `redesign or replace generator families before rerunning long campaigns; current born seeds die at ${dominantBlocker ?? "unknown"} pressure`
      : pressure.insightCandidatesCreated > 0
        ? "continue generator-born InsightCandidate closure with full downstream gates"
        : "continue generator pressure only after new birth-eligible hard seeds appear",
    pressureRef: `${daemonArtifactRoot}/${generatorBornPressureDir}/latest.json`,
  };
}

function generatorClosureYieldSignal(
  closure: GeneratorBornFundClosureReport | null,
): GeneratorClosureYieldSignal {
  if (closure === null) {
    return {
      closureRunFound: false,
      closureCandidateCount: 0,
      discoveryScoredCandidates: 0,
      nonDiscoveryClassifiedCandidates: 0,
      fundClassDistribution: {},
      allClosedAsNonDiscovery: false,
      claimLiftRequired: false,
      dominantFundClass: null,
      recommendedAction:
        "run discover-daemon generator-fund-closure after generator-insight-closure before treating closure candidates as discovery candidates",
      closureRef: null,
    };
  }
  const dominantFundClass =
    Object.entries(closure.fundClassDistribution)
      .filter(([, count]) => count > 0)
      .sort((left, right) => right[1] - left[1])[0]?.[0] ?? null;
  const allClosedAsNonDiscovery =
    closure.closureCandidateCount > 0 &&
    closure.discoveryScoredCandidates === 0 &&
    closure.nonDiscoveryClassifiedCandidates === closure.closureCandidateCount;
  const claimLiftRequired = closure.claimLiftRequired === true;
  return {
    closureRunFound: true,
    closureCandidateCount: closure.closureCandidateCount,
    discoveryScoredCandidates: closure.discoveryScoredCandidates,
    nonDiscoveryClassifiedCandidates: closure.nonDiscoveryClassifiedCandidates,
    fundClassDistribution: closure.fundClassDistribution,
    allClosedAsNonDiscovery,
    claimLiftRequired,
    dominantFundClass,
    recommendedAction: allClosedAsNonDiscovery
      ? claimLiftRequired
        ? `create a new stable DiscoveryCandidate claim lift with external scientific significance before rerunning long searches; current closure candidates classify as ${dominantFundClass ?? "non-discovery"} because the frozen InsightCandidate scope still carries anti-discovery or pipeline-scope caveats`
        : `replace or redesign generator families around external scientific significance before long runs; current closure candidates classify as ${dominantFundClass ?? "non-discovery"}`
      : closure.discoveryScoredCandidates > 0
        ? "run the full discovery-scored Fund notification path only for discovery-scored closure candidates"
        : "continue generator-born InsightCandidate closure only after closure candidates exist",
    closureRef: `${daemonArtifactRoot}/${generatorFundClosureDir}/latest.json`,
  };
}

