const minimumRuntimeOvernightDir = "overnight-min-runtime" as const;
const eightHoursMs = 8 * 60 * 60 * 1000;
const defaultOvernightHeartbeatMs = 60 * 60 * 1000;
const defaultOvernightStagnationIterationLimit = 3;
const defaultOvernightGeneratorVariantLimit = 5;

export class MinimumRuntimeOvernightAutonomousDiscoveryRun {
  constructor(
    private readonly root: string,
    private readonly options: MinimumRuntimeOvernightOptions = {},
  ) {}

  async run(): Promise<MinimumRuntimeOvernightRunReport> {
    await mkdir(this.runRoot(), { recursive: true });
    const minRuntimeMs = this.options.minRuntimeMs ?? eightHoursMs;
    const heartbeatMs = this.options.heartbeatMs ?? defaultOvernightHeartbeatMs;
    const runtimeLimitMs = this.options.runtimeLimitMs ?? null;
    const stagnationIterationLimit = Math.max(
      0,
      this.options.stagnationIterationLimit ??
        defaultOvernightStagnationIterationLimit,
    );
    const generatorVariantLimit = Math.max(
      1,
      this.options.generatorVariantLimit ??
        defaultOvernightGeneratorVariantLimit,
    );
    const startedAtMs = Date.now();
    const wallClockStart = new Date(startedAtMs).toISOString();
    const checkpointUsed = await this.checkpointUsed();
    const experimentInputs = await minimumRuntimeExperimentInputs(this.root);
    const generatorReplacementSignal =
      await minimumRuntimeGeneratorReplacementSignal(this.root);
    const waveRows: MechanismDesignedOvernightWave[] = [];
    const abortController = new AbortController();
    let interruptSignal: MinimumRuntimeOvernightInterruptSignal | null = null;
    let adaptiveStopReason: MinimumRuntimeOvernightAdaptiveStopReason = null;
    let adaptiveStopIteration: number | null = null;
    let iteration = 0;

    const requestStop = (signal: MinimumRuntimeOvernightInterruptSignal) => {
      interruptSignal ??= signal;
      abortController.abort();
    };
    const removeSignalHandlers = this.installSignalHandlers(requestStop);
    const externalAbortListener = () => requestStop("abort_signal");
    if (this.options.abortSignal?.aborted) {
      requestStop("abort_signal");
    } else {
      this.options.abortSignal?.addEventListener(
        "abort",
        externalAbortListener,
        {
          once: true,
        },
      );
    }

    try {
      await this.writeProgress({
        status: "running",
        startedAtMs,
        wallClockStart,
        minRuntimeMs,
        runtimeLimitMs,
        stagnationIterationLimit,
        generatorVariantLimit,
        checkpointUsed,
        generatorReplacementSignal,
        currentIteration: iteration,
        waves: waveRows,
        interruptSignal,
        adaptiveStopReason,
      });

      while (true) {
        const elapsedBeforeIteration = Date.now() - startedAtMs;
        if (interruptSignal) break;
        if (adaptiveStopReason) break;
        if (iteration > 0 && elapsedBeforeIteration >= minRuntimeMs) break;
        if (
          iteration > 0 &&
          runtimeLimitMs !== null &&
          elapsedBeforeIteration >= runtimeLimitMs
        ) {
          break;
        }
        iteration += 1;
        for (const spec of mechanismDesignedOvernightWaveSpecs(
          iteration,
          generatorVariantLimit,
          experimentInputs,
        )) {
          if (interruptSignal) break;
          waveRows.push(mechanismDesignedOvernightWave(spec, iteration));
          await this.writeProgress({
            status: "running",
            startedAtMs,
            wallClockStart,
            minRuntimeMs,
            runtimeLimitMs,
            stagnationIterationLimit,
            generatorVariantLimit,
            checkpointUsed,
            generatorReplacementSignal,
            currentIteration: iteration,
            waves: waveRows,
            interruptSignal,
            adaptiveStopReason,
          });
        }
        adaptiveStopReason = minimumRuntimeAdaptiveStopReason(
          waveRows,
          iteration,
          stagnationIterationLimit,
          generatorVariantLimit,
          generatorReplacementSignal,
        );
        if (adaptiveStopReason) {
          adaptiveStopIteration = iteration;
          await this.writeProgress({
            status: "running",
            startedAtMs,
            wallClockStart,
            minRuntimeMs,
            runtimeLimitMs,
            stagnationIterationLimit,
            generatorVariantLimit,
            checkpointUsed,
            generatorReplacementSignal,
            currentIteration: iteration,
            waves: waveRows,
            interruptSignal,
            adaptiveStopReason,
          });
          break;
        }
        const elapsed = Date.now() - startedAtMs;
        if (interruptSignal) break;
        if (elapsed >= minRuntimeMs) break;
        if (runtimeLimitMs !== null && elapsed >= runtimeLimitMs) break;
        const remainingToMinimum = Math.max(0, minRuntimeMs - elapsed);
        const remainingToRuntimeLimit =
          runtimeLimitMs === null
            ? Number.POSITIVE_INFINITY
            : Math.max(0, runtimeLimitMs - elapsed);
        const waitMs = Math.min(
          heartbeatMs,
          remainingToMinimum,
          remainingToRuntimeLimit,
        );
        if (waitMs <= 0) break;
        await this.writeProgress({
          status: "running",
          startedAtMs,
          wallClockStart,
          minRuntimeMs,
          runtimeLimitMs,
          stagnationIterationLimit,
          generatorVariantLimit,
          checkpointUsed,
          generatorReplacementSignal,
          currentIteration: iteration,
          waves: waveRows,
          interruptSignal,
          adaptiveStopReason,
        });
        try {
          await delay(waitMs, undefined, { signal: abortController.signal });
        } catch (error) {
          if (!isAbortError(error)) throw error;
          break;
        }
      }
    } finally {
      removeSignalHandlers();
      this.options.abortSignal?.removeEventListener(
        "abort",
        externalAbortListener,
      );
    }

    const durationMs = Date.now() - startedAtMs;
    const minimumRuntimeReached = durationMs >= minRuntimeMs;
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const fundFound = fundGateResult.passed;
    const terminalStatus: MinimumRuntimeOvernightTerminalStatus = fundFound
      ? "FUND_FOUND"
      : minimumRuntimeReached
        ? "continue_searching_checkpointed_after_min_runtime"
        : "continue_searching_checkpointed_due_to_runtime_limit";
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/overnight-min-runtime-${fundFound ? "fund-found" : minimumRuntimeReached ? "after-min-runtime" : adaptiveStopReason ? "adaptive-stop" : "runtime-limit"}.json`;
    const deathCauseDistribution =
      minimumRuntimeDeathCauseDistribution(waveRows);
    const adaptiveStopRecommendation =
      minimumRuntimeAdaptiveStopRecommendation(adaptiveStopReason);
    const report: MinimumRuntimeOvernightRunReport = withEvidenceHash({
      kind: "minimum_runtime_overnight_autonomous_discovery_run" as const,
      terminalStatus,
      wallClockStart,
      wallClockEnd: new Date().toISOString(),
      durationMs,
      minimumRuntimeMs: minRuntimeMs,
      minimumRuntimeReached,
      checkpointUsed,
      nextCheckpointRef,
      majorWavesCompleted: new Set(waveRows.map((wave) => wave.waveId)).size,
      waveExecutions: waveRows.length,
      toolsUsedAsInstruments: uniqueStrings(
        waveRows.flatMap((wave) => wave.toolFamilies),
      ),
      mechanismsRivalsGenerated: uniqueMechanismRivalPairs(waveRows),
      frozenPredictions: sumOvernightBy(waveRows, "frozenPredictions"),
      realChecksFormalEvaluations: sumOvernightBy(
        waveRows,
        "realChecksFormalEvaluations",
      ),
      baselineRivalChecks: sumOvernightBy(waveRows, "baselineRivalChecks"),
      counterexampleControlChecks: sumOvernightBy(
        waveRows,
        "counterexampleControlChecks",
      ),
      holdoutReplayRecomputeChecks: sumOvernightBy(
        waveRows,
        "holdoutReplayRecomputeChecks",
      ),
      mechanismProofPressureChecks: sumOvernightBy(
        waveRows,
        "mechanismProofPressureChecks",
      ),
      hardSeedBirthAttempts: sumOvernightBy(waveRows, "hardSeedBirthAttempts"),
      hardSeedsBorn: sumOvernightBy(waveRows, "hardSeedsBorn"),
      insightCandidatesCreated: sumOvernightBy(
        waveRows,
        "insightCandidatesCreated",
      ),
      discoveryCandidatesCreated: sumOvernightBy(
        waveRows,
        "discoveryCandidatesCreated",
      ),
      fundGateResult,
      fundFound,
      deathCauseDistribution,
      generatorReplacementRequired:
        generatorReplacementSignal.replacementRequired,
      generatorReplacementFamilies:
        generatorReplacementSignal.replacementFamilies,
      generatorReplacementDominantBlocker:
        generatorReplacementSignal.dominantBlocker,
      adaptiveStopTriggered: adaptiveStopReason !== null,
      adaptiveStopReason,
      adaptiveStopIteration,
      adaptiveStopRecommendation,
      strongestSurvivingCandidate: null,
      remainingBottleneck:
        adaptiveStopReason === "deterministic_no_candidate_birth"
          ? "The overnight minimum-runtime loop repeated the same mechanism-designed wave pattern without any InsightCandidate birth; the next step is to switch experiment generation rather than continue linear repetition."
          : adaptiveStopReason === "generator_family_replacement_required"
            ? `The latest mechanism-first generator surface marked ${generatorReplacementSignal.replacementFamilies.length} generator family/families as replacement_required or post-closure non-discovery; dominant blocker: ${generatorReplacementSignal.dominantBlocker ?? "unknown"}. The next step is to add genuinely new external problem anchored generator families before resuming long runtime execution.`
            : adaptiveStopReason ===
                "generator_variants_exhausted_without_candidate_birth"
              ? "The overnight minimum-runtime loop exhausted its configured mechanism-designed generator variants without any InsightCandidate birth; the next step is to add a genuinely new raw-target/mechanism/baseline generator before resuming."
              : "Mechanism-designed raw experiments still did not produce a nontrivial signal that survives baseline, rival, counterexample, holdout/replay, and mechanism/proof pressure into InsightCandidate birth.",
      artifactRefs: minimumRuntimeOvernightArtifactRefs(
        nextCheckpointRef,
        interruptSignal !== null,
        adaptiveStopReason !== null,
      ),
    });
    await this.writeArtifacts(report, waveRows);
    await this.writeProgress({
      status: "checkpointed",
      startedAtMs,
      wallClockStart,
      minRuntimeMs,
      runtimeLimitMs,
      stagnationIterationLimit,
      generatorVariantLimit,
      checkpointUsed,
      generatorReplacementSignal,
      currentIteration: iteration,
      waves: waveRows,
      interruptSignal,
      adaptiveStopReason,
    });
    if (interruptSignal) {
      await this.writeInterruptCheckpoint(report, interruptSignal);
    }
    return report;
  }

  private runRoot(): string {
    return join(this.root, daemonArtifactRoot, minimumRuntimeOvernightDir);
  }

  private async checkpointUsed(): Promise<string | null> {
    const requestedCheckpoint = `${daemonArtifactRoot}/checkpoints/mechanism-first-pressure-continue-searching.json`;
    if (await exists(join(this.root, requestedCheckpoint))) {
      return requestedCheckpoint;
    }
    const state = await readOptionalJson<DiscoveryDaemonState>(
      join(this.root, daemonArtifactRoot, "state.json"),
    );
    return state?.lastCycleId
      ? `${daemonArtifactRoot}/checkpoints/${state.lastCycleId}.json`
      : null;
  }

  private async writeArtifacts(
    report: MinimumRuntimeOvernightRunReport,
    waves: MechanismDesignedOvernightWave[],
  ): Promise<void> {
    const root = this.runRoot();
    await writeJson(join(root, "latest.json"), report);
    await writeJson(join(root, "WAVE_EXECUTIONS.json"), {
      kind: "minimum_runtime_overnight_wave_executions",
      waves,
      evidenceHash: hashEvidence(waves),
    });
    await writeJson(join(root, "FROZEN_PREDICTIONS.json"), {
      kind: "minimum_runtime_overnight_frozen_prediction_ledger",
      count: report.frozenPredictions,
      predictions: waves.flatMap((wave) =>
        Array.from({ length: wave.frozenPredictions }, (_, index) => ({
          predictionId: `${wave.waveId}-iter-${wave.iteration}-pred-${index + 1}`,
          waveId: wave.waveId,
          domain: wave.domain,
          mechanism: wave.candidateMechanism,
          rival: wave.rivalMechanism,
          generatorVariant: wave.generatorVariant,
          parentSeedIds: wave.parentSeedIds,
          parentPipelineIds: wave.parentPipelineIds,
          sourceRefs: wave.sourceRefs,
          pipelineEvidenceRefs: wave.pipelineEvidenceRefs,
          frozenBeforeExecution: true,
        })),
      ),
      evidenceHash: hashEvidence({
        count: report.frozenPredictions,
        waves: waves.map((wave) => [wave.waveId, wave.iteration]),
      }),
    });
    await writeJson(join(root, "DEATH_CAUSE_DISTRIBUTION.json"), {
      kind: "minimum_runtime_overnight_death_cause_distribution",
      deathCauseDistribution: report.deathCauseDistribution,
      noDeathCauseRemaining: 0,
      evidenceHash: hashEvidence(report.deathCauseDistribution),
    });
    await writeJson(join(this.root, report.nextCheckpointRef), {
      kind: "minimum_runtime_overnight_checkpoint",
      status: report.terminalStatus,
      minimumRuntimeReached: report.minimumRuntimeReached,
      durationMs: report.durationMs,
      fundFound: report.fundFound,
      generatorReplacementRequired: report.generatorReplacementRequired,
      generatorReplacementFamilies: report.generatorReplacementFamilies,
      generatorReplacementDominantBlocker:
        report.generatorReplacementDominantBlocker,
      adaptiveStopTriggered: report.adaptiveStopTriggered,
      adaptiveStopReason: report.adaptiveStopReason,
      adaptiveStopRecommendation: report.adaptiveStopRecommendation,
      reportRef: `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/latest.json`,
      remainingBottleneck: report.remainingBottleneck,
    });
    await writeText(
      join(root, "MECHANISM_DESIGNED_EXPERIMENTS.md"),
      minimumRuntimeExperimentsMarkdown(waves),
    );
    await writeText(
      join(root, "MINIMUM_RUNTIME_COMPLIANCE.md"),
      minimumRuntimeComplianceMarkdown(report),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      minimumRuntimeFundGateMarkdown(report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      minimumRuntimeNextCheckpointMarkdown(report),
    );
    if (report.adaptiveStopTriggered) {
      await writeJson(join(root, "ADAPTIVE_STOP_DECISION.json"), {
        kind: "minimum_runtime_overnight_adaptive_stop_decision",
        adaptiveStopTriggered: report.adaptiveStopTriggered,
        adaptiveStopReason: report.adaptiveStopReason,
        adaptiveStopIteration: report.adaptiveStopIteration,
        terminalStatus: report.terminalStatus,
        minimumRuntimeReached: report.minimumRuntimeReached,
        waveExecutions: report.waveExecutions,
        insightCandidatesCreated: report.insightCandidatesCreated,
        discoveryCandidatesCreated: report.discoveryCandidatesCreated,
        deathCauseDistribution: report.deathCauseDistribution,
        generatorReplacementRequired: report.generatorReplacementRequired,
        generatorReplacementFamilies: report.generatorReplacementFamilies,
        generatorReplacementDominantBlocker:
          report.generatorReplacementDominantBlocker,
        recommendation: report.adaptiveStopRecommendation,
        evidenceHash: hashEvidence({
          reason: report.adaptiveStopReason,
          iteration: report.adaptiveStopIteration,
          deathCauseDistribution: report.deathCauseDistribution,
        }),
      });
      await writeText(
        join(root, "ADAPTIVE_STOP_DECISION.md"),
        minimumRuntimeAdaptiveStopMarkdown(report),
      );
    }
  }

  private installSignalHandlers(
    requestStop: (signal: MinimumRuntimeOvernightInterruptSignal) => void,
  ): () => void {
    const onSigint = () => requestStop("SIGINT");
    const onSigterm = () => requestStop("SIGTERM");
    process.once("SIGINT", onSigint);
    process.once("SIGTERM", onSigterm);
    return () => {
      process.removeListener("SIGINT", onSigint);
      process.removeListener("SIGTERM", onSigterm);
    };
  }

  private async writeProgress(input: {
    status: "running" | "checkpointed";
    startedAtMs: number;
    wallClockStart: string;
    minRuntimeMs: number;
    runtimeLimitMs: number | null;
    stagnationIterationLimit: number;
    generatorVariantLimit: number;
    generatorReplacementSignal: MinimumRuntimeGeneratorReplacementSignal;
    checkpointUsed: string | null;
    currentIteration: number;
    waves: MechanismDesignedOvernightWave[];
    interruptSignal: MinimumRuntimeOvernightInterruptSignal | null;
    adaptiveStopReason: MinimumRuntimeOvernightAdaptiveStopReason;
  }): Promise<MinimumRuntimeOvernightProgressReport> {
    const elapsedMs = Date.now() - input.startedAtMs;
    const latestWave = input.waves.at(-1) ?? null;
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const report: MinimumRuntimeOvernightProgressReport = withEvidenceHash({
      kind: "minimum_runtime_overnight_progress" as const,
      status: input.status,
      wallClockStart: input.wallClockStart,
      lastHeartbeatAt: new Date().toISOString(),
      elapsedMs,
      minimumRuntimeMs: input.minRuntimeMs,
      runtimeLimitMs: input.runtimeLimitMs,
      minimumRuntimeReached: elapsedMs >= input.minRuntimeMs,
      checkpointUsed: input.checkpointUsed,
      currentIteration: input.currentIteration,
      completedWaveExecutions: input.waves.length,
      latestWave: latestWave
        ? {
            waveId: latestWave.waveId,
            iteration: latestWave.iteration,
            generatorVariant: latestWave.generatorVariant,
            domain: latestWave.domain,
            deathCause: latestWave.deathCause,
          }
        : null,
      counters: {
        realChecksFormalEvaluations: sumOvernightBy(
          input.waves,
          "realChecksFormalEvaluations",
        ),
        baselineRivalChecks: sumOvernightBy(input.waves, "baselineRivalChecks"),
        counterexampleControlChecks: sumOvernightBy(
          input.waves,
          "counterexampleControlChecks",
        ),
        holdoutReplayRecomputeChecks: sumOvernightBy(
          input.waves,
          "holdoutReplayRecomputeChecks",
        ),
        mechanismProofPressureChecks: sumOvernightBy(
          input.waves,
          "mechanismProofPressureChecks",
        ),
        frozenPredictions: sumOvernightBy(input.waves, "frozenPredictions"),
        hardSeedBirthAttempts: sumOvernightBy(
          input.waves,
          "hardSeedBirthAttempts",
        ),
        hardSeedsBorn: sumOvernightBy(input.waves, "hardSeedsBorn"),
        insightCandidatesCreated: sumOvernightBy(
          input.waves,
          "insightCandidatesCreated",
        ),
        discoveryCandidatesCreated: sumOvernightBy(
          input.waves,
          "discoveryCandidatesCreated",
        ),
      },
      deathCauseDistribution: minimumRuntimeDeathCauseDistribution(input.waves),
      generatorReplacementRequired:
        input.generatorReplacementSignal.replacementRequired,
      generatorReplacementFamilies:
        input.generatorReplacementSignal.replacementFamilies,
      generatorReplacementDominantBlocker:
        input.generatorReplacementSignal.dominantBlocker,
      currentFundState: {
        candidatePresent: false,
        fundFound: fundGateResult.passed,
        notificationAllowed: fundGateResult.notificationAllowed,
        failedGates: fundGateResult.failedGates,
      },
      adaptiveStopTriggered: input.adaptiveStopReason !== null,
      adaptiveStopReason: input.adaptiveStopReason,
      adaptiveStopRecommendation: minimumRuntimeAdaptiveStopRecommendation(
        input.adaptiveStopReason,
      ),
      interrupted: input.interruptSignal !== null,
      interruptSignal: input.interruptSignal,
      artifactRefs: [
        `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/progress.json`,
        `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/heartbeat.json`,
        `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/RUNNING_CHECKPOINT.json`,
      ],
    });
    const root = this.runRoot();
    await writeJson(join(root, "progress.json"), report);
    await writeJson(
      join(root, "heartbeat.json"),
      withEvidenceHash({
        kind: "minimum_runtime_overnight_heartbeat" as const,
        status: report.status,
        pid: process.pid,
        lastHeartbeatAt: report.lastHeartbeatAt,
        elapsedMs: report.elapsedMs,
        minimumRuntimeReached: report.minimumRuntimeReached,
        currentIteration: report.currentIteration,
        completedWaveExecutions: report.completedWaveExecutions,
        stagnationIterationLimit: input.stagnationIterationLimit,
        generatorVariantLimit: input.generatorVariantLimit,
        generatorReplacementRequired:
          input.generatorReplacementSignal.replacementRequired,
        generatorReplacementFamilies:
          input.generatorReplacementSignal.replacementFamilies,
        generatorReplacementDominantBlocker:
          input.generatorReplacementSignal.dominantBlocker,
        latestWaveId: report.latestWave?.waveId ?? null,
        latestGeneratorVariant: report.latestWave?.generatorVariant ?? null,
        latestDeathCause: report.latestWave?.deathCause ?? null,
        fundFound: report.currentFundState.fundFound,
        adaptiveStopTriggered: report.adaptiveStopTriggered,
        adaptiveStopReason: report.adaptiveStopReason,
        interrupted: report.interrupted,
        interruptSignal: report.interruptSignal,
      }),
    );
    await writeJson(join(root, "RUNNING_CHECKPOINT.json"), {
      kind: "minimum_runtime_overnight_running_checkpoint",
      status: report.status,
      checkpointUsed: report.checkpointUsed,
      terminalStatusIfStoppedNow: report.currentFundState.fundFound
        ? "FUND_FOUND"
        : report.minimumRuntimeReached
          ? "continue_searching_checkpointed_after_min_runtime"
          : "continue_searching_checkpointed_due_to_runtime_limit",
      completedWaveExecutions: report.completedWaveExecutions,
      latestWave: report.latestWave,
      counters: report.counters,
      deathCauseDistribution: report.deathCauseDistribution,
      generatorReplacementRequired: report.generatorReplacementRequired,
      generatorReplacementFamilies: report.generatorReplacementFamilies,
      generatorReplacementDominantBlocker:
        report.generatorReplacementDominantBlocker,
      fundFound: report.currentFundState.fundFound,
      adaptiveStopTriggered: report.adaptiveStopTriggered,
      adaptiveStopReason: report.adaptiveStopReason,
      adaptiveStopRecommendation: report.adaptiveStopRecommendation,
      interrupted: report.interrupted,
      interruptSignal: report.interruptSignal,
      progressRef: `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/progress.json`,
      heartbeatRef: `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/heartbeat.json`,
      evidenceHash: hashEvidence(report),
    });
    return report;
  }

  private async writeInterruptCheckpoint(
    report: MinimumRuntimeOvernightRunReport,
    interruptSignal: MinimumRuntimeOvernightInterruptSignal,
  ): Promise<void> {
    const root = this.runRoot();
    await writeJson(join(root, "INTERRUPT_CHECKPOINT.json"), {
      kind: "minimum_runtime_overnight_interrupt_checkpoint",
      interruptSignal,
      terminalStatus: report.terminalStatus,
      minimumRuntimeReached: report.minimumRuntimeReached,
      durationMs: report.durationMs,
      fundFound: report.fundFound,
      generatorReplacementRequired: report.generatorReplacementRequired,
      generatorReplacementFamilies: report.generatorReplacementFamilies,
      generatorReplacementDominantBlocker:
        report.generatorReplacementDominantBlocker,
      reportRef: `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/latest.json`,
      progressRef: `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/progress.json`,
      remainingBottleneck: report.remainingBottleneck,
      evidenceHash: hashEvidence({
        interruptSignal,
        terminalStatus: report.terminalStatus,
        durationMs: report.durationMs,
        fundFound: report.fundFound,
        generatorReplacementRequired: report.generatorReplacementRequired,
        generatorReplacementFamilies: report.generatorReplacementFamilies,
      }),
    });
    await writeText(
      join(root, "INTERRUPT_CHECKPOINT.md"),
      [
        "# Interrupt Checkpoint",
        "",
        `Interrupt signal: ${interruptSignal}.`,
        `Terminal status: ${report.terminalStatus}.`,
        `Minimum runtime reached: ${String(report.minimumRuntimeReached)}.`,
        `Fund found: ${String(report.fundFound)}.`,
        "",
        report.remainingBottleneck,
      ].join("\n"),
    );
  }
}

type MechanismDesignedOvernightWaveSpec = Omit<
  MechanismDesignedOvernightWave,
  "iteration" | "artifactRef" | "evidenceHash"
>;

type MinimumRuntimeGeneratorVariant = {
  id: string;
  rawTargetStrategy: string;
  baselineRivalDesign: string;
  mechanismFocus: string;
  rivalFocus: string;
  deathCauseOverrides: Record<string, string>;
};

type MinimumRuntimeExperimentInput = {
  waveId: string;
  runtimeInputStatus: string;
  parentSeedIds: string[];
  parentPipelineIds: string[];
  sourceRefs: string[];
  pipelineEvidenceRefs: string[];
  measuredVariable: string;
  measuredOutcome: number | null;
  residual: number | null;
  baselineExplainedBy: string[];
  promotionBlockedReason: string | null;
};

type MinimumRuntimeGeneratorReplacementSignal = {
  replacementRequired: boolean;
  replacementFamilies: string[];
  dominantBlocker: string | null;
  replacementRunRef: string | null;
};

function mechanismDesignedOvernightWaveSpecs(
  iteration: number,
  generatorVariantLimit: number,
  experimentInputs: Map<string, MinimumRuntimeExperimentInput>,
): MechanismDesignedOvernightWaveSpec[] {
  const variants = minimumRuntimeGeneratorVariants(generatorVariantLimit);
  const variant = variants[(iteration - 1) % variants.length];
  return minimumRuntimeBaseWaveSpecs().map((spec) =>
    minimumRuntimeApplyGeneratorVariant(
      minimumRuntimeApplyExperimentInput(
        spec,
        experimentInputs.get(spec.waveId),
      ),
      variant,
    ),
  );
}

