function minimumRuntimeApplyGeneratorVariant(
  spec: MechanismDesignedOvernightWaveSpec,
  variant: MinimumRuntimeGeneratorVariant,
): MechanismDesignedOvernightWaveSpec {
  return {
    ...spec,
    generatorVariant: variant.id,
    rawTargetStrategy: variant.rawTargetStrategy,
    baselineRivalDesign: variant.baselineRivalDesign,
    candidateMechanism: `${spec.candidateMechanism} (${variant.mechanismFocus})`,
    rivalMechanism: `${spec.rivalMechanism} (${variant.rivalFocus})`,
    deathCause: variant.deathCauseOverrides[spec.waveId] ?? spec.deathCause,
  };
}

function minimumRuntimeApplyExperimentInput(
  spec: MechanismDesignedOvernightWaveSpec,
  input: MinimumRuntimeExperimentInput | undefined,
): MechanismDesignedOvernightWaveSpec {
  if (!input) {
    return {
      ...spec,
      hardSeedBirthAttempts: 0,
      hardSeedsBorn: 0,
      seedBirthStatus: "blocked_missing_runtime_pipeline_evidence",
      seedBirthBlockers: ["missing_runtime_pipeline_evidence"],
      deathCause: "missing_runtime_evidence",
    };
  }
  const birthAssessment = minimumRuntimeHardSeedBirthAssessment(spec, input);
  return {
    ...spec,
    runtimeInputStatus: input.runtimeInputStatus,
    parentSeedIds: input.parentSeedIds,
    parentPipelineIds: input.parentPipelineIds,
    sourceRefs: input.sourceRefs,
    pipelineEvidenceRefs: input.pipelineEvidenceRefs,
    measuredVariable: input.measuredVariable,
    measuredOutcome: input.measuredOutcome,
    residual: input.residual,
    baselineExplainedBy: input.baselineExplainedBy,
    pipelinePromotionBlockedReason: input.promotionBlockedReason,
    hardSeedBirthAttempts: spec.hardSeedsBorn,
    hardSeedsBorn: birthAssessment.allowed ? spec.hardSeedsBorn : 0,
    seedBirthStatus: birthAssessment.allowed
      ? "born_from_runtime_pipeline_evidence"
      : "blocked_by_runtime_pipeline_evidence",
    seedBirthBlockers: birthAssessment.blockers,
  };
}

function minimumRuntimeHardSeedBirthAssessment(
  spec: MechanismDesignedOvernightWaveSpec,
  input: MinimumRuntimeExperimentInput,
): { allowed: boolean; blockers: string[] } {
  const blockers = uniqueStrings([
    input.runtimeInputStatus !== "loaded_from_tool_expansion_seed_and_pipeline"
      ? "missing_tool_expansion_seed_binding"
      : "",
    input.baselineExplainedBy.length > 0
      ? `baseline_explains_signal:${input.baselineExplainedBy.join(",")}`
      : "",
    input.promotionBlockedReason
      ? `promotion_blocked:${input.promotionBlockedReason}`
      : "",
    input.residual === null ? "missing_residual_measurement" : "",
    spec.hardSeedsBorn <= 0 ? "no_seed_birth_attempts_configured" : "",
  ]).filter(Boolean);
  return {
    allowed: blockers.length === 0,
    blockers,
  };
}

async function minimumRuntimeExperimentInputs(
  root: string,
): Promise<Map<string, MinimumRuntimeExperimentInput>> {
  const seedPayload = await readOptionalJson<{ hardSeeds?: unknown[] }>(
    join(
      root,
      daemonArtifactRoot,
      "tool-expansion",
      "HARD_SEEDS_FROM_TOOL_MEASUREMENTS.json",
    ),
  );
  const pipelinePayload = await readOptionalJson<{ pipelines?: unknown[] }>(
    join(
      root,
      daemonArtifactRoot,
      "tool-expansion",
      "DOMAIN_EVIDENCE_PIPELINES.json",
    ),
  );
  const seeds = Array.isArray(seedPayload?.hardSeeds)
    ? seedPayload.hardSeeds.filter(isRecord)
    : [];
  const pipelines = Array.isArray(pipelinePayload?.pipelines)
    ? pipelinePayload.pipelines.filter(isRecord)
    : [];
  const seedByPipeline = new Map<string, Record<string, unknown>>();
  for (const seed of seeds) {
    const parentPipelineId = stringValue(seed.parentPipelineId);
    if (parentPipelineId) seedByPipeline.set(parentPipelineId, seed);
  }
  const inputs = new Map<string, MinimumRuntimeExperimentInput>();
  for (const pipeline of pipelines) {
    const pipelineId = stringValue(pipeline.pipelineId);
    const waveId = minimumRuntimeWaveIdForPipeline(pipelineId);
    if (!pipelineId || !waveId) continue;
    const seed = seedByPipeline.get(pipelineId);
    inputs.set(waveId, {
      waveId,
      runtimeInputStatus: seed
        ? "loaded_from_tool_expansion_seed_and_pipeline"
        : "loaded_from_tool_expansion_pipeline_without_seed",
      parentSeedIds: seed ? [stringValue(seed.seedId)].filter(Boolean) : [],
      parentPipelineIds: [pipelineId],
      sourceRefs: uniqueStrings([
        ...stringArray(seed?.sourceRefs),
        stringValue(pipeline.targetRef),
        stringValue(pipeline.targetEvidenceRef),
      ]).filter(Boolean),
      pipelineEvidenceRefs: uniqueStrings([
        stringValue(pipeline.producedArtifact),
        `${daemonArtifactRoot}/tool-expansion/DOMAIN_EVIDENCE_PIPELINES.json#${pipelineId}`,
        seed
          ? `${daemonArtifactRoot}/tool-expansion/HARD_SEEDS_FROM_TOOL_MEASUREMENTS.json#${stringValue(seed.seedId)}`
          : "",
      ]).filter(Boolean),
      measuredVariable:
        stringValue(seed?.measuredVariable) ||
        stringValue(pipeline.measuredVariable) ||
        "unknown",
      measuredOutcome:
        numberOrNull(seed?.measuredOutcome) ??
        numberOrNull(pipeline.measuredOutcome),
      residual: numberOrNull(seed?.residual) ?? numberOrNull(pipeline.residual),
      baselineExplainedBy: minimumRuntimeBaselineExplainedBy(
        pipeline.baselineResults,
      ),
      promotionBlockedReason:
        stringValue(seed?.promotionBlockedReason) ||
        stringValue(pipeline.promotionBlockedReason) ||
        null,
    });
  }
  return inputs;
}

async function minimumRuntimeGeneratorReplacementSignal(
  root: string,
): Promise<MinimumRuntimeGeneratorReplacementSignal> {
  const run = await readOptionalJson<{
    generatorSet?: MechanismFirstGeneratorSet;
    replacementRequired?: boolean;
    replacementRequirements?: Array<{
      generatorId?: string;
      status?: string;
      dominantBlocker?: string | null;
    }>;
  }>(join(root, daemonArtifactRoot, generatorFamilyDir, "latest.json"));
  const closure = await readOptionalJson<{
    closureCandidateCount?: number;
    discoveryScoredCandidates?: number;
    nonDiscoveryClassifiedCandidates?: number;
    fundClassDistribution?: Record<string, number>;
  }>(join(root, daemonArtifactRoot, generatorFundClosureDir, "latest.json"));
  const replacementRequirements = Array.isArray(run?.replacementRequirements)
    ? run.replacementRequirements
    : [];
  const replacementFamilies = replacementRequirements
    .filter((item) => item.status === "replacement_required")
    .map((item) => item.generatorId)
    .filter((item): item is string => typeof item === "string");
  const dominantBlocker =
    replacementRequirements.find(
      (item) =>
        item.status === "replacement_required" &&
        typeof item.dominantBlocker === "string",
    )?.dominantBlocker ?? null;
  const closureCandidateCount = Number(closure?.closureCandidateCount ?? 0);
  const nonDiscoveryClassifiedCandidates = Number(
    closure?.nonDiscoveryClassifiedCandidates ?? 0,
  );
  const discoveryScoredCandidates = Number(
    closure?.discoveryScoredCandidates ?? 0,
  );
  const closureAllNonDiscovery =
    closure !== null &&
    closureCandidateCount > 0 &&
    discoveryScoredCandidates === 0 &&
    nonDiscoveryClassifiedCandidates === closureCandidateCount;
  const dominantClosureFundClass =
    Object.entries(closure?.fundClassDistribution ?? {})
      .filter(([, count]) => Number(count) > 0)
      .sort((left, right) => Number(right[1]) - Number(left[1]))[0]?.[0] ??
    null;
  if (closureAllNonDiscovery) {
    const explicitFamilies = replacementRequirements
      .map((item) => item.generatorId)
      .filter((item): item is string => typeof item === "string");
    const closureReplacementFamilies =
      explicitFamilies.length > 0
        ? explicitFamilies
        : run?.generatorSet
          ? mechanismFirstGeneratorFamilies(run.generatorSet).map(
              (family) => family.generatorId,
            )
          : [];
    return {
      replacementRequired: true,
      replacementFamilies: uniqueStrings(closureReplacementFamilies),
      dominantBlocker: `post_closure_non_discovery:${dominantClosureFundClass ?? "non_discovery"}`,
      replacementRunRef: `${daemonArtifactRoot}/${generatorFundClosureDir}/latest.json`,
    };
  }
  return {
    replacementRequired:
      run?.replacementRequired === true || replacementFamilies.length > 0,
    replacementFamilies,
    dominantBlocker,
    replacementRunRef:
      run === null
        ? null
        : `${daemonArtifactRoot}/${generatorFamilyDir}/latest.json`,
  };
}

function minimumRuntimeBaselineExplainedBy(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return uniqueStrings(
    value.filter(isRecord).flatMap((baseline) => {
      if (baseline.explainsSignal !== true) return [];
      return [
        stringValue(baseline.baseline) ||
          stringValue(baseline.name) ||
          "unnamed_baseline",
      ];
    }),
  );
}

function minimumRuntimeWaveIdForPipeline(pipelineId: string): string | null {
  const byPipeline: Record<string, string> = {
    "TOOL-MATERIALS-001": "wave-1-mechanism-designed-materials",
    "TOOL-ASTRO-001": "wave-2-mechanism-designed-astrophysics",
    "TOOL-CLIMATE-001": "wave-3-mechanism-designed-climate-energy",
    "TOOL-FORMAL-001": "wave-4-formal-bounded-property",
    "TOOL-BENCH-001": "wave-5-benchmark-protocol-delta",
    "TOOL-REPRO-001": "wave-6-repo-reproduction-outcome-labels",
  };
  return byPipeline[pipelineId] ?? null;
}

function stringValue(value: unknown): string {
  return typeof value === "string" ? value : "";
}

function mechanismDesignedOvernightWave(
  spec: MechanismDesignedOvernightWaveSpec,
  iteration: number,
): MechanismDesignedOvernightWave {
  const artifactRef = `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}/WAVE_EXECUTIONS.json#${spec.waveId}-iteration-${iteration}`;
  return withEvidenceHash({
    ...spec,
    iteration,
    artifactRef,
  });
}

function sumOvernightBy<K extends keyof MechanismDesignedOvernightWave>(
  rows: MechanismDesignedOvernightWave[],
  key: K,
): number {
  return rows.reduce((sum, row) => {
    const value = row[key];
    return typeof value === "number" ? sum + value : sum;
  }, 0);
}

function uniqueMechanismRivalPairs(
  waves: MechanismDesignedOvernightWave[],
): Array<{ mechanism: string; rival: string }> {
  const seen = new Set<string>();
  const pairs: Array<{ mechanism: string; rival: string }> = [];
  for (const wave of waves) {
    const key = `${wave.candidateMechanism}\n${wave.rivalMechanism}`;
    if (seen.has(key)) continue;
    seen.add(key);
    pairs.push({
      mechanism: wave.candidateMechanism,
      rival: wave.rivalMechanism,
    });
  }
  return pairs;
}

function minimumRuntimeDeathCauseDistribution(
  waves: MechanismDesignedOvernightWave[],
): Record<string, number> {
  const counts: Record<string, number> = {};
  for (const wave of waves) {
    const count = Math.max(wave.hardSeedsBorn, wave.hardSeedBirthAttempts);
    counts[wave.deathCause] = (counts[wave.deathCause] ?? 0) + count;
  }
  counts.unknown_requires_manual_review ??= 0;
  return counts;
}

function minimumRuntimeAdaptiveStopReason(
  waves: MechanismDesignedOvernightWave[],
  currentIteration: number,
  stagnationIterationLimit: number,
  generatorVariantLimit: number,
  generatorReplacementSignal: MinimumRuntimeGeneratorReplacementSignal,
): MinimumRuntimeOvernightAdaptiveStopReason {
  if (stagnationIterationLimit <= 0) return null;
  if (sumOvernightBy(waves, "insightCandidatesCreated") > 0) return null;
  if (sumOvernightBy(waves, "discoveryCandidatesCreated") > 0) return null;
  if (generatorReplacementSignal.replacementRequired && currentIteration >= 1) {
    return "generator_family_replacement_required";
  }
  if (currentIteration >= stagnationIterationLimit) {
    const recentIterations = Array.from(
      { length: stagnationIterationLimit },
      (_, index) => currentIteration - index,
    );
    const signatures = recentIterations.map((iteration) =>
      minimumRuntimeIterationSignature(waves, iteration),
    );
    if (
      signatures.every((signature) => signature !== "") &&
      new Set(signatures).size === 1
    ) {
      return "deterministic_no_candidate_birth";
    }
  }
  if (
    currentIteration >=
      Math.max(generatorVariantLimit, stagnationIterationLimit) &&
    minimumRuntimeGeneratorVariantsExhausted(waves, generatorVariantLimit)
  ) {
    return "generator_variants_exhausted_without_candidate_birth";
  }
  return null;
}

function minimumRuntimeGeneratorVariantsExhausted(
  waves: MechanismDesignedOvernightWave[],
  generatorVariantLimit: number,
): boolean {
  const expectedVariants = minimumRuntimeGeneratorVariants(
    generatorVariantLimit,
  ).map((variant) => variant.id);
  const seen = new Set(waves.map((wave) => wave.generatorVariant));
  return expectedVariants.every((variant) => seen.has(variant));
}

function minimumRuntimeIterationSignature(
  waves: MechanismDesignedOvernightWave[],
  iteration: number,
): string {
  return waves
    .filter((wave) => wave.iteration === iteration)
    .sort((left, right) => left.waveId.localeCompare(right.waveId))
    .map(
      (wave) =>
        `${wave.waveId}:${wave.generatorVariant}:${wave.deathCause}:${wave.insightCandidatesCreated}:${wave.discoveryCandidatesCreated}`,
    )
    .join("|");
}

function minimumRuntimeAdaptiveStopRecommendation(
  reason: MinimumRuntimeOvernightAdaptiveStopReason,
): string | null {
  if (reason === "deterministic_no_candidate_birth") {
    return "Stop repeating the same six mechanism-designed waves; switch to a different experiment generator that changes raw target selection, mechanism hypotheses, or baseline/rival design before resuming overnight execution.";
  }
  if (reason === "generator_family_replacement_required") {
    return "Do not rerun long overnight searches on generator families already marked replacement_required or closed entirely as non-discovery FundClasses; add or select new external problem anchored generator families first.";
  }
  if (reason === "generator_variants_exhausted_without_candidate_birth") {
    return "The configured raw-target/mechanism/baseline generator variants were all tried without InsightCandidate birth; add a genuinely new generator family before resuming long runtime execution.";
  }
  return null;
}

function minimumRuntimeOvernightArtifactRefs(
  nextCheckpointRef: string,
  includeInterruptCheckpoint = false,
  includeAdaptiveStopDecision = false,
): string[] {
  const root = `${daemonArtifactRoot}/${minimumRuntimeOvernightDir}`;
  const refs = [
    `${root}/latest.json`,
    `${root}/progress.json`,
    `${root}/heartbeat.json`,
    `${root}/RUNNING_CHECKPOINT.json`,
    `${root}/WAVE_EXECUTIONS.json`,
    `${root}/FROZEN_PREDICTIONS.json`,
    `${root}/DEATH_CAUSE_DISTRIBUTION.json`,
    `${root}/MECHANISM_DESIGNED_EXPERIMENTS.md`,
    `${root}/MINIMUM_RUNTIME_COMPLIANCE.md`,
    `${root}/FUND_GATE_RESULTS.md`,
    `${root}/NEXT_CHECKPOINT.md`,
    nextCheckpointRef,
  ];
  if (includeInterruptCheckpoint) {
    refs.push(`${root}/INTERRUPT_CHECKPOINT.json`);
    refs.push(`${root}/INTERRUPT_CHECKPOINT.md`);
  }
  if (includeAdaptiveStopDecision) {
    refs.push(`${root}/ADAPTIVE_STOP_DECISION.json`);
    refs.push(`${root}/ADAPTIVE_STOP_DECISION.md`);
  }
  return refs;
}

function isAbortError(error: unknown): boolean {
  return (
    error instanceof Error &&
    (error.name === "AbortError" || error.name === "TimeoutError")
  );
}

