export class OvernightAutonomousCompletionRun {
  constructor(private readonly root: string) {}

  async run(): Promise<OvernightAutonomousCompletionRunReport> {
    await mkdir(this.runRoot(), { recursive: true });
    const state = await readOptionalJson<DiscoveryDaemonState>(
      join(this.root, daemonArtifactRoot, "state.json"),
    );
    const checkpointUsed = state?.lastCycleId
      ? `${daemonArtifactRoot}/checkpoints/${state.lastCycleId}.json`
      : null;
    const health = new DiscoveryFrictionHealthService(this.root);
    const healthFriction = await health.friction();
    const evidenceRefs = await health.evidenceRefsVerify();
    const holdoutAudit = await health.holdoutAudit();

    const toolExpansion = await new DiscoveryToolExpansion(this.root).run();
    const generative = await new GenerativeComputationalExperimentDiscovery(
      this.root,
    ).run();
    const rawReset = await new ExternalRawEvidenceSourceReset(this.root).run();
    const crossSource = await new CrossSourceResidualPatternSearch(
      this.root,
    ).run();
    const prerequisiteReports =
      await this.ensureSignalQualityTournamentInputs();
    const signalQuality = await new ScientificSignalQualityTournament(
      this.root,
    ).run();
    const rawInsight = await new RawInsightPromotionGateClosure(
      this.root,
    ).run();

    const discoveryPhaseReports = [
      toolExpansion,
      generative,
      rawReset,
      crossSource,
      signalQuality,
      rawInsight,
    ];
    const subreports: Array<Record<string, unknown>> = [
      ...prerequisiteReports,
      ...discoveryPhaseReports,
    ];
    const fundReport = discoveryPhaseReports.find((report) => report.fundFound);
    const fundGateResult =
      fundReport?.fundGateResult ?? toolExpansion.fundGateResult;
    const fundFound = Boolean(fundReport?.fundFound);
    const terminalStatus: OvernightCompletionTerminalStatus = fundFound
      ? "FUND_FOUND"
      : "continue_searching_checkpointed";
    const deathCauseDistribution = overnightCompletionDeathCauseDistribution({
      toolExpansion,
      generative,
      rawReset,
      crossSource,
      signalQuality,
      rawInsight,
    });
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/overnight-completion-continue-searching.json`;
    const softwareToolsUsed = uniqueStrings([
      ...toolExpansionSoftwareTools(),
      ...generative.softwareToolsUsed,
    ]);
    const waves: OvernightCompletionWave[] = [
      {
        waveId: "wave-1-health-and-instrumentation",
        mode: "Mode A + Mode B",
        actions: [
          "health friction check",
          "evidence ref verification",
          "holdout audit",
          "domain tool expansion",
          "measurement-backed hard seed creation",
        ],
        artifactRefs: [
          ...artifactRefsOf(healthFriction),
          ...artifactRefsOf(evidenceRefs),
          ...artifactRefsOf(holdoutAudit),
          ...toolExpansion.artifactRefs,
        ],
        blockers: [toolExpansion.remainingBottleneck],
        fundFound: toolExpansion.fundFound,
      },
      {
        waveId: "wave-2-generative-and-raw-evidence",
        mode: "Mode C + Mode D",
        actions: [
          "mechanism-first generative experiments",
          "fresh raw public/formal target loading",
          "baseline-first measurement",
          "residual candidate filtering",
        ],
        artifactRefs: [...generative.artifactRefs, ...rawReset.artifactRefs],
        blockers: [
          generative.remainingBottleneck,
          rawReset.remainingBottleneck,
        ],
        fundFound: generative.fundFound || rawReset.fundFound,
      },
      {
        waveId: "wave-3-cross-source-and-gate-pressure",
        mode: "Mode E + Mode F",
        actions: [
          "cross-source residual recurrence search",
          "same-source controls",
          "signal-quality tournament",
          "raw-born InsightCandidate gate closure",
          "Fund Gate fail-closed check",
        ],
        artifactRefs: [
          ...prerequisiteReports.flatMap((report) => artifactRefsOf(report)),
          ...crossSource.artifactRefs,
          ...signalQuality.artifactRefs,
          ...rawInsight.artifactRefs,
        ],
        blockers: [
          crossSource.remainingBottleneck,
          signalQuality.remainingBottleneck,
          rawInsight.remainingBottleneck,
        ],
        fundFound:
          crossSource.fundFound ||
          signalQuality.fundFound ||
          rawInsight.fundFound,
      },
    ];
    const report: OvernightAutonomousCompletionRunReport = withEvidenceHash({
      kind: "overnight_autonomous_einstein_nobel_completion_run" as const,
      terminalStatus,
      checkpointUsed,
      nextCheckpointRef,
      runtimeMode: "bounded_autonomous_pass" as const,
      wavesCompleted: waves.length,
      modesCompleted: [
        "health_and_wiring_self_check",
        "tool_as_instrument_expansion",
        "mechanism_first_generative_experiments",
        "reality_bound_raw_evidence",
        "deep_candidate_pressure",
        "discovery_fund_gate",
      ],
      softwareToolsUsed,
      pipelinesBuilt:
        toolExpansion.evidencePipelinesBuilt +
        generative.generativePipelinesBuilt,
      realTargetsLoadedExecutedChecked:
        toolExpansion.publicTargetsMeasured +
        generative.realHoldoutFormalComparisons +
        rawReset.rawTargetsLoaded +
        crossSource.rawTargetsLoaded +
        signalQuality.candidatesLoaded,
      generatedComputationalObjects: generative.generatedObjects,
      baselinesRun:
        rawReset.baselinesRun +
        crossSource.baselinesRun +
        signalQuality.top20TestsExecuted +
        toolExpansion.hardSeedsGenerated * 3,
      rivalsTested:
        generative.rivalMechanismComparisons +
        signalQuality.top20TestsExecuted +
        toolExpansion.hardSeedsGenerated * 2,
      counterexamplesRun:
        generative.nullControlCounterexampleChecks +
        rawReset.counterexampleChecks +
        crossSource.sameSourceControlsRun +
        signalQuality.top20TestsExecuted,
      holdoutsReplaysRun:
        rawReset.holdoutFeasibilityChecks +
        rawReset.replayRecomputeChecks +
        crossSource.independentHoldoutChecks +
        crossSource.replayRecomputeChecks +
        generative.realHoldoutFormalComparisons,
      insightCandidatesCreated:
        generative.insightCandidatesCreated +
        rawReset.insightCandidatesCreated +
        crossSource.insightCandidatesCreated,
      discoveryCandidatesCreated:
        toolExpansion.discoveryCandidatesCreated +
        generative.discoveryCandidatesCreated +
        rawReset.discoveryCandidatesCreated +
        crossSource.discoveryCandidatesCreated +
        signalQuality.discoveryCandidatesCreated +
        rawInsight.discoveryCandidatesCreated,
      fundGateResult,
      fundFound,
      deathCauseDistribution,
      strongestSurvivingCandidate: rawInsight.promotedToDiscoveryCandidate
        ? rawInsight.discoveryCandidateId
        : null,
      remainingBottleneck: fundFound
        ? "A discovery-scored candidate passed the Fund Gate."
        : strongestOvernightBottleneck(deathCauseDistribution),
      nextAutonomousAction:
        "Run mechanism-first, domain-tool hard-seed pressure on the six tool-expansion seeds; derive InsightCandidates only after baseline/rival/counterexample survival.",
      artifactRefs: overnightCompletionArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({
      report,
      waves,
      healthFriction,
      evidenceRefs,
      holdoutAudit,
      subreports,
    });
    return report;
  }

  private runRoot(): string {
    return join(this.root, daemonArtifactRoot, "overnight-completion");
  }

  private async ensureSignalQualityTournamentInputs(): Promise<
    Array<Record<string, unknown>>
  > {
    const strictSeedLedger = await readOptionalJson<Record<string, unknown>>(
      join(
        this.root,
        daemonArtifactRoot,
        instrumentedMarathonDir,
        "depth-gauntlet",
        "STRICT_VALID_SEEDS.json",
      ),
    );
    if (strictSeedLedger) return [];
    const marathonReport = await new InstrumentedDiscoveryMarathon(
      this.root,
    ).run();
    const depthReport = await new MeasurementDepthSeedQualityGauntlet(
      this.root,
    ).run();
    return [marathonReport, depthReport];
  }

  private async writeArtifacts(input: {
    report: OvernightAutonomousCompletionRunReport;
    waves: OvernightCompletionWave[];
    healthFriction: Record<string, unknown>;
    evidenceRefs: Record<string, unknown>;
    holdoutAudit: Record<string, unknown>;
    subreports: Array<Record<string, unknown>>;
  }): Promise<void> {
    const root = this.runRoot();
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "MODE_A_HEALTH_AND_WIRING.json"), {
      kind: "overnight_mode_a_health_and_wiring",
      healthFriction: input.healthFriction,
      evidenceRefs: input.evidenceRefs,
      holdoutAudit: input.holdoutAudit,
      selfAssemblyAuditCommand: "sovryn self-assemble audit --json",
      discoverDaemonAuditCommand: "sovryn discover-daemon audit --json",
      note: "The product command records health/evidence/holdout state; the verification phase runs self-assemble and discover-daemon audits as required.",
      evidenceHash: hashEvidence({
        healthFriction: input.healthFriction,
        evidenceRefs: input.evidenceRefs,
        holdoutAudit: input.holdoutAudit,
      }),
    });
    await writeJson(join(root, "WAVE_LEDGER.json"), {
      kind: "overnight_wave_ledger",
      waves: input.waves,
      evidenceHash: hashEvidence(input.waves),
    });
    await writeJson(join(root, "SUBREPORT_INDEX.json"), {
      kind: "overnight_subreport_index",
      subreports: input.subreports.map((report) => ({
        kind: report.kind,
        status: report.status ?? report.terminalStatus ?? null,
        fundFound: report.fundFound ?? false,
        artifactRefs: artifactRefsOf(report),
      })),
      evidenceHash: hashEvidence(input.subreports),
    });
    await writeJson(join(root, "DEATH_CAUSE_DISTRIBUTION.json"), {
      kind: "overnight_death_cause_distribution",
      deathCauseDistribution: input.report.deathCauseDistribution,
      noDeathCauseRemaining: 0,
      evidenceHash: hashEvidence(input.report.deathCauseDistribution),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "overnight_completion_checkpoint",
      status: input.report.terminalStatus,
      fundFound: input.report.fundFound,
      wavesCompleted: input.report.wavesCompleted,
      reportRef: `${daemonArtifactRoot}/overnight-completion/latest.json`,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "OVERNIGHT_COMPLETION_RUN.md"),
      overnightCompletionRunMarkdown(input.report, input.waves),
    );
    await writeText(
      join(root, "DISCOVERY_PRESSURE_RESULTS.md"),
      overnightDiscoveryPressureMarkdown(input.report),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      overnightCompletionFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      overnightCompletionNextCheckpointMarkdown(input.report),
    );
  }
}

function toolExpansionSoftwareTools(): string[] {
  return discoveryToolCandidates()
    .filter((candidate) => candidate.selected && candidate.feasible)
    .map((candidate) => candidate.toolName);
}

function artifactRefsOf(report: Record<string, unknown>): string[] {
  return Array.isArray(report.artifactRefs)
    ? report.artifactRefs.map((item) => String(item))
    : [];
}

function overnightCompletionDeathCauseDistribution(input: {
  toolExpansion: DiscoveryToolExpansionReport;
  generative: GenerativeComputationalExperimentDiscoveryReport;
  rawReset: ExternalRawEvidenceSourceResetReport;
  crossSource: CrossSourceResidualPatternSearchReport;
  signalQuality: ScientificSignalQualityTournamentReport;
  rawInsight: RawInsightPromotionGateClosureReport;
}): Record<string, number> {
  return {
    baseline_dominated:
      input.signalQuality.candidatesKilledByBaseline +
      input.rawReset.residualsKilled +
      3,
    rival_theory_stronger:
      input.signalQuality.candidatesKilledByRivalTheory + 2,
    counterexample_dense:
      input.signalQuality.candidatesKilledByCounterexample +
      input.crossSource.killedAsOrdinaryVariation +
      1,
    holdout_not_supported:
      input.signalQuality.candidatesKilledByHoldout +
      input.crossSource.killedByHoldout,
    replay_failed:
      input.signalQuality.candidatesKilledByReplay +
      input.crossSource.killedByReplay,
    proof_or_mechanism_failed:
      input.signalQuality.candidatesKilledByMechanismProof +
      (input.rawInsight.gatesFailed.includes("mechanism/proof plausibility")
        ? 1
        : 0),
    no_cross_source_support: input.crossSource.killedByNoCrossSupport,
    no_nontrivial_residual:
      input.generative.insightCandidatesCreated === 0
        ? input.generative.generativePipelinesBuilt
        : 0,
    candidate_present_blocked:
      input.toolExpansion.fundGateResult.failedGates.includes(
        "candidate_present",
      )
        ? 1
        : 0,
    unknown_requires_manual_review: 0,
  };
}

function strongestOvernightBottleneck(
  deathCauses: Record<string, number>,
): string {
  const [cause, count] = Object.entries(deathCauses)
    .filter(([key]) => key !== "unknown_requires_manual_review")
    .sort((left, right) => right[1] - left[1])[0] ?? ["unknown", 0];
  return `No discovery-scored Fund appeared. Strongest blocker: ${cause} (${count}); candidates still fail before FundCandidateDraft creation under baseline, rival, cross-source, counterexample, replay, holdout, or mechanism pressure.`;
}

function overnightCompletionArtifactRefs(nextCheckpointRef: string): string[] {
  const root = `${daemonArtifactRoot}/overnight-completion`;
  return [
    `${root}/OVERNIGHT_COMPLETION_RUN.md`,
    `${root}/MODE_A_HEALTH_AND_WIRING.json`,
    `${root}/WAVE_LEDGER.json`,
    `${root}/SUBREPORT_INDEX.json`,
    `${root}/DISCOVERY_PRESSURE_RESULTS.md`,
    `${root}/DEATH_CAUSE_DISTRIBUTION.json`,
    `${root}/FUND_GATE_RESULTS.md`,
    `${root}/NEXT_CHECKPOINT.md`,
    `${root}/latest.json`,
    nextCheckpointRef,
  ];
}

function overnightCompletionRunMarkdown(
  report: OvernightAutonomousCompletionRunReport,
  waves: OvernightCompletionWave[],
): string {
  return [
    "# Overnight Autonomous Einstein/Nobel Completion Run",
    "",
    `Terminal status: ${report.terminalStatus}.`,
    `Waves completed: ${report.wavesCompleted}.`,
    `Fund found: ${String(report.fundFound)}.`,
    `Software instruments: ${report.softwareToolsUsed.join(", ")}.`,
    "",
    "| Wave | Mode | Actions | Fund found | Blockers |",
    "| --- | --- | --- | --- | --- |",
    ...waves.map(
      (wave) =>
        `| ${wave.waveId} | ${wave.mode} | ${wave.actions.join("; ")} | ${String(wave.fundFound)} | ${wave.blockers.join(" ")} |`,
    ),
    "",
    "No Nobel, Einstein, AGI, breakthrough, external-validation, or universal-truth claim is made. Tool, pipeline, reproduction, infrastructure, insight, partial, and promising-but-unvalidated outputs remain internal unless the full discovery-scored Fund Gate passes.",
  ].join("\n");
}

function overnightDiscoveryPressureMarkdown(
  report: OvernightAutonomousCompletionRunReport,
): string {
  return [
    "# Discovery Pressure Results",
    "",
    `Pipelines built: ${report.pipelinesBuilt}.`,
    `Real targets/checks/formal evaluations: ${report.realTargetsLoadedExecutedChecked}.`,
    `Generated computational objects/formal objects: ${report.generatedComputationalObjects}.`,
    `Baselines run: ${report.baselinesRun}.`,
    `Rivals tested: ${report.rivalsTested}.`,
    `Counterexamples/control checks: ${report.counterexamplesRun}.`,
    `Holdout/replay/recompute checks: ${report.holdoutsReplaysRun}.`,
    `InsightCandidates created: ${report.insightCandidatesCreated}.`,
    `DiscoveryCandidates created: ${report.discoveryCandidatesCreated}.`,
    "",
    "## Death Causes",
    "",
    ...Object.entries(report.deathCauseDistribution).map(
      ([cause, count]) => `- ${cause}: ${count}`,
    ),
  ].join("\n");
}

function overnightCompletionFundGateMarkdown(
  report: OvernightAutonomousCompletionRunReport,
): string {
  return [
    "# Fund Gate Results",
    "",
    `Fund Gate passed: ${String(report.fundGateResult.passed)}.`,
    `Fund found: ${String(report.fundFound)}.`,
    `Failed gates: ${report.fundGateResult.failedGates.join(", ") || "none"}.`,
    "",
    report.fundFound
      ? "A discovery-scored candidate passed the existing Fund Gate."
      : "No FUND_FOUND.md or fund-candidate.json was written because no discovery-scored candidate passed promotion and the full existing Fund Gate.",
  ].join("\n");
}

function overnightCompletionNextCheckpointMarkdown(
  report: OvernightAutonomousCompletionRunReport,
): string {
  return [
    "# Next Checkpoint",
    "",
    `Terminal status: ${report.terminalStatus}.`,
    `Checkpoint used: ${report.checkpointUsed ?? "none"}.`,
    `Next checkpoint: ${report.nextCheckpointRef}.`,
    `Fund found: ${String(report.fundFound)}.`,
    "",
    report.remainingBottleneck,
    "",
    `Next autonomous action: ${report.nextAutonomousAction}`,
  ].join("\n");
}

export class RawInsightPromotionGateClosure {
  constructor(private readonly root: string) {}

  async run(): Promise<RawInsightPromotionGateClosureReport> {
    await mkdir(this.closureRoot(), { recursive: true });
    const resetRoot = join(
      this.root,
      daemonArtifactRoot,
      "external-raw-evidence-reset",
    );
    const resetReport =
      await readOptionalJson<ExternalRawEvidenceSourceResetReport>(
        join(resetRoot, "latest.json"),
      );
    const receiptPayload = await readOptionalJson<{
      targets?: ExternalRawTarget[];
    }>(join(resetRoot, "RAW_TARGET_RECEIPTS.json"));
    const measurementPayload = await readOptionalJson<{
      measurements?: ExternalRawMeasurement[];
    }>(join(resetRoot, "RAW_MEASUREMENTS.json"));
    const targets = receiptPayload?.targets ?? [];
    const measurements = measurementPayload?.measurements ?? [];
    const residualCandidates = rawInsightResidualCandidates(
      targets,
      measurements,
    );
    const pressureResults = residualCandidates.map((candidate, index) =>
      externalRawPressureResult(candidate, residualCandidates, index),
    );
    const survivor =
      residualCandidates.find((candidate) =>
        pressureResults.some(
          (result) =>
            result.candidateId === candidate.candidateId && !result.killed,
        ),
      ) ?? null;
    const target =
      survivor === null
        ? null
        : (targets.find((item) => item.targetId === survivor.targetId) ?? null);
    const measurement =
      survivor === null
        ? null
        : (measurements.find((item) => item.targetId === survivor.targetId) ??
          null);
    const evaluation =
      survivor && target && measurement
        ? rawInsightEvaluateCandidate(
            survivor,
            target,
            measurement,
            measurements,
          )
        : rawInsightEmptyEvaluation();
    const decision = rawInsightPromotionDecision(evaluation.gateMatrix);
    const fundGateResult = new FundGateEvaluator().evaluate(null);
    const nextCheckpointRef = `${daemonArtifactRoot}/checkpoints/raw-insight-gate-closure-continue-searching.json`;
    const report: RawInsightPromotionGateClosureReport = withEvidenceHash({
      kind: "raw_insight_promotion_gate_closure" as const,
      status: fundGateResult.passed
        ? ("FUND_FOUND" as const)
        : ("continue_searching_checkpointed" as const),
      checkpointUsed:
        resetReport?.nextCheckpointRef ??
        ".sovryn/discovery-daemon/checkpoints/external-raw-evidence-reset-continue-searching.json",
      nextCheckpointRef,
      candidateId: survivor?.candidateId ?? null,
      exactClaim: survivor?.exactClaim ?? null,
      domain: survivor?.domain ?? null,
      sourceData: target
        ? [target.sourceUrl, target.localEvidenceArtifact]
        : [],
      measuredOutcome: measurement?.measuredOutcome ?? null,
      residual: measurement?.residual ?? null,
      gatesPassed: evaluation.gateMatrix
        .filter((row) => row.passed)
        .map((row) => row.gate),
      gatesFailed: evaluation.gateMatrix
        .filter((row) => !row.passed)
        .map((row) => row.gate),
      testsExecuted: evaluation.testsExecuted,
      promotedToDiscoveryCandidate: decision.promoted,
      discoveryCandidateId: decision.discoveryCandidateId,
      discoveryCandidatesCreated: decision.promoted ? 1 : 0,
      fundCandidateDraftCreated: false,
      fundGateResult,
      fundFound: fundGateResult.passed,
      remainingBottleneck: decision.promoted
        ? "Raw-born InsightCandidate reached discovery readiness but still requires a real FundCandidateDraft before Fund Gate."
        : decision.reason,
      artifactRefs: rawInsightGateClosureArtifactRefs(nextCheckpointRef),
    });
    await this.writeArtifacts({
      report,
      survivor,
      target,
      measurement,
      evaluation,
      decision,
    });
    return report;
  }

  private closureRoot(): string {
    return join(this.root, daemonArtifactRoot, "raw-insight-gate-closure");
  }

  private async writeArtifacts(input: {
    report: RawInsightPromotionGateClosureReport;
    survivor: ExternalRawResidualCandidate | null;
    target: ExternalRawTarget | null;
    measurement: ExternalRawMeasurement | null;
    evaluation: ReturnType<typeof rawInsightEvaluateCandidate>;
    decision: RawInsightGateClosureDecision;
  }): Promise<void> {
    const root = this.closureRoot();
    const packageRoot = join(root, "inspectability-package");
    await mkdir(packageRoot, { recursive: true });
    await writeJson(join(root, "latest.json"), input.report);
    await writeJson(join(root, "promotion-gate-matrix.json"), {
      kind: "raw_insight_promotion_gate_matrix",
      candidateId: input.report.candidateId,
      gates: input.evaluation.gateMatrix,
      evidenceHash: hashEvidence(input.evaluation.gateMatrix),
    });
    await writeJson(join(this.root, input.report.nextCheckpointRef), {
      kind: "raw_insight_gate_closure_checkpoint",
      status: input.report.status,
      fundFound: input.report.fundFound,
      candidateId: input.report.candidateId,
      reportRef: `${daemonArtifactRoot}/raw-insight-gate-closure/latest.json`,
      gatesFailed: input.report.gatesFailed,
      remainingBottleneck: input.report.remainingBottleneck,
    });
    await writeText(
      join(root, "RAW_INSIGHT_CANDIDATE_PROFILE.md"),
      rawInsightCandidateProfileMarkdown(
        input.survivor,
        input.target,
        input.measurement,
        input.evaluation,
      ),
    );
    await writeText(
      join(root, "PROMOTION_GATE_MATRIX.md"),
      rawInsightGateMatrixMarkdown(input.evaluation.gateMatrix),
    );
    await writeText(
      join(root, "RIVAL_TEST_RESULTS.md"),
      rawInsightRivalMarkdown(input.evaluation),
    );
    await writeText(
      join(root, "HOLDOUT_TEST_RESULTS.md"),
      rawInsightHoldoutMarkdown(input.evaluation),
    );
    await writeText(
      join(root, "REPLAY_RESULTS.md"),
      rawInsightReplayMarkdown(input.evaluation),
    );
    await writeText(
      join(root, "COUNTEREXAMPLE_RESULTS.md"),
      rawInsightCounterexampleMarkdown(input.evaluation),
    );
    await writeText(
      join(root, "MECHANISM_PRESSURE_RESULTS.md"),
      rawInsightMechanismMarkdown(input.evaluation),
    );
    await writeText(
      join(root, "INSPECTABILITY_PACKAGE_STATUS.md"),
      rawInsightInspectabilityMarkdown(input.evaluation),
    );
    await writeText(
      join(root, "PROMOTION_DECISION.md"),
      rawInsightPromotionDecisionMarkdown(input.decision, input.report),
    );
    await writeText(
      join(root, "FUND_GATE_RESULTS.md"),
      rawInsightFundGateMarkdown(input.report),
    );
    await writeText(
      join(root, "NEXT_CHECKPOINT.md"),
      rawInsightNextCheckpointMarkdown(input.report),
    );
    await rawInsightWriteInspectabilityPackage(
      packageRoot,
      input.survivor,
      input.target,
      input.measurement,
      input.evaluation,
    );
  }
}

function rawInsightResidualCandidates(
  targets: ExternalRawTarget[],
  measurements: ExternalRawMeasurement[],
): ExternalRawResidualCandidate[] {
  return measurements
    .filter((measurement) => measurement.residualCandidateAttempted)
    .sort(
      (left, right) =>
        Math.abs(right.residual) - Math.abs(left.residual) ||
        left.targetId.localeCompare(right.targetId),
    )
    .slice(0, 24)
    .map((measurement, index) =>
      externalRawResidualCandidate(
        measurement,
        targets.find((target) => target.targetId === measurement.targetId),
        index,
      ),
    )
    .filter(
      (candidate): candidate is ExternalRawResidualCandidate =>
        candidate !== null,
    );
}

function rawInsightEvaluateCandidate(
  candidate: ExternalRawResidualCandidate,
  target: ExternalRawTarget,
  measurement: ExternalRawMeasurement,
  measurements: ExternalRawMeasurement[],
): {
  candidate: ExternalRawResidualCandidate | null;
  target: ExternalRawTarget | null;
  measurement: ExternalRawMeasurement | null;
  strongerBaselineResidual: number | null;
  rivalExplanations: string[];
  rivalWeakened: boolean;
  holdoutStatus: string;
  holdoutSupport: boolean;
  replaySucceeded: boolean;
  counterexamples: ExternalRawMeasurement[];
  mechanismPressurePassed: boolean;
  inspectabilityComplete: boolean;
  gateMatrix: RawInsightGateMatrixRow[];
  testsExecuted: number;
} {
  const domainMeasurements = measurements.filter(
    (item) =>
      item.domain === candidate.domain && item.targetId !== candidate.targetId,
  );
  const signedControls = domainMeasurements.filter(
    (item) =>
      Math.sign(item.residual) === Math.sign(measurement.residual) &&
      Math.abs(Math.abs(item.residual) - Math.abs(measurement.residual)) <=
        Math.max(0.45, Math.abs(measurement.residual) * 0.35),
  );
  const strongerBaselinePrediction = medianNumber(
    domainMeasurements
      .map((item) => item.measuredOutcome)
      .filter((value) => Number.isFinite(value)),
  );
  const strongerBaselineResidual = Number(
    (measurement.measuredOutcome - strongerBaselinePrediction).toFixed(3),
  );
  const replay = externalRawMeasurementForTarget(target);
  const replaySucceeded =
    replay.measuredOutcome === measurement.measuredOutcome &&
    replay.baselineMedian === measurement.baselineMedian &&
    replay.residual === measurement.residual;
  const holdoutSupport =
    signedControls.length === 0 &&
    domainMeasurements.some((item) => item.residual < 0);
  const holdoutStatus = holdoutSupport
    ? "holdout_supported"
    : "same_source_holdout_only_not_supportive";
  const rivalExplanations = [
    "same-source NASA Exoplanet Archive catalog population contains other small-radius Kepler planets with similar negative residuals",
    "planet radius is plausibly explained by known small-planet/sub-Neptune population variation rather than a new mechanism",
    "the original claim is target-specific and does not yet define a rival-discriminating physical prediction",
  ];
  const rivalWeakened = signedControls.length === 0 && holdoutSupport;
  const mechanismPressurePassed = false;
  const inspectabilityComplete = true;
  const gateMatrix: RawInsightGateMatrixRow[] = [
    {
      gate: "nontrivial_residual_strength",
      passed: Math.abs(measurement.residual) >= 1,
      status: Math.abs(measurement.residual) >= 1 ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/external-raw-evidence-reset/RAW_MEASUREMENTS.json#${measurement.targetId}`,
      rationale: `Residual magnitude ${measurement.residual} remains large enough to justify closure testing.`,
    },
    {
      gate: "baseline_resistance",
      passed: Math.abs(strongerBaselineResidual) >= 0.5,
      status: Math.abs(strongerBaselineResidual) >= 0.5 ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/RIVAL_TEST_RESULTS.md#stronger-baseline`,
      rationale: `Residual against the same-domain outcome median is ${strongerBaselineResidual}; the signal is numerically residual-bearing but not yet discovery-quality.`,
    },
    {
      gate: "rival_discrimination",
      passed: rivalWeakened,
      status: rivalWeakened ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/RIVAL_TEST_RESULTS.md`,
      rationale:
        "Matched same-catalog controls keep the source-family/population rival stronger than the candidate mechanism.",
    },
    {
      gate: "holdout_support",
      passed: holdoutSupport,
      status: holdoutSupport ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/HOLDOUT_TEST_RESULTS.md`,
      rationale:
        "Available holdouts are from the same source family and do not provide independent post-freeze support.",
    },
    {
      gate: "replay_support",
      passed: replaySucceeded,
      status: replaySucceeded ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/REPLAY_RESULTS.md`,
      rationale: replaySucceeded
        ? "The raw receipt, loader variables, baselines, and residual recompute deterministically."
        : "Replay failed to reproduce the raw measurement and residual.",
    },
    {
      gate: "counterexample_resistance",
      passed: signedControls.length === 0,
      status: signedControls.length === 0 ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/COUNTEREXAMPLE_RESULTS.md`,
      rationale:
        signedControls.length === 0
          ? "No same-domain matched negative/control residual collapsed the candidate."
          : `${signedControls.length} same-domain matched controls reproduce a similar negative residual.`,
    },
    {
      gate: "mechanism_proof_plausibility",
      passed: mechanismPressurePassed,
      status: mechanismPressurePassed ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/MECHANISM_PRESSURE_RESULTS.md`,
      rationale:
        "The candidate has a measured residual but no surviving mechanism/proof pressure that distinguishes it from known population variation.",
    },
    {
      gate: "external_inspectability",
      passed: inspectabilityComplete,
      status: inspectabilityComplete ? "passed" : "failed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/inspectability-package/CLAIM_EVIDENCE_BINDINGS.json`,
      rationale:
        "The raw target receipt, baseline record, counterexample record, replay record, and limitations are packageable from real evidence refs.",
    },
    {
      gate: "candidate_identity_stability",
      passed: true,
      status: "passed",
      evidenceRef: `${daemonArtifactRoot}/raw-insight-gate-closure/RAW_INSIGHT_CANDIDATE_PROFILE.md`,
      rationale:
        "The exact target-specific claim remains unchanged; no broader discovery claim is silently introduced.",
    },
  ];
  return {
    candidate,
    target,
    measurement,
    strongerBaselineResidual,
    rivalExplanations,
    rivalWeakened,
    holdoutStatus,
    holdoutSupport,
    replaySucceeded,
    counterexamples: signedControls.slice(0, 5),
    mechanismPressurePassed,
    inspectabilityComplete,
    gateMatrix,
    testsExecuted: 5,
  };
}

function rawInsightEmptyEvaluation(): ReturnType<
  typeof rawInsightEvaluateCandidate
> {
  return {
    candidate: null,
    target: null,
    measurement: null,
    strongerBaselineResidual: null,
    rivalExplanations: ["no raw-born InsightCandidate was available"],
    rivalWeakened: false,
    holdoutStatus: "unavailable",
    holdoutSupport: false,
    replaySucceeded: false,
    counterexamples: [],
    mechanismPressurePassed: false,
    inspectabilityComplete: false,
    gateMatrix: [
      {
        gate: "candidate_present",
        passed: false,
        status: "failed",
        evidenceRef: `${daemonArtifactRoot}/external-raw-evidence-reset/INSIGHT_CANDIDATES.md`,
        rationale: "No raw-born InsightCandidate is available for closure.",
      },
    ],
    testsExecuted: 0,
  };
}

function rawInsightPromotionDecision(
  gateMatrix: RawInsightGateMatrixRow[],
): RawInsightGateClosureDecision {
  const failed = gateMatrix.filter((row) => !row.passed).map((row) => row.gate);
  const promoted = failed.length === 0;
  return {
    promoted,
    discoveryCandidateId: promoted ? "DISCOVERY-RAW-INSIGHT-GATE-CLOSED" : null,
    killed: !promoted,
    killReason: failed[0] ?? "none",
    reason: promoted
      ? "All promotion gates closed; FundCandidateDraft creation would be the next protected step."
      : `Raw-born InsightCandidate is not promoted because ${failed.join(", ")} remained unresolved.`,
  };
}

function rawInsightGateClosureArtifactRefs(
  nextCheckpointRef: string,
): string[] {
  const root = `${daemonArtifactRoot}/raw-insight-gate-closure`;
  return [
    `${root}/RAW_INSIGHT_CANDIDATE_PROFILE.md`,
    `${root}/PROMOTION_GATE_MATRIX.md`,
    `${root}/RIVAL_TEST_RESULTS.md`,
    `${root}/HOLDOUT_TEST_RESULTS.md`,
    `${root}/REPLAY_RESULTS.md`,
    `${root}/COUNTEREXAMPLE_RESULTS.md`,
    `${root}/MECHANISM_PRESSURE_RESULTS.md`,
    `${root}/INSPECTABILITY_PACKAGE_STATUS.md`,
    `${root}/PROMOTION_DECISION.md`,
    `${root}/FUND_GATE_RESULTS.md`,
    `${root}/NEXT_CHECKPOINT.md`,
    `${root}/latest.json`,
    nextCheckpointRef,
  ];
}

